var fabOpen = false;
function toggleDarkMode(on) {
  document.body.classList.toggle('dark-mode', on);
  try { localStorage.setItem('nixa_dark', on ? '1' : '0'); } catch(e){}
  var ico = document.querySelector('#dark-mode-toggle');
  if (ico) ico.checked = on;
  var tonicono = document.getElementById('dark-mode-icon');
  if (tonicono) tonicono.className = on ? 'ti ti-sun' : 'ti ti-moon';
}

(function() {
  try {
    var saved = localStorage.getItem('nixa_dark');
    if (saved === '1') {
      document.body.classList.add('dark-mode');
    }
  } catch(e) {}
})();
function initSearchableSelect(selectId, placeholder) {
  var sel = document.getElementById(selectId);
  if (!sel || sel.dataset.ssInit) return;
  sel.dataset.ssInit = '1';
  sel.style.display = 'none';
  var ph = placeholder || 'Seleccionar...';
  var currentLabel = sel.selectedIndex >= 0 && sel.options[sel.selectedIndex]
    ? sel.options[sel.selectedIndex].text : ph;

  var wrap = document.createElement('div');
  wrap.className = 'ss-wrap';
  wrap.dataset.ss = selectId;
  sel.parentNode.insertBefore(wrap, sel);
  wrap.appendChild(sel);

  var inp = document.createElement('input');
  inp.type = 'text'; inp.className = 'ss-input';
  inp.readOnly = true; inp.value = currentLabel; inp.placeholder = ph;
  inp.dataset.ssId = selectId;
  inp.onclick = function() { ssToggle(this); };
  wrap.insertBefore(inp, sel);

  var drop = document.createElement('div');
  drop.className = 'ss-drop'; drop.id = 'ss-drop-' + selectId;

  var srch = document.createElement('input');
  srch.type = 'text'; srch.className = 'ss-search'; srch.placeholder = 'Buscar...';
  srch.dataset.ssFor = selectId;
  srch.oninput = function() { ssFilterByData(this); };
  srch.onclick = function(e) { e.stopPropagation(); };

  var list = document.createElement('div');
  list.className = 'ss-list'; list.id = 'ss-list-' + selectId;

  drop.appendChild(srch); drop.appendChild(list);
  document.body.appendChild(drop);

  ssRenderList(selectId, sel.value, '');

  document.addEventListener('click', function(e) {
    if (!e.target.closest('[data-ss="' + selectId + '"]') &&
        !e.target.closest('#ss-drop-' + selectId)) {
      ssClose(selectId);
    }
  });
}

function ssToggle(inp) {
  var id   = inp.dataset.ssId;
  var drop = document.getElementById('ss-drop-' + id);
  if (!drop) return;
  var isOpen = drop.classList.contains('open');
  document.querySelectorAll('.ss-drop.open').forEach(function(d){ d.classList.remove('open'); });
  if (!isOpen) {
    var rect = inp.getBoundingClientRect();
    drop.style.top   = (rect.bottom + 2) + 'px';
    drop.style.left  = rect.left + 'px';
    drop.style.width = Math.max(rect.width, 200) + 'px';
    drop.classList.add('open');
    var srch = drop.querySelector('.ss-search');
    if (srch) { srch.value = ''; ssFilter(srch, id); srch.focus(); }
  }
}

function ssClose(id) {
  var drop = document.getElementById('ss-drop-' + id);
  if (drop) drop.classList.remove('open');
}

function ssFilterByData(inp) {
  var id = inp.dataset.ssFor;
  if (id) ssFilter(inp, id);
}

function ssFilter(inp, id) {
  var sel = document.getElementById(id);
  if (!sel) return;
  ssRenderList(id, sel.value, inp.value);
}

function ssRenderList(id, currentVal, q) {
  var sel  = document.getElementById(id);
  var list = document.getElementById('ss-list-' + id);
  if (!list || !sel) return;
  var opts = Array.from(sel.options).map(function(o){ return { value:o.value, label:o.text }; });
  var filtered = q ? opts.filter(function(o){ return o.label.toLowerCase().includes(q.toLowerCase()); }) : opts;
  if (!filtered.length) { list.innerHTML = '<div class="ss-empty">Sin resultados</div>'; return; }
  list.innerHTML = '';
  filtered.forEach(function(o) {
    var item = document.createElement('div');
    item.className = 'ss-item' + (o.value === currentVal ? ' selected' : '');
    item.textContent = o.label;
    item.dataset.val  = o.value;
    item.dataset.ssId = id;
    item.onmousedown  = function() { ssSelect(this); };
    list.appendChild(item);
  });
}

function ssSelect(item) {
  var id  = item.dataset.ssId;
  var val = item.dataset.val;
  var sel = document.getElementById(id);
  var inp = document.querySelector('[data-ss-id="' + id + '"]');
  if (!sel || !inp) return;
  sel.value = val; inp.value = item.textContent.trim();
  sel.dispatchEvent(new Event('change'));
  ssClose(id);
}

function actualizarSelectCategorias() {
  var cats = window.categoriasData || [];
  ['filter-cat','pf-categoria'].forEach(function(sid) {
    var sel = document.getElementById(sid);
    if (!sel) return;
    sel.innerHTML = '<option value="">Todas las categorías</option>' +
      cats.map(function(c){ return '<option value="'+c+'">'+c+'</option>'; }).join('');
    // Re-inicializar el searchable select si ya existe
    var wrap = sel.parentNode;
    if (wrap && wrap.dataset && wrap.dataset.ss) {
      var inp = wrap.querySelector('.ss-input');
      if (inp) inp.value = sel.options[0] ? sel.options[0].text : '';
      ssRenderList(sid, sel.value, '');
    }
  });
}
