function fbCargarOTs() {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo), function(snap) {
    var data = snap.val();
    if (data) {
      otData = Object.entries(data).map(function(e) {
        return Object.assign({ fbKey: e[0] }, e[1]);
      });
    } else {
      otData = []; // sin OTs — resetear el array para que el dashboard muestre vacío
    }
    var pageAgenda = document.getElementById('page-agenda');
    if (pageAgenda && pageAgenda.classList.contains('active')) {
      if (typeof agRenderCalendario === 'function') agRenderCalendario();
      if (typeof agActualizarMetricas === 'function') agActualizarMetricas();
    }
    // guardado automático — refrescar en caliente podría pisar lo que el usuario está
    var otDetEl = document.getElementById('ot-detalle-view');
    if (otDetEl && otDetEl.style.display === 'block' && typeof otActualId !== 'undefined' && otActualId) {
      var otNueva = otData.find(function(o){ return o.id === otActualId || o.fbKey === otActualId; });
      if (otNueva && window._otDetalleHuella) {
        var huellaNueva = JSON.stringify(otNueva);
        if (window._otDetalleHuella !== huellaNueva) {
          var avisoEl = document.getElementById('ot-aviso-cambio-externo');
          if (window._otGuardandoLocalHasta && Date.now() < window._otGuardandoLocalHasta) {
            window._otDetalleHuella = huellaNueva;
            if (avisoEl) avisoEl.style.display = 'none';
          } else {
            if (avisoEl) avisoEl.style.display = 'flex';
          }
        }
      }
    }
    var pageDash = document.getElementById('page-dashboard');
    if (pageDash && pageDash.classList.contains('active') && typeof renderKPIsDashboard === 'function') renderKPIsDashboard();
  });
}

function fbGuardarOT(ot) {
  if (!window.fbDB) return Promise.resolve();
  window._otGuardandoLocalHasta = Date.now() + 2500;
  var r = window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo);
  var prom;
  if (ot.fbKey) {
    prom = window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo + '/' + ot.fbKey), ot);
  } else {
    prom = window.fbPush(r, ot).then(function(ref) { ot.fbKey = ref.key; return ref.key; });
  }
  return prom.then(function(res){
    if (typeof otActualId !== 'undefined' && otActualId && (ot.id === otActualId || ot.fbKey === otActualId)) {
      window._otDetalleHuella = JSON.stringify(ot);
      var avisoEl = document.getElementById('ot-aviso-cambio-externo');
      if (avisoEl) avisoEl.style.display = 'none';
    }
    return res;
  });
}
function fbSeedDatos() {
  if (!window.fbDB) { notify('Sin conexión Firebase'); return; }
  notify('Cargando datos demo a Firebase...');

  // Seed clientes
  clientesData.forEach(function(c) {
    var copia = Object.assign({}, c);
    delete copia.fbKey;
    window.fbPush(window.fbRef(window.fbDB, FB_PATHS.clientes), copia);
  });

  // Seed productos
  Object.values(prodData).forEach(function(p) {
    var copia = Object.assign({}, p);
    delete copia.fbKey;
    window.fbPush(window.fbRef(window.fbDB, FB_PATHS.productos), copia);
  });

  // Seed presupuestos
  pptoData.forEach(function(p) {
    var copia = Object.assign({}, p);
    delete copia.fbKey;
    window.fbPush(window.fbRef(window.fbDB, FB_PATHS.presupuestos), copia);
  });

  // Seed ventas
  ventasList.forEach(function(v) {
    var copia = Object.assign({}, v);
    delete copia.fbKey;
    window.fbPush(window.fbRef(window.fbDB, FB_PATHS.ventas), copia);
  });

  // Seed OTs
  otData.forEach(function(o) {
    var copia = Object.assign({}, o);
    delete copia.fbKey;
    window.fbPush(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo), copia);
  });

  setTimeout(function() { notify('✓ Datos demo cargados en Firebase'); }, 2000);
}
function fbMostrarEstadoConexion() {
  var badges = [document.getElementById('fb-status'), document.getElementById('fb-status-cfg')].filter(Boolean);
  if (!badges.length) return;
  var sinInternet = typeof navigator !== 'undefined' && navigator.onLine === false;
  var label = fbOnline ? 'Online' : (sinInternet ? 'Sin internet' : 'Reconectando');
  var icon = fbOnline ? 'ti-wifi' : 'ti-wifi-off';
  var color = fbOnline ? 'var(--green)' : 'var(--amber)';
  var title = fbOnline
    ? 'Conectado en tiempo real a Firebase'
    : (sinInternet ? 'El dispositivo informa que no tiene internet' : 'Firebase todavía no confirmó conexión activa');
  badges.forEach(function(badge) {
    badge.innerHTML = '<i class="ti '+icon+'" style="font-size:11px"></i> ' + label;
    badge.style.color = color;
    badge.title = title;
  });
}

var _monitorConexionFirebaseActivo = false;
function iniciarMonitorConexionFirebase() {
  if (_monitorConexionFirebaseActivo || !window.fbDB || !window.fbOnValue || !window.fbRef) {
    fbMostrarEstadoConexion();
    return;
  }
  _monitorConexionFirebaseActivo = true;
  window.fbOnValue(window.fbRef(window.fbDB, '.info/connected'), function(snap) {
    fbOnline = snap.val() === true;
    fbMostrarEstadoConexion();
  });
}

window.addEventListener('online', function() {
  fbMostrarEstadoConexion();
  if (typeof iniciarMonitorConexionFirebase === 'function') iniciarMonitorConexionFirebase();
});
window.addEventListener('offline', function() {
  fbOnline = false;
  fbMostrarEstadoConexion();
});

document.addEventListener('firebase-ready', function() {
  iniciarMonitorConexionFirebase();
  fbMostrarEstadoConexion();
});

