// Interceptar errores de getContext en elementos null
window.addEventListener('error', function(e) {
  if (e.message && e.message.includes('getContext')) {
    e.preventDefault(); // Suprimir el error
    return true;
  }
});
var notifT;
var PERMISOS_DEFAULT = {
  admin:          { bloqueados: [] },
  administrativo: { bloqueados: ['usuarios','configuracion','rentabilidad','tesoreria'] },
  vendedor:       { bloqueados: ['usuarios','configuracion','rentabilidad','empleados','vacaciones','reportes','estadisticas','proveedores','ordenes','cuentacorriente','creditofiscal','gastos','tesoreria'] },
  tecnico:        { bloqueados: ['usuarios','configuracion','rentabilidad','empleados','vacaciones','reportes','estadisticas','proveedores','ordenes','cuentacorriente','detalle','venta','presupuesto','cobranzas','creditofiscal','caja','gastos','clientes','productos','kits','tesoreria'] }
};
var PERMISOS_ROLES = JSON.parse(JSON.stringify(PERMISOS_DEFAULT));
// Fuente única para decisiones de permisos en botones/acciones.
// Mantiene compatibilidad con la solapa Configuración → Roles, que hoy gobierna
// visibilidad/acceso por módulo. Las acciones finas usan esta base para evitar
// validaciones dispersas por nombre de rol.
function rolActualNormalizado() {
  return window.SisVentas && window.SisVentas.Access
    ? window.SisVentas.Access.current()
    : String(currentRole || '').toLowerCase();
}
function esAdmin() { return rolActualNormalizado() === 'admin'; }
function esAdministrativo() { return rolActualNormalizado() === 'administrativo'; }
function esTecnico() { return rolActualNormalizado() === 'tecnico'; }
function esAdminOAdministrativo() { return esAdmin() || esAdministrativo(); }
function permisoModulo(idModulo) {
  if (window.SisVentas && window.SisVentas.Access) {
    if (idModulo === 'tesoreria' && !esAdmin()) return false;
    return window.SisVentas.Access.canAccess(idModulo, PERMISOS_ROLES, PERMISOS_DEFAULT);
  }
  if (!idModulo) return false;
  if (esAdmin()) return true;
  if (idModulo === 'tesoreria') return false;
  var cfg = (PERMISOS_ROLES[rolActualNormalizado()] || PERMISOS_DEFAULT[rolActualNormalizado()] || { bloqueados: [] });
  return (cfg.bloqueados || []).indexOf(idModulo) === -1;
}
function puedeEditarVentaPermiso(v) {
  return esAdminOAdministrativo() && permisoModulo('detalle') && !ventaTienePagoTotal(v);
}
function puedeEditarPresupuestoPermiso(p) {
  return esAdminOAdministrativo() && permisoModulo('presupuesto') && pptoPuedeEditar(p);
}

var _paginaAntesDeNotif = null;

function toggleNotificacionesPanel() {
  if (typeof closeSidebarMobile === 'function') closeSidebarMobile();
  var pagNotif = document.getElementById('page-notificaciones');
  var estaAbierta = pagNotif && pagNotif.classList.contains('active');

  if (estaAbierta) {
    // Volver a la página anterior
    if (_paginaAntesDeNotif) {
      showPage(_paginaAntesDeNotif.id, _paginaAntesDeNotif.el);
    } else {
      showPage('dashboard', document.querySelector('[onclick*="dashboard"]'));
    }
    _paginaAntesDeNotif = null;
  } else {
    var actual = document.querySelector('.page.active');
    var actualId = actual ? actual.id.replace('page-','') : 'dashboard';
    var actualNav = document.querySelector('.nav-item.active');
    _paginaAntesDeNotif = { id: actualId, el: actualNav };
    showPage('notificaciones', document.querySelector('[onclick*="notificaciones"]'));
  }
}

function showPage(id, el) {
  if (!isAuthenticated) { notify('Primero iniciá sesión'); return; }
  if (window.SisVentas && window.SisVentas.Access) {
    var resolvedPage = window.SisVentas.Access.resolvePage(id);
    if (resolvedPage.redirected) {
      notify('No tenés permiso para acceder a este módulo.');
      id = resolvedPage.page;
      el = document.querySelector('[onclick*="' + id + '"]');
    }
  }
  var page = document.getElementById('page-' + id);
  if (!page) { notify('Módulo no disponible'); return; }
  // Validar permisos dinámicos (Configuración → Roles)
  if (!permisoModulo(id)) {
    notify('Acceso restringido para tu rol');
    return;
  }
  if (id === 'cobranzas' && el) {
    var btnVolver = document.getElementById('cob-volver-venta');
    if (btnVolver) btnVolver.style.display = 'none';
    window._cobOrigenVentaId = null;
  }
  // Ocultar todas las páginas
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.querySelectorAll('.nav-item').forEach(function(n) { n.classList.remove('active'); });
  page.classList.add('active');
  if (el && el.classList) el.classList.add('active');

  var _titulo = titles[id] || 'SisVentas';
  var _setTitulo = function() {
    var titleEl = document.getElementById('page-title');
    if (titleEl) titleEl.textContent = _titulo;
  };
  _setTitulo();
  setTimeout(_setTitulo, 50);
  setTimeout(_setTitulo, 200);

  // Lógica por módulo
  if (id === 'empleados')      { if(typeof volverlista==='function') volverlista(); setTimeout(function(){ if(typeof renderTablaEmpleados==='function') renderTablaEmpleados(); }, 100); }
  if (id === 'clientes')      { window._histClienteHuella = null; setTimeout(function(){ if(typeof renderTablaClientes==='function'){ var inp=document.querySelector('#page-clientes .search-input'); renderTablaClientes(inp?inp.value:''); } if(typeof actualizarStatClientes==='function') actualizarStatClientes(); }, 100); }
  if (id === 'venta') {
    setTimeout(function(){
      var body = document.getElementById('det-body');
      if (body && body.children.length === 0) addRow();
    }, 100);
  }
  if (id === 'detalle')       { setTimeout(function(){ if(window._ventaDesdeHistorialOrigen) return; if(typeof volverListaVentas==='function') volverListaVentas(); if(typeof renderMetricasVentas==='function') renderMetricasVentas(); }, 100); }
  if (id === 'presupuesto')    { setTimeout(function(){ if(typeof renderPptoTabla==='function') renderPptoTabla(); }, 50); }
  if (id === 'ordentrabajo')   { setTimeout(function(){ if(typeof volverListaOT==='function'){volverListaOT();renderOTTabla();} }, 50); }
  if (id === 'venta')          { setTimeout(function(){ if(typeof inicializarFilasVenta==='function') inicializarFilasVenta(); if(typeof iniciarMonedaVenta==='function') iniciarMonedaVenta(); }, 50); }
  if (id === 'gastos')         { setTimeout(function(){ if(typeof renderTablaGastos==='function'){ renderTablaGastos(); actualizarMetricasGastos(); }}, 50); }
  if (id === 'dashboard') { setTimeout(function(){
    if(typeof renderKPIsDashboard==='function') renderKPIsDashboard();
    applyDashWidgets();
    var mc=document.getElementById('dash-micuenta-card');
    if (currentRole === 'admin' && mc) mc.style.display='none';
    if (currentRole === 'tecnico') renderDashMisOTs();
    if (currentRole === 'administrativo' || currentRole === 'vendedor') renderDashAdministrativo();
    if (currentRole !== 'admin') renderDashMiCuenta();
    renderAvisoProximasVacaciones();
  }, 100); }
  if (id === 'ctaemp')         { setTimeout(function(){
    if(typeof iniciarCtaEmp==='function') iniciarCtaEmp();
  }, 300); }
  if (id === 'rentabilidad')   { setTimeout(function(){ if(typeof calcRentabilidad==='function') calcRentabilidad(); }, 100); }
  if (id === 'informes')       { setTimeout(function(){ renderTablaInformes(); }, 50); }
  if (id === 'equipos')        { setTimeout(function(){ renderEquiposCards(); actualizarMetricasEquipos(); }, 50); }
  if (id === 'ordenes')        { setTimeout(function(){ renderDashOrdenes(); }, 50); }
  if (id === 'garantias')      { setTimeout(function(){ fbCargarGarantias(); }, 50); }
  if (id === 'soporte')        { setTimeout(function(){ fbCargarTickets(); }, 50); }
  if (id === 'remitos')        { setTimeout(function(){ fbCargarRemitos(); }, 50); }
  if (id === 'agenda')         { setTimeout(function(){ fbCargarAgenda(); }, 50); }
  if (id === 'servicios')      { setTimeout(function(){ fbCargarServicios(); }, 50); }
  if (id === 'asistente')      { setTimeout(function(){ document.getElementById('asist-inicio').style.display='';document.getElementById('asist-preguntas').style.display='none';document.getElementById('asist-resumen').style.display='none'; }, 50); }
  if (id === 'vacaciones')     { setTimeout(function(){
    if(typeof renderModuloVacaciones==='function') renderModuloVacaciones();
  }, 300); }
  if (id === 'tablero')        { setTimeout(function(){ renderTablero(); }, 100); }
  if (id === 'creditofiscal')  { setTimeout(function(){ if(typeof cfRenderTodo==='function') cfRenderTodo(); if(typeof fvRenderTodo==='function') fvRenderTodo(); if(typeof fvRenderCompensacion==='function') fvRenderCompensacion(); }, 100); }
  if (id === 'reportes')       { setTimeout(function(){ renderReportes(); }, 100); }
  if (id === 'estadisticas')   { setTimeout(function(){ if(typeof renderEstadisticas==='function') renderEstadisticas(); }, 150); }
  if (id === 'caja')           { setTimeout(function(){ fbCargarCaja(); }, 50); }
  if (id === 'cobranzas')      { setTimeout(function(){ fbCargarPagos(); }, 50); }
  if (id === 'cuentacorriente'){ setTimeout(function(){ fbCargarPagos(); }, 50); }
  if (id === 'configuracion')   { setTimeout(function(){
    try{ if(typeof cargarConfigGeneral==='function') cargarConfigGeneral(); }catch(e){}
    try{ if(typeof cargarConfigImpuestos==='function') cargarConfigImpuestos(); }catch(e){}
    try{ if(typeof cargarConfigComisiones==='function') cargarConfigComisiones(); }catch(e){}
    try{ if(typeof cargarCargos==='function') cargarCargos(); }catch(e){}
    try{ if(typeof renderMediosPagoConfig==='function') renderMediosPagoConfig(); }catch(e){}
  }, 200); }
  if (id === 'kits') {
    var klv=document.getElementById('kits-list-view');
    var kfv=document.getElementById('kit-form-view');
    if(klv) klv.style.display='block';
    if(kfv) kfv.style.display='none';
    if (typeof cargarKits === 'function') cargarKits();
  }
  if (id === 'productos')      {
    try { if(typeof mostrarAlertasStock==='function') mostrarAlertasStock(); } catch(e){}
    var plv=document.getElementById('prod-list-view');
    var pfv=document.getElementById('prod-form-view');
    var pdv=document.getElementById('prod-detail-view');
    if(plv) plv.style.display='block';
    if(pfv) pfv.style.display='none';
    if(pdv) pdv.style.display='none';
  }

  // FAB y Home en mobile
  if (typeof actualizarFabYHome === 'function') actualizarFabYHome(id);
  // Cerrar sidebar en mobile
  // Scroll al top al cambiar de página
  var contentEl = document.querySelector('.content');
  if (contentEl) contentEl.scrollTop = 0;

  if (window.innerWidth <= 768 && typeof closeSidebarMobile === 'function') closeSidebarMobile();
  if (window.SisVentas && window.SisVentas.Access) {
    window.SisVentas.Access.emit('page-changed', { page: id });
  }
}

function notify(msg) {
  var n = document.getElementById('notif');
  if (!n) return;
  n.innerHTML = '<i class="ti ti-check" style="font-size:15px"></i> ' + String(msg || '');
  n.classList.add('show');
  clearTimeout(notifT);
  notifT = setTimeout(function() { n.classList.remove('show'); }, 2500);
}
function applyRole() {
  var isAdmin         = currentRole === 'admin';
  var isTecnico       = currentRole === 'tecnico';
  var isAdministrativo= currentRole === 'administrativo';
  var isVendedor      = currentRole === 'vendedor';

  // Cambiar label "Mi cuenta" / "Cuentas" según rol
  var labelCtaemp = document.getElementById('nav-label-ctaemp');
  if (labelCtaemp) labelCtaemp.textContent = isAdmin ? 'Cuentas' : 'Mi cuenta';
  var rolLabels = { admin:'Admin', administrativo:'Administrativo', vendedor:'Vendedor', tecnico:'Técnico' };
  var rolClases = { admin:'admin', administrativo:'vendedor', vendedor:'vendedor', tecnico:'vendedor' };

  var badge = document.getElementById('role-badge-el');
  if (badge) {
    badge.textContent = rolLabels[currentRole] || currentRole;
    badge.className   = 'role-badge ' + (rolClases[currentRole] || 'vendedor');
  }

  document.querySelectorAll('.admin-only').forEach(function(el){
    el.style.display = isAdmin ? '' : 'none';
  });
  document.querySelectorAll('.admin-o-administrativo').forEach(function(el){
    el.style.display = (isAdmin || isAdministrativo) ? '' : 'none';
  });
  document.querySelectorAll('.no-tecnico').forEach(function(el){
    el.style.display = isTecnico ? 'none' : '';
  });
  document.querySelectorAll('.no-administrativo').forEach(function(el){
    el.style.display = isAdministrativo ? 'none' : '';
  });
  document.querySelectorAll('.no-vendedor').forEach(function(el){
    el.style.display = isVendedor ? 'none' : '';
  });
  document.querySelectorAll('.tecnico-only').forEach(function(el){
    el.style.display = isTecnico ? '' : 'none';
  });

  if (typeof applyDashWidgets === 'function') applyDashWidgets();
  // del rol actual. Esto evita que queden ocultos ítems de una sesión anterior con
  // un rol más restrictivo (ej: cerrar sesión de vendedor y entrar como admin).
  document.querySelectorAll('.nav-item[onclick]').forEach(function(el) {
    el.style.display = '';
  });
  var bloqueados = (PERMISOS_ROLES[currentRole]||PERMISOS_DEFAULT[currentRole]||{bloqueados:[]}).bloqueados||[];
  if (bloqueados.length) {
    document.querySelectorAll('.nav-item[onclick]').forEach(function(el) {
      var onclick = el.getAttribute('onclick')||'';
      var match = onclick.match(/showPage\('([^']+)'/);
      if (match && bloqueados.includes(match[1])) {
        el.style.display = 'none';
      }
    });
  }
  // Tesorería queda reservada al administrador aunque una configuración vieja
  // de roles no la tenga bloqueada.
  document.querySelectorAll('.nav-item[onclick*="tesoreria"]').forEach(function(el){
    el.style.display = isAdmin ? '' : 'none';
  });
  // Los guards agregados al final del archivo deben reaccionar al cambio de rol,
  // no volver a aplicar estilos mediante un intervalo permanente.
  if (typeof window.sv361ApplyRoleGuard === 'function') {
    window.sv361ApplyRoleGuard();
  }
  if (window.SisVentas && window.SisVentas.Access) {
    window.SisVentas.Access.emit('role-changed', { role: rolActualNormalizado() });
  }
}
