window.doLogin = function doLogin() {
  var u = document.getElementById('l-user').value.trim();
  var p = document.getElementById('l-pass').value;
  var err = document.getElementById('login-error');

  if (window.fbAuth && window.fbSignIn) {
    // v20.362: el campo de usuario vuelve a aceptar usuario corto (nixa) o email completo.
    // El input ya no es type=email para evitar la validación nativa del navegador antes de autocompletar.
    var usuarioLogin = u.toLowerCase().replace(/\s+/g,'');
    var email = usuarioLogin.includes('@') ? usuarioLogin : usuarioLogin + '@sistemanixa.com';
    window._loginEnCurso = true;
    window.fbSignIn(window.fbAuth, email, p)
      .then(function(cred) {
        if(err) err.style.display = 'none';
        isAuthenticated = true;

        var userPart = (typeof usuarioLogin !== 'undefined' ? usuarioLogin : u.toLowerCase().trim()); // parte antes del @ o el usuario completo
        var passLower = p.toLowerCase().trim();
        var esPasswordDefault = passLower === userPart ||
          passLower === email.split('@')[0].toLowerCase() ||
          passLower === (userPart.replace(/[^a-z]/g,''));

        if (esPasswordDefault) {
          window._pendingLoginUser = cred.user;
          _mostrarForzarCambioPassword(cred.user, err);
          return;
        }

        _resolverRolYCompletarLogin(cred.user, err);
      })
      .catch(function(fbError) {
        window._loginEnCurso = false;
        if (typeof window._resetLoginBtn === 'function') window._resetLoginBtn();
        var code = fbError ? fbError.code : 'desconocido';
        var msg  = fbError ? fbError.message : '';
        if(err) {
          err.textContent = 'Error: ' + code + (msg ? ' — ' + msg.slice(0,80) : '');
          err.style.display = 'block';
        }
      });
  } else {
    var demo = APP_CONFIG.DEMO_USERS[u.toLowerCase()];
    if (!demo || demo.password !== p) {
      if(err) err.style.display = 'block';
      return;
    }
    if(err) err.style.display = 'none';
    isAuthenticated = true;
    currentRole = demo.role;
    _completarLogin(demo.name);
  }
}
function _resolverRolYCompletarLogin(user, err) {
  var emailLower = user.email.toLowerCase();
  currentUserUid = user.uid;
  currentUserEmail = emailLower;

  // Timeout de emergencia: si en 8 segundos no completó el login,
  // cerrar sesión y mostrar el login limpio para no quedar colgado.
  var _loginTimeout = setTimeout(function() {
    if (!isAuthenticated) return;
    isAuthenticated = false;
    if (window.fbAuth && window.fbSignOut) window.fbSignOut(window.fbAuth).catch(function(){});
    var loadingEl = document.getElementById('screen-loading');
    if (loadingEl) loadingEl.style.display = 'none';
    document.getElementById('screen-login').style.display = '';
    var errEl = document.getElementById('login-error');
    if (errEl) {
      errEl.textContent = 'El servidor tardó demasiado en responder. Intentá de nuevo.';
      errEl.style.display = 'block';
    }
  }, 8000);

  function aplicarRolYNombre(lista) {
    clearTimeout(_loginTimeout); // login completado, cancelar timeout
    lista = lista || [];
    var usuario = lista.find(function(u) {
      var mailDB = (u.mail || (u.login && u.login.includes('@') ? u.login : (u.login||'')+'@sistemanixa.com')).toLowerCase();
      return mailDB === emailLower;
    });
    if (!usuario) {
      var esAdmin = emailLower === 'nixa@sistemanixa.com' || emailLower.startsWith('admin@');
      currentRole = esAdmin ? 'admin' : 'vendedor';
      if (esAdmin) {
        notify('⚠ï¸ Ingresaste como Admin. Creá tu usuario en Usuarios → Nuevo usuario para quitar este aviso.');
      } else {
        notify('⚠ï¸ Usuario no registrado en el sistema — rol limitado. Pedile al admin que te agregue.');
      }
      _completarLogin(user.displayName || user.email.split('@')[0]);
      return;
    }
    if (usuario.activo === false) {
      clearTimeout(_loginTimeout);
      window.fbSignOut(window.fbAuth);
      isAuthenticated = false;
      var loadingEl = document.getElementById('screen-loading');
      if (loadingEl) loadingEl.style.display = 'none';
      document.getElementById('screen-login').style.display = '';
      if (err) { err.textContent = 'Tu cuenta está desactivada. Contactá al administrador.'; err.style.display = 'block'; }
      return;
    }
    var r = (usuario.rol||'').toLowerCase();
    currentRole = (r==='admin'||r==='administrador') ? 'admin'
                : (r==='tecnico'||r==='técnico')     ? 'tecnico'
                : (r==='vendedor')                   ? 'vendedor'
                : 'administrativo';
    _completarLogin(usuario.nombre || user.email.split('@')[0]);
  }

  // Siempre leer frescos desde Firebase — no confiar en caché de sesión anterior
  // que podría tener datos de otro usuario o de una versión vieja del código.
  var _usuariosTimeout = setTimeout(function() {
    console.warn('[Auth] fbGet usuarios timeout — usando fallback');
    if (window.usuariosData && window.usuariosData.length) {
      aplicarRolYNombre(window.usuariosData);
    } else {
      // Sin caché: asumir admin si es el email de nixa
      var esAdminFallback = emailLower === 'nixa@sistemanixa.com' || emailLower.startsWith('admin@');
      currentRole = esAdminFallback ? 'admin' : 'vendedor';
      _completarLogin(user.displayName || user.email.split('@')[0]);
    }
  }, 5000);

  window.fbGet(window.fbRef(window.fbDB, 'sisventas/usuarios')).then(function(snap) {
    clearTimeout(_usuariosTimeout);
    var data = snap.val();
    var lista = data ? Object.values(data) : [];
    window.usuariosData = lista; // actualizar caché
    aplicarRolYNombre(lista);
  }).catch(function() {
    clearTimeout(_usuariosTimeout);
    clearTimeout(_loginTimeout);
    // Fallback: intentar con datos cacheados si los hay
    if (window.usuariosData && window.usuariosData.length) {
      aplicarRolYNombre(window.usuariosData);
    } else {
      window.fbSignOut(window.fbAuth);
      isAuthenticated = false;
      var loadingEl = document.getElementById('screen-loading');
      if (loadingEl) loadingEl.style.display = 'none';
      document.getElementById('screen-login').style.display = '';
      if (err) { err.textContent = 'No se pudo verificar el rol. Verificá tu conexión.'; err.style.display = 'block'; }
    }
  });
}
// Aislado del flujo de login manual. Si Firebase detecta una sesión ya activa
// al cargar la página, restaura directamente sin pedir credenciales de nuevo.
var _sesionYaRestaurada = false;
var _primeraVerificacionAuth = true;
window._restaurandoSesionInicial = false;
document.addEventListener('firebase-ready', function() {
  if (!window.fbOnAuth || !window.fbAuth) {
    // Sin Firebase Auth disponible — mostrar login directamente
    _mostrarLoginSinSesion();
    return;
  }
  window.fbOnAuth(window.fbAuth, function(user) {
    if (user && !_sesionYaRestaurada && !isAuthenticated) {
      _sesionYaRestaurada = true;
      _primeraVerificacionAuth = false;
      window._restaurandoSesionInicial = true;
      var appScreen = document.getElementById('screen-app');
      if (appScreen && !appScreen.classList.contains('visible')) {
        isAuthenticated = true;
        _resolverRolYCompletarLogin(user, null);
      }
    } else if (!user) {
      _sesionYaRestaurada = false;
      if (_primeraVerificacionAuth) {
        _primeraVerificacionAuth = false;
        _mostrarLoginSinSesion();
      }
    }
  });
});

function _mostrarLoginSinSesion() {
  var loadingEl = document.getElementById('screen-loading');
  var loginEl   = document.getElementById('screen-login');
  window._restaurandoSesionInicial = false;
  if (loadingEl) {
    loadingEl.classList.remove('sv-intro-loading', 'sv-boot-exit');
    loadingEl.style.display = 'none';
  }
  if (loginEl)   loginEl.style.display = '';
}

// Red de seguridad: si después de 6 segundos Firebase nunca respondió
// (sin internet, error de configuración, etc.), mostrar el login igual
// para no dejar al usuario trabado en la pantalla de carga indefinidamente.
setTimeout(function() {
  if (_primeraVerificacionAuth && !isAuthenticated) {
    _primeraVerificacionAuth = false;
    _mostrarLoginSinSesion();
  }
}, 6000);

// Timeout ABSOLUTO: si después de 12 segundos la app no está visible,
// mostrar login sin importar qué — cubre casos donde Auth responde pero
// fbGet de usuarios se cuelga sin error (modo avión con sesión cacheada)
setTimeout(function() {
  if (window._loginEnCurso) return;
  var appScreen = document.getElementById('screen-app');
  var loginEl   = document.getElementById('screen-login');
  var loadingEl = document.getElementById('screen-loading');
  var appVisible = appScreen && appScreen.classList.contains('visible');
  if (!appVisible && loadingEl && loadingEl.style.display !== 'none') {
    if (loadingEl) loadingEl.style.display = 'none';
    if (loginEl)   loginEl.style.display = '';
    // NO hacer fbSignOut aquí — puede interrumpir un login manual lento
  }
}, 15000);
// y aplica el cambio a online:false automáticamente, sin depender de que el
// a diferencia de simplemente registrar el último login.
function registrarPresenciaOnline() {
  if (!window.fbDB || !window.fbOnDisconnect || !currentUserUid) return;
  var refPresencia = window.fbRef(window.fbDB, 'sisventas/presencia/' + currentUserUid);
  var datosOnline = {
    online: true,
    nombre: currentUser || '',
    email: currentUserEmail || '',
    rol: currentRole || '',
    ultimaConexion: window.fbServerTimestamp ? window.fbServerTimestamp() : Date.now()
  };
  window.fbSet(refPresencia, datosOnline);
  // Firebase aplica esto solo del lado del servidor.
  window.fbOnDisconnect(refPresencia).set({
    online: false,
    nombre: currentUser || '',
    email: currentUserEmail || '',
    rol: currentRole || '',
    ultimaDesconexion: window.fbServerTimestamp ? window.fbServerTimestamp() : Date.now()
  });
}

function limpiarPresenciaOnline() {
  if (!window.fbDB || !currentUserUid) return;
  window.fbUpdate(window.fbRef(window.fbDB, 'sisventas/presencia/' + currentUserUid), {
    online: false,
    ultimaDesconexion: window.fbServerTimestamp ? window.fbServerTimestamp() : Date.now()
  }).catch(function(){});
}

function _verificarHaberesPendientes() {
  if (!['admin','administrativo'].includes(currentRole)) return;
  var hoy = new Date();
  var dia = hoy.getDate();
  if (dia < 1 || dia > 5) return;

  var mesPasado = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);
  var mesKey    = mesPasado.toISOString().slice(0,7).replace('-','_');
  var mesLbl    = mesPasado.toLocaleDateString('es-AR',{month:'long',year:'numeric'});

  if (!window.fbDB) return;
  window.fbGet(window.fbRef(window.fbDB, 'sisventas/haberes')).then(function(snap) {
    var habData = snap.val() || {};
    var empleados = Object.values(empData||{}).filter(function(e){ return e.activo !== false && e.cargoId; });
    if (!empleados.length) return;
    // Ver si hay algún empleado activo sin haberes del mes pasado
    var sinRegistrar = empleados.filter(function(e) {
      return !habData[e.fbKey] || !habData[e.fbKey][mesKey];
    });
    if (sinRegistrar.length > 0) {
      // Mostrar notificación no intrusiva
      var msg = '⚠ï¸ No se registraron los haberes de ' + mesLbl + ' para ' +
        sinRegistrar.length + ' empleado' + (sinRegistrar.length !== 1 ? 's' : '') + '. ';
      if (typeof notify === 'function') {
        setTimeout(function() {
          notify(msg + 'Ir a Empleados → Registrar haberes del mes.', 8000);
        }, 3000);
      }
    }
  }).catch(function(){});
}

function _mostrarForzarCambioPassword(fbUser, errEl) {
  // Mostrar pantalla de login limpia con modal de cambio encima
  var loadingEl = document.getElementById('screen-loading');
  if (loadingEl) loadingEl.style.display = 'none';

  var prev = document.getElementById('modal-forzar-pass');
  if (prev) prev.remove();

  var overlay = document.createElement('div');
  overlay.id = 'modal-forzar-pass';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:10000;background:rgba(0,0,0,.7);display:flex;align-items:center;justify-content:center;padding:16px';
  overlay.innerHTML =
    '<div style="background:var(--bg2);border-radius:var(--radius-lg);width:100%;max-width:420px;padding:28px;box-shadow:0 16px 48px rgba(0,0,0,.5)">' +
      '<div style="text-align:center;margin-bottom:20px">' +
        '<div style="font-size:32px;margin-bottom:8px">🔐</div>' +
        '<div style="font-weight:700;font-size:16px;margin-bottom:6px">Cambiá tu contraseña</div>' +
        '<div style="font-size:13px;color:var(--text3)">Es tu primer ingreso al sistema.<br>Elegí una contraseña personal para continuar.</div>' +
      '</div>' +
      '<div style="display:flex;flex-direction:column;gap:12px">' +
        '<div class="fg"><label>Nueva contraseña</label><input type="password" id="forzar-pass-nueva" placeholder="Mínimo 6 caracteres" autocomplete="new-password" style="width:100%;padding:10px 12px;border:0.5px solid var(--border2);border-radius:var(--radius);background:var(--bg);color:var(--text);font-family:inherit;font-size:14px"></div>' +
        '<div class="fg"><label>Repetir contraseña</label><input type="password" id="forzar-pass-confirm" placeholder="Repetí la contraseña" autocomplete="new-password" style="width:100%;padding:10px 12px;border:0.5px solid var(--border2);border-radius:var(--radius);background:var(--bg);color:var(--text);font-family:inherit;font-size:14px"></div>' +
        '<div id="forzar-pass-error" style="display:none;color:var(--red);font-size:12px;padding:8px 10px;background:rgba(239,68,68,.1);border-radius:6px"></div>' +
        '<button class="btn btn-primary" style="width:100%;margin-top:4px" onclick="_confirmarCambioForzado()">' +
          '<i class="ti ti-check"></i> Guardar y entrar al sistema' +
        '</button>' +
      '</div>' +
    '</div>';

  document.body.appendChild(overlay);

  window._fbUserPendingPass = fbUser;

  setTimeout(function(){
    var inp = document.getElementById('forzar-pass-nueva');
    if (inp) inp.focus();
  }, 100);
}

async function _confirmarCambioForzado() {
  var nueva   = (document.getElementById('forzar-pass-nueva').value || '').trim();
  var confirm = (document.getElementById('forzar-pass-confirm').value || '').trim();
  var errEl   = document.getElementById('forzar-pass-error');

  var mostrarError = function(msg) {
    errEl.textContent = msg;
    errEl.style.display = '';
  };

  if (!nueva || !confirm) { mostrarError('Completá ambos campos'); return; }
  if (nueva.length < 6)   { mostrarError('Mínimo 6 caracteres'); return; }
  if (nueva !== confirm)  { mostrarError('Las contraseñas no coinciden'); return; }

  var fbUser = window._fbUserPendingPass;
  if (!fbUser) { mostrarError('Error: sesión no disponible'); return; }

  try {
    await window.fbUpdatePass(fbUser, nueva);
    // Contraseña cambiada — ahora sí continuar con el login normal
    document.getElementById('modal-forzar-pass').remove();
    window._fbUserPendingPass = null;
    notify('✓ Contraseña guardada — bienvenido al sistema');
    _resolverRolYCompletarLogin(fbUser, null);
  } catch(e) {
    mostrarError('Error al guardar: ' + (e.message || e));
  }
}

function _completarLogin(nombre) {
  currentUser = nombre;
  applyRole();
  registrarPresenciaOnline();
  if (typeof registrarActividad === 'function') registrarActividad('Inicio de sesión', '');
  // Iniciar listener de versión en tiempo real vía Firebase
  if (typeof iniciarChequeoPeriodicoVersion === 'function') iniciarChequeoPeriodicoVersion();
  if (typeof window.iniciarSyncNotificaciones === 'function') window.iniciarSyncNotificaciones();
  if (typeof restaurarPaginaPostActualizacion === 'function') restaurarPaginaPostActualizacion();
  // la detectan en tiempo real sin depender del CDN de GitHub Pages.
  if (currentRole === 'admin' && window.fbDB && APP_CONFIG && APP_CONFIG.VERSION) {
    window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/version'), APP_CONFIG.VERSION)
      .catch(function(){});
  }

  // Mostrar versión en el sidebar
  var vSidebar = document.getElementById('s-version-el');
  if (vSidebar && APP_CONFIG && APP_CONFIG.VERSION) {
    vSidebar.textContent = APP_CONFIG.VERSION.replace('-firebase','') + ' · Firebase';
  }

  // Ocultar login, mostrar pantalla de carga
  document.getElementById('screen-login').style.display = 'none';
  var loadingEl = document.getElementById('screen-loading');
  var bar       = document.getElementById('loading-bar');
  var msg       = document.getElementById('loading-msg');
  var logoEl    = document.getElementById('loading-logo');
  var modoIntroRecarga = window._restaurandoSesionInicial === true && !window._loginEnCurso;
  if (loadingEl) {
    loadingEl.classList.remove('sv-boot-exit');
    loadingEl.classList.toggle('sv-intro-loading', modoIntroRecarga);
    loadingEl.style.display = 'flex';
  }
  aplicarLogoSistema(logoActualUrl());

  var sname = document.getElementById('s-uname-el');
  if (sname) sname.textContent = nombre;
  var srole = document.getElementById('s-urole-el');
  var rolLabels = { admin:'Administrador', administrativo:'Administrativo', vendedor:'Vendedor', tecnico:'Técnico' };
  if (srole) srole.textContent = rolLabels[currentRole] || currentRole;
  var av = document.getElementById('s-avatar-el');
  if (av) {
    var partes = nombre.split(' ');
    av.textContent = partes.length >= 2 ? (partes[0][0]+(partes[1][0]||'')).toUpperCase() : nombre.slice(0,2).toUpperCase();
  }

  // Secuencia de carga con progreso
  var pasos = [
    { pct: 15, txt: 'Cargando clientes y productos...' },
    { pct: 35, txt: 'Cargando ventas y presupuestos...' },
    { pct: 55, txt: 'Cargando empleados y usuarios...' },
    { pct: 75, txt: 'Cargando equipos e informes...' },
    { pct: 90, txt: 'Preparando el dashboard...' },
    { pct: 100, txt: '¡Listo!' },
  ];
  var paso = 0;
  var iv = setInterval(function() {
    if (paso < pasos.length) {
      if (bar) bar.style.width = pasos[paso].pct + '%';
      if (msg) msg.textContent = pasos[paso].txt;
      paso++;
    } else {
      clearInterval(iv);
    }
  }, 400);

  // Iniciar carga de datos
  if (typeof startSessionTimer === 'function') startSessionTimer();
  if (typeof actualizarPanelUsuario === 'function') actualizarPanelUsuario();
  if (typeof fbCargarTodo === 'function') fbCargarTodo();
  if (typeof cargarLogoGuardado === 'function') setTimeout(cargarLogoGuardado, 300);
  if (typeof cargarConfigGeneral === 'function') setTimeout(cargarConfigGeneral, 350);
  if (typeof cargarConfigImpuestos === 'function') setTimeout(cargarConfigImpuestos, 350);
  if (typeof cargarConfigComisiones === 'function') setTimeout(cargarConfigComisiones, 350);
  if (typeof cargarMediosPago === 'function') setTimeout(cargarMediosPago, 400);
  if (typeof inicializarFlujoVentas === 'function') setTimeout(inicializarFlujoVentas, 4000);
  if (typeof iaInicializar === 'function') setTimeout(iaInicializar, 1000);
  if (typeof chatInicializar === 'function') setTimeout(chatInicializar, 1500);
  // Mostrar FAB solo en mobile
  setTimeout(function(){
    if (window.innerWidth <= 1024) {
      var fab = document.getElementById('fab-container');
      if (fab) fab.style.display = 'flex';
    }
  }, 1200);
  if (typeof cargarCargos === 'function') setTimeout(cargarCargos, 350);
  if (typeof cargarPresenciaUsuarios === 'function') setTimeout(cargarPresenciaUsuarios, 350);
  if (typeof spCargar === 'function') setTimeout(spCargar, 400);
  if (typeof fbCargarVacaciones === 'function') setTimeout(fbCargarVacaciones, 400);
  if (typeof cfCargar === 'function') setTimeout(cfCargar, 450);
  if (typeof fvCargar === 'function') setTimeout(fvCargar, 450);
  if (typeof cargarCargos === 'function') setTimeout(cargarCargos, 450);
  if (typeof chequearActualizacionAutoDolar === 'function') setTimeout(chequearActualizacionAutoDolar, 500);
  if (typeof cargarPermisosRoles === 'function') setTimeout(function(){ cargarPermisosRoles(); cargarDashWidgets(); setTimeout(applyRole, 400); }, 400);
  if (typeof cargarConfigComisiones === 'function') setTimeout(cargarConfigComisiones, 600);

  // Mostrar app después de ~2.5 segundos (tiempo de carga de Firebase)
  setTimeout(function() {
    clearInterval(iv);
    if (bar) bar.style.width = '100%';
    if (msg) msg.textContent = '¡Listo!';
    setTimeout(function() {
      window._loginEnCurso = false;
      if (loadingEl) loadingEl.classList.add('sv-boot-exit');
      setTimeout(function(){
        if (loadingEl) {
          loadingEl.style.display = 'none';
          loadingEl.classList.remove('sv-boot-exit', 'sv-intro-loading');
        }
        window._restaurandoSesionInicial = false;
      }, modoIntroRecarga ? 280 : 0);
      document.getElementById('screen-app').classList.add('visible');
      if (typeof renderKPIsDashboard === 'function') renderKPIsDashboard();
      if (typeof applyDashWidgets === 'function') applyDashWidgets();
      if (currentRole !== 'admin') setTimeout(function(){
        if(typeof renderDashMiCuenta==='function') renderDashMiCuenta();
        if((currentRole==='administrativo'||currentRole==='vendedor') && typeof renderDashAdministrativo==='function') renderDashAdministrativo();
        if(currentRole==='tecnico' && typeof renderDashMisOTs==='function') renderDashMisOTs();
      }, 1500);
      // Botones flotantes manejados por aplicarVisibilidadBotonesFlotantes()
      if (typeof generarNotificaciones === 'function') setTimeout(generarNotificaciones, 500);
      if (typeof actualizarBadgeHsExtraPendientes === 'function') setTimeout(actualizarBadgeHsExtraPendientes, 3000);
      if (typeof actualizarFabYHome === 'function') actualizarFabYHome('dashboard');
      if (typeof _verificarHaberesPendientes === 'function') setTimeout(_verificarHaberesPendientes, 6000);
      notify('Bienvenido, ' + nombre + '!');
    }, 400);
  }, 2600);
}

// selCli definida arriba con parámetros (id, nombre, dir)
document.addEventListener('click', function(e) { if (!e.target.closest('.sw')) _hide('cli-drop'); });
function calcRow(inp) {
  const tr = inp.closest('tr');
  const q  = parseFloat(tr.querySelector('.qty').value) || 0;
  const priceInp = tr.querySelector('.price');
  const p  = priceInp.dataset.moneyInit ? getMontoRaw(priceInp) : (parseFloat(priceInp.value) || 0);
  const dp = parseFloat((tr.querySelector('.disc')||{}).value) || 0;
  // Validar descuento por ítem contra el límite configurado
  if (dp > 0 && APROBACION_CONFIG && dp > APROBACION_CONFIG.descuentoLimite) {
    var discInp = tr.querySelector('.disc');
    if (discInp) { discInp.style.borderColor = 'var(--amber)'; discInp.title = 'Supera el límite de ' + APROBACION_CONFIG.descuentoLimite + '% — requiere aprobación'; }
  } else {
    var discInp2 = tr.querySelector('.disc');
    if (discInp2) { discInp2.style.borderColor = ''; discInp2.title = ''; }
  }
  const bruto = q * p;
  const neto  = dp > 0 ? bruto * (1 - dp/100) : bruto;
  const sub = tr.querySelector('.sub');
  if (sub) {
    if (dp > 0) {
      sub.innerHTML = '<span style="text-decoration:line-through;color:var(--text3);font-size:11px;font-weight:400">$' + Math.round(bruto).toLocaleString('es-AR') + '</span><br>$' + Math.round(neto).toLocaleString('es-AR');
    } else {
      sub.textContent = '$' + Math.round(neto).toLocaleString('es-AR');
    }
    // Colorear el campo de descuento
    var discInp = tr.querySelector('.disc');
    if (discInp) discInp.style.color = dp > 0 ? 'var(--green)' : 'var(--text3)';
  }
  calcTotals();
}

var _ventaConIva = true; // estado global del toggle IVA en nueva venta

function aplicarEstadoIvaVenta(conIva, recalcular) {
  _ventaConIva = conIva !== false;
  var btn = document.getElementById('btn-toggle-iva-venta');
  if (btn) {
    btn.innerHTML = '<i class="ti ti-receipt-tax"></i> ' + (_ventaConIva ? 'Con IVA' : 'Sin IVA');
    btn.style.color = _ventaConIva ? '' : 'var(--amber)';
    btn.style.borderColor = _ventaConIva ? '' : 'var(--amber)';
  }
  var ivaRow = document.getElementById('t-iva-row');
  if (ivaRow) ivaRow.style.display = _ventaConIva ? '' : 'none';
  if (recalcular !== false && typeof calcTotals === 'function') calcTotals();
}

function recalcularTotalesVenta() { calcTotals(); }

function toggleIvaVenta(btn) {
  aplicarEstadoIvaVenta(!_ventaConIva, true);
}

function toggleIvaDetalle(btn, ventaId) {
  var venta = _svResolverVentaRegistro(ventaId);
  if (!venta || !window.fbDB) return;
  var nuevoConIva = venta.conIva === false ? true : false;
  window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ventas + '/' + venta.fbKey), { conIva: nuevoConIva })
    .then(function(){
      venta.conIva = nuevoConIva;
      btn.innerHTML = '<i class="ti ti-receipt-tax"></i> ' + (nuevoConIva ? 'Con IVA' : 'Sin IVA');
      btn.style.color = nuevoConIva ? '' : 'var(--amber)';
      btn.style.borderColor = nuevoConIva ? '' : 'var(--amber)';
      notify((nuevoConIva ? 'Con IVA activado' : 'Sin IVA — precio final sin impuesto'));
    });
}

function calcTotals() {
  // Subtotal suma de netos por fila (ya con descuento por ítem)
  let s = 0;
  document.querySelectorAll('#det-body tr').forEach(function(tr) {
    var q  = parseFloat((tr.querySelector('.qty')||{}).value) || 0;
    var priceInp = tr.querySelector('.price');
    var p  = priceInp ? (priceInp.dataset.moneyInit ? getMontoRaw(priceInp) : (parseFloat(priceInp.value) || 0)) : 0;
    var dp = parseFloat((tr.querySelector('.disc')||{}).value) || 0;
    s += q * p * (1 - dp/100);
  });

  // Descuento general
  var descGenPct = parseFloat((document.getElementById('desc-general')||{}).value) || 0;
  var descGenAmt = s * descGenPct / 100;
  var sConDesc   = s - descGenAmt;

  // Toggle IVA — usa variable global
  var conIva = typeof _ventaConIva !== 'undefined' ? _ventaConIva : true;
  var iva    = conIva ? sConDesc * 0.21 : 0;

  _set('t-sub', '$' + Math.round(s).toLocaleString('es-AR'));
  var descRow = document.getElementById('t-desc-row');
  if (descRow) descRow.style.display = descGenPct > 0 ? '' : 'none';
  _set('t-desc', '-' + descGenPct + '% (-$' + Math.round(descGenAmt).toLocaleString('es-AR') + ')');
  // Mostrar/ocultar línea de IVA
  var ivaRow = document.getElementById('t-iva-row');
  if (ivaRow) ivaRow.style.display = conIva ? '' : 'none';
  _set('t-iva',  '$' + Math.round(iva).toLocaleString('es-AR'));
  _set('t-tot',  '$' + Math.round(sConDesc + iva).toLocaleString('es-AR'));
  calcMargenGanancia();
}

function normalizarCodigoProducto(cod) {
  return String(cod || '').trim().toUpperCase().replace(/\s+/g,'').replace(/^COD[:\-]?/,'');
}

function obtenerProductoPorCodigoVenta(cod, item) {
  var codNorm = normalizarCodigoProducto(cod || (item && (item.cod || item.codigo)) || '');
  var pid = item && (item.pid || item.productoId || item.fbKeyProducto || item.productoFbKey);
  var lista = Object.values(prodData || {});
  var prod = null;
  if (pid) prod = (prodData || {})[pid] || lista.find(function(p){ return p.fbKey === pid || p.id === pid; });
  if (!prod && codNorm) {
    prod = lista.find(function(p){
      return normalizarCodigoProducto(p.codigo) === codNorm ||
             normalizarCodigoProducto(p.cod) === codNorm ||
             normalizarCodigoProducto(p.sku) === codNorm;
    });
  }
  return prod || null;
}

function obtenerCostoUnitarioVenta(cod, item) {
  item = item || {};
  var costoDirecto = parseFloat(item.costoUnitarioCompra || item.costoUnitario || item.costoCompra || item.compra || item.precioCompra || item.precio_compra || 0) || 0;
  var prod = obtenerProductoPorCodigoVenta(cod, item);
  var costoProd = prod ? (parseFloat(prod.compraARS || prod.compra || prod.precio_compra || prod.precioCompra || prod.costo || 0) || 0) : 0;
  var costoUnit = costoDirecto || costoProd;

  var moneda = (item.monedaOriginal || (prod && (prod.moneda || prod.monedaCompra)) || '').toUpperCase();
  if (moneda === 'USD') {
    var yaARS = !!(item.costoUnitarioCompra || item.costoUnitario || item.costoCompra || item.compra || item.precioCompra || item.precio_compra) && !item.costoUnitarioUSD;
    if (!yaARS) {
      var cotiz = parseFloat(item.cotizacionUsada) || 0;
      if (!cotiz) {
        var tc = window.TIPO_CAMBIO_CONFIG || {};
        cotiz = parseFloat(tc[tc.dolarConversion || 'oficial']) || parseFloat(tc.oficial) || parseFloat(tc.blue) || parseFloat(tc.mep) || 0;
      }
      if (cotiz > 0) costoUnit = costoUnit * cotiz;
    }
  }
  return costoUnit || 0;
}

function obtenerCostoItemVenta(item) {
  item = item || {};
  if (parseFloat(item.costoTotalCompra || item.costoTotal || item.costo) > 0) {
    return parseFloat(item.costoTotalCompra || item.costoTotal || item.costo) || 0;
  }
  var qty = parseFloat(item.qty || item.cantidad || 1) || 1;
  return obtenerCostoUnitarioVenta(item.cod || item.codigo, item) * qty;
}

try { window._mostrarCostoCompraDetalleVenta = localStorage.getItem('sv_mostrar_costo_compra_detalle') === '1'; }
catch(e) { window._mostrarCostoCompraDetalleVenta = false; }

function toggleCostoCompraDetalleVenta() {
  window._mostrarCostoCompraDetalleVenta = !window._mostrarCostoCompraDetalleVenta;
  try { localStorage.setItem('sv_mostrar_costo_compra_detalle', window._mostrarCostoCompraDetalleVenta ? '1' : '0'); } catch(e) {}
  if (window._ventaDetalleActual) renderDetalleVenta(window._ventaDetalleActual);
}

function obtenerCostoUnitarioDetalleVenta(item) {
  item = item || {};
  var qty = parseFloat(item.qty || item.cantidad || 1) || 1;
  if (qty <= 0) qty = 1;
  var costoTotal = parseFloat(item.costoTotalCompra || item.costoTotal || item.costo) || 0;
  if (costoTotal > 0) return costoTotal / qty;
  return obtenerCostoUnitarioVenta(item.cod || item.codigo, item);
}
// la mano de obra NO se excluye porque representa un egreso real para el técnico).
// Margen % = (Total venta - Costo) / Total venta * 100
var ventaRequiereAutorizacion = false;
var ventaAutorizadaPorAdmin = false;
window._mostrarMargenGanancia = false;

function toggleMargenGanancia() {
  var box  = document.getElementById('margen-ganancia-box');
  var ico  = document.getElementById('margen-eye-icon');
  var lbl  = document.getElementById('margen-eye-lbl');
  if (!box) return;
  window._mostrarMargenGanancia = !window._mostrarMargenGanancia;
  if (ico) ico.className = window._mostrarMargenGanancia ? 'ti ti-eye-off' : 'ti ti-eye';
  if (lbl) lbl.textContent = window._mostrarMargenGanancia ? 'Ocultar margen' : 'Ver margen de ganancia';
  calcMargenGanancia();
}

function calcMargenGanancia() {
  var box = document.getElementById('margen-ganancia-box');
  if (!box) return;

  var totalTxt = (document.getElementById('t-tot')||{}).textContent || '$0';
  var total = parseFloat(normalizarNumeroExcel(totalTxt)) || 0;

  var costoTotal = 0;
  var filas = Array.from(document.querySelectorAll('#det-body tr'));
  filas.forEach(function(tr) {
    var selCod = tr.querySelector('.prod-sel-cod');
    var cod = selCod ? selCod.textContent.trim() : '';
    var qty = parseInt((tr.querySelector('.qty')||{}).value) || 0;
    var prod = obtenerProductoPorCodigoVenta(cod, null);
    var costoUnit = obtenerCostoUnitarioVenta(cod, { cotizacionUsada: parseFloat(tr.dataset.cotizacionUsada)||0, monedaOriginal: tr.dataset.monedaOriginal || (prod && prod.moneda) || '' });
    costoTotal += costoUnit * qty;
  });

  if (total <= 0) {
    box.style.display = 'none';
    ventaRequiereAutorizacion = false;
    return;
  }

  var margenPct = ((total - costoTotal) / total) * 100;
  var pctEl = document.getElementById('margen-ganancia-pct');
  var lblEl = document.getElementById('margen-ganancia-label');
  var costoEl = document.getElementById('margen-ganancia-costo');

  pctEl.textContent = margenPct.toFixed(1) + '%';
  costoEl.textContent = 'Costo: $' + Math.round(costoTotal).toLocaleString('es-AR') + ' (productos + mano de obra)';

  if (margenPct < 15) {
    box.style.background = 'var(--red-bg)';
    pctEl.style.color = 'var(--red)';
    lblEl.style.color = 'var(--red)';
    lblEl.innerHTML = '<i class="ti ti-alert-triangle"></i> Margen bajo — requiere autorización del admin para confirmar';
    ventaRequiereAutorizacion = true;
  } else if (margenPct <= 20) {
    box.style.background = 'var(--amber-bg)';
    pctEl.style.color = 'var(--amber)';
    lblEl.style.color = 'var(--amber)';
    lblEl.innerHTML = '<i class="ti ti-info-circle"></i> Margen regular';
    ventaRequiereAutorizacion = false;
  } else {
    box.style.background = 'var(--green-bg)';
    pctEl.style.color = 'var(--green)';
    lblEl.style.color = 'var(--green)';
    lblEl.innerHTML = '<i class="ti ti-check"></i> Ganancia perfecta';
    ventaRequiereAutorizacion = false;
  }
  if (margenPct >= 15) ventaAutorizadaPorAdmin = false; // reset si vuelve a estar en rango normal
  box.style.display = window._mostrarMargenGanancia ? '' : 'none';
}
var rc = 20;

// Crear fila de producto con búsqueda y stock

function addRow() {
  rc++;
  const tr = crearFilaProducto('P-0'+rc, 'Nuevo producto', 0, 1);
  document.getElementById('det-body').appendChild(tr);
  document.addEventListener('click', e => { if (!e.target.closest('.prod-search-drop') && !e.target.classList.contains('cod-inp')) document.querySelectorAll('.prod-search-drop').forEach(d => d.style.display='none'); }, {once:true});
}

function delRow(btn) { btn.closest('tr').remove(); calcTotals(); actualizarResumenStock(); }
function toggleAll(cb) { document.querySelectorAll('#det-body input[type=checkbox]').forEach(c => c.checked = cb.checked); }

function confirmarVenta() {
  if (!document.getElementById('cli-inp').value) { notify('Seleccioná un cliente primero'); return; }

  // Validar descuento general contra límite configurado
  var _descGen = parseFloat((document.getElementById('desc-general')||{}).value) || 0;
  if (_descGen > 0 && APROBACION_CONFIG && _descGen > APROBACION_CONFIG.descuentoLimite) {
    if (currentRole !== 'admin') {
      notify('El descuento general ' + _descGen + '% supera el límite de ' + APROBACION_CONFIG.descuentoLimite + '%. Necesitás autorización del admin.');
      return;
    }
    if (!confirm('Descuento ' + _descGen + '% supera el límite configurado de ' + APROBACION_CONFIG.descuentoLimite + '%. ¿Autorizar como admin?')) return;
  }
  if (ventaRequiereAutorizacion && !ventaAutorizadaPorAdmin) {
    if (currentRole === 'admin') {
      if (!confirm('⚠ï¸ El margen de ganancia de esta venta está por debajo del 15% (rojo).\n\n¿Autorizás confirmar la venta igual?')) return;
      ventaAutorizadaPorAdmin = true;
    } else {
      notify('⚠ï¸ El margen de esta venta es muy bajo (rojo). Necesitás autorización del admin para confirmarla.');
      return;
    }
  }

  var filas = Array.from(document.querySelectorAll('#det-body tr'));
  var errores = [];
  filas.forEach(function(tr) {
    var selCod = tr.querySelector('.prod-sel-cod');
    var cod = selCod ? selCod.textContent : '';
    var qty = parseInt((tr.querySelector('.qty')||{}).value) || 1;
    var s = stockData[cod];
    if (s) {
      var disp = s.real - s.reservado;
      if (qty > disp) errores.push(cod + ': necesitás ' + qty + ', disponible ' + disp);
    }
  });
  if (errores.length) { notify('Stock insuficiente: ' + errores[0]); return; }

  // Reservar stock
  filas.forEach(function(tr) {
    var selCod = tr.querySelector('.prod-sel-cod');
    var cod = selCod ? selCod.textContent : '';
    var qty = parseInt((tr.querySelector('.qty')||{}).value) || 1;
    if (stockData[cod]) stockData[cod].reservado += qty;
  });

  var cli = document.getElementById('cli-inp').value;
  var idCliEl = document.getElementById('id-cli');
  var idCliVal = idCliEl ? idCliEl.value.trim() : '';
  if (!idCliVal) {
    var cliMatch = (clientesData || []).find(function(c){
      return String(c.nombre || '').trim().toLowerCase() === String(cli || '').trim().toLowerCase() ||
             String(c.empresa || '').trim().toLowerCase() === String(cli || '').trim().toLowerCase() ||
             String(c.razonSocial || '').trim().toLowerCase() === String(cli || '').trim().toLowerCase();
    });
    if (cliMatch) idCliVal = String(cliMatch.id || cliMatch.fbKey || '');
    if (idCliEl && idCliVal) idCliEl.value = idCliVal;
  }
  var dir = (_get('cli-dir-hidden')||{}).value || 'Sin definir';
  var hoy = new Date();
  var dd = String(hoy.getDate()).padStart(2,'0');
  var mm = String(hoy.getMonth()+1).padStart(2,'0');
  var aaaa = hoy.getFullYear();
  var fechaHoy = dd + '/' + mm + '/' + aaaa;

  var nuevaVenta = {
    id: obtenerProximoIdVenta(),
    cliente:  cli,
    idCliente: idCliVal,        // ← ID real del cliente para filtrar en historial
    clienteId: idCliVal,        // ← campo alternativo para compatibilidad
    empleado: (function(){
      var sel = document.querySelector('#venta-empleado');
      if (!sel || !sel.value) return '';
      if (sel.value === '__admin__') return currentUser || 'Admin'; // admin sin perfil de empleado
      var empEncontrado = Object.values(empData||{}).find(function(e){ return e.fbKey === sel.value; });
      return empEncontrado ? empEncontrado.nombre : sel.value;
    })(),
    empleadoFbKey: (function(){ var sel=document.querySelector('#venta-empleado'); return sel ? (sel.value||'') : ''; })(),
    comisionado2: (function(){
      var sel = document.querySelector('#venta-comisionado2');
      if (!sel || !sel.value) return '';
      var empEncontrado = Object.values(empData||{}).find(function(e){ return e.fbKey === sel.value; });
      return empEncontrado ? empEncontrado.nombre : sel.value;
    })(),
    comisionado2FbKey: (function(){ var sel=document.querySelector('#venta-comisionado2'); return sel ? (sel.value||'') : ''; })(),
    comisionHabilitada: (function(){ var cb=document.getElementById('venta-generar-comision'); return currentRole === 'admin' ? !!(cb && cb.checked) : true; })(),
    creadaPorRol: currentRole || '',
    fecha: fechaHoy,
    fechaOrden: fechaVentaOrdenISO(fechaHoy, Date.now()),
    ts: Date.now(),
    estadoPago: 'pendiente_pago',
    estadoInst: 'pendiente_inst',
    total: 0, subtotal: 0, iva: 0, descuento: 0,
    items: filas.map(function(tr) {
      var cod   = (tr.querySelector('.prod-sel-cod')||{}).textContent || '';
      var descEl = tr.querySelector('.desc-txt-clean') || tr.querySelector('.desc-txt');
      var desc  = descEl ? descEl.textContent : '';
      var qty   = parseInt((tr.querySelector('.qty')||{}).value) || 1;
      var priceInpItem = tr.querySelector('.price');
      var punit = priceInpItem ? (priceInpItem.dataset.moneyInit ? getMontoRaw(priceInpItem) : (parseFloat(priceInpItem.value) || 0)) : 0;
      var disc  = parseFloat((tr.querySelector('.disc')||{}).value) || 0;
      var sub   = Math.round(qty * punit * (1 - disc/100));
      var item  = { cod:cod, desc:desc, qty:qty, punit:punit, disc:disc, sub:sub };
      var prodItemCosto = obtenerProductoPorCodigoVenta(cod, item);
      var costoUnitarioItem = obtenerCostoUnitarioVenta(cod, {
        cod: cod,
        cotizacionUsada: parseFloat(tr.dataset.cotizacionUsada) || 0,
        monedaOriginal: tr.dataset.monedaOriginal || (prodItemCosto && prodItemCosto.moneda) || ''
      });
      item.pid = prodItemCosto ? (prodItemCosto.fbKey || prodItemCosto.id || '') : '';
      item.productoFbKey = item.pid || tr.dataset.productoFbKey || '';
      item.imagenUrl = prodItemCosto && prodItemCosto.imagenUrl ? prodItemCosto.imagenUrl : '';
      item.costoUnitarioCompra = Math.round(costoUnitarioItem * 100) / 100;
      item.costoTotalCompra = Math.round(costoUnitarioItem * qty * 100) / 100;
      if (tr.dataset.monedaOriginal === 'USD') {
        item.monedaOriginal    = 'USD';
        item.precioUsdOriginal = parseFloat(tr.dataset.precioUsdOriginal) || 0;
        item.cotizacionUsada   = parseFloat(tr.dataset.cotizacionUsada) || 0;
        item.cotizacionTipo    = tr.dataset.cotizacionTipo || 'oficial';
      }
      return item;
    }),
    descuentoGeneral: parseFloat((document.getElementById('desc-general')||{}).value) || 0,
    pagos: [],
    obs: (document.getElementById('venta-obs')||{}).value || '',
    audit: [{ fecha: fechaHoy, usuario: 'Sistema', accion: 'Venta confirmada' }]
  };
  var subtotalBruto = nuevaVenta.items.reduce(function(s,i){ return s + (i.qty * i.punit); }, 0);
  var subtotalNeto  = nuevaVenta.items.reduce(function(s,i){ return s + i.sub; }, 0);
  var descGenAmt    = Math.round(subtotalNeto * (nuevaVenta.descuentoGeneral/100));
  nuevaVenta.subtotal  = subtotalNeto - descGenAmt;
  nuevaVenta.descuento = descGenAmt + (subtotalBruto - subtotalNeto);
  var _conIvaGuardar   = typeof _ventaConIva !== 'undefined' ? _ventaConIva : true;
  nuevaVenta.conIva    = _conIvaGuardar;
  nuevaVenta.iva       = _conIvaGuardar ? Math.round(nuevaVenta.subtotal * 0.21) : 0;
  nuevaVenta.total     = nuevaVenta.subtotal + nuevaVenta.iva;

  // Costo y margen calculados al momento de la venta (controlador de ganancia)
  var costoTotalVenta = nuevaVenta.items.reduce(function(s, item) {
    return s + obtenerCostoItemVenta(item);
  }, 0);
  nuevaVenta.costoTotal = costoTotalVenta;
  nuevaVenta.margenPct = nuevaVenta.total > 0 ? ((nuevaVenta.total - costoTotalVenta) / nuevaVenta.total) * 100 : 0;
  nuevaVenta.margenAutorizadoPorAdmin = ventaAutorizadaPorAdmin;

  if (window._ventaEditandoFbKey) {
    var ventaOriginalEdit = window._ventaEditandoOriginal || (ventasList||[]).find(function(x){ return x.fbKey === window._ventaEditandoFbKey; }) || {};
    nuevaVenta.fbKey = window._ventaEditandoFbKey;
    nuevaVenta.id = ventaOriginalEdit.id || nuevaVenta.id;
    nuevaVenta.estadoPago = ventaOriginalEdit.estadoPago || nuevaVenta.estadoPago;
    nuevaVenta.estadoInst = ventaOriginalEdit.estadoInst || nuevaVenta.estadoInst;
    nuevaVenta.pagos = ventaOriginalEdit.pagos || [];
    nuevaVenta.totalPagado = parseFloat(ventaOriginalEdit.totalPagado || 0) || 0;
    nuevaVenta.factura = ventaOriginalEdit.factura || null;
    nuevaVenta.ventaEditada = true;
    nuevaVenta.editadaPor = currentUser || '';
    nuevaVenta.fechaEdicion = new Date().toISOString();
    nuevaVenta.audit = (ventaOriginalEdit.audit || []).concat([{ fecha: fechaHoy, usuario: currentUser || 'Sistema', accion: 'Venta editada' }]);
    window._ventaEditandoFbKey = null;
    window._ventaEditandoOriginal = null;
  }
  var guardarPromise;
  if (typeof fbGuardarVenta === 'function') {
    guardarPromise = fbGuardarVenta(nuevaVenta);
  } else {
    ventasList.unshift(nuevaVenta);
    guardarPromise = Promise.resolve(null);
  }
  if (typeof registrarActividad === 'function') {
    registrarActividad('Venta creada', nuevaVenta.id + ' — ' + cli + ' — $' + Math.round(nuevaVenta.total).toLocaleString('es-AR'));
  }

  if (!window._editandoVentaId && !nuevaVenta.ventaEditada && typeof generarOTdesdeVenta === 'function') generarOTdesdeVenta(nuevaVenta.id, cli, dir);

  // Reset del formulario
  setTimeout(function() {
    document.getElementById('det-body').innerHTML = '';
    document.getElementById('cli-inp').value = '';
    document.getElementById('id-cli').value = '';
    _hide('venta-stock-resumen');
    ['t-sub','t-iva','t-tot'].forEach(function(id){ _set(id,'$0'); });
    ventaAutorizadaPorAdmin = false;
    ventaRequiereAutorizacion = false;
    window._mostrarMargenGanancia = false;
    var margenBox = document.getElementById('margen-ganancia-box');
    var margenIco = document.getElementById('margen-eye-icon');
    var margenLbl = document.getElementById('margen-eye-lbl');
    if (margenBox) margenBox.style.display = 'none';
    if (margenIco) margenIco.className = 'ti ti-eye';
    if (margenLbl) margenLbl.textContent = 'Ver margen de ganancia';
    if (typeof inicializarFilasVenta === 'function') inicializarFilasVenta();
  }, 300);

  // Mostrar modal de confirmación — esperamos un poco para que el listener de
  // Firebase actualice ventasList con el fbKey real antes de buscarlo
  guardarPromise.then(function() {
    // Si se editó una venta ya pagada y se habilitó comisión, generar la comisión ahora.
    // Antes solo se generaba en registrarPago(), por eso al cambiar vendedor/comisionado
    // sobre una venta ya cobrada no se acreditaba nada en Mi Cuenta.
    try {
      var pagadoReal = parseFloat(nuevaVenta.totalPagado || 0) || 0;
      var ventaPagada = (nuevaVenta.estadoPago === 'pago_total') || (pagadoReal >= (parseFloat(nuevaVenta.total)||0) && (parseFloat(nuevaVenta.total)||0) > 0);
      if (nuevaVenta.ventaEditada && nuevaVenta.comisionHabilitada === true && ventaPagada && typeof generarComisionesVenta === 'function') {
        generarComisionesVenta(nuevaVenta, pagadoReal || nuevaVenta.total);
      }
    } catch(_e) { console.warn('[comisiones editar venta]', _e); }
    setTimeout(function() {
      var ventaGuardada = (ventasList || []).find(function(v) { return v.id === nuevaVenta.id; });
      mostrarConfirmacionVenta(nuevaVenta, ventaGuardada ? ventaGuardada.fbKey : null);
    }, 800);
  }).catch(function(e) {
    console.error('[confirmarVenta]', e);
    notify('Venta ' + nuevaVenta.id + ' confirmada ✓');
  });
}

// Inicializar filas al cargar nueva venta
// Modal de confirmación que aparece al guardar una venta, con acciones rápidas.
// Reemplaza el notify simple y da acceso inmediato al detalle y al cobro.
function mostrarConfirmacionVenta(venta, fbKey) {
  // Remover cualquier modal previo por las dudas
  var prev = document.getElementById('modal-venta-confirmada');
  if (prev) prev.remove();

  var div = document.createElement('div');
  div.id = 'modal-venta-confirmada';
  div.style.cssText = 'position:fixed;inset:0;z-index:9998;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,.45)';
  div.innerHTML =
    '<div style="background:var(--bg2);border-radius:var(--radius-lg);padding:28px 32px;max-width:420px;width:90%;box-shadow:0 16px 48px rgba(0,0,0,.4);text-align:center">' +
      '<div style="width:48px;height:48px;border-radius:50%;background:var(--green-bg);display:flex;align-items:center;justify-content:center;margin:0 auto 12px">' +
        '<i class="ti ti-check" style="font-size:24px;color:var(--green)"></i>' +
      '</div>' +
      '<div style="font-weight:700;font-size:18px;margin-bottom:4px">Venta ' + escapeHTML(venta.id) + ' confirmada</div>' +
      '<div style="color:var(--text3);font-size:13px;margin-bottom:4px">' + escapeHTML(venta.cliente) + '</div>' +
      '<div style="font-size:22px;font-weight:700;color:var(--green);margin-bottom:20px">$' + Math.round(venta.total).toLocaleString('es-AR') + '</div>' +
      '<div style="display:flex;flex-direction:column;gap:10px">' +
        '<button class="btn btn-primary" onclick="abrirDetalleVentaConfirmada309(\'' + escapeHTML(venta.id) + '\',\'' + escapeHTML(fbKey||'') + '\')" style="width:100%;padding:12px">' +
          '<i class="ti ti-eye"></i> Ver detalle de la venta' +
        '</button>' +
        '<button class="btn" onclick="cerrarConfirmacionVenta();abrirCobroRapido(\'' + escapeHTML(venta.id) + '\',' + Math.round(venta.total) + ',\'' + escapeHTML(venta.cliente) + '\')" style="width:100%;padding:12px;border-color:var(--green);color:var(--green)">' +
          '<i class="ti ti-cash"></i> Cobrar ahora' +
        '</button>' +
        '<button class="btn" onclick="cerrarConfirmacionVenta()" style="width:100%;padding:10px;color:var(--text3);border-color:var(--border)">' +
          '<i class="ti ti-plus"></i> Cargar otra venta' +
        '</button>' +
      '</div>' +
    '</div>';
  document.body.appendChild(div);
  // Cerrar al tocar el fondo
  div.addEventListener('click', function(e) { if (e.target === div) cerrarConfirmacionVenta(); });
}

function cerrarConfirmacionVenta() {
  var m = document.getElementById('modal-venta-confirmada');
  if (m) m.remove();
}

// Abre el módulo de cobranzas con la venta precargada
function abrirCobroRapido(ventaId, total, cliente) {
  // Recordar la venta de origen para poder volver
  window._cobOrigenVentaId = ventaId;
  // Mostrar botón de volver al entrar desde una venta
  setTimeout(function() {
    var btnVolver = document.getElementById('cob-volver-venta');
    if (btnVolver) btnVolver.style.display = '';
  }, 200);
  // Usar irACobranzasConVenta que precarga todos los campos correctamente
  irACobranzasConVenta(ventaId);
}

function volverADetalleVenta() {
  var ventaId = window._cobOrigenVentaId;
  var btnVolver = document.getElementById('cob-volver-venta');
  if (btnVolver) btnVolver.style.display = 'none';
  window._cobOrigenVentaId = null;
  if (ventaId && typeof showPage === 'function') {
    showPage('detalle');
    setTimeout(function() {
      if (typeof verVenta === 'function') verVenta(ventaId);
    }, 300);
  } else if (typeof showPage === 'function') {
    showPage('detalle');
  }
}

function inicializarFilasVenta() {
  // Reset toggle IVA
  _ventaConIva = true;
  var btnIva = document.getElementById('btn-toggle-iva-venta');
  if (btnIva) { btnIva.innerHTML = '<i class="ti ti-receipt-tax"></i> Con IVA'; btnIva.style.color=''; btnIva.style.borderColor=''; }
  // Reset toggle Con detalle/Sin detalle
  _ventaImpConDetalle = true;
  var btnDet = document.getElementById('btn-detalle-venta');
  var iconDet = document.getElementById('icon-detalle-venta');
  var labelDet = document.getElementById('label-detalle-venta');
  if (btnDet) { btnDet.style.color=''; btnDet.style.borderColor=''; }
  if (iconDet) iconDet.className = 'ti ti-eye';
  if (labelDet) labelDet.textContent = 'Con detalle';
  const body = document.getElementById('det-body');
  if (!body) return;
  body.innerHTML = '';
  body.appendChild(crearFilaProducto('','',0,1));
  calcTotals();
  actualizarResumenStock();

  // Mostrar el próximo número de venta (mismo cálculo que usa confirmarVenta)
  var numPreview = document.getElementById('vf-numero-preview');
  if (numPreview) {
    numPreview.value = obtenerProximoIdVenta();
  }

  // Siempre pre-seleccionar el usuario logueado al abrir nueva venta
  // (no solo cuando está vacío, para evitar que quede otro de una venta anterior)
  var selEmp = document.getElementById('venta-empleado');
  if (selEmp) {
    var match = Object.values(empData||{}).find(function(e){
      return (e.nombre||'').toLowerCase().trim() === (currentUser||'').toLowerCase().trim();
    });
    if (match) {
      selEmp.value = match.fbKey;
    } else if (currentRole === 'admin' && currentUser) {
      var optAdmin = Array.from(selEmp.options).find(function(o){ return o.value === '__admin__'; });
      if (optAdmin) selEmp.value = '__admin__';
    }
  }
  if (typeof actualizarControlComisionVenta === 'function') actualizarControlComisionVenta();

  // Fecha de hoy por defecto
  var fechaInp = document.getElementById('venta-fecha');
  if (fechaInp && !fechaInp.value) fechaInp.value = new Date().toISOString().slice(0,10);
}
function filtrarCategoria(v) {
  window._prodCategoriaFiltro = v || '';
  var sel = document.getElementById('filter-cat');
  if (sel && v) sel.value = v;
  renderTablaProductos((document.getElementById('prod-search')||{}).value || '');
}

function navegarAProductosPorCategoria(cat) {
  showPage('productos', document.querySelector('[onclick*="productos"]'));
  setTimeout(function() {
    var sel = document.getElementById('filter-cat');
    if (sel) { sel.value = cat; filtrarCategoria(cat); }
  }, 300);
}

function navegarAProducto(prodRef) {
  var p = Object.values(prodData || {}).find(function(x){
    return String(x.fbKey || '') === String(prodRef) ||
           String(x.id || '') === String(prodRef) ||
           String(x.codigo || '') === String(prodRef) ||
           String(x.nombre || '').trim().toLowerCase() === String(prodRef || '').trim().toLowerCase() ||
           String(x.descripcion || '').trim().toLowerCase() === String(prodRef || '').trim().toLowerCase();
  });
  showPage('productos', document.querySelector('[onclick*="productos"]'));
  setTimeout(function() {
    if (p && typeof verProducto === 'function') {
      verProducto(p.fbKey);
      return;
    }
    var q = p ? (p.codigo || p.nombre || p.descripcion || '') : String(prodRef || '');
    var inp = document.getElementById('prod-search');
    var sel = document.getElementById('filter-cat');
    if (sel) sel.value = '';
    window._prodCategoriaFiltro = '';
    if (inp) inp.value = q;
    renderTablaProductos(q);
    var card = document.getElementById('prod-list-view');
    if (card) card.scrollIntoView({ behavior:'smooth', block:'start' });
  }, 250);
}
function productoRefDesdeItem(item) {
  item = item || {};
  var candidatos = [
    item.pid, item.productoFbKey, item.productoKey, item.fbKeyProducto,
    item.idProducto, item.productoId, item.cod, item.codigo,
    item.nombre, item.desc, item.descripcion
  ].map(function(x){ return String(x || '').trim(); }).filter(Boolean);
  for (var i = 0; i < candidatos.length; i++) {
    var ref = candidatos[i];
    var p = Object.values(prodData || {}).find(function(x) {
      return String(x.fbKey || '') === ref ||
             String(x.id || '') === ref ||
             String(x.codigo || '') === ref ||
             String(x.nombre || '').trim().toLowerCase() === ref.toLowerCase() ||
             String(x.descripcion || '').trim().toLowerCase() === ref.toLowerCase();
    });
    if (p) return p.fbKey || p.codigo || ref;
  }
  return candidatos[0] || '';
}
function productoDesdeItem(item) {
  var ref = productoRefDesdeItem(item);
  if (!ref) return null;
  return Object.values(prodData || {}).find(function(x) {
    return String(x.fbKey || '') === String(ref) ||
           String(x.id || '') === String(ref) ||
           String(x.codigo || '') === String(ref) ||
           String(x.nombre || '').trim().toLowerCase() === String(ref).trim().toLowerCase() ||
           String(x.descripcion || '').trim().toLowerCase() === String(ref).trim().toLowerCase();
  }) || null;
}
function imagenProductoItemHTML(item, extraClass) {
  var prod = productoDesdeItem(item);
  var src = (prod && prod.imagenUrl) || item.imagenUrl || item.productoImagenUrl || '';
  var cls = escapeHTML('item-prod-img ' + (extraClass || ''));
  if (src) {
    return '<img class="'+cls+'" src="'+escapeHTML(src)+'">';
  }
  return '<span class="'+cls+' item-prod-img-placeholder"><i class="ti ti-photo"></i></span>';
}
function jsStringAttr(valor) {
  return String(valor || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/\n/g, ' ');
}
function botonVerCompraProducto(item) {
  var prodRef = productoRefDesdeItem(item);
  if (!prodRef) return '<span style="color:var(--text3);font-size:11px">—</span>';
  return '<button class="btn btn-sm btn-ver-compra-prod" onclick="event.stopPropagation();navegarAProducto(\''+jsStringAttr(prodRef)+'\')" title="Ver ficha de compra del producto">' +
    '<i class="ti ti-eye"></i> Ver compra' +
  '</button>';
}
var editingProdId = null;

// Alertas de stock al entrar al módulo
function mostrarAlertasStock() {
  const cont = document.getElementById('stock-alerts');
  if (!cont) return;
  cont.replaceChildren();
  Object.values(prodData).forEach(p => {
    const ref = p.fbKey || p.id || p.codigo || p.descripcion || '';
    const nombreAlerta = p.nombre || p.descripcion || p.codigo || 'Producto sin nombre';
    const accion = { label:'Ver', fn:function(){ navegarAProducto(ref); } };
    if (p.stock === 0) {
      appendAlert(cont, 'red', 'ti ti-alert-circle', nombreAlerta, `sin stock (mín: ${p.stockMin})`, accion);
    } else if (p.stock < p.stockMin) {
      appendAlert(cont, 'amber', 'ti ti-alert-triangle', nombreAlerta, `stock bajo: ${p.stock} unidades (mín: ${p.stockMin})`, accion);
    }
  });
}

var prodProveedoresActuales = [];
var prodImagenArchivoTemp = null; // File pendiente de subir a Storage al guardar
var prodImagenBase64Temp = null;  // Preview local mientras no se guardó
var prodImagenUrlActual = '';     // URL final (sea de Storage o pegada a mano)

function margenProductoDefault() {
  var n = parseFloat(window._margenProductoDefault);
  return isFinite(n) && n >= 0 ? n : 30;
}

function obtenerDolarReferenciaProducto() {
  var cfg = window.TIPO_CAMBIO_CONFIG || {};
  var tipo = cfg.dolarConversion || 'oficial';
  var valor = parseFloat(cfg[tipo]) || parseFloat(cfg.oficial) || parseFloat(cfg.blue) || parseFloat(cfg.mep) || 0;
  if (!valor && window._tipoCambioActual && window._tipoCambioActual.venta) {
    tipo = 'venta';
    valor = parseFloat(window._tipoCambioActual.venta) || 0;
  }
  return { tipo: tipo, valor: valor };
}

function normalizarUrlProveedorProducto(url) {
  var u = String(url || '').trim();
  if (!u) return '';
  if (/^https?:\/\//i.test(u)) return u;
  if (/^\d+$/.test(u)) return 'https://www.tecnoprices.com/' + u;
  return u;
}

function normalizarUrlComparacionProveedor(url) {
  var u = normalizarUrlProveedorProducto(url);
  return String(u || '')
    .trim()
    .replace(/^https?:\/\//i, '')
    .replace(/^www\./i, '')
    .replace(/[?#].*$/, '')
    .replace(/\/+$/, '')
    .toLowerCase();
}

function urlsProveedorEquivalentes(a, b) {
  var ua = normalizarUrlComparacionProveedor(a);
  var ub = normalizarUrlComparacionProveedor(b);
  return !!ua && !!ub && ua === ub;
}

function resultadoCotizacionUsaUrlExacta(match, resultado, respuesta) {
  if (!match || !match.urlProducto) return true;
  resultado = resultado || {};
  respuesta = respuesta || {};
  var urlRes = String(resultado.url || '').trim();
  if (!urlRes || !urlsProveedorEquivalentes(match.url, urlRes)) return false;
  var textoControl = [
    resultado.error,
    resultado.observaciones,
    resultado.producto,
    resultado.detalle,
    respuesta.observaciones
  ].filter(Boolean).join(' ').toLowerCase();
  if (/no fue accesible|no accesible|inaccesible|categor[ií]a|p[aá]gina de categor|resultado de b[uú]squeda|b[uú]squeda|requiere login|iniciar sesi[oó]n|verificaci[oó]n manual|producto parecido|otra secci[oó]n/.test(textoControl)) {
    return false;
  }
  return true;
}

function parsePrecioProveedorARS(valor) {
  if (typeof valor === 'number') return valor;
  var s = String(valor || '').replace(/[^\d,.-]/g, '').trim();
  if (!s) return 0;
  if (typeof normalizarNumeroExcel === 'function') {
    var nExcel = parseFloat(normalizarNumeroExcel(s));
    if (nExcel > 0) return nExcel;
  }
  var lastComma = s.lastIndexOf(',');
  var lastDot = s.lastIndexOf('.');
  if (lastComma > lastDot) s = s.replace(/\./g, '').replace(',', '.');
  else if (lastDot > lastComma) s = s.replace(/,/g, '');
  return parseFloat(s) || 0;
}

function completarReferenciaProveedorProducto(pv, urlFallback, origen) {
  pv = Object.assign({}, pv || {});
  var tc = obtenerDolarReferenciaProducto();
  var precio = parseFloat(pv.precio) || parseFloat(pv.precioArsPublicado) || 0;
  var monedaDeclarada = String(pv.moneda || pv.monedaPublicada || pv.monedaPrecio || '').toUpperCase();
  var origenTexto = String(origen || pv.actualizadoOrigen || '').toLowerCase();
  var esLegacyUsd = precio > 0 && tc.valor > 0 && (
    monedaDeclarada === 'USD' ||
    ((origenTexto.indexOf('legacy') >= 0 || origenTexto === '') && precio < 100)
  );
  var precioUsdLegacy = esLegacyUsd ? precio : 0;
  if (esLegacyUsd) {
    precio = Math.round(precio * tc.valor * 100) / 100;
  }
  var url = normalizarUrlProveedorProducto(pv.url || urlFallback || '');
  var costoReal = precio > 0 && pv.sinIva ? precio * 1.21 : precio;
  pv.nombre = String(pv.nombre || pv.proveedor || '').trim();
  pv.precio = Math.round(precio * 100) / 100;
  pv.precioArsPublicado = pv.precio;
  pv.monedaPublicada = 'ARS';
  if (esLegacyUsd) pv.monedaOriginalLegacy = 'USD';
  pv.sinIva = !!pv.sinIva;
  pv.costoRealArs = Math.round(costoReal * 100) / 100;
  pv.url = url;
  if (tc.valor > 0 && pv.precio > 0) {
    pv.dolarUsado = tc.valor;
    pv.dolarTipo = tc.tipo;
    pv.precioUsdReferencia = precioUsdLegacy || Math.round((pv.precio / tc.valor) * 100) / 100;
    pv.costoRealUsdReferencia = Math.round((pv.costoRealArs / tc.valor) * 100) / 100;
  }
  pv.actualizado = pv.actualizado || new Date().toISOString().slice(0,10);
  pv.actualizadoEn = pv.actualizadoEn || Date.now();
  pv.actualizadoOrigen = esLegacyUsd ? 'legacy-usd-convertido-ars' : (origen || pv.actualizadoOrigen || 'manual');
  return pv;
}

function precioGremioARSDesdeProducto(p) {
  p = p || {};
  var proveedorPrincipal = Array.isArray(p.proveedores) && p.proveedores.length ? p.proveedores[0] : null;
  var tc = obtenerDolarReferenciaProducto();
  var candidatos = [
    p.precioArsPublicado,
    p.costoRealArs,
    p.precioGremio,
    p.compraARS,
    proveedorPrincipal && proveedorPrincipal.precioArsPublicado,
    proveedorPrincipal && proveedorPrincipal.costoRealArs,
    proveedorPrincipal && proveedorPrincipal.precio
  ];
  for (var i = 0; i < candidatos.length; i++) {
    var n = parseFloat(candidatos[i]);
    if (n > 0) {
      var monedaProv = String((proveedorPrincipal && (proveedorPrincipal.moneda || proveedorPrincipal.monedaPublicada || proveedorPrincipal.monedaPrecio)) || '').toUpperCase();
      var origenProv = String((proveedorPrincipal && proveedorPrincipal.actualizadoOrigen) || '').toLowerCase();
      var pareceUsdLegacy = tc.valor > 0 && n < 100 && (monedaProv === 'USD' || origenProv.indexOf('legacy') >= 0);
      return pareceUsdLegacy ? Math.round(n * tc.valor * 100) / 100 : n;
    }
  }
  var compraLegacy = parseFloat(p.compra) || 0;
  if (compraLegacy > 0 && String(p.moneda || '').toUpperCase() === 'USD' && tc.valor > 0) {
    return Math.round(compraLegacy * tc.valor * 100) / 100;
  }
  return compraLegacy || 0;
}

function asegurarMargenProductoDefaultEnForm() {
  var margenEl = document.getElementById('pf-margen-deseado');
  if (!margenEl) return margenProductoDefault();
  var margen = parseFloat(margenEl.value);
  if (!isFinite(margen) || margen <= 0) {
    margen = margenProductoDefault();
    margenEl.value = margen;
  }
  return margen;
}

function previewImagenProducto(input) {
  var file = input.files[0];
  if (!file) return;
  if (file.size > 3 * 1024 * 1024) { notify('La imagen no puede superar 3MB'); input.value=''; return; }
  prodImagenArchivoTemp = file;
  document.getElementById('pf-imagen-url').value = ''; // si sube archivo, prioriza eso sobre la URL pegada
  var reader = new FileReader();
  reader.onload = function(e) {
    prodImagenBase64Temp = e.target.result;
    _mostrarPreviewImagenProducto(e.target.result);
  };
  reader.readAsDataURL(file);
}

function actualizarPreviewImagenURL(url) {
  url = url.trim();
  if (!url) return;
  prodImagenArchivoTemp = null;
  prodImagenBase64Temp = null;
  prodImagenUrlActual = url;
  _mostrarPreviewImagenProducto(url);
}

function _mostrarPreviewImagenProducto(src) {
  var img = document.getElementById('pf-imagen-preview-img');
  var icon = document.getElementById('pf-imagen-placeholder-icon');
  if (!img || !icon) return;
  img.src = src;
  img.style.display = '';
  icon.style.display = 'none';
  img.onerror = function() {
    notify('No se pudo cargar la imagen de esa URL');
    img.style.display = 'none';
    icon.style.display = '';
  };
}

function quitarImagenProducto() {
  prodImagenArchivoTemp = null;
  prodImagenBase64Temp = null;
  prodImagenUrlActual = '';
  document.getElementById('pf-imagen-url').value = '';
  var img = document.getElementById('pf-imagen-preview-img');
  var icon = document.getElementById('pf-imagen-placeholder-icon');
  if (img) { img.style.display = 'none'; img.src=''; }
  if (icon) icon.style.display = '';
}

function abrirFormProducto(id) {
  editingProdId = id;
  _hide('prod-list-view');
  _hide('prod-detail-view');
  _block('prod-form-view');
  _set('prod-form-title',id ? 'Editar producto' : 'Nuevo producto');
  const p = id ? (Object.values(prodData||{}).find(function(x){ return String(x.fbKey) === String(id); }) || {}) : {};
  if (id) actualizarStatProductoActual(p);
  else actualizarStatProductos();
  document.getElementById('pf-codigo').value = p.codigo || '';
  var nomEl = document.getElementById('pf-nombre');
  var descEl = document.getElementById('pf-descripcion');
  if (nomEl) nomEl.value = p.nombre || p.descripcion || '';
  if (descEl) descEl.value = p.descripcion || '';
  // Poblar y seleccionar categoría
  var catSel = document.getElementById('pf-categoria');
  if (catSel) {
    var cats = [...new Set(Object.values(prodData||{}).map(function(x){ return x.categoria||x.catId||''; }).filter(Boolean))].sort();
    catSel.innerHTML = '<option value="">Seleccionar...</option>' +
      cats.map(function(c){ return '<option value="'+escapeHTML(c)+'"'+(c===(p.categoria||p.catId||'')?'selected':'')+'>'+escapeHTML(c)+'</option>'; }).join('');
    if (p.categoria && !cats.includes(p.categoria)) {
      catSel.innerHTML += '<option value="'+escapeHTML(p.categoria)+'" selected>'+escapeHTML(p.categoria)+'</option>';
    }
  }
  // Campo URL proveedor (codWeb)
  var cwEl = document.getElementById('pf-cod-web');
  if (cwEl) cwEl.value = p.codWeb || p.urlProveedor || '';
  _setMontoInput(document.getElementById('pf-venta'), p.venta || 0);
  // Cargar campos de calculadora de precio
  var pgEl = document.getElementById('pf-precio-gremio');
  var mdEl = document.getElementById('pf-margen-deseado');
  var rawGremio = precioGremioARSDesdeProducto(p);
  if (pgEl) _setMontoInput(pgEl, rawGremio);
  if (mdEl) mdEl.value = parseFloat(p.margenDeseado) > 0 ? p.margenDeseado : margenProductoDefault();
  document.getElementById('pf-iva').value = p.iva || 21;
  document.getElementById('pf-stock').value = p.stock !== undefined ? p.stock : '';
  document.getElementById('pf-stock-min').value = p.stockMin || (id ? '' : (window._stockMinDefault || 5));
  document.getElementById('pf-estado').value = p.estado || 'activo';
  document.getElementById('pf-unidad').value = p.unidad || 'Unidad';
  document.getElementById('pf-es-mano-obra').checked = !!p.esManoDeObra;
  var monedaSel = document.getElementById('pf-moneda');
  if (monedaSel) monedaSel.value = String(p.moneda || '').toUpperCase() === 'USD' ? 'USD' : 'ARS';
  cambiarMonedaProducto();

  // Imagen del producto
  quitarImagenProducto();
  if (p.imagenUrl) {
    prodImagenUrlActual = p.imagenUrl;
    document.getElementById('pf-imagen-url').value = p.imagenUrl;
    _mostrarPreviewImagenProducto(p.imagenUrl);
  }
  if (Array.isArray(p.proveedores) && p.proveedores.length) {
    prodProveedoresActuales = p.proveedores.map(function(pv){ return completarReferenciaProveedorProducto(pv, p.codWeb || p.urlProveedor || '', pv.actualizadoOrigen || 'legacy'); });
  } else if (p.proveedor) {
    prodProveedoresActuales = [completarReferenciaProveedorProducto({ nombre: p.proveedor, precio: precioGremioARSDesdeProducto(p), actualizado: p.fechaActualizacionPrecio || '', url: p.codWeb || p.urlProveedor || '' }, p.codWeb || p.urlProveedor || '', 'legacy')];
  } else {
    prodProveedoresActuales = [];
  }
  if (prodProveedoresActuales.length && !prodProveedoresActuales[0].url && cwEl && cwEl.value) {
    var cwVal = normalizarUrlProveedorProducto(cwEl.value.trim());
    var nombreProv0 = (prodProveedoresActuales[0].nombre || '').trim().toLowerCase();
    var esSoloCodigo = /^\d+$/.test(cwVal); // solo dígitos, sin http
    if (nombreProv0 === 'tecnoprices' && esSoloCodigo) {
      prodProveedoresActuales[0].url = normalizarUrlProveedorProducto(cwVal);
    } else {
      prodProveedoresActuales[0].url = cwVal;
    }
  }
  renderTablaProveedoresProducto();
  recalcularCompraDesdeProveedores();
  calcMargen();
  setTimeout(function(){ initSearchableSelect("pf-categoria","Seleccionar categoría..."); },50);
}

function renderTablaProveedoresProducto() {
  var tbl = document.getElementById('pf-proveedores-tbl');
  var vacioEl = document.getElementById('pf-proveedores-vacio');
  if (!tbl) return;
  if (!prodProveedoresActuales.length) {
    tbl.querySelectorAll('tr:not(:first-child)').forEach(function(tr){ tr.remove(); });
    if (vacioEl) vacioEl.style.display = '';
    return;
  }
  if (vacioEl) vacioEl.style.display = 'none';

  var masBaratoIdx = 0;
  prodProveedoresActuales.forEach(function(pv, i) {
    if ((parseFloat(pv.precio)||Infinity) < (parseFloat(prodProveedoresActuales[masBaratoIdx].precio)||Infinity)) masBaratoIdx = i;
  });

  tbl.querySelectorAll('tr:not(:first-child)').forEach(function(tr){ tr.remove(); });
  var costosReales = prodProveedoresActuales.map(function(pv) {
    var p = parseFloat(pv.precio) || 0;
    return pv.sinIva ? p * 1.21 : p;
  });
  masBaratoIdx = 0;
  costosReales.forEach(function(c, i) {
    if (c > 0 && (costosReales[masBaratoIdx] === 0 || c < costosReales[masBaratoIdx])) masBaratoIdx = i;
  });

  prodProveedoresActuales.forEach(function(pv, i) {
    var esMasBarato = i === masBaratoIdx && prodProveedoresActuales.length > 1;
    var sinIva = !!pv.sinIva;
    var precioRaw = parseFloat(pv.precio) || 0;
    var costoReal = sinIva ? Math.round(precioRaw * 1.21) : precioRaw;
    var dolarInfo = pv.dolarUsado ? '<br><span style="font-size:10px;color:var(--blue);font-weight:400">USD ref. '+(parseFloat(pv.costoRealUsdReferencia || pv.precioUsdReferencia)||0).toLocaleString('es-AR', {minimumFractionDigits:2, maximumFractionDigits:2})+' · $'+Math.round(parseFloat(pv.dolarUsado)||0).toLocaleString('es-AR')+'</span>' : '';
    var costoRealFmt = costoReal > 0
      ? (sinIva
          ? '<span style="color:var(--amber);font-size:12px;font-weight:600">$'+costoReal.toLocaleString('es-AR')+'</span><span style="font-size:10px;color:var(--text3);margin-left:3px">(+IVA)</span>'+dolarInfo
          : '<span style="color:var(--text3);font-size:12px">incluido</span>'+dolarInfo)
      : '<span style="color:var(--text3);font-size:12px">—</span>';
    var tr = document.createElement('tr');
    if (esMasBarato) tr.style.background = 'var(--green-bg)';
    tr.innerHTML =
      '<td style="padding:6px 4px;min-width:110px"><input type="text" value="'+escapeHTML(pv.nombre||'')+'" placeholder="Ej: Biosegur" oninput="actualizarProveedorProducto('+i+',\'nombre\',this.value)" style="width:100%;background:var(--bg3);border:0.5px solid var(--border);border-radius:4px;padding:6px 8px;font-size:13px;font-family:inherit"></td>' +
      '<td style="padding:6px 4px;text-align:right"><input type="number" value="'+(pv.precio||'')+'" placeholder="0" oninput="actualizarProveedorProducto('+i+',\'precio\',this.value)" style="width:90px;background:var(--bg3);border:0.5px solid var(--border);border-radius:4px;padding:6px 8px;text-align:right;font-size:13px;font-family:inherit"></td>' +
      '<td style="padding:6px 4px;text-align:center">' +
        '<label style="display:flex;align-items:center;justify-content:center;gap:4px;cursor:pointer;font-size:12px" title="El precio que cotiza el proveedor NO incluye IVA — el sistema sumará el 21% para calcular el costo real">' +
          '<input type="checkbox" '+(sinIva?'checked':'')+' onchange="actualizarProveedorProducto('+i+',\'sinIva\',this.checked);renderTablaProveedoresProducto();calcMargen();" style="accent-color:var(--amber);width:14px;height:14px;cursor:pointer">' +
        '</label>' +
      '</td>' +
      '<td style="padding:6px 4px;text-align:right;white-space:nowrap">'+costoRealFmt+'</td>' +
      '<td style="padding:6px 4px"><input type="url" value="'+escapeHTML(pv.url||'')+'" placeholder="https://proveedor.com/producto..." oninput="actualizarProveedorProducto('+i+',\'url\',this.value)" style="width:100%;min-width:150px;background:var(--bg3);border:0.5px solid var(--border);border-radius:4px;padding:6px 8px;font-size:12px;font-family:inherit;color:var(--blue)"></td>' +
      '<td style="padding:6px 4px;text-align:center;font-size:11px;color:var(--text3);white-space:nowrap">' + (pv.actualizado||'sin fecha') + (pv.actualizadoOrigen ? '<br><span style="font-size:10px;color:var(--text3)">'+escapeHTML(pv.actualizadoOrigen)+'</span>' : '') + (esMasBarato ? '<br><span class="badge b-green" style="font-size:9px">+ económico</span>' : '') + '</td>' +
      '<td style="padding:6px 4px;text-align:right;white-space:nowrap">' +
        (pv.url ? '<a href="'+escapeHTML(pv.url)+'" target="_blank" class="btn btn-sm btn-icon" title="Abrir en proveedor"><i class="ti ti-external-link" style="font-size:13px;color:var(--blue)"></i></a>' : '') +
        '<button class="btn btn-sm btn-icon" onclick="quitarFilaProveedor('+i+')" title="Quitar"><i class="ti ti-trash" style="font-size:14px;color:var(--red)"></i></button>' +
      '</td>';
    tbl.appendChild(tr);
  });
}

function cotizarPreciosProveedores() {
  var nombreProducto = (document.getElementById('pf-nombre')||{}).value || (document.getElementById('pf-descripcion')||{}).value || '';
  var codigoProducto = (document.getElementById('pf-codigo')||{}).value || '';
  var termino = (codigoProducto + ' ' + nombreProducto).trim();
  function proveedorMaestro(nombre) {
    var n = String(nombre || '').trim().toLowerCase();
    if (!n) return null;
    return (proveedoresData || []).find(function(p) {
      return String(p.nombre || '').trim().toLowerCase() === n;
    }) || null;
  }
  var provCotizables = prodProveedoresActuales.map(function(pv, idx) {
    var maestro = proveedorMaestro(pv.nombre);
    var webBase = maestro && (maestro.web || maestro.url || maestro.portal || maestro.sitio || '');
    return {
      idx: idx,
      nombre: pv.nombre || (maestro && maestro.nombre) || 'Proveedor',
      proveedorKey: pv.proveedorKey || pv.proveedorFbKey || pv.fbKey || pv.key || (maestro && (maestro.fbKey || maestro.key || maestro.id)) || '',
      url: (pv.url || webBase || '').trim(),
      urlProducto: !!(pv.url && pv.url.trim()),
      precioActual: parseFloat(pv.precio) || 0
    };
  }).filter(function(pv) {
    return pv.nombre && pv.url;
  });
  if (!prodProveedoresActuales.length) {
    notify('Agregá al menos un proveedor para este producto');
    return;
  }
  if (!provCotizables.length) {
    notify('Agregá una URL del producto o cargá la web del proveedor en el módulo Proveedores');
    return;
  }

  var btn = document.getElementById('btn-cotizar-prov');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="ti ti-loader-2" style="animation:spin 1s linear infinite"></i> Consultando...'; }
  var box = document.getElementById('pf-proveedores-cotizacion-resultado');
  if (box) {
    box.style.display = 'block';
    box.innerHTML = '<i class="ti ti-loader-2" style="animation:spin 1s linear infinite"></i> Consultando ' + provCotizables.length + ' proveedor' + (provCotizables.length !== 1 ? 'es' : '') + '...';
  }

  cotizarProveedoresCloudRun(provCotizables, codigoProducto, nombreProducto)
    .then(function(resReal) {
      if (resReal) {
        var actualizadosReal = procesarResultadoCotizacionProveedores(resReal, provCotizables, box);
        if (actualizadosReal > 0 || resReal) {
          restaurarBotonCotizacionProveedores();
          return null;
        }
      }
      if (box) {
        box.innerHTML = '<span style="color:var(--amber)">No se pudo llamar al cotizador real. Revisá que el proveedor tenga URL exacta y credenciales cargadas.</span>';
      }
      restaurarBotonCotizacionProveedores();
      return null;
    })
    .catch(function(err) {
      restaurarBotonCotizacionProveedores();
      if (box) {
        box.style.display = 'block';
        box.innerHTML = '<span style="color:var(--red)">Error al conectar con el servidor de cotización: ' + escapeHTML(err.message || '') + '</span>';
      }
      notify('Error al conectar con el servidor de cotización: ' + (err.message||''));
      console.error('[Cotizador]', err);
    });
}

function agregarFilaProveedor() {
  prodProveedoresActuales.push(completarReferenciaProveedorProducto({ nombre:'', precio:0, actualizado: new Date().toISOString().split('T')[0], actualizadoOrigen:'manual' }, (document.getElementById('pf-cod-web')||{}).value || '', 'manual'));
  renderTablaProveedoresProducto();
}

function quitarFilaProveedor(idx) {
  prodProveedoresActuales.splice(idx,1);
  renderTablaProveedoresProducto();
  recalcularCompraDesdeProveedores();
  calcMargen();
}

function actualizarProveedorProducto(idx, campo, valor) {
  if (!prodProveedoresActuales[idx]) return;
  prodProveedoresActuales[idx][campo] = campo === 'precio' ? (parseFloat(valor)||0) : valor;
  if (campo === 'precio') {
    prodProveedoresActuales[idx].actualizado = new Date().toISOString().split('T')[0];
    prodProveedoresActuales[idx].actualizadoEn = Date.now();
    prodProveedoresActuales[idx].actualizadoOrigen = 'manual';
  }
  if (campo === 'precio' || campo === 'url' || campo === 'sinIva') {
    prodProveedoresActuales[idx] = completarReferenciaProveedorProducto(prodProveedoresActuales[idx], (document.getElementById('pf-cod-web')||{}).value || '', prodProveedoresActuales[idx].actualizadoOrigen || 'manual');
  }
  recalcularCompraDesdeProveedores();
  calcMargen();
  if (campo === 'precio') renderTablaProveedoresProducto();
}

function restaurarBotonCotizacionProveedores() {
  var btn = document.getElementById('btn-cotizar-prov');
  if (btn) {
    btn.disabled = false;
    btn.innerHTML = '<i class="ti ti-refresh"></i> Cotizar online';
  }
}

function procesarResultadoCotizacionProveedores(res, provCotizables, box) {
  if (!res || !Array.isArray(res.resultados)) {
    if (box) box.innerHTML = '<span style="color:var(--amber)">No se pudo interpretar la cotización.</span>';
    notify('No se pudo obtener precios');
    return 0;
  }

  var actualizados = 0;
  var filasResultado = [];
  res.resultados.forEach(function(r) {
    var precio = parsePrecioProveedorARS(r.precio || r.precioArs || r.precioARS);
    var nombreRes = String(r.proveedor || r.nombre || '').trim().toLowerCase();
    var urlRes = String(r.url || '').trim();
    var proveedorKeyRes = String(r.proveedorKey || '').trim();
    var match = provCotizables.find(function(pv) {
      if (proveedorKeyRes && String(pv.proveedorKey || '') === proveedorKeyRes) return true;
      if (urlRes && urlsProveedorEquivalentes(pv.url, urlRes)) return true;
      if (pv.urlProducto) return false;
      return nombreRes && String(pv.nombre || '').trim().toLowerCase() === nombreRes;
    });
    if (!match && provCotizables.length === 1 && precio > 0 && !provCotizables[0].urlProducto) match = provCotizables[0];

    var rechazo = '';
    if (!match && precio > 0) {
      rechazo = 'No se actualizó: el precio no proviene de la URL exacta cargada.';
    }
    if (match && precio > 0 && !resultadoCotizacionUsaUrlExacta(match, r, res)) {
      rechazo = 'No se actualizó: la respuesta no confirmó la URL exacta del producto.';
      match = null;
    }

    var aceptado = !!(match && precio > 0);
    if (aceptado) {
      prodProveedoresActuales[match.idx] = completarReferenciaProveedorProducto(Object.assign({}, prodProveedoresActuales[match.idx], {
        precio: precio,
        url: urlRes || prodProveedoresActuales[match.idx].url || match.url,
        actualizado: new Date().toISOString().slice(0,10),
        actualizadoEn: Date.now(),
        actualizadoOrigen: r.fuente || r.origen || 'scraping-url-exacta',
        sinIva: r.sinIva !== undefined ? !!r.sinIva : prodProveedoresActuales[match.idx].sinIva
      }), '', r.fuente || r.origen || 'scraping-url-exacta');
      actualizados++;
    }

    filasResultado.push(
      '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:10px;padding:7px 0;border-bottom:0.5px solid var(--border)">' +
        '<div style="min-width:0"><strong style="color:var(--text)">' + escapeHTML(r.proveedor || r.nombre || 'Proveedor') + '</strong>' +
        '<div style="color:var(--text3);font-size:11px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escapeHTML(rechazo || (precio > 0 ? String(r.producto || '') : (r.error || r.mensaje || (typeof r.producto === 'string' ? r.producto : 'Sin precio devuelto por el cotizador'))) || 'Sin coincidencia clara') + '</div>' +
        (r.url ? '<a href="' + escapeHTML(r.url) + '" target="_blank" style="font-size:11px;color:var(--blue)">Ver fuente ↗</a>' : '') + '</div>' +
        '<div style="font-weight:700;color:' + (aceptado ? 'var(--green)' : 'var(--amber)') + ';white-space:nowrap">$' + Math.round(precio).toLocaleString('es-AR') + '</div>' +
        (r.debug || r.raw ? '<details style="grid-column:1/-1;width:100%;margin-top:6px;color:var(--text3);font-size:11px"><summary style="cursor:pointer;color:var(--blue)">Ver diagnóstico técnico</summary><pre style="white-space:pre-wrap;overflow:auto;max-height:220px;background:rgba(0,0,0,.18);border:0.5px solid var(--border);border-radius:8px;padding:8px;margin-top:6px">' + escapeHTML(JSON.stringify({ error: r.error || r.mensaje || '', debug: r.debug || null, raw: r.raw || null }, null, 2)) + '</pre></details>' : '') +
      '</div>'
    );
  });

  renderTablaProveedoresProducto();
  recalcularCompraDesdeProveedores();
  calcMargen();

  if (box) {
    box.style.display = 'block';
    box.innerHTML =
      '<div style="display:flex;justify-content:space-between;gap:10px;margin-bottom:6px"><strong>Resultado de cotización</strong><span style="color:var(--green)">' + actualizados + ' actualizado' + (actualizados !== 1 ? 's' : '') + '</span></div>' +
      filasResultado.join('') +
      (res.observaciones ? '<div style="font-size:11px;color:var(--text3);margin-top:8px">' + escapeHTML(res.observaciones) + '</div>' : '') +
      '<div style="font-size:11px;color:var(--amber);margin-top:8px"><i class="ti ti-alert-circle"></i> Revisá el resultado y tocá Guardar producto para conservar proveedores y precios.</div>';
  }

  notify('✓ ' + actualizados + ' precio' + (actualizados !== 1 ? 's' : '') + ' actualizados' + (actualizados ? '' : ' — algunos no pudieron obtenerse'));
  return actualizados;
}

function cotizarProveedoresCloudRun(provCotizables, codigoProducto, nombreProducto) {
  var directos = provCotizables.filter(function(pv) {
    return pv.urlProducto && pv.proveedorKey && pv.url && SISVENTAS_FUNCTIONS.cotizadorProveedor;
  });
  if (!directos.length) return Promise.resolve(null);

  return Promise.all(directos.map(function(pv) {
    return fetch(SISVENTAS_FUNCTIONS.cotizadorProveedor + '/cotizar', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'X-Frontend-Key': SISVENTAS_FUNCTIONS.frontendKey },
      body: JSON.stringify({
        proveedorKey: pv.proveedorKey,
        url: pv.url,
        codigo: codigoProducto || '',
        producto: nombreProducto || '',
        debug: true
      })
    })
    .then(function(r){
      return r.text().then(function(txt) {
        var data = null;
        try { data = txt ? JSON.parse(txt) : null; } catch(e) {}
        return { status: r.status, okHttp: r.ok, data: data, text: txt };
      });
    })
    .then(function(resp) {
      var data = resp.data;
      if (!data) {
        return {
          proveedor: pv.nombre,
          proveedorKey: pv.proveedorKey,
          url: pv.url,
          producto: nombreProducto,
          precio: 0,
          error: 'Respuesta inválida del cotizador HTTP ' + resp.status,
          raw: resp.text
        };
      }
      return data;
    })
    .then(function(data) {
      if (data && data.ok) {
        var precioOk = parseFloat(data.precioArs || data.precio || 0) || 0;
        return {
          proveedor: data.proveedor || pv.nombre,
          proveedorKey: pv.proveedorKey,
          url: data.url || pv.url,
          producto: typeof data.producto === 'string' ? data.producto : nombreProducto,
          precio: precioOk,
          sinIva: data.sinIva !== undefined ? data.sinIva : true,
          fuente: data.fuente || 'cotizador-cloud-run',
          error: precioOk > 0 ? '' : 'El cotizador respondió OK pero no devolvió precio',
          debug: data.debug || null,
          raw: data
        };
      }
      return {
        proveedor: pv.nombre,
        proveedorKey: pv.proveedorKey,
        url: pv.url,
        producto: nombreProducto,
        precio: 0,
        error: (data && (data.error || data.mensaje)) || 'No se pudo cotizar con el servicio real',
        debug: data && data.debug,
        raw: data
      };
    })
    .catch(function(err) {
      return {
        proveedor: pv.nombre,
        proveedorKey: pv.proveedorKey,
        url: pv.url,
        producto: nombreProducto,
        precio: 0,
        error: err.message || 'Error del cotizador real'
      };
    });
  })).then(function(resultados) {
    return {
      resultados: resultados,
      observaciones: 'Cotización realizada con el servicio real de proveedores. Si un proveedor no actualiza, se mantiene el valor anterior.'
    };
  });
}

function cotizarProveedoresAsistente(provCotizables, termino) {
  var systemPrompt = 'Sos un asistente de precios para Nixa, empresa de seguridad en Argentina. ' +
    'Para cada proveedor recibido, si la URL está marcada como URL exacta del producto, usá EXCLUSIVAMENTE esa URL. ' +
    'No busques páginas de categoría, cache, productos parecidos ni otras secciones del mismo sitio cuando la URL es exacta. ' +
    'Si usaste una URL distinta a la recibida, aunque sea del mismo producto, devolvé precio 0. ' +
    'El precio buscado es el precio principal visible de compra/lista/gremio SIN IVA en pesos argentinos, no el precio con IVA. ' +
    'Si esa URL requiere iniciar sesión o no podés ver el precio exacto, devolvé precio 0 y error "requiere login o verificación manual". ' +
    'Si la URL es la web general del proveedor, recién ahí buscá por código/nombre y solo aceptá coincidencia clara. ' +
    'No inventes precios: si no hay coincidencia clara, devolvé precio 0 y error. ' +
    'Respondé SOLO con JSON: {"resultados":[{"proveedor":"nombre","url":"url exacta usada","producto":"nombre encontrado","precio":1234,"moneda":"ARS","error":""}],"observaciones":"..."}';

  var userMsg = 'Producto a cotizar: ' + termino + '\nProveedores:\n' +
    provCotizables.map(function(pv){
      return '- ' + pv.nombre + ': ' + pv.url + (pv.urlProducto ? ' (URL exacta del producto)' : ' (web del proveedor)');
    }).join('\n');

  return fetch('https://asistente-171899432710.southamerica-east1.run.app', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-Frontend-Key': SISVENTAS_FUNCTIONS.frontendKey },
    body: JSON.stringify({ system: systemPrompt, messages: [{ role: 'user', content: userMsg }] })
  })
  .then(function(r){ return r.json(); })
  .then(function(resp) {
    var texto = (resp.content && resp.content[0] && resp.content[0].text) || '';
    var jsonMatch = texto.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { return JSON.parse(jsonMatch[0]); } catch(e) {}
    }
    return null;
  });
}

function recalcularCompraDesdeProveedores() {
  if (!prodProveedoresActuales.length) return;
  var masBarato = prodProveedoresActuales.reduce(function(min, pv) {
    var costoReal = parseFloat(pv.precio)||0;
    if (pv.sinIva && costoReal > 0) costoReal = costoReal * 1.21;
    var costoMin  = parseFloat(min.precio)||Infinity;
    if (min.sinIva && costoMin < Infinity) costoMin = costoMin * 1.21;
    return (costoReal > 0 && costoReal < costoMin) ? pv : min;
  }, prodProveedoresActuales[0]);

  var costoCompra = parseFloat(masBarato.precio) || 0;
  if (masBarato.sinIva && costoCompra > 0) costoCompra = Math.round(costoCompra * 1.21);

  var compraEl = document.getElementById('pf-compra');
  if (compraEl) _setMontoInput(compraEl, costoCompra);
  var gremioEl = document.getElementById('pf-precio-gremio');
  if (gremioEl) _setMontoInput(gremioEl, costoCompra);
  asegurarMargenProductoDefaultEnForm();
  if (costoCompra > 0) calcPrecioDesdeGremio();
}

function cerrarFormProducto() {
  _hide('prod-form-view');
  _block('prod-list-view');
  actualizarStatProductos();
}

function cambiarMonedaProducto() {
  var sel = document.getElementById('pf-moneda');
  var esUSD = sel && sel.value === 'USD';
  var switchEl = document.getElementById('pf-moneda-switch');
  var compraLbl = document.getElementById('pf-compra-moneda-lbl');
  var ventaLbl  = document.getElementById('pf-venta-moneda-lbl');
  var hint      = document.getElementById('pf-moneda-hint');
  var badgeHead = document.getElementById('pf-moneda-badge-head');
  if (switchEl) switchEl.classList.toggle('is-usd', !!esUSD);
  if (compraLbl) compraLbl.textContent = esUSD ? 'USD' : '$';
  if (ventaLbl)  ventaLbl.textContent  = esUSD ? 'USD' : '$';
  if (hint) hint.textContent = esUSD
    ? 'Carga manual en dólares. Usalo solo si este producto realmente se maneja en USD.'
    : 'Precio gremio/costo cargado en pesos. El sistema guarda aparte la referencia USD con el dólar vigente.';
  if (badgeHead) badgeHead.innerHTML = esUSD
    ? '<span class="badge b-blue">💵 USD</span>' : '<span class="badge b-gray">🇦🇷 ARS</span>';
  var equivBox = document.getElementById('pf-equiv-ars-box');
  if (equivBox) equivBox.style.display = esUSD ? '' : 'none';
  calcMargen();
}

function setMonedaProducto(moneda) {
  var sel = document.getElementById('pf-moneda');
  if (sel) sel.value = moneda === 'USD' ? 'USD' : 'ARS';
  cambiarMonedaProducto();
}

async function buscarPreciosProveedores() {
  var nombre = (document.getElementById('pf-nombre')||{}).value || (document.getElementById('pf-descripcion')||{}).value || '';
  var codigo = (document.getElementById('pf-codigo')||{}).value || '';
  var termino = codigo || nombre;
  if (!termino) { notify('Ingresá un nombre o código de producto primero'); return; }

  var btn = document.getElementById('btn-buscar-precios');
  var res = document.getElementById('pf-precios-resultado');
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Buscando...'; }
  if (res) { res.style.display = 'flex'; res.innerHTML = '<div style="color:var(--text3);font-size:12px">Consultando proveedores...</div>'; }

  var precioActual = getMontoRaw(document.getElementById('pf-compra'));
  var systemPrompt = 'Sos un asistente especializado en precios de materiales para instalaciones de seguridad y domótica en Argentina. ' +
    'Buscá el precio de "' + termino + '" en estos proveedores argentinos: ' +
    '1) Biosegur (biosegur.com.ar) - usar URL: biosegur.com.ar/busqueda_avanzada.php?buscar=1&palabra=TERMINO ' +
    '2) Free Electron (free-electron.com.ar) - buscar en la web ' +
    '3) Tecnoprices (tecnoprices.com) - buscar en la web. ' +
    'Para cada proveedor devolvé: nombre del producto encontrado, precio en pesos SIN IVA, URL del producto. ' +
    'Si no encontrás el producto exacto, indicá el más similar. ' +
    'Respondé en formato JSON así: {"resultados":[{"proveedor":"Biosegur","producto":"nombre","precio":12345,"url":"https://..."},...],"observaciones":"texto opcional"}';

  try {
    var resp = await fetch('https://asistente-171899432710.southamerica-east1.run.app', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'X-Frontend-Key': SISVENTAS_FUNCTIONS.frontendKey },
      body: JSON.stringify({
        system: systemPrompt,
        messages: [{ role: 'user', content: 'Busca el precio de: ' + termino + (precioActual ? '. Mi precio actual de compra es $' + precioActual.toLocaleString('es-AR') : '') }]
      })
    });
    var data = await resp.json();
    var texto = (data.content && data.content[0] && data.content[0].text) || '';

    // Intentar parsear JSON de la respuesta
    var jsonMatch = texto.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        var parsed = JSON.parse(jsonMatch[0]);
        var resultados = parsed.resultados || [];
        if (resultados.length) {
          var minPrecio = Math.min(...resultados.filter(r=>r.precio>0).map(r=>r.precio));
          res.innerHTML = resultados.map(function(r) {
            var esMasBajo = r.precio === minPrecio && r.precio > 0;
            var diffPct = precioActual > 0 && r.precio > 0 ? Math.round((r.precio/precioActual - 1)*100) : null;
            var diffStr = diffPct !== null ? (diffPct > 0 ? '<span style="color:var(--red)">+'+diffPct+'%</span>' : '<span style="color:var(--green)">'+diffPct+'%</span>') : '';
            return '<div style="display:flex;align-items:center;gap:8px;padding:8px;background:var(--bg3);border-radius:var(--radius);' + (esMasBajo?'border:1px solid var(--green)':'') + '">' +
              '<div style="flex:1">' +
                '<div style="font-size:11px;font-weight:600;color:var(--text2)">' + escapeHTML(r.proveedor||'') + (esMasBajo?' ✓ más barato':'') + '</div>' +
                '<div style="font-size:12px;color:var(--text)">' + escapeHTML(r.producto||'') + '</div>' +
                (r.url ? '<a href="'+escapeHTML(r.url)+'" target="_blank" style="font-size:10px;color:var(--blue)">Ver producto ↗</a>' : '') +
              '</div>' +
              '<div style="text-align:right">' +
                '<div style="font-size:13px;font-weight:600">$' + (r.precio||0).toLocaleString('es-AR') + '</div>' +
                (diffStr ? '<div style="font-size:10px">vs actual ' + diffStr + '</div>' : '') +
                (r.precio > 0 ? '<button onclick="pfUsarPrecio('+r.precio+')" class="btn btn-sm" style="margin-top:4px;font-size:10px;padding:2px 8px">Usar este</button>' : '') +
              '</div>' +
            '</div>';
          }).join('') + (parsed.observaciones ? '<div style="font-size:11px;color:var(--text3);padding:4px 8px">'+escapeHTML(parsed.observaciones)+'</div>' : '');
        } else {
          res.innerHTML = '<div style="font-size:12px;color:var(--text3)">No se encontraron resultados en los proveedores</div>';
        }
      } catch(e) {
        res.innerHTML = '<div style="font-size:12px;color:var(--text2);white-space:pre-wrap">'+escapeHTML(texto)+'</div>';
      }
    } else {
      res.innerHTML = '<div style="font-size:12px;color:var(--text2);white-space:pre-wrap">'+escapeHTML(texto)+'</div>';
    }
  } catch(e) {
    res.innerHTML = '<div style="font-size:12px;color:var(--red)">Error: ' + escapeHTML(e.message) + '</div>';
  }

  if (btn) { btn.disabled = false; btn.textContent = 'Buscar ahora'; }
}

function pfUsarPrecio(precio) {
  var compraInp = document.getElementById('pf-compra');
  var gremioInp = document.getElementById('pf-precio-gremio');
  if (compraInp) _setMontoInput(compraInp, precio);
  if (gremioInp) _setMontoInput(gremioInp, precio);
  asegurarMargenProductoDefaultEnForm();
  calcPrecioDesdeGremio();
  calcMargen();
  notify('✓ Precio de compra actualizado a $' + precio.toLocaleString('es-AR'));
}

function pfFormatearPrecio(val) {
  // Redondear a 2 decimales máximo, eliminar decimales innecesarios
  var n = parseFloat(val) || 0;
  return n % 1 === 0 ? String(Math.round(n)) : n.toFixed(2).replace(/\.?0+$/, '');
}

function calcPrecioDesdeGremio() {
  var gremio  = getMontoRaw(document.getElementById('pf-precio-gremio'));
  var margen  = asegurarMargenProductoDefaultEnForm();
  var calcEl  = document.getElementById('pf-precio-calculado');
  var usdEl   = document.getElementById('pf-precio-usd-equiv');
  if (!gremio || !margen) { if (calcEl) calcEl.value = ''; return; }
  // Precio venta = costo / (1 - margen/100)
  var precioVenta = Math.round(gremio / (1 - margen / 100));
  if (calcEl) calcEl.value = '$' + precioVenta.toLocaleString('es-AR');
  // Cargar en el campo de precio venta
  var pfVenta = document.getElementById('pf-venta');
  var pfCompra = document.getElementById('pf-compra');
  if (pfVenta)  _setMontoInput(pfVenta, precioVenta);
  if (pfCompra) _setMontoInput(pfCompra, gremio);
  // Mostrar equivalente USD
  var dolarRef = obtenerDolarReferenciaProducto();
  var tc = dolarRef.valor || 0;
  if (tc && usdEl) {
    usdEl.textContent = '= USD ' + (precioVenta / tc).toFixed(2) + ' (' + dolarRef.tipo + ' $' + Math.round(tc).toLocaleString('es-AR') + ')';
  } else if (usdEl) {
    usdEl.textContent = 'TC no disponible';
  }
  calcMargen();
}

// sincronizados tanto el texto visible como el dato crudo (dataset.raw).
function _setMontoInput(input, valor) {
  if (!input) return;
  if (input.dataset.moneyInit) {
    input.dataset.raw = String(valor);
    delete input.dataset.tieneComa;
    _refrescarMoneyVisual(input);
  } else {
    input.value = valor;
  }
}

function calcMargen() {
  const c = getMontoRaw(document.getElementById('pf-compra'));
  const v = getMontoRaw(document.getElementById('pf-venta'));
  const iva = parseFloat(document.getElementById('pf-iva').value) || 0;
  if (c > 0 && v > 0) {
    const margenCosto = ((v - c) / c * 100);
    const margenVenta = ((v - c) / v * 100);
    var margenEl = document.getElementById('pf-margen');
    if (margenEl) {
      margenEl.value = margenCosto.toFixed(1) + '% costo · ' + margenVenta.toFixed(1) + '% venta';
      margenEl.title = 'Sobre costo: ' + margenCosto.toFixed(1) + '%. Sobre venta: ' + margenVenta.toFixed(1) + '%.';
      margenEl.style.color = margenVenta >= 0 ? 'var(--green)' : 'var(--red)';
    }
  } else {
    document.getElementById('pf-margen').value = '—';
  }
  if (v > 0 && iva > 0) {
    document.getElementById('pf-venta-iva').value = '$' + Math.round(v * (1 + iva / 100)).toLocaleString('es-AR');
  } else {
    document.getElementById('pf-venta-iva').value = v > 0 ? '$' + Math.round(v).toLocaleString('es-AR') : '—';
  }
  var monedaSel = document.getElementById('pf-moneda');
  var equivEl = document.getElementById('pf-equiv-ars');
  if (monedaSel && monedaSel.value === 'USD' && equivEl) {
    var tc = (window.TIPO_CAMBIO_CONFIG||{});
    var cotiz = tc[tc.dolarConversion || 'oficial'] || tc.oficial || 0;
    if (v > 0 && cotiz > 0) {
      equivEl.value = '$' + Math.round(v * cotiz).toLocaleString('es-AR') + ' ARS (cotiz. ' + (tc.dolarConversion||'oficial') + ' $' + cotiz + ')';
    } else {
      equivEl.value = cotiz ? '—' : 'Configurá el tipo de cambio primero';
    }
  }
}

function guardarProducto() {
  const cod  = document.getElementById('pf-codigo').value.trim();
  const nom  = (document.getElementById('pf-nombre')||{}).value.trim() || '';
  const desc = document.getElementById('pf-descripcion').value.trim();
  if (!cod || (!nom && !desc)) { notify('Completá al menos código y nombre'); return; }
  var urlGeneralProveedor = normalizarUrlProveedorProducto((document.getElementById('pf-cod-web')||{}).value || '');

  var proveedoresValidos = prodProveedoresActuales.filter(function(pv) {
    return (pv.nombre||'').trim() || (pv.url||'').trim() || parseFloat(pv.precio) > 0;
  }).map(function(pv) {
    return completarReferenciaProveedorProducto(pv, urlGeneralProveedor, pv.actualizadoOrigen || 'manual');
  });
  var proveedorSinUrl = proveedoresValidos.find(function(pv){ return !pv.url; });
  if (proveedorSinUrl) {
    notify('Completá la URL del proveedor o la URL general del producto antes de guardar');
    return;
  }
  var proveedorPrincipal = proveedoresValidos.length
    ? proveedoresValidos.reduce(function(min, pv){
        var cPv  = parseFloat(pv.costoRealArs) || ((parseFloat(pv.precio)||0) * (pv.sinIva ? 1.21 : 1));
        var cMin = parseFloat(min.costoRealArs) || ((parseFloat(min.precio)||0) * (min.sinIva ? 1.21 : 1));
        return cPv > 0 && cPv < cMin ? pv : min;
      }, proveedoresValidos[0])
    : null;
  var dolarRef = obtenerDolarReferenciaProducto();

  var datos = {
    codigo:       cod,
    descripcion:  desc,
    nombre:       document.getElementById('pf-nombre').value.trim() || desc,
    descripcion:  desc,
    categoria:    document.getElementById('pf-categoria').value,
    proveedores:  proveedoresValidos,
    proveedor:    proveedorPrincipal ? proveedorPrincipal.nombre : '',
    moneda:       (document.getElementById('pf-moneda')||{}).value || 'ARS',
    compra:       Math.round(getMontoRaw(document.getElementById('pf-compra')) * 100) / 100,
    venta:        Math.round(getMontoRaw(document.getElementById('pf-venta')) * 100) / 100,
    iva:          parseFloat(document.getElementById('pf-iva').value) || 21,
    stock:        parseInt(document.getElementById('pf-stock').value) || 0,
    stockMin:     parseInt(document.getElementById('pf-stock-min').value) || 5,
    estado:       document.getElementById('pf-estado').value,
    unidad:       document.getElementById('pf-unidad').value,
    esManoDeObra: document.getElementById('pf-es-mano-obra').checked,
    precioGremio: getMontoRaw(document.getElementById('pf-precio-gremio')),
    margenDeseado: parseFloat(document.getElementById('pf-margen-deseado').value) || margenProductoDefault(),
    codWeb:  urlGeneralProveedor,
    imagenUrl: (document.getElementById('pf-imagen-url')||{}).value || ''
  };
  if (proveedorPrincipal) {
    datos.proveedorUrl = proveedorPrincipal.url || '';
    datos.proveedorActualizado = proveedorPrincipal.actualizado || '';
    datos.precioArsPublicado = proveedorPrincipal.precioArsPublicado || proveedorPrincipal.precio || datos.compra;
    datos.costoRealArs = proveedorPrincipal.costoRealArs || datos.compra;
    datos.precioUsdReferencia = proveedorPrincipal.precioUsdReferencia || 0;
    datos.costoRealUsdReferencia = proveedorPrincipal.costoRealUsdReferencia || 0;
    datos.dolarUsado = proveedorPrincipal.dolarUsado || dolarRef.valor || 0;
    datos.dolarTipo = proveedorPrincipal.dolarTipo || dolarRef.tipo || 'oficial';
    datos.precioActualizadoOrigen = proveedorPrincipal.actualizadoOrigen || 'manual';
    datos.precioActualizadoEn = proveedorPrincipal.actualizadoEn || Date.now();
  }
  var tc = dolarRef.valor || 0;
  if (datos.moneda === 'ARS' && tc > 0) {
    datos.ventaUSD   = parseFloat((datos.venta  / tc).toFixed(2));
    datos.compraUSD  = parseFloat((datos.compra / tc).toFixed(2));
    datos.ventaARS   = datos.venta;
    datos.compraARS  = datos.compra;
    datos.tcGuardado = tc;
    datos.tcTipoGuardado = dolarRef.tipo;
    datos.tcFecha    = new Date().toISOString().slice(0,10);
  } else if (datos.moneda === 'USD') {
    // Ya está en USD — guardar también equivalente ARS
    datos.ventaUSD  = datos.venta;
    datos.compraUSD = datos.compra;
    if (tc > 0) {
      datos.ventaARS  = Math.round(datos.venta  * tc);
      datos.compraARS = Math.round(datos.compra * tc);
    }
  }

  if (editingProdId) {
    datos.fbKey = editingProdId;
  }
  if (prodImagenArchivoTemp && window.fbStorage) {
    var path = 'productos/' + cod.replace(/[^a-zA-Z0-9_-]/g,'_') + '/imagen_' + Date.now() + '.jpg';
    var sRef = window.fbStorageRef(window.fbStorage, path);
    window.fbUploadBytes(sRef, prodImagenArchivoTemp).then(function() {
      return window.fbGetDownloadURL(sRef);
    }).then(function(url) {
      datos.imagenUrl = url;
      fbGuardarProducto(datos);
      cerrarFormProducto();
    }).catch(function(e) {
      notify('No se pudo subir la imagen: ' + e.message + ' — se guardó el producto sin imagen');
      fbGuardarProducto(datos);
      cerrarFormProducto();
    });
    return; // el guardado continúa async arriba
  }

  if (prodImagenUrlActual) {
    datos.imagenUrl = prodImagenUrlActual;
  } else if (editingProdId && !document.getElementById('pf-imagen-url').value.trim()) {
    datos.imagenUrl = null; // se quitó explícitamente
  }

  fbGuardarProducto(datos);
  cerrarFormProducto();
}

function verProducto(id) {
  var p = null;
  if (prodData) {
    p = Object.values(prodData).find(function(x){ return String(x.fbKey) === String(id); });
  }
  if (!p) { notify('Producto no encontrado'); return; }
  _hide('prod-list-view'); _hide('prod-form-view'); _block('prod-detail-view');
  actualizarStatProductoActual(p);
  var pc = precioGremioARSDesdeProducto(p);
  var pv = parseFloat(p.ventaARS || p.precioArsPublicadoVenta || p.venta || p.precio_venta || 0) || 0;
  if (pv > 0 && pv < 100 && String(p.moneda || '').toUpperCase() === 'USD') {
    var dolarFicha = obtenerDolarReferenciaProducto();
    if (dolarFicha.valor > 0) pv = Math.round(pv * dolarFicha.valor * 100) / 100;
  }
  if (pc > 100 && (!pv || pv < pc * 0.2)) {
    var margenFicha = parseFloat(p.margenDeseado);
    if (!isFinite(margenFicha) || margenFicha <= 0 || margenFicha >= 95) margenFicha = margenProductoDefault();
    pv = Math.round(pc / (1 - margenFicha / 100));
  }
  var iva = parseFloat(p.iva||21);
  var stk = parseInt(p.stock)||0;
  var stkMin = parseInt(p.stockMin)||2;
  _set('pd-nombre', p.nombre||p.descripcion||'');
  _set('pd-codigo-lbl', p.codigo||'');
  var catEl = document.getElementById('pd-cat-lbl');
  if (catEl) catEl.innerHTML = '<span class="badge b-amber">' + (p.categoria||p.idcategoria||'—') + '</span>';
  _set('pd-prov-lbl', (p.proveedor||p.nom_prov||'—') + (p.marca ? ' · '+p.marca : ''));

  var pdImg = document.getElementById('pd-imagen-img');
  var pdIcon = document.getElementById('pd-imagen-placeholder');
  if (pdImg && pdIcon) {
    if (p.imagenUrl) { pdImg.src = p.imagenUrl; pdImg.style.display=''; pdIcon.style.display='none'; pdImg.onerror=function(){ pdImg.style.display='none'; pdIcon.style.display=''; }; }
    else { pdImg.style.display='none'; pdIcon.style.display=''; }
  }
  _set('pd-compra', '$' + (parseFloat(pc)||0).toLocaleString('es-AR'));
  _set('pd-venta',  '$' + (parseFloat(pv)||0).toLocaleString('es-AR'));
  _set('pd-venta-iva-lbl', 'c/IVA: $' + Math.round(pv*(1+iva/100)).toLocaleString('es-AR'));
  var margen = pc > 0 ? ((pv-pc)/pc*100).toFixed(1) : '—';
  _set('pd-margen', margen !== '—' ? margen + '%' : '—');
  _set('pd-margen-abs', margen !== '—' ? '$' + (pv-pc).toLocaleString('es-AR') + ' por unidad' : '');
  _set('pd-stock', stk);
  _set('pd-stock-sub', 'mín: ' + stkMin + ' unidades');
  var sc = document.getElementById('pd-stock-card');
  var se = document.getElementById('pd-stock');
  if (sc && se) {
    sc.style.background = stk <= 0 ? 'var(--red-bg)' : stk < stkMin ? 'var(--amber-bg)' : 'var(--bg3)';
    se.style.color = stk <= 0 ? 'var(--red)' : stk < stkMin ? 'var(--amber)' : 'var(--text)';
  }

  // Datos completos
  var _si = function(id, val) { var e = document.getElementById(id); if(e) e.value = val||''; };
  _si('pd-cod-inp',    p.codigo||'');
  _si('pd-cat-inp',    p.categoria||p.catId||'');
  _si('pd-prov-inp',   p.proveedor||p.nom_prov||'');
  _si('pd-iva-inp',    (p.iva||21) + '%');
  _si('pd-stmin-inp',  p.stockMin||'');
  _si('pd-unidad-inp', p.unidad||'');
  var provBox = document.getElementById('pd-proveedores-box');
  if (provBox) {
    var lista = Array.isArray(p.proveedores) ? p.proveedores : [];
    if (!lista.length) {
      provBox.innerHTML = '<div style="text-align:center;color:var(--text3);padding:16px;font-size:13px">Sin proveedores cargados para este producto</div>';
    } else {
      var masBaratoIdx = 0;
      lista.forEach(function(pv, i) {
        var precioPv = completarReferenciaProveedorProducto(pv, pv.url || '', pv.actualizadoOrigen || '').precio || 0;
        var precioMejor = completarReferenciaProveedorProducto(lista[masBaratoIdx], lista[masBaratoIdx].url || '', lista[masBaratoIdx].actualizadoOrigen || '').precio || 0;
        if ((precioPv || Infinity) < (precioMejor || Infinity)) masBaratoIdx = i;
      });
      var rows = lista.map(function(pv, i) {
        var pvNormalizado = completarReferenciaProveedorProducto(pv, pv.url || '', pv.actualizadoOrigen || '');
        var esMasBarato = i === masBaratoIdx && lista.length > 1;
        return '<tr' + (esMasBarato ? ' style="background:var(--green-bg)"' : '') + '>' +
          '<td style="padding:8px 4px">' + escapeHTML(pv.nombre||'—') + (esMasBarato ? ' <span class="badge b-green" style="font-size:9px;margin-left:4px"><i class="ti ti-check"></i> Más económico</span>' : '') + '</td>' +
          '<td style="padding:8px 4px;text-align:right;font-weight:500">$' + Math.round(parseFloat(pvNormalizado.precio)||0).toLocaleString('es-AR') + '</td>' +
          '<td style="padding:8px 4px;text-align:right;color:var(--text3);font-size:12px">' + escapeHTML(pv.actualizado||'—') + '</td>' +
        '</tr>';
      }).join('');
      provBox.innerHTML = '<table style="width:100%;font-size:13px"><tr><th style="text-align:left">Proveedor</th><th style="text-align:right">Precio costo</th><th style="text-align:right">Actualizado</th></tr>' + rows + '</table>';
    }
  }

  editingProdId = id;
}

function cerrarDetalleProducto() {
  _hide('prod-detail-view');
  _block('prod-list-view');
  actualizarStatProductos();
}

function editarDesdeDetalle() { abrirFormProducto(editingProdId); }

// Mostrar alertas al navegar a productos
// lógica productos integrada en showPage
function buscarEmpleado(v) { document.querySelectorAll('.er').forEach(tr => tr.style.display = tr.textContent.toLowerCase().includes(v.toLowerCase()) ? '' : 'none'); }
function abrirFormPresupuesto() {
  document.querySelector('#page-presupuesto .card').style.display='none';
  _block('ppto-form');
  const d=new Date(); document.getElementById('pp-fecha').value=d.toISOString().split('T')[0];
  var numEl = document.getElementById('pp-numero');
  if (numEl && !numEl.value) {
    var base = (pptoData||[]).length + 1;
    numEl.value = 'PP-' + String(base).padStart(4,'0');
  }
  calcVencimiento(); calcPpTotales();
}
function cerrarFormPresupuesto() {
  document.querySelector('#page-presupuesto .card').style.display='';
  _hide('ppto-form');
}
function calcVencimiento() {
  const fEl = document.getElementById('pp-fecha');
  const diasEl = document.getElementById('pp-validez') || document.getElementById('pp-dias');
  const vencEl = document.getElementById('pp-vencimiento') || document.getElementById('pp-venc');
  if (!fEl || !fEl.value) return;
  const dias = parseInt(diasEl ? diasEl.value : 15) || 15;
  const partes = fEl.value.split('-').map(Number);
  if (partes.length !== 3 || !partes[0] || !partes[1] || !partes[2]) return;
  const venc = new Date(partes[0], partes[1] - 1, partes[2]);
  venc.setDate(venc.getDate() + dias);
  const fechaISO = venc.getFullYear() + '-' + String(venc.getMonth()+1).padStart(2,'0') + '-' + String(venc.getDate()).padStart(2,'0');
  if (vencEl) vencEl.value = fechaISO;
}
function filterPpCli(v) {
  const d=_get('pp-cli-drop');
  if(!v){d.style.display='none';return;}
  let any=false;
  d.querySelectorAll('.di').forEach(i=>{const s=i.textContent.toLowerCase().includes(v.toLowerCase());i.style.display=s?'':'none';if(s)any=true;});
  d.style.display=any?'block':'none';
}
function selPpCli(nombre,dir) {
  _get('pp-cli-inp').value=nombre;
  _hide('pp-cli-drop');
}
document.addEventListener('click', e=>{if(!e.target.closest('#page-presupuesto .sw'))_hide('pp-cli-drop');});
var _pptoConIva = true; // estado global del toggle IVA en presupuesto

function toggleIvaPpto(btn) {
  _pptoConIva = !_pptoConIva;
  btn.innerHTML = '<i class="ti ti-receipt-tax"></i> ' + (_pptoConIva ? 'Con IVA' : 'Sin IVA');
  btn.style.color = _pptoConIva ? '' : 'var(--amber)';
  btn.style.borderColor = _pptoConIva ? '' : 'var(--amber)';
  calcPpTotales();
}

function calcPpTotales() {
  let s = 0;
  document.querySelectorAll('#pp-body tr').forEach(tr => {
    var qEl  = tr.querySelector('.qty,.ppqty');
    var pEl  = tr.querySelector('.price,.ppprice');
    var dEl  = tr.querySelector('.disc');
    var subEl = tr.querySelector('.sub,.ppsub');
    var q    = parseFloat(qEl  ? qEl.value  : 0) || 0;
    var p    = pEl && pEl.dataset.moneyInit ? getMontoRaw(pEl) : (parseFloat(pEl ? pEl.value : 0) || 0);
    var d    = parseFloat(dEl  ? dEl.value  : 0) || 0;
    var sub  = Math.round(q * p * (1 - d/100));
    s += sub;
    if (subEl) subEl.textContent = '$' + sub.toLocaleString('es-AR');
  });
  var descEl  = document.getElementById('pp-descuento');
  var desc    = parseFloat(descEl ? descEl.value : 0) || 0;
  var descAmt = Math.round(s * desc / 100);
  var base    = s - descAmt;
  var conIva  = typeof _pptoConIva !== 'undefined' ? _pptoConIva : true;
  var iva     = conIva ? Math.round(base * 0.21) : 0;
  _set('pp-sub',  '$' + s.toLocaleString('es-AR'));
  _set('pp-desc-label', 'Descuento ' + desc.toLocaleString('es-AR',{maximumFractionDigits:2}) + '%');
  _set('pp-damt', descAmt > 0 ? '-$' + descAmt.toLocaleString('es-AR') : '$0');
  var ivaRow = document.getElementById('pp-iva-row');
  if (ivaRow) ivaRow.style.display = conIva ? '' : 'none';
  _set('pp-iva',  '$' + iva.toLocaleString('es-AR'));
  _set('pp-total','$' + (base + iva).toLocaleString('es-AR'));
  if (typeof calcMargenPpto === 'function') calcMargenPpto();
}
window._mostrarMargenPpto = false;

function toggleMargenPpto() {
  var ico = document.getElementById('ppto-margen-eye-icon');
  var lbl = document.getElementById('ppto-margen-eye-lbl');
  window._mostrarMargenPpto = !window._mostrarMargenPpto;
  if (ico) ico.className = window._mostrarMargenPpto ? 'ti ti-eye-off' : 'ti ti-eye';
  if (lbl) lbl.textContent = window._mostrarMargenPpto ? 'Ocultar margen' : 'Ver margen de ganancia';
  calcMargenPpto();
}

function calcMargenPpto() {
  var box = document.getElementById('ppto-margen-ganancia-box');
  if (!box) return;
  var totalTxt = (document.getElementById('pp-total')||{}).textContent || '$0';
  var total = parseFloat(typeof normalizarNumeroExcel === 'function' ? normalizarNumeroExcel(totalTxt) : String(totalTxt).replace(/[^\d,.-]/g,'').replace(/\./g,'').replace(',','.')) || 0;
  var costoTotal = 0;
  Array.from(document.querySelectorAll('#pp-body tr')).forEach(function(tr) {
    var selCod = tr.querySelector('.prod-sel-cod');
    var cod = selCod ? selCod.textContent.trim() : '';
    var qty = parseFloat((tr.querySelector('.qty,.ppqty')||{}).value) || 0;
    var prod = typeof obtenerProductoPorCodigoVenta === 'function' ? obtenerProductoPorCodigoVenta(cod, null) : null;
    var costoUnit = typeof obtenerCostoUnitarioVenta === 'function'
      ? obtenerCostoUnitarioVenta(cod, { cotizacionUsada: parseFloat(tr.dataset.cotizacionUsada)||0, monedaOriginal: tr.dataset.monedaOriginal || (prod && prod.moneda) || '' })
      : 0;
    costoTotal += costoUnit * qty;
  });
  if (total <= 0) { box.style.display = 'none'; return; }
  var margenPct = ((total - costoTotal) / total) * 100;
  var pctEl = document.getElementById('ppto-margen-ganancia-pct');
  var lblEl = document.getElementById('ppto-margen-ganancia-label');
  var costoEl = document.getElementById('ppto-margen-ganancia-costo');
  if (pctEl) pctEl.textContent = margenPct.toFixed(1) + '%';
  if (costoEl) costoEl.textContent = 'Costo: $' + Math.round(costoTotal).toLocaleString('es-AR') + ' (productos + mano de obra)';
  if (margenPct < 15) {
    box.style.background = 'var(--red-bg)';
    if (pctEl) pctEl.style.color = 'var(--red)';
    if (lblEl) { lblEl.style.color = 'var(--red)'; lblEl.innerHTML = '<i class="ti ti-alert-triangle"></i> Margen bajo'; }
  } else if (margenPct <= 20) {
    box.style.background = 'var(--amber-bg)';
    if (pctEl) pctEl.style.color = 'var(--amber)';
    if (lblEl) { lblEl.style.color = 'var(--amber)'; lblEl.innerHTML = '<i class="ti ti-info-circle"></i> Margen regular'; }
  } else {
    box.style.background = 'var(--green-bg)';
    if (pctEl) pctEl.style.color = 'var(--green)';
    if (lblEl) { lblEl.style.color = 'var(--green)'; lblEl.innerHTML = '<i class="ti ti-check"></i> Ganancia perfecta'; }
  }
  box.style.display = window._mostrarMargenPpto ? '' : 'none';
}
var ppRowCount=2;

// guardarPresupuesto definida abajo con implementación completa en Firebase
// convertirVenta y verPresupuesto definidas en el módulo de presupuestos
function buscarPresupuesto(v) { document.querySelectorAll('.pprow').forEach(tr=>tr.style.display=tr.textContent.toLowerCase().includes(v.toLowerCase())?'':'none'); }
function filtrarEstadoPpto(v) { document.querySelectorAll('.pprow').forEach(tr=>tr.style.display=(!v||tr.dataset.estado===v)?'':'none'); }
document.addEventListener('DOMContentLoaded',()=>{ const f=document.getElementById('cob-fecha'); if(f)f.value=new Date().toISOString().split('T')[0]; });
function buscarVentaCob(v) {
  const d = document.getElementById('cob-drop');
  if (!v || v.length < 2) { d.style.display='none'; return; }
  var q = v.toLowerCase().replace(/[#v\-]/g,'');
  var matches = (ventasList||[]).filter(function(venta) {
    var idN = String(venta.id||'').toLowerCase().replace(/[#v\-]/g,'');
    var cli = String(venta.cliente||'').toLowerCase();
    return idN.includes(q) || cli.includes(v.toLowerCase());
  }).slice(0, 15);
  if (!matches.length) { d.style.display='none'; return; }
  d.innerHTML = matches.map(function(venta) {
    var total   = parseFloat(venta.total)||0;
    var cobrado = parseFloat(venta.totalPagado)||0;
    var saldo   = Math.max(0, total - cobrado);
    var fmtARS  = function(n){ return '$' + Math.round(n).toLocaleString('es-AR'); };
    return '<div class="di" onmousedown="selVentaCob(\'' +
      escapeHTML(venta.id||'') + '\',\'' +
      escapeHTML(venta.cliente||'') + '\',\'' +
      fmtARS(total) + '\',\'' +
      fmtARS(cobrado) + '\',\'' +
      fmtARS(saldo) + '\')">' +
      '<span><strong style="font-family:monospace;font-size:12px">' + escapeHTML(venta.id||'') + '</strong>' +
      ' <span style="color:var(--text3);font-size:12px">' + escapeHTML(venta.cliente||'') + '</span></span>' +
      '<span style="font-size:12px;color:' + (saldo>0?'var(--amber)':'var(--green)') + '">' +
        (saldo>0 ? 'Saldo: ' + fmtARS(saldo) : '✓ Cobrado') +
      '</span>' +
      '</div>';
  }).join('');
  d.style.display = 'block';
}
document.addEventListener('click',e=>{if(!e.target.closest('#page-cobranzas .sw'))_hide('cob-drop');});
function selVentaCob(ventaId, cliente, total, cobrado, saldo) {
  document.getElementById('cob-venta').value = ventaId;
  document.getElementById('cob-cliente').value = cliente;
  document.getElementById('cob-total-venta').value = total;
  document.getElementById('cob-ya-cobrado').value = cobrado;
  document.getElementById('cob-saldo').value = saldo;
  _hide('cob-drop');
  _setMontoInput(document.getElementById('cob-monto'), 0);
  document.getElementById('cob-nuevo-saldo').value='';
  var refEl = document.getElementById('cob-ref'); if (refEl) refEl.value = '';
  var obsEl = document.getElementById('cob-obs'); if (obsEl) obsEl.value = '';
}

// Navega a Cobranzas y precarga el formulario con los datos reales de la venta,
// para no tener que volver a buscarla y tipear todo de nuevo.
function irACobranzasConVenta(ventaId) {
  var vid = String(ventaId||'').trim();
  var num = vid.replace(/[^0-9]/g,'');
  var venta = (ventasList||[]).find(function(v){
    return v.id === vid || v.fbKey === vid ||
      (num && (String(v.id).replace(/[^0-9]/g,'') === num || String(v.fbKey||'').replace(/[^0-9]/g,'') === num));
  });
  showPage('cobranzas', document.querySelector('[onclick*=cobranzas]'));
  if (!venta) return;
  setTimeout(function() {
    var total   = parseFloat(venta.total) || 0;
    var cobrado = parseFloat(venta.totalPagado) || 0;
    var saldo   = Math.max(0, total - cobrado);
    selVentaCob(
      venta.id || '',
      venta.cliente || '',
      '$' + Math.round(total).toLocaleString('es-AR'),
      '$' + Math.round(cobrado).toLocaleString('es-AR'),
      '$' + Math.round(saldo).toLocaleString('es-AR')
    );
    var elFecha = document.getElementById('cob-fecha');
    if (elFecha && !elFecha.value) elFecha.value = new Date().toISOString().split('T')[0];
    var elMonto = document.getElementById('cob-monto');
    if (elMonto) elMonto.focus();
  }, 150);
}
function calcSaldoTrasCobranza() {
  const saldoStr=normalizarNumeroExcel(document.getElementById('cob-saldo').value);
  const saldo=parseFloat(saldoStr)||0;
  const monto=getMontoRaw(document.getElementById('cob-monto'));
  const nuevo=Math.max(0,saldo-monto);
  const el=document.getElementById('cob-nuevo-saldo');
  el.value='$'+Math.round(nuevo).toLocaleString('es-AR');
  el.style.color=nuevo===0?'var(--green)':'var(--amber)';
}
function showCfgTab(id, el) {
  if (id === 'asistente' && currentRole !== 'admin' && currentRole !== 'administrativo') {
    notify('Acceso restringido para tu rol');
    return;
  }
  var generalPanel = document.getElementById('cfg-general');
  if (generalPanel) generalPanel.classList.remove('cfg-dolar-only');
  document.querySelectorAll('.cfg-panel').forEach(function(p){ p.style.display = 'none'; });
  document.querySelectorAll('.cfg-tab').forEach(function(t){ t.classList.remove('active'); });
  document.getElementById('cfg-' + id).style.display = 'block';
  if (el) el.classList.add('active');
  if (id === 'roles') { renderTablaRoles(); cargarDashWidgets(); }
  if (id === 'facturacion' && typeof recargarConfigTFAppEnUI === 'function') recargarConfigTFAppEnUI();
  if (id === 'productos' && typeof actualizarStatProductos === 'function') setTimeout(actualizarStatProductos, 200);
  if (id === 'cargos') renderCargosConfig();
  if (id === 'comisiones') renderComisionesConfig();
  if (id === 'notificaciones' && typeof renderConfigAlertas === 'function') renderConfigAlertas();
  if (id === 'actividad') cargarLogActividad();
  if (id === 'mantenimiento' && typeof mntInicializar === 'function') mntInicializar();
  if (id === 'asistente') aacfgInicializar();
}
function showCfgDolarTab(el) {
  showCfgTab('general', el);
  var generalPanel = document.getElementById('cfg-general');
  if (generalPanel) generalPanel.classList.add('cfg-dolar-only');
  if (typeof dolarHistoricoCargar === 'function') setTimeout(dolarHistoricoCargar, 120);
}
// CONFIGURACIÓN DEL ASISTENTE DE VENTAS — editor visual
var AACFG_RUBROS = {};       // Estado en memoria, espejo de Firebase
var AACFG_RUBRO_ACTUAL = null;   // id del rubro que se está editando
var AACFG_PASO_ACTUAL = null;    // índice del paso en edición, o null si es nuevo
var AACFG_REGLA_ACTUAL = null;   // índice de la regla en edición, o null si es nueva
var AACFG_CARGADO = false;

function aacfgInicializar() {
  if (!window.fbDB) { notify('Sin conexión'); return; }
  if (AACFG_CARGADO) { aacfgVolverALista(); return; }
  window.fbGet(window.fbRef(window.fbDB, 'sisventas/config/asistente/rubros')).then(function(snap) {
    var data = snap.val();
    if (data && Object.keys(data).length) {
      AACFG_RUBROS = data;
    } else {
      // Firebase vacío todavía: usar la semilla migrada como punto de partida
      AACFG_RUBROS = JSON.parse(JSON.stringify(AACFG_SEMILLA_RUBROS));
      window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/asistente/rubros'), AACFG_RUBROS);
    }
    AACFG_CARGADO = true;
    aacfgVolverALista();
  }).catch(function(e){ notify('Error al cargar: '+e.message); });
}

function aacfgGuardarTodo() {
  if (!window.fbDB) { notify('Sin conexión'); return; }
  window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/asistente/rubros'), AACFG_RUBROS)
    .then(function(){ notify('✓ Guardado'); })
    .catch(function(e){ notify('Error: '+e.message); });
}
function aacfgVolverALista() {
  document.getElementById('aacfg-pantalla-lista').style.display = '';
  document.getElementById('aacfg-pantalla-preguntas').style.display = 'none';
  document.getElementById('aacfg-editor-paso').style.display = 'none';
  document.getElementById('aacfg-pantalla-reglas').style.display = 'none';
  document.getElementById('aacfg-editor-regla').style.display = 'none';
  document.getElementById('aacfg-pantalla-preview').style.display = 'none';
  aacfgRenderListaRubros();
}

function aacfgRenderListaRubros() {
  var grid = document.getElementById('aacfg-rubros-grid');
  if (!grid) return;
  var ids = Object.keys(AACFG_RUBROS);
  if (!ids.length) { grid.innerHTML = '<div style="padding:24px;text-align:center;color:var(--text3)">Sin rubros configurados</div>'; return; }
  ids.sort(function(a,b){ return (AACFG_RUBROS[a].orden||99) - (AACFG_RUBROS[b].orden||99); });
  grid.innerHTML = ids.map(function(id) {
    var r = AACFG_RUBROS[id];
    var activo = r.activo !== false;
    return '<div class="card" style="margin-bottom:0">' +
      '<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">' +
        '<div style="width:36px;height:36px;border-radius:8px;background:'+(r.color||'#888')+'22;color:'+(r.color||'#888')+';display:flex;align-items:center;justify-content:center"><i class="ti '+(r.icono||'ti-box')+'"></i></div>' +
        '<div style="flex:1"><div style="font-weight:500;font-size:14px">'+escapeHTML(r.nombre||id)+'</div>' +
        '<div style="font-size:11px;color:var(--text3)">'+(r.pasos||[]).length+' preguntas · '+(r.reglas||[]).length+' reglas</div></div>' +
        '<span class="badge '+(activo?'b-green':'b-amber')+'" style="font-size:10px">'+(activo?'Activo':'Inactivo')+'</span>' +
      '</div>' +
      '<button class="btn btn-sm" style="width:100%" onclick="aacfgAbrirRubro(\''+id+'\')"><i class="ti ti-settings"></i> Configurar</button>' +
    '</div>';
  }).join('');
}

function aacfgAbrirNuevoRubro() {
  var nombre = prompt('Nombre del rubro nuevo (ej: "Cercos eléctricos"):');
  if (!nombre || !nombre.trim()) return;
  var id = nombre.trim().toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'');
  if (AACFG_RUBROS[id]) { notify('Ya existe un rubro con ese nombre'); return; }
  var maxOrden = Object.values(AACFG_RUBROS).reduce(function(m,r){ return Math.max(m, r.orden||0); }, 0);
  AACFG_RUBROS[id] = { nombre: nombre.trim(), color:'#1d4ed8', icono:'ti-box', activo:true, orden:maxOrden+1, pasos:[], reglas:[] };
  aacfgGuardarTodo();
  aacfgAbrirRubro(id);
}
function aacfgAbrirRubro(id) {
  AACFG_RUBRO_ACTUAL = id;
  document.getElementById('aacfg-pantalla-lista').style.display = 'none';
  document.getElementById('aacfg-pantalla-preguntas').style.display = '';
  document.getElementById('aacfg-editor-paso').style.display = 'none';
  document.getElementById('aacfg-pantalla-reglas').style.display = 'none';
  document.getElementById('aacfg-pantalla-preview').style.display = 'none';

  var r = AACFG_RUBROS[id];
  document.getElementById('aacfg-preguntas-titulo').textContent = r.nombre;
  document.getElementById('aacfg-rubro-nombre').value = r.nombre || '';
  document.getElementById('aacfg-rubro-color').value = r.color || '#1d4ed8';
  document.getElementById('aacfg-rubro-icono').value = r.icono || 'ti-box';
  document.getElementById('aacfg-rubro-activo').value = String(r.activo !== false);
  aacfgRenderPasos();
}

function aacfgGuardarDatosRubro() {
  var r = AACFG_RUBROS[AACFG_RUBRO_ACTUAL];
  r.nombre = document.getElementById('aacfg-rubro-nombre').value.trim() || r.nombre;
  r.color = document.getElementById('aacfg-rubro-color').value;
  r.icono = document.getElementById('aacfg-rubro-icono').value.trim() || 'ti-box';
  r.activo = document.getElementById('aacfg-rubro-activo').value === 'true';
  aacfgGuardarTodo();
  document.getElementById('aacfg-preguntas-titulo').textContent = r.nombre;
}

function aacfgRenderPasos() {
  var cont = document.getElementById('aacfg-pasos-lista');
  var r = AACFG_RUBROS[AACFG_RUBRO_ACTUAL];
  var pasos = r.pasos || [];
  if (!pasos.length) { cont.innerHTML = '<div style="padding:20px;text-align:center;color:var(--text3);font-size:13px">Sin preguntas todavía</div>'; return; }
  var tipoLbl = { opciones:'Opción única', multi:'Múltiple', numero:'Número' };
  cont.innerHTML = pasos.map(function(p, i) {
    return '<div style="display:flex;align-items:center;gap:10px;padding:10px 12px;background:var(--bg3);border-radius:var(--radius)">' +
      '<span style="font-size:11px;color:var(--text3);min-width:18px">'+(i+1)+'</span>' +
      '<div style="flex:1"><div style="font-size:13px;font-weight:500">'+escapeHTML(p.titulo||'(sin título)')+'</div>' +
      '<div style="font-size:11px;color:var(--text3)">'+tipoLbl[p.tipo]+' · campo: '+escapeHTML(p.id||'')+'</div></div>' +
      '<button class="btn btn-sm btn-icon" onclick="aacfgMoverPaso('+i+',-1)" title="Subir" '+(i===0?'disabled':'')+'><i class="ti ti-arrow-up" style="font-size:13px"></i></button>' +
      '<button class="btn btn-sm btn-icon" onclick="aacfgMoverPaso('+i+',1)" title="Bajar" '+(i===pasos.length-1?'disabled':'')+'><i class="ti ti-arrow-down" style="font-size:13px"></i></button>' +
      '<button class="btn btn-sm btn-icon" onclick="aacfgAbrirEditorPaso('+i+')" title="Editar"><i class="ti ti-edit" style="font-size:13px"></i></button>' +
    '</div>';
  }).join('');
}

function aacfgMoverPaso(idx, delta) {
  var pasos = AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos;
  var nuevoIdx = idx + delta;
  if (nuevoIdx < 0 || nuevoIdx >= pasos.length) return;
  var tmp = pasos[idx]; pasos[idx] = pasos[nuevoIdx]; pasos[nuevoIdx] = tmp;
  aacfgGuardarTodo();
  aacfgRenderPasos();
}

function aacfgIrAReglas() { aacfgAbrirReglas(AACFG_RUBRO_ACTUAL); }
function aacfgVolverAPreguntas() { aacfgAbrirRubro(AACFG_RUBRO_ACTUAL); }
var AACFG_OPCIONES_TEMP = [];

function aacfgAbrirEditorPaso(idx) {
  AACFG_PASO_ACTUAL = idx;
  document.getElementById('aacfg-pantalla-preguntas').style.display = 'none';
  document.getElementById('aacfg-editor-paso').style.display = '';

  var paso = (idx !== null) ? AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos[idx] : null;
  document.getElementById('aacfg-paso-titulo-header').textContent = idx !== null ? 'Editar pregunta' : 'Nueva pregunta';
  document.getElementById('aacfg-paso-titulo').value = paso ? paso.titulo||'' : '';
  document.getElementById('aacfg-paso-desc').value = paso ? paso.desc||'' : '';
  document.getElementById('aacfg-paso-tipo').value = paso ? paso.tipo||'opciones' : 'opciones';
  document.getElementById('aacfg-paso-num-min').value = paso ? (paso.min!==undefined?paso.min:1) : 1;
  document.getElementById('aacfg-paso-num-max').value = paso ? (paso.max!==undefined?paso.max:64) : 64;
  document.getElementById('aacfg-paso-num-default').value = paso ? (paso.default!==undefined?paso.default:4) : 4;
  document.getElementById('aacfg-paso-num-label').value = paso ? paso.label||'' : '';
  document.getElementById('aacfg-paso-btn-eliminar').style.display = idx !== null ? '' : 'none';

  AACFG_OPCIONES_TEMP = paso && Array.isArray(paso.opciones) ? JSON.parse(JSON.stringify(paso.opciones)) : [];
  aacfgCambiarTipoPaso();
  aacfgRenderOpcionesPaso();
}

function aacfgCerrarEditorPaso() {
  document.getElementById('aacfg-editor-paso').style.display = 'none';
  document.getElementById('aacfg-pantalla-preguntas').style.display = '';
}

function aacfgCambiarTipoPaso() {
  var tipo = document.getElementById('aacfg-paso-tipo').value;
  document.getElementById('aacfg-paso-config-numero').style.display = tipo === 'numero' ? '' : 'none';
  document.getElementById('aacfg-paso-config-opciones').style.display = tipo !== 'numero' ? '' : 'none';
}

function aacfgRenderOpcionesPaso() {
  var cont = document.getElementById('aacfg-paso-opciones-lista');
  if (!AACFG_OPCIONES_TEMP.length) { cont.innerHTML = '<div style="padding:12px;text-align:center;color:var(--text3);font-size:12px">Sin opciones — agregá al menos una</div>'; return; }
  cont.innerHTML = AACFG_OPCIONES_TEMP.map(function(o, i) {
    return '<div style="display:flex;gap:8px;align-items:center">' +
      '<input type="text" placeholder="id (ej: residencial)" value="'+escapeHTML(o.id||'')+'" style="width:120px" onchange="aacfgOpcionCambio('+i+',\'id\',this.value)">' +
      '<input type="text" placeholder="Título visible" value="'+escapeHTML(o.titulo||'')+'" style="flex:1" onchange="aacfgOpcionCambio('+i+',\'titulo\',this.value)">' +
      '<input type="text" placeholder="Descripción" value="'+escapeHTML(o.desc||'')+'" style="flex:1" onchange="aacfgOpcionCambio('+i+',\'desc\',this.value)">' +
      '<input type="text" placeholder="ti-icono" value="'+escapeHTML(o.ico||'')+'" style="width:110px" onchange="aacfgOpcionCambio('+i+',\'ico\',this.value)">' +
      '<button class="btn btn-sm btn-icon" onclick="aacfgEliminarOpcionPaso('+i+')" style="color:var(--red)"><i class="ti ti-trash" style="font-size:13px"></i></button>' +
    '</div>';
  }).join('');
}

function aacfgOpcionCambio(idx, campo, val) { AACFG_OPCIONES_TEMP[idx][campo] = val; }
function aacfgAgregarOpcionPaso() { AACFG_OPCIONES_TEMP.push({id:'',titulo:'',desc:'',ico:'ti-circle'}); aacfgRenderOpcionesPaso(); }
function aacfgEliminarOpcionPaso(idx) { AACFG_OPCIONES_TEMP.splice(idx,1); aacfgRenderOpcionesPaso(); }

function aacfgGuardarPaso() {
  var titulo = document.getElementById('aacfg-paso-titulo').value.trim();
  if (!titulo) { notify('Ingresá el título de la pregunta'); return; }
  var tipo = document.getElementById('aacfg-paso-tipo').value;

  var paso;
  if (AACFG_PASO_ACTUAL !== null) {
    paso = AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos[AACFG_PASO_ACTUAL];
  } else {
    paso = { id: titulo.toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'') };
  }
  paso.titulo = titulo;
  paso.desc = document.getElementById('aacfg-paso-desc').value.trim();
  paso.tipo = tipo;

  if (tipo === 'numero') {
    paso.min = parseInt(document.getElementById('aacfg-paso-num-min').value)||1;
    paso.max = parseInt(document.getElementById('aacfg-paso-num-max').value)||64;
    paso.default = parseInt(document.getElementById('aacfg-paso-num-default').value)||1;
    paso.label = document.getElementById('aacfg-paso-num-label').value.trim();
    delete paso.opciones;
  } else {
    var opcionesValidas = AACFG_OPCIONES_TEMP.filter(function(o){ return (o.id||'').trim() && (o.titulo||'').trim(); });
    if (!opcionesValidas.length) { notify('Agregá al menos una opción válida (con id y título)'); return; }
    paso.opciones = opcionesValidas;
  }

  if (AACFG_PASO_ACTUAL === null) {
    if (!AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos) AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos = [];
    AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos.push(paso);
  }
  aacfgGuardarTodo();
  aacfgCerrarEditorPaso();
  aacfgRenderPasos();
}

function aacfgEliminarPaso() {
  if (AACFG_PASO_ACTUAL === null) return;
  if (!confirm('¿Eliminar esta pregunta?')) return;
  AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos.splice(AACFG_PASO_ACTUAL, 1);
  aacfgGuardarTodo();
  aacfgCerrarEditorPaso();
  aacfgRenderPasos();
}
var AACFG_OP_LABELS = { eq:'es igual a', neq:'no es', gt:'es mayor que', lte:'es menor o igual a', in:'es alguna de', incluye:'incluye' };

function aacfgAbrirReglas(id) {
  AACFG_RUBRO_ACTUAL = id;
  document.getElementById('aacfg-pantalla-preguntas').style.display = 'none';
  document.getElementById('aacfg-pantalla-reglas').style.display = '';
  document.getElementById('aacfg-reglas-titulo').textContent = 'Reglas — ' + AACFG_RUBROS[id].nombre;
  aacfgRenderReglas();
}

function aacfgRenderReglas() {
  var cont = document.getElementById('aacfg-reglas-lista');
  var reglas = AACFG_RUBROS[AACFG_RUBRO_ACTUAL].reglas || [];
  if (!reglas.length) { cont.innerHTML = '<div style="padding:20px;text-align:center;color:var(--text3);font-size:13px">Sin reglas todavía</div>'; return; }
  cont.innerHTML = reglas.map(function(reg, i) {
    var condTxt = reg.condiciones && reg.condiciones.length
      ? reg.condiciones.map(function(c){ return escapeHTML(c.campo) + ' ' + (AACFG_OP_LABELS[c.op]||c.op) + ' ' + escapeHTML(Array.isArray(c.valor)?c.valor.join('/'):String(c.valor)); }).join(' y ')
      : 'Siempre';
    var cantTxt = aacfgDescribirCantidad(reg.cantidad);
    return '<div style="display:flex;align-items:center;gap:10px;padding:10px 0;border-bottom:0.5px solid var(--border)">' +
      '<div style="flex:1;font-size:13px"><span style="color:var(--text3)">Si</span> <b>'+condTxt+'</b><br>' +
      '<span style="color:var(--text3)">→ Buscar:</span> '+escapeHTML(reg.accion?(reg.accion.clave||''):'')+' <span style="color:var(--text3)">· Cant:</span> '+cantTxt+'</div>' +
      '<button class="btn btn-sm btn-icon" onclick="aacfgAbrirEditorRegla('+i+')"><i class="ti ti-edit" style="font-size:13px"></i></button>' +
    '</div>';
  }).join('');
}

function aacfgDescribirCantidad(c) {
  if (!c) return '—';
  if (c.modo === 'fija') return 'fija: '+c.valor;
  if (c.modo === 'igual_variable') return 'igual a "'+c.variable+'"';
  if (c.modo === 'proporcional') return '"'+c.variable+'" × '+c.multiplicador+' ('+c.redondeo+')';
  if (c.modo === 'dividido_entre') return '"'+c.variable+'" ÷ '+c.divisor+' ('+c.redondeo+')';
  return '—';
}
var AACFG_CONDICIONES_TEMP = [];

function aacfgAbrirEditorRegla(idx) {
  AACFG_REGLA_ACTUAL = idx;
  document.getElementById('aacfg-pantalla-reglas').style.display = 'none';
  document.getElementById('aacfg-editor-regla').style.display = '';

  var reg = (idx !== null) ? AACFG_RUBROS[AACFG_RUBRO_ACTUAL].reglas[idx] : null;
  AACFG_CONDICIONES_TEMP = reg && reg.condiciones ? JSON.parse(JSON.stringify(reg.condiciones)) : [];
  document.getElementById('aacfg-regla-clave').value = reg ? (reg.accion?reg.accion.clave||'':'') : '';
  document.getElementById('aacfg-regla-ref-nombre').value = reg ? reg.refNombre||'' : '';
  _setMontoInput(document.getElementById('aacfg-regla-ref-precio'), reg ? reg.refPrecio||0 : 0);
  document.getElementById('aacfg-regla-btn-eliminar').style.display = idx !== null ? '' : 'none';

  aacfgPoblarSelectVariables();
  var cant = reg ? reg.cantidad : { modo:'fija', valor:1 };
  document.getElementById('aacfg-regla-cant-modo').value = cant.modo || 'fija';
  document.getElementById('aacfg-regla-cant-fija').value = cant.valor!==undefined?cant.valor:1;
  document.getElementById('aacfg-regla-cant-variable').value = cant.variable||'';
  document.getElementById('aacfg-regla-cant-mult').value = cant.multiplicador!==undefined?cant.multiplicador:1;
  document.getElementById('aacfg-regla-cant-div').value = cant.divisor!==undefined?cant.divisor:2;
  document.getElementById('aacfg-regla-cant-redondeo').value = cant.redondeo||'arriba';
  aacfgCambiarModoCantidad();
  aacfgRenderCondiciones();
}

function aacfgCerrarEditorRegla() {
  document.getElementById('aacfg-editor-regla').style.display = 'none';
  document.getElementById('aacfg-pantalla-reglas').style.display = '';
}

function aacfgPoblarSelectVariables() {
  var sel = document.getElementById('aacfg-regla-cant-variable');
  var pasos = AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos || [];
  var numericos = pasos.filter(function(p){ return p.tipo === 'numero'; });
  var actual = sel.value;
  sel.innerHTML = numericos.map(function(p){ return '<option value="'+p.id+'">'+escapeHTML(p.titulo)+'</option>'; }).join('');
  if (actual) sel.value = actual;
}

function aacfgCambiarModoCantidad() {
  var modo = document.getElementById('aacfg-regla-cant-modo').value;
  document.getElementById('aacfg-regla-cant-fija-box').style.display = modo === 'fija' ? '' : 'none';
  document.getElementById('aacfg-regla-cant-variable-box').style.display = modo !== 'fija' ? '' : 'none';
  document.getElementById('aacfg-regla-cant-mult-box').style.display = modo === 'proporcional' ? '' : 'none';
  document.getElementById('aacfg-regla-cant-div-box').style.display = modo === 'dividido_entre' ? '' : 'none';
  document.getElementById('aacfg-regla-cant-redondeo-box').style.display = (modo === 'proporcional' || modo === 'dividido_entre') ? '' : 'none';
}

function aacfgRenderCondiciones() {
  var cont = document.getElementById('aacfg-regla-condiciones');
  var pasos = AACFG_RUBROS[AACFG_RUBRO_ACTUAL].pasos || [];
  if (!AACFG_CONDICIONES_TEMP.length) { cont.innerHTML = '<div style="padding:10px;text-align:center;color:var(--text3);font-size:12px">Sin condiciones — se aplica siempre</div>'; return; }
  cont.innerHTML = AACFG_CONDICIONES_TEMP.map(function(c, i) {
    var campoOpts = pasos.map(function(p){ return '<option value="'+p.id+'" '+(c.campo===p.id?'selected':'')+'>'+escapeHTML(p.titulo)+'</option>'; }).join('');
    var opOpts = Object.keys(AACFG_OP_LABELS).map(function(k){ return '<option value="'+k+'" '+(c.op===k?'selected':'')+'>'+AACFG_OP_LABELS[k]+'</option>'; }).join('');
    return '<div style="display:flex;gap:8px;align-items:center">' +
      '<select style="flex:1" onchange="aacfgCondicionCambio('+i+',\'campo\',this.value)"><option value="">— pregunta —</option>'+campoOpts+'</select>' +
      '<select style="width:140px" onchange="aacfgCondicionCambio('+i+',\'op\',this.value)">'+opOpts+'</select>' +
      '<input type="text" placeholder="valor" value="'+escapeHTML(Array.isArray(c.valor)?c.valor.join(','):String(c.valor||''))+'" style="flex:1" onchange="aacfgCondicionCambio('+i+',\'valor\',this.value)">' +
      '<button class="btn btn-sm btn-icon" onclick="aacfgEliminarCondicion('+i+')" style="color:var(--red)"><i class="ti ti-trash" style="font-size:13px"></i></button>' +
    '</div>';
  }).join('');
}

function aacfgCondicionCambio(idx, campo, val) {
  if (campo === 'valor' && val.includes(',')) val = val.split(',').map(function(s){return s.trim();});
  AACFG_CONDICIONES_TEMP[idx][campo] = val;
}
function aacfgAgregarCondicion() { AACFG_CONDICIONES_TEMP.push({campo:'',op:'eq',valor:''}); aacfgRenderCondiciones(); }
function aacfgEliminarCondicion(idx) { AACFG_CONDICIONES_TEMP.splice(idx,1); aacfgRenderCondiciones(); }

function aacfgGuardarRegla() {
  var clave = document.getElementById('aacfg-regla-clave').value.trim();
  if (!clave) { notify('Ingresá la palabra clave de búsqueda en Productos'); return; }

  var modo = document.getElementById('aacfg-regla-cant-modo').value;
  var cantidad = { modo: modo };
  if (modo === 'fija') cantidad.valor = parseInt(document.getElementById('aacfg-regla-cant-fija').value)||1;
  else {
    cantidad.variable = document.getElementById('aacfg-regla-cant-variable').value;
    if (!cantidad.variable) { notify('Elegí la pregunta numérica que define la cantidad'); return; }
    if (modo === 'proporcional') { cantidad.multiplicador = parseFloat(document.getElementById('aacfg-regla-cant-mult').value)||1; cantidad.redondeo = document.getElementById('aacfg-regla-cant-redondeo').value; cantidad.minimo = 1; }
    if (modo === 'dividido_entre') { cantidad.divisor = parseFloat(document.getElementById('aacfg-regla-cant-div').value)||1; cantidad.redondeo = document.getElementById('aacfg-regla-cant-redondeo').value; }
  }

  var condicionesValidas = AACFG_CONDICIONES_TEMP.filter(function(c){ return c.campo; });

  var reg;
  if (AACFG_REGLA_ACTUAL !== null) {
    reg = AACFG_RUBROS[AACFG_RUBRO_ACTUAL].reglas[AACFG_REGLA_ACTUAL];
  } else {
    reg = { id: 'r' + Date.now() };
    if (!AACFG_RUBROS[AACFG_RUBRO_ACTUAL].reglas) AACFG_RUBROS[AACFG_RUBRO_ACTUAL].reglas = [];
    AACFG_RUBROS[AACFG_RUBRO_ACTUAL].reglas.push(reg);
  }
  reg.condiciones = condicionesValidas;
  reg.accion = { tipo:'buscar_db', clave: clave };
  reg.cantidad = cantidad;
  reg.refNombre = document.getElementById('aacfg-regla-ref-nombre').value.trim() || clave;
  reg.refPrecio = getMontoRaw(document.getElementById('aacfg-regla-ref-precio'));

  aacfgGuardarTodo();
  aacfgCerrarEditorRegla();
  aacfgRenderReglas();
}

function aacfgEliminarRegla() {
  if (AACFG_REGLA_ACTUAL === null) return;
  if (!confirm('¿Eliminar esta regla?')) return;
  AACFG_RUBROS[AACFG_RUBRO_ACTUAL].reglas.splice(AACFG_REGLA_ACTUAL, 1);
  aacfgGuardarTodo();
  aacfgCerrarEditorRegla();
  aacfgRenderReglas();
}
// migrados al sistema de configuración visual.
function aacfgEvaluarCondicion(c, respuestas) {
  var val = respuestas[c.campo];
  if (c.op === 'eq') return String(val) === String(c.valor);
  if (c.op === 'neq') return String(val) !== String(c.valor);
  if (c.op === 'gt') return parseFloat(val) > parseFloat(c.valor);
  if (c.op === 'lte') return parseFloat(val) <= parseFloat(c.valor);
  if (c.op === 'in') return Array.isArray(c.valor) && c.valor.map(String).includes(String(val));
  if (c.op === 'incluye') return Array.isArray(val) && val.includes(c.valor);
  return false;
}

function aacfgCalcularCantidad(cfgCant, respuestas) {
  if (!cfgCant) return 1;
  if (cfgCant.modo === 'fija') return cfgCant.valor||1;
  var base = parseFloat(respuestas[cfgCant.variable]) || 0;
  if (cfgCant.modo === 'igual_variable') return Math.max(0, Math.round(base));
  if (cfgCant.modo === 'proporcional') {
    var r = base * (cfgCant.multiplicador||1);
    r = cfgCant.redondeo === 'abajo' ? Math.floor(r) : Math.ceil(r);
    return Math.max(cfgCant.minimo||0, r);
  }
  if (cfgCant.modo === 'dividido_entre') {
    var r2 = base / (cfgCant.divisor||1);
    return cfgCant.redondeo === 'abajo' ? Math.floor(r2) : Math.ceil(r2);
  }
  return 1;
}

function aacfgCalcularProductosPorReglas(rubroId, respuestas) {
  var rubro = AACFG_RUBROS[rubroId];
  if (!rubro) return [];
  var lista = [];
  (rubro.reglas||[]).forEach(function(reg) {
    var cumple = (reg.condiciones||[]).every(function(c){ return aacfgEvaluarCondicion(c, respuestas); });
    if (!cumple) return;
    var qty = aacfgCalcularCantidad(reg.cantidad, respuestas);
    if (qty <= 0) return;
    var enDB = buscarProductoEnDB(reg.accion.clave, qty);
    lista.push(enDB || { nombre: reg.refNombre||reg.accion.clave, sku:'', precio: reg.refPrecio||0, qty: qty });
  });
  return lista;
}
function aacfgAbrirPreview() {
  document.getElementById('aacfg-pantalla-preguntas').style.display = 'none';
  document.getElementById('aacfg-pantalla-reglas').style.display = 'none';
  document.getElementById('aacfg-pantalla-preview').style.display = '';
  var cont = document.getElementById('aacfg-preview-cont');
  var rubro = AACFG_RUBROS[AACFG_RUBRO_ACTUAL];

  if (!rubro.pasos || !rubro.pasos.length) {
    cont.innerHTML = '<div style="padding:24px;text-align:center;color:var(--text3)">Agregá al menos una pregunta para poder probar</div>';
    return;
  }

  // Vista previa simplificada: formulario con todas las preguntas a la vez,
  // y al tocar "Calcular" corre el motor de reglas y muestra qué traería.
  var html = '<div class="card"><div class="card-head"><span class="card-title">Respuestas de prueba</span></div><div class="form-grid">';
  rubro.pasos.forEach(function(p) {
    if (p.tipo === 'numero') {
      html += '<div class="fg"><label>'+escapeHTML(p.titulo)+'</label><input type="number" id="aacfg-prev-'+p.id+'" value="'+(p.default||1)+'" min="'+(p.min||0)+'" max="'+(p.max||999)+'"></div>';
    } else if (p.tipo === 'multi') {
      html += '<div class="fg full"><label>'+escapeHTML(p.titulo)+'</label><div style="display:flex;gap:10px;flex-wrap:wrap">';
      (p.opciones||[]).forEach(function(o) {
        html += '<label style="display:flex;align-items:center;gap:4px;font-size:12px"><input type="checkbox" id="aacfg-prev-'+p.id+'-'+o.id+'" data-grupo="'+p.id+'" data-val="'+o.id+'" class="aacfg-prev-multi">'+escapeHTML(o.titulo)+'</label>';
      });
      html += '</div></div>';
    } else {
      html += '<div class="fg"><label>'+escapeHTML(p.titulo)+'</label><select id="aacfg-prev-'+p.id+'">';
      (p.opciones||[]).forEach(function(o) { html += '<option value="'+o.id+'">'+escapeHTML(o.titulo)+'</option>'; });
      html += '</select></div>';
    }
  });
  html += '</div><div class="flex-end"><button class="btn btn-sm btn-primary" onclick="aacfgEjecutarPreview()"><i class="ti ti-player-play"></i> Calcular</button></div></div>';
  html += '<div class="card" id="aacfg-prev-resultado-box" style="display:none"><div class="card-head"><span class="card-title">Productos que traería</span></div><div id="aacfg-prev-resultado"></div></div>';
  cont.innerHTML = html;
}

function aacfgEjecutarPreview() {
  var rubro = AACFG_RUBROS[AACFG_RUBRO_ACTUAL];
  var respuestas = {};
  rubro.pasos.forEach(function(p) {
    if (p.tipo === 'numero') {
      respuestas[p.id] = parseInt((document.getElementById('aacfg-prev-'+p.id)||{}).value) || 0;
    } else if (p.tipo === 'multi') {
      var marcados = [];
      document.querySelectorAll('.aacfg-prev-multi[data-grupo="'+p.id+'"]:checked').forEach(function(el){ marcados.push(el.dataset.val); });
      respuestas[p.id] = marcados;
    } else {
      respuestas[p.id] = (document.getElementById('aacfg-prev-'+p.id)||{}).value || '';
    }
  });

  var resultado = aacfgCalcularProductosPorReglas(AACFG_RUBRO_ACTUAL, respuestas);
  var box = document.getElementById('aacfg-prev-resultado-box');
  var cont = document.getElementById('aacfg-prev-resultado');
  box.style.display = '';
  if (!resultado.length) { cont.innerHTML = '<div style="padding:16px;text-align:center;color:var(--text3);font-size:13px">Ninguna regla coincidió con estas respuestas</div>'; return; }
  var total = 0;
  cont.innerHTML = resultado.map(function(p) {
    var sub = (p.precio||0) * p.qty;
    total += sub;
    var sinPrecio = !p.precio || p.precio <= 0;
    return '<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:0.5px solid var(--border)">' +
      '<span style="font-size:13px">'+escapeHTML(p.nombre)+(sinPrecio?' <span class="badge b-red" style="font-size:9px">Sin precio</span>':'')+' × '+p.qty+'</span>' +
      '<span style="font-size:13px;font-weight:500;color:'+(sinPrecio?'var(--red)':'')+'">$'+Math.round(sub).toLocaleString('es-AR')+'</span>' +
    '</div>';
  }).join('') + '<div style="display:flex;justify-content:space-between;padding:10px 0;font-weight:600"><span>Total</span><span>$'+Math.round(total).toLocaleString('es-AR')+'</span></div>';
}

function aacfgCerrarPreview() {
  document.getElementById('aacfg-pantalla-preview').style.display = 'none';
  document.getElementById('aacfg-pantalla-preguntas').style.display = '';
}
var CARGOS_DATA = {}; // espejo en memoria de sisventas/config/cargos
var PRESENCIA_DATA = {}; // espejo en memoria de sisventas/presencia, clave = uid
// usuario dispara esto al instante (es lo que da el efecto "tiempo real").
function cargarPresenciaUsuarios() {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/presencia'), function(snap) {
    PRESENCIA_DATA = snap.val() || {};
    if (typeof renderTablaUsuarios === 'function') renderTablaUsuarios();
  });
}
function estaUsuarioOnline(email) {
  if (!email) return false;
  var emailLower = String(email).toLowerCase();
  return Object.values(PRESENCIA_DATA).some(function(p) {
    return p.online === true && String(p.email||'').toLowerCase() === emailLower;
  });
}
// de clientes/productos/empleados. Pensado para que el admin pueda auditar el uso
// real del sistema sin ahogarse en ruido de navegación.
function registrarActividad(accion, detalle) {
  if (!window.fbDB) return;
  window.fbPush(window.fbRef(window.fbDB, 'sisventas/log_actividad'), {
    usuario: currentUser || 'Desconocido',
    email: currentUserEmail || '',
    accion: accion || '',
    detalle: detalle || '',
    timestamp: window.fbServerTimestamp ? window.fbServerTimestamp() : Date.now(),
    fecha: new Date().toISOString()
  }).catch(function(){});
}

var LOG_ACTIVIDAD_DATA = []; // últimos registros cargados, más reciente primero

/* v20.362: limpieza del historial de actividad — solo administrador. */
async function limpiarLogActividad() {
  if (currentRole !== 'admin') { notify('Solo el administrador puede limpiar el registro'); return; }
  if (!window.fbDB) { notify('Sin conexión'); return; }
  if (!confirm('¿Borrar TODO el historial de actividad? Esta acción no se puede deshacer.')) return;
  try {
    await window.fbSet(window.fbRef(window.fbDB, 'sisventas/log_actividad'), null);
    LOG_ACTIVIDAD_DATA = [];
    notify('✓ Historial de actividad limpiado');
    if (typeof registrarActividad === 'function') registrarActividad('Historial limpiado', 'El administrador vació el registro de actividad');
    if (typeof cargarLogActividad === 'function') cargarLogActividad();
  } catch(err) { notify('Error: ' + err.message); }
}

function cargarLogActividad() {
  if (!window.fbDB) return;
  window.fbGet(window.fbRef(window.fbDB, 'sisventas/log_actividad')).then(function(snap) {
    var data = snap.val() || {};
    LOG_ACTIVIDAD_DATA = Object.values(data).sort(function(a,b) {
      return (b.fecha||'').localeCompare(a.fecha||'');
    }).slice(0, 300); // últimos 300 registros — suficiente para auditoría reciente sin sobrecargar la tabla
    // Llenar selects de filtro con los usuarios y acciones que aparecen en el log
    var selUsu = document.getElementById('act-filtro-usuario');
    var selAcc = document.getElementById('act-filtro-accion');
    if (selUsu) {
      var usuarios = Array.from(new Set(LOG_ACTIVIDAD_DATA.map(function(l){ return l.usuario; }).filter(Boolean))).sort();
      var valActual = selUsu.value;
      selUsu.innerHTML = '<option value="">— Todos los usuarios —</option>' + usuarios.map(function(u){ return '<option value="'+escapeHTML(u)+'">'+escapeHTML(u)+'</option>'; }).join('');
      selUsu.value = valActual;
    }
    if (selAcc) {
      var acciones = Array.from(new Set(LOG_ACTIVIDAD_DATA.map(function(l){ return l.accion; }).filter(Boolean))).sort();
      var valActualAcc = selAcc.value;
      selAcc.innerHTML = '<option value="">— Todas las acciones —</option>' + acciones.map(function(a){ return '<option value="'+escapeHTML(a)+'">'+escapeHTML(a)+'</option>'; }).join('');
      selAcc.value = valActualAcc;
    }
    renderLogActividad();
  }).catch(function(){});
}

function renderLogActividad() {
  var tbody = document.getElementById('act-tbody');
  if (!tbody) return;
  var filtroUsu = (document.getElementById('act-filtro-usuario')||{}).value || '';
  var filtroAcc = (document.getElementById('act-filtro-accion')||{}).value || '';
  var lista = LOG_ACTIVIDAD_DATA.filter(function(l) {
    return (!filtroUsu || l.usuario === filtroUsu) && (!filtroAcc || l.accion === filtroAcc);
  });
  if (!lista.length) {
    tbody.innerHTML = '<tr><td colspan="4" style="text-align:center;color:var(--text3);padding:24px">Sin actividad registrada todavía</td></tr>';
    return;
  }
  tbody.innerHTML = lista.map(function(l) {
    var fechaFmt = l.fecha ? new Date(l.fecha).toLocaleString('es-AR', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' }) : '—';
    return '<tr>' +
      '<td style="font-size:12px;color:var(--text3);white-space:nowrap">' + escapeHTML(fechaFmt) + '</td>' +
      '<td style="font-weight:500">' + escapeHTML(l.usuario||'—') + '</td>' +
      '<td>' + escapeHTML(l.accion||'—') + '</td>' +
      '<td style="color:var(--text3)">' + escapeHTML(l.detalle||'') + '</td>' +
    '</tr>';
  }).join('');
}

function cargarCargos() {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/config/cargos'), function(snap) {
    var data = snap.val();
    if (!data) {
      // Primera vez: sembrar los 6 cargos reales de CATEGORIAS_SUEL
      var seed = {
        'tecnico_c': { nombre:'Técnico C', categoriaBase:'TECNICO C', valorHora:6450, diasMes:23, valorHoraExtra:9700 },
        'tecnico_b': { nombre:'Técnico B', categoriaBase:'TECNICO B', valorHora:6450, diasMes:23, valorHoraExtra:9700 },
        'tecnico_a': { nombre:'Técnico A', categoriaBase:'TECNICO A', valorHora:5000, diasMes:23, valorHoraExtra:7500 },
        'administrativo': { nombre:'Administrativo', categoriaBase:'ADMINIS', valorHora:5800, diasMes:23, valorHoraExtra:8700 },
        'inicial': { nombre:'Inicial', categoriaBase:'INICIAL', valorHora:4500, diasMes:0, valorHoraExtra:6750 },
        'temporal': { nombre:'Temporal', categoriaBase:'A-TEMP', valorHora:4800, diasMes:0, valorHoraExtra:7200 }
      };
      window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/cargos'), seed);
      CARGOS_DATA = seed;
      renderCargosConfig();
      if (typeof renderTablaEmpleados === 'function') renderTablaEmpleados();
      return;
    }
    CARGOS_DATA = data;
    renderCargosConfig();
    // datos reales (ambos listeners de Firebase cargan en paralelo, sin orden
    // garantizado) — por eso "Mensual (cargo)" quedaba en "—" hasta tocar algo que
    // forzara un segundo render. Ahora se refresca solo apenas los cargos llegan.
    if (typeof renderTablaEmpleados === 'function') renderTablaEmpleados();
  });
}

function renderCargosConfig() {
  var tbl = document.getElementById('cargos-tbl');
  var vacioEl = document.getElementById('cargos-vacio');
  if (!tbl) return;

  var ids = Object.keys(CARGOS_DATA);
  tbl.querySelectorAll('tr:not(:first-child)').forEach(function(tr){ tr.remove(); });

  if (!ids.length) {
    if (vacioEl) vacioEl.style.display = '';
    return;
  }
  if (vacioEl) vacioEl.style.display = 'none';

  var empleadosActivos = Object.values(empData||{}).filter(function(e){ return e.activo !== false; });
  var inpStyle = 'width:80px;text-align:right;background:var(--bg3);border:0.5px solid var(--border2);border-radius:4px;padding:3px 6px;font-size:12px';

  ids.sort(function(a,b){ return (CARGOS_DATA[a].nombre||'').localeCompare(CARGOS_DATA[b].nombre||''); }).forEach(function(id) {
    var c = CARGOS_DATA[id];
    var valorHora = parseFloat(c.valorHora)||0;
    var valorHoraExtra = parseFloat(c.valorHoraExtra)||0;
    var diasMes = parseFloat(c.diasMes)||0;
    var sueldo8hs = valorHora * 8;
    var sueldo4hs = valorHora * 4;
    var mensual = valorHora * 8 * diasMes;
    var cantEmpleados = empleadosActivos.filter(function(e){ return e.cargoId === id; }).length;
    var tr = document.createElement('tr');
    tr.id = 'cargo-row-' + id;
    tr.innerHTML =
      '<td style="font-weight:500">' + escapeHTML(c.nombre||'') + '<div style="font-size:10px;color:var(--text3)">' + escapeHTML(c.categoriaBase||'') + '</div></td>' +
      '<td style="text-align:right"><input type="number" value="' + valorHora + '" style="' + inpStyle + '" onchange="cargosEditarRapido(\'' + id + '\',\'valorHora\',this.value)"></td>' +
      '<td style="text-align:right"><input type="number" value="' + valorHoraExtra + '" style="' + inpStyle + '" onchange="cargosEditarRapido(\'' + id + '\',\'valorHoraExtra\',this.value)"></td>' +
      '<td style="text-align:right"><input type="number" value="' + diasMes + '" style="width:55px;text-align:right;background:var(--bg3);border:0.5px solid var(--border2);border-radius:4px;padding:3px 6px;font-size:12px" onchange="cargosEditarRapido(\'' + id + '\',\'diasMes\',this.value)"></td>' +
      '<td style="text-align:right;font-weight:600" id="cargo-mensual-' + id + '">$' + Math.round(mensual).toLocaleString('es-AR') + '</td>' +
      '<td style="text-align:right;color:var(--text3)" id="cargo-8hs-' + id + '">$' + Math.round(sueldo8hs).toLocaleString('es-AR') + '</td>' +
      '<td style="text-align:right;color:var(--text3)" id="cargo-4hs-' + id + '">$' + Math.round(sueldo4hs).toLocaleString('es-AR') + '</td>' +
      '<td style="text-align:right">' + cantEmpleados + '</td>' +
      '<td><button class="btn btn-sm btn-icon" onclick="cargosAbrirNuevo(\''+id+'\')" title="Editar"><i class="ti ti-edit" style="font-size:14px"></i></button>' +
      '<button class="btn btn-sm btn-icon" onclick="cargosEliminar(\''+id+'\')" title="Eliminar" style="color:var(--text3)"><i class="ti ti-trash" style="font-size:14px"></i></button></td>';
    tbl.appendChild(tr);
  });
}

function cargosEditarRapido(id, campo, valor) {
  var c = CARGOS_DATA[id];
  if (!c || !window.fbDB) { notify('Sin conexión'); return; }
  var num = parseFloat(valor) || 0;

  // Recalcular columnas derivadas en la fila al instante (sin esperar a Firebase)
  var valorHora = campo === 'valorHora' ? num : (parseFloat(c.valorHora)||0);
  var diasMes   = campo === 'diasMes'   ? num : (parseFloat(c.diasMes)||0);
  var _e = function(elId, val) { var el = document.getElementById(elId); if (el) el.textContent = '$'+Math.round(val).toLocaleString('es-AR'); };
  if (campo === 'valorHora' || campo === 'diasMes') {
    _e('cargo-mensual-'+id, valorHora*8*diasMes);
    _e('cargo-8hs-'+id, valorHora*8);
    _e('cargo-4hs-'+id, valorHora*4);
  }

  window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/cargos/'+id+'/'+campo), num)
    .then(function(){ notify('✓ Guardado'); })
    .catch(function(e){ notify('Error: '+e.message); });
}

function _previewCargoCalculos() {
  var vh = parseFloat((document.getElementById('cargo-valor-hora')||{}).value) || 0;
  var p8 = document.getElementById('cargo-preview-8hs');
  var p4 = document.getElementById('cargo-preview-4hs');
  if (p8) p8.value = '$' + Math.round(vh*8).toLocaleString('es-AR');
  if (p4) p4.value = '$' + Math.round(vh*4).toLocaleString('es-AR');
}

function cargosAbrirNuevo(idExistente) {
  var c = idExistente ? CARGOS_DATA[idExistente] : null;
  document.getElementById('cargo-id-edit').value = idExistente || '';
  document.getElementById('modal-cargo-titulo').textContent = idExistente ? 'Editar cargo' : 'Nuevo cargo';
  document.getElementById('cargo-nombre').value = c ? (c.nombre||'') : '';
  document.getElementById('cargo-categoria-base').value = c ? (c.categoriaBase||'TECNICO A') : 'TECNICO A';
  document.getElementById('cargo-valor-hora').value = c ? (c.valorHora||5000) : 5000;
  document.getElementById('cargo-dias-mes').value = c ? (c.diasMes||23) : 23;
  document.getElementById('cargo-valor-hora-extra').value = c ? (c.valorHoraExtra||7500) : 7500;
  _previewCargoCalculos();
  document.getElementById('modal-cargo').style.display = 'flex';
}

function cargosGuardar() {
  var idExistente = document.getElementById('cargo-id-edit').value;
  var nombre = document.getElementById('cargo-nombre').value.trim();
  if (!nombre) { notify('Ingresá un nombre para el cargo'); return; }

  var datos = {
    nombre: nombre,
    categoriaBase: document.getElementById('cargo-categoria-base').value,
    valorHora: parseFloat(document.getElementById('cargo-valor-hora').value) || 0,
    diasMes: parseFloat(document.getElementById('cargo-dias-mes').value) || 0,
    valorHoraExtra: parseFloat(document.getElementById('cargo-valor-hora-extra').value) || 0
  };

  var id = idExistente || nombre.toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'');
  if (!idExistente && CARGOS_DATA[id]) { notify('Ya existe un cargo con ese nombre'); return; }

  if (!window.fbDB) { notify('Sin conexión'); return; }
  window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/cargos/'+id), datos)
    .then(function(){
      notify('✓ Cargo guardado');
      document.getElementById('modal-cargo').style.display = 'none';
    })
    .catch(function(e){ notify('Error: '+e.message); });
}

function cargosEliminar(id) {
  var c = CARGOS_DATA[id];
  var empleadosActivos = Object.values(empData||{}).filter(function(e){ return e.activo !== false && e.cargoId === id; });
  if (empleadosActivos.length) {
    notify('No se puede eliminar: hay '+empleadosActivos.length+' empleado(s) activo(s) con este cargo');
    return;
  }
  if (!confirm('¿Eliminar el cargo "'+(c.nombre||id)+'"?')) return;
  window.fbRemove(window.fbRef(window.fbDB, 'sisventas/config/cargos/'+id))
    .then(function(){ notify('Cargo eliminado'); })
    .catch(function(e){ notify('Error: '+e.message); });
}

