function editarOrden(fbKey) {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/ordenes/' + fbKey), function(snap) {
    var o = snap.val();
    if (!o) { notify('Orden no encontrada'); return; }
    abrirModalNuevo('ordencompra', {
      num: o.numero, prov: o.proveedor, desc: o.descripcion,
      cant: o.cantidad, monto: o.monto, fecha: o.fecha, est: o.estado
    }, fbKey);
  }, { onlyOnce: true });
}
