// Cargar equipos desde Firebase
function fbCargarEquipos() {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/equipos'), function(snap) {
    var data = snap.val();
    equiposData = data ? Object.entries(data).map(function(e){
      return Object.assign({ fbKey: e[0] }, e[1]);
    }).sort(function(a,b){ return (b.ts||0)-(a.ts||0); }) : [];
    renderEquiposCards();
    actualizarMetricasEquipos();
  });
}

// Métricas
function actualizarMetricasEquipos() {
  var hoy = new Date().toISOString().split('T')[0];
  var conGar = equiposData.filter(function(e){
    if (!e.fechaInstalacion || !e.garantiaMeses) return false;
    var venc = new Date(e.fechaInstalacion);
    venc.setMonth(venc.getMonth() + parseInt(e.garantiaMeses));
    return venc >= new Date();
  }).length;
  var intervsHoy = 0;
  equiposData.forEach(function(e){
    if (e.intervenciones) {
      Object.values(e.intervenciones).forEach(function(iv){
        if ((iv.fecha||'').slice(0,10) === hoy) intervsHoy++;
      });
    }
  });
  var _el = function(id){ return document.getElementById(id); };
  if (_el('eq-total'))    _el('eq-total').textContent    = equiposData.length;
  if (_el('eq-garantia')) _el('eq-garantia').textContent = conGar;
  if (_el('eq-hoy'))      _el('eq-hoy').textContent      = intervsHoy;
  if (_el('eq-soporte'))  _el('eq-soporte').textContent  = equiposData.filter(function(e){ return e.estado === 'alerta' || e.estado === 'mantenimiento'; }).length;
}

// Render tarjetas
function renderEquiposCards() {
  var busq  = ((document.getElementById('eq-search')||{}).value||'').toLowerCase();
  var cat   = (document.getElementById('eq-filtro-cat')||{}).value||'';
  var est   = (document.getElementById('eq-filtro-estado')||{}).value||'';
  var lista = equiposData.filter(function(e){
    var texto = ((e.descripcion||'')+(e.modelo||'')+(e.cliente||'')+(e.serie||'')+(e.dir||'')).toLowerCase();
    return (!busq||texto.includes(busq)) && (!cat||e.categoria===cat) && (!est||e.estado===est);
  });
  var grid = document.getElementById('eq-cards');
  if (!grid) return;
  if (!lista.length) {
    grid.innerHTML = '<div style="text-align:center;color:var(--text3);padding:40px;grid-column:1/-1;font-size:13px">' +
      (busq||cat||est ? 'Sin resultados para la búsqueda' : 'Sin equipos registrados. Tocá + Registrar equipo para comenzar.') + '</div>';
    return;
  }
  var catColors = {Alarmas:'#ef4444','Camaras':'#3b82f6','Domotica':'#8b5cf6',Redes:'#06b6d4','UPS / Solar':'#f59e0b','Control de acceso':'#10b981',Otro:'#6b7280'};
  grid.innerHTML = lista.map(function(e) {
    var catKey = String(e.categoria||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'');
    var color  = catColors[e.categoria] || catColors[catKey] || '#6b7280';
    var estMap = {operativo:{txt:'Operativo',cls:'green'},alerta:{txt:'Con alerta',cls:'amber'},mantenimiento:{txt:'En mant.',cls:'blue'},baja:{txt:'De baja',cls:'red'}};
    var est    = estMap[e.estado] || {txt:'—',cls:'text3'};
    // Fecha vencimiento garantía
    var garTxt = '—';
    if (e.fechaInstalacion && e.garantiaMeses && parseInt(e.garantiaMeses) > 0) {
      var v = new Date(e.fechaInstalacion);
      v.setMonth(v.getMonth() + parseInt(e.garantiaMeses));
      var diasRest = Math.round((v - new Date()) / 86400000);
      garTxt = diasRest > 0 ? 'Gar. ' + diasRest + 'd restantes' : 'Vencida';
    }
    var cantFotos = e.fotos ? Object.keys(e.fotos).length : 0;
    var cantInterv = e.intervenciones ? Object.keys(e.intervenciones).length : 0;
    return '<div class="eq-card" onclick="abrirFichaEquipo(\''+e.fbKey+'\')">' +
      '<div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:10px;gap:8px">' +
        '<div>' +
          '<div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:2px">'+escapeHTML(e.descripcion||e.modelo||'Sin nombre')+'</div>' +
          '<div style="font-size:11px;color:var(--text3)">'+escapeHTML(e.modelo||'')+'</div>' +
        '</div>' +
        '<span class="eq-cat-badge" style="background:'+color+'22;color:'+color+'">'+escapeHTML(e.categoria||'—')+'</span>' +
      '</div>' +
      '<div class="eq-card-row"><i class="ti ti-user"></i>'+escapeHTML(e.cliente||'Sin cliente')+'</div>' +
      '<div class="eq-card-row"><i class="ti ti-map-pin"></i>'+escapeHTML(e.dir||'Sin dirección')+'</div>' +
      (e.serie ? '<div class="eq-card-row"><i class="ti ti-barcode"></i>'+escapeHTML(e.serie)+'</div>' : '') +
      '<div style="display:flex;align-items:center;justify-content:space-between;margin-top:10px;padding-top:8px;border-top:0.5px solid var(--border)">' +
        '<div style="display:flex;align-items:center;gap:5px;font-size:12px">' +
          '<span style="width:8px;height:8px;border-radius:50%;background:var(--'+est.cls+');display:inline-block"></span>' +
          '<span style="color:var(--'+est.cls+')">'+est.txt+'</span>' +
        '</div>' +
        '<div style="display:flex;gap:10px;align-items:center">' +
          (cantInterv ? '<span style="font-size:11px;color:var(--text3)"><i class="ti ti-history" style="font-size:11px"></i> '+cantInterv+'</span>' : '') +
          (cantFotos ? '<span style="font-size:11px;color:var(--text3)"><i class="ti ti-photo" style="font-size:11px"></i> '+cantFotos+'</span>' : '') +
          '<span style="font-size:11px;color:var(--text3)">'+garTxt+'</span>' +
          '<button onclick="event.stopPropagation();eliminarRegistro(\'equipos\',\''+e.fbKey+'\')" style="background:none;border:none;color:var(--text3);cursor:pointer;padding:2px 4px;margin-left:4px" title="Eliminar" onmouseenter="this.style.color=\'var(--red)\'" onmouseleave="this.style.color=\'var(--text3)\'"><i class="ti ti-trash" style="font-size:13px"></i></button>' +
        '</div>' +
      '</div>' +
    '</div>';
  }).join('');
}

function filtrarEquipos() { renderEquiposCards(); }

// Abrir ficha
function abrirFichaEquipo(fbKey) {
  var eq = equiposData.find(function(e){ return e.fbKey === fbKey; });
  if (!eq) return;
  equipoActual = fbKey;
  eqFotosTemp = [];
  document.getElementById('eq-ficha-titulo').textContent = eq.descripcion || 'Ficha de equipo';
  // Llenar campos
  var _v = function(id, val){ var el=document.getElementById(id); if(el) el.value=val||''; };
  _v('eq-f-cat',       eq.categoria||'Alarmas');
  _v('eq-f-modelo',    eq.modelo||'');
  _v('eq-f-desc',      eq.descripcion||'');
  _v('eq-f-serie',     eq.serie||'');
  _v('eq-f-serie2',    eq.serie2||'');
  _v('eq-f-cliente',   eq.cliente||'');
  _v('eq-f-dir',       eq.dir||'');
  _v('eq-f-fecha',     eq.fechaInstalacion||'');
  _v('eq-f-garantia',  eq.garantiaMeses||'12');
  _v('eq-f-estado',    eq.estado||'operativo');
  _v('eq-f-venta',     eq.venta||'');
  _v('eq-f-obs',       eq.obs||'');
  // Llenar select técnico
  var selTec = document.getElementById('eq-f-tecnico');
  if (selTec) {
    var opts = '<option value="">— Seleccionar —</option>';
    Object.values(empData||{}).forEach(function(e){ if(e.activo!==false) opts+='<option value="'+escapeHTML(e.nombre)+'">'+escapeHTML(e.nombre)+'</option>'; });
    selTec.innerHTML = opts;
    selTec.value = eq.tecnico||'';
  }
  // Fotos
  renderFotosEquipo(eq.fotos||{});
  // Historial intervenciones
  renderHistorialEquipo(eq.intervenciones||{});
  // Mostrar ficha
  document.getElementById('eq-lista-view').style.display = 'none';
  document.getElementById('eq-ficha-view').style.display = '';
}

function abrirNuevoEquipo() {
  equipoActual = null;
  eqFotosTemp = [];
  var _c = function(id){ var el=document.getElementById(id); if(el) el.value=''; };
  ['eq-f-cat','eq-f-modelo','eq-f-desc','eq-f-serie','eq-f-serie2','eq-f-cliente','eq-f-dir','eq-f-fecha','eq-f-venta','eq-f-obs'].forEach(_c);
  document.getElementById('eq-f-fecha').value = new Date().toISOString().split('T')[0];
  document.getElementById('eq-f-garantia').value = '12';
  document.getElementById('eq-f-estado').value = 'operativo';
  document.getElementById('eq-ficha-titulo').textContent = 'Nuevo equipo';
  renderFotosEquipo({});
  renderHistorialEquipo({});
  var selTec = document.getElementById('eq-f-tecnico');
  if (selTec) {
    var opts = '<option value="">— Seleccionar —</option>';
    Object.values(empData||{}).forEach(function(e){ if(e.activo!==false) opts+='<option>'+escapeHTML(e.nombre)+'</option>'; });
    selTec.innerHTML = opts;
  }
  document.getElementById('eq-lista-view').style.display = 'none';
  document.getElementById('eq-ficha-view').style.display = '';
}

function volverListaEquipos() {
  document.getElementById('eq-ficha-view').style.display = 'none';
  document.getElementById('eq-lista-view').style.display = '';
  equipoActual = null;
}

function guardarEquipo() {
  if (!window.fbDB) { notify('Sin conexión'); return; }
  var g = function(id){ var el=document.getElementById(id); return el?el.value.trim():''; };
  var datos = {
    categoria:       g('eq-f-cat'),
    modelo:          g('eq-f-modelo'),
    descripcion:     g('eq-f-desc'),
    serie:           g('eq-f-serie'),
    serie2:          g('eq-f-serie2'),
    cliente:         g('eq-f-cliente'),
    dir:             g('eq-f-dir'),
    tecnico:         g('eq-f-tecnico'),
    fechaInstalacion:g('eq-f-fecha'),
    garantiaMeses:   g('eq-f-garantia'),
    estado:          g('eq-f-estado'),
    venta:           g('eq-f-venta'),
    obs:             g('eq-f-obs'),
  };
  if (!datos.descripcion && !datos.modelo) { notify('Ingresá descripción o modelo'); return; }
  var promesa = equipoActual
    ? window.fbUpdate(window.fbRef(window.fbDB, 'sisventas/equipos/'+equipoActual), datos)
    : (datos.ts = Date.now(), window.fbPush(window.fbRef(window.fbDB, 'sisventas/equipos'), datos).then(function(ref){ equipoActual = ref.key; return ref; }));
  promesa.then(function(){
    // Subir fotos pendientes
    if (eqFotosTemp.length && window.fbStorage) subirFotosEquipo();
    else { notify(equipoActual ? 'Equipo actualizado' : 'Equipo guardado'); volverListaEquipos(); }
  }).catch(function(e){ notify('Error: '+e.message); });
}

// Fotos del equipo
function agregarFotosEquipo(input) {
  var files = Array.from(input.files||[]);
  files.forEach(function(file){
    eqFotosTemp.push(file);
    var reader = new FileReader();
    reader.onload = function(e) {
      var grid = document.getElementById('eq-fotos-grid');
      if (!grid) return;
      // Quitar placeholder
      grid.querySelectorAll('.foto-placeholder').forEach(function(el){ el.remove(); });
      var img = document.createElement('img');
      img.src = e.target.result;
      img.className = 'rel-foto-thumb';
      img.title = 'Foto pendiente de guardar';
      img.style.opacity = '.6';
      grid.appendChild(img);
    };
    reader.readAsDataURL(file);
  });
}

function renderFotosEquipo(fotosObj) {
  var grid = document.getElementById('eq-fotos-grid');
  if (!grid) return;
  var fotos = Object.values(fotosObj||{});
  if (!fotos.length) {
    grid.innerHTML = '<div class="foto-placeholder" style="color:var(--text3);font-size:12px;text-align:center;padding:20px;grid-column:1/-1">Sin fotos. Tocá el botón para agregar.</div>';
    return;
  }
  grid.innerHTML = fotos.map(function(f){
    return '<img src="'+f.url+'" class="rel-foto-thumb" onclick="window.open(\''+f.url+'\',\'_blank\')" title="'+(f.fecha||'')+'">';
  }).join('');
}

function subirFotosEquipo() {
  if (!equipoActual || !eqFotosTemp.length || !window.fbStorage) return;
  var pendientes = eqFotosTemp.length;
  eqFotosTemp.forEach(function(file) {
    var path = 'sisventas/equipos/'+equipoActual+'/fotos/'+Date.now()+'_'+file.name;
    var ref = window.fbStorageRef(window.fbStorage, path);
    window.fbUploadBytes(ref, file).then(function(snap){ return window.fbGetDownloadURL(snap.ref); })
    .then(function(url){
      window.fbPush(window.fbRef(window.fbDB, 'sisventas/equipos/'+equipoActual+'/fotos'), {
        url: url, fecha: new Date().toLocaleDateString('es-AR'), tecnico: currentUser||''
      });
      pendientes--;
      if (pendientes === 0) { notify('Equipo y fotos guardados'); eqFotosTemp = []; volverListaEquipos(); }
    }).catch(function(){ pendientes--; if(pendientes===0){ notify('Equipo guardado (error en algunas fotos)'); volverListaEquipos(); } });
  });
}
