var SP_MODAL_KEY = null;  // fbKey del reclamo abierto en modal

var SP_ESTADOS = {
  nuevo:       { label:'Nuevo',            color:'var(--blue)',   badge:'b-blue'   },
  diagnostico: { label:'En diagnóstico',   color:'var(--amber)',  badge:'b-amber'  },
  visita:      { label:'Visita requerida', color:'var(--red)',    badge:'b-red'    },
  ot_activa:   { label:'OT activa',        color:'var(--purple)', badge:'b-purple' },
  cerrado:     { label:'Cerrado',          color:'var(--green)',  badge:'b-green'  }
};
// CRÉDITO FISCAL — IVA Compras (comprobantes recibidos AFIP)
// Ruta Firebase: sisventas/comprobantesCompra/{id}
// Factura de Crédito Electrónica A generan crédito fiscal computable.
var CF_DATA = [];          // todos los comprobantes (acumulado histórico)
var CF_PERIODO_ACTIVO = null;

var CF_TIPOS_COMP = {
  '1':'Factura A','2':'Nota Débito A','3':'Nota Crédito A',
  '6':'Factura B','7':'Nota Débito B','8':'Nota Crédito B',
  '11':'Nota Débito C','12':'Nota Crédito C','13':'Remito',
  '51':'Factura M','81':'Tique Factura A','82':'Tique Factura B',
  '83':'Tique','86':'Despacho de Importación',
  '112':'Ticket de Sorteo','201':'Factura de Crédito Electrónica A',
  '206':'Factura de Crédito Electrónica B'
};
var CF_TIPOS_CON_CREDITO = ['1','2','3','81','201'];
function cfEsCreditoFiscal(tipo) { return CF_TIPOS_CON_CREDITO.includes(String(tipo)); }

function cfNum(v) {
  if (!v || !String(v).trim()) return 0;
  return parseFloat(String(v).replace(/\./g,'').replace(',','.')) || 0;
}
function cfPesos(v) { return '$' + v.toLocaleString('es-AR', {minimumFractionDigits:2, maximumFractionDigits:2}); }

var FACT_TAB_ACTIVA = 'cf';
function showFactTab(id, el) {
  FACT_TAB_ACTIVA = id;
  document.querySelectorAll('.fact-panel').forEach(function(p){ p.style.display = 'none'; });
  document.querySelectorAll('.fact-tab').forEach(function(t){ t.classList.remove('active'); });
  document.getElementById('fact-' + id).style.display = 'block';
  el.classList.add('active');
  if (id === 'fv' && typeof fvCargar === 'function') fvCargar();
  if (typeof fvRenderCompensacion === 'function') fvRenderCompensacion();
}

function cfCargar() {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/comprobantesCompra'), function(snap) {
    var data = snap.val() || {};
    CF_DATA = Object.entries(data).map(function(e){ return Object.assign({fbKey:e[0]}, e[1]); });
    var periodos = [...new Set(CF_DATA.map(function(c){ return (c.fecha||'').slice(0,7); }))].filter(Boolean).sort();
    if (!CF_PERIODO_ACTIVO && periodos.length) CF_PERIODO_ACTIVO = periodos[periodos.length-1];
    cfActualizarPeriodosUI();
    if (CF_DATA.length) cfRenderTodo();
    if (typeof fvRenderCompensacion === 'function') fvRenderCompensacion();
    if (typeof actualizarKpiIvaDashboard === 'function') actualizarKpiIvaDashboard();
  });
}
// o emitidos (facturas realizadas) mirando las columnas del encabezado.
// Recibidos: tienen columna "Denominación Emisor" o "Cuit Emisor"
// Emitidos:  tienen columna "Denominación Receptor" o "Nro. Doc. Receptor"
function detectarTipoCSVAfip(text) {
  var firstLine = (text.split('\n')[0] || '').toLowerCase();
  if (firstLine.includes('denominación emisor') || firstLine.includes('cuit emisor') || firstLine.includes('denominacion emisor')) return 'recibidos';
  if (firstLine.includes('denominación receptor') || firstLine.includes('nro. doc. receptor') || firstLine.includes('denominacion receptor')) return 'emitidos';
  return 'desconocido';
}

function cfCargarCSV(input) {
  var file = input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    var tipo = detectarTipoCSVAfip(e.target.result);
    if (tipo === 'emitidos') {
      if (confirm('Este archivo parece ser de Comprobantes Emitidos — corresponde a "Facturas Emitidas", no a "Facturas Recibidas".\n\n¿Querés cargarlo en Facturas Recibidas?')) {
        showFactTab('fv', document.querySelector('.fact-tab:last-child'));
        fvProcesarTexto(e.target.result);
      }
      input.value = '';
      return;
    }
    cfProcesarArchivo(file);
  };
  reader.readAsText(file, 'UTF-8');
}

function fvCargarCSV(input) {
  var file = input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    var tipo = detectarTipoCSVAfip(e.target.result);
    if (tipo === 'recibidos') {
      if (confirm('Este archivo parece ser de Comprobantes Recibidos — corresponde a "Facturas Recibidas", no a "Facturas Emitidas".\n\n¿Querés cargarlo en Facturas Recibidas?')) {
        showFactTab('cf', document.querySelector('.fact-tab:first-child'));
        cfProcesarArchivo(file);
      }
      input.value = '';
      return;
    }
    fvProcesarArchivo(file);
  };
  reader.readAsText(file, 'UTF-8');
}
function fvProcesarTexto(text) {
  try {
    var rows = fvParsearCSV(text);
    if (!rows.length) { notify('El archivo no tiene datos válidos'); return; }
    fvSubirAFirebase(rows);
  } catch(err) {
    notify('Error al procesar el CSV: ' + err.message);
  }
}

function cfProcesarArchivo(file) {
  var reader = new FileReader();
  reader.onload = function(e) {
    try {
      var rows = cfParsearCSV(e.target.result);
      if (!rows.length) { notify('El archivo no tiene datos válidos'); return; }
      cfSubirAFirebase(rows);
    } catch(err) {
      notify('Error al procesar el CSV: ' + err.message);
    }
  };
  reader.readAsText(file, 'UTF-8');
}

function cfParsearCSV(text) {
  var lines = text.split('\n').filter(function(l){ return l.trim(); });
  var sep = lines[0].includes(';') ? ';' : ',';
  var headers = lines[0].split(sep).map(function(h){ return h.replace(/^"|"$/g,'').trim(); });
  return lines.slice(1).filter(function(l){ return l.trim(); }).map(function(line) {
    var vals = [], cur = '', inQ = false;
    for (var i=0; i<line.length; i++) {
      var ch = line[i];
      if (ch==='"') { inQ=!inQ; continue; }
      if (ch===sep && !inQ) { vals.push(cur.trim()); cur=''; continue; }
      cur+=ch;
    }
    vals.push(cur.trim());
    var obj = {};
    headers.forEach(function(h,i){ obj[h]=vals[i]||''; });
    return {
      fecha:      obj['Fecha de Emisión']||'',
      tipo:       obj['Tipo de Comprobante']||'',
      ptoVta:     obj['Punto de Venta']||'',
      nroDoc:     obj['Número Desde']||'',
      cuitEmisor: obj['Nro. Doc. Emisor']||'',
      nombre:     obj['Denominación Emisor']||'',
      moneda:     obj['Moneda']||'$',
      tipoCambio: cfNum(obj['Tipo Cambio']) || 1,
      neto:       cfNum(obj['Imp. Neto Gravado Total']),
      iva105:     cfNum(obj['IVA 10,5%']),
      neto105:    cfNum(obj['Imp. Neto Gravado IVA 10,5%']),
      iva21:      cfNum(obj['IVA 21%']),
      neto21:     cfNum(obj['Imp. Neto Gravado IVA 21%']),
      iva25:      cfNum(obj['IVA 2,5%']),
      iva5:       cfNum(obj['IVA 5%']),
      iva27:      cfNum(obj['IVA 27%']),
      totalIVA:   cfNum(obj['Total IVA']),
      total:      cfNum(obj['Imp. Total'])
    };
  }).filter(function(r){ return r.cuitEmisor && r.total !== 0; })
  .map(function(r) {
    if (r.moneda && r.moneda !== '$' && r.tipoCambio > 1) {
      var tc = r.tipoCambio;
      var round2 = function(n){ return Math.round(n * 100) / 100; };
      r.netoOriginal   = r.neto;
      r.totalOriginal  = r.total;
      r.monedaOriginal = r.moneda;
      r.neto     = round2(r.neto     * tc);
      r.iva105   = round2(r.iva105   * tc);
      r.neto105  = round2(r.neto105  * tc);
      r.iva21    = round2(r.iva21    * tc);
      r.neto21   = round2(r.neto21   * tc);
      r.iva25    = round2(r.iva25    * tc);
      r.iva5     = round2(r.iva5     * tc);
      r.iva27    = round2(r.iva27    * tc);
      r.totalIVA = round2(r.totalIVA * tc);
      r.total    = round2(r.total    * tc);
    }
    return r;
  });
}

function cfSubirAFirebase(rows) {
  if (!window.fbDB) { notify('Sin conexión'); return; }
  var nuevos = 0, existentes = 0;
  var promesas = rows.map(function(r) {
    var key = r.cuitEmisor + '_' + r.tipo + '_' + r.ptoVta + '_' + r.nroDoc;
    var yaExiste = CF_DATA.some(function(c){ return c.fbKey === key; });
    if (yaExiste) { existentes++; return Promise.resolve(); }
    nuevos++;
    return window.fbSet(window.fbRef(window.fbDB, 'sisventas/comprobantesCompra/'+key),
      Object.assign({}, r, { cargadoPor: currentUser||'', ts: Date.now() }));
  });
  Promise.all(promesas).then(function() {
    document.getElementById('cf-drop-txt').textContent = '✓ ' + nuevos + ' comprobantes nuevos cargados' + (existentes ? ' · '+existentes+' ya existían' : '');
    notify('✓ ' + nuevos + ' comprobantes nuevos importados' + (existentes ? ' ('+existentes+' ya estaban cargados)' : ''));
    if (nuevos > 0) setTimeout(function(){ if(typeof cfRenderTodo==='function') cfRenderTodo(); }, 1500);
  }).catch(function(e){ notify('Error: '+e.message); });
}
function cfActualizarPeriodosUI() {
  var periodos = [...new Set(CF_DATA.map(function(c){ return (c.fecha||'').slice(0,7); }))].filter(Boolean).sort();
  var box = document.getElementById('cf-periodos-chips');
  var cont = document.getElementById('cf-periodos-box');
  if (!box || !cont) return;
  if (!periodos.length) { cont.style.display='none'; return; }
  cont.style.display='block';
  var esAdmin = currentRole === 'admin';
  var aniosCF = [...new Set(periodos.map(function(p){ return p.slice(0,4); }))].sort();
  var htmlCF = '';
  if (aniosCF.length > 1) {
    aniosCF.forEach(function(anio) {
      var meses = periodos.filter(function(p){ return p.startsWith(anio); });
      htmlCF += '<div style="margin-bottom:8px"><div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px;margin-bottom:4px;padding-left:2px">'+anio+'</div><div style="display:flex;flex-wrap:wrap;gap:4px">';
      meses.forEach(function(p) {
        var d = new Date(p+'-01T12:00:00');
        var lbl = d.toLocaleDateString('es-AR',{month:'long'});
        var activo = p === CF_PERIODO_ACTIVO;
        var equis = esAdmin ? '<i class="ti ti-x" onclick="event.stopPropagation();cfEliminarPeriodo(\''+p+'\')" style="margin-left:6px;font-size:10px;vertical-align:middle"></i>' : '';
        htmlCF += '<span onclick="cfSelPeriodo(\''+p+'\')" style="padding:3px 10px;border-radius:20px;font-size:11px;cursor:pointer;background:'+(activo?'var(--blue)':'var(--blue-bg)')+';color:'+(activo?'#fff':'var(--blue)')+'">'+lbl+equis+'</span>';
      });
      htmlCF += '</div></div>';
    });
  } else {
    htmlCF = periodos.map(function(p) {
      var d = new Date(p+'-01T12:00:00');
      var lbl = d.toLocaleDateString('es-AR',{month:'long',year:'numeric'});
      var activo = p === CF_PERIODO_ACTIVO;
      var equis = esAdmin ? '<i class="ti ti-x" onclick="event.stopPropagation();cfEliminarPeriodo(\''+p+'\')" style="margin-left:6px;font-size:11px;vertical-align:middle" title="Eliminar período"></i>' : '';
      return '<span onclick="cfSelPeriodo(\''+p+'\')" style="padding:4px 10px;border-radius:20px;font-size:11px;cursor:pointer;background:'+(activo?'var(--blue)':'var(--blue-bg)')+';color:'+(activo?'#fff':'var(--blue)')+'">'+lbl+equis+'</span>';
    }).join('');
  }
  htmlCF += '<span onclick="cfSelPeriodo(null)" style="padding:4px 10px;border-radius:20px;font-size:11px;cursor:pointer;background:'+(!CF_PERIODO_ACTIVO?'var(--blue)':'var(--bg3)')+';color:'+(!CF_PERIODO_ACTIVO?'#fff':'var(--text3)')+'">Todos</span>';
  box.innerHTML = htmlCF;
}

function cfEliminarPeriodo(periodo) {
  if (currentRole !== 'admin') { notify('Solo un administrador puede eliminar un período'); return; }
  if (!window.fbDB) { notify('Sin conexión'); return; }
  var d = new Date(periodo+'-01T12:00:00');
  var lbl = d.toLocaleDateString('es-AR',{month:'long',year:'numeric'});
  var comps = CF_DATA.filter(function(c){ return (c.fecha||'').slice(0,7) === periodo; });
  if (!confirm('⚠ï¸ ATENCIÓN: Esto borra los '+comps.length+' comprobantes de '+lbl+' de FIREBASE (base de datos).\n\nNo es solo ocultar la vista — los datos se eliminan permanentemente.\nPodés volver a cargar el CSV después si los necesitás.\n\n¿Confirmar eliminación?')) return;
  var promesas = comps.map(function(c){ return window.fbRemove(window.fbRef(window.fbDB, 'sisventas/comprobantesCompra/'+c.fbKey)); });
  Promise.all(promesas).then(function(){
    if (CF_PERIODO_ACTIVO === periodo) CF_PERIODO_ACTIVO = null;
    notify('✓ Período '+lbl+' eliminado de Firebase ('+comps.length+' comprobantes)');
    if (typeof fvRenderCompensacion === 'function') fvRenderCompensacion();
    if (typeof actualizarKpiIvaDashboard === 'function') actualizarKpiIvaDashboard();
  }).catch(function(e){ notify('Error: '+e.message); });
}

function cfSelPeriodo(p) { CF_PERIODO_ACTIVO = p; cfActualizarPeriodosUI(); cfRenderTodo(); if (typeof fvRenderCompensacion==='function') fvRenderCompensacion(); }

function cfGetCompFiltrados() {
  return CF_DATA.filter(function(c){ return !CF_PERIODO_ACTIVO || (c.fecha||'').startsWith(CF_PERIODO_ACTIVO); });
}
function cfRenderTodo() {
  var comps = cfGetCompFiltrados();
  document.getElementById('cf-card-totales').style.display = comps.length ? '' : 'none';
  document.getElementById('cf-card-historial').style.display = comps.length ? '' : 'none';
  if (!comps.length) return;

  var lbl = CF_PERIODO_ACTIVO
    ? new Date(CF_PERIODO_ACTIVO+'-01T12:00:00').toLocaleDateString('es-AR',{month:'long',year:'numeric'})
    : 'todos los períodos';
  document.getElementById('cf-totales-titulo').textContent = 'Totales — ' + lbl;
  document.getElementById('cf-totales-qty').textContent = comps.length + ' comprobantes';

  cfRenderMetricas(comps);
  cfRenderAlicuotas(comps);
  cfRenderTipos(comps);
  cfRenderHistorial(comps, '');
}

function cfMetricCard(label, value, sub, color) {
  return '<div class="metric"><div class="m-label">'+label+'</div>' +
    '<div class="m-value" style="font-size:17px'+(color?';color:var(--'+color+')':'')+'">'+value+'</div>' +
    '<div class="m-sub">'+sub+'</div></div>';
}

function cfSigno(c) { return ['3','8','12'].includes(String(c.tipo)) ? -1 : 1; }

function cfRenderMetricas(comps) {
  var compsA = comps.filter(function(c){ return cfEsCreditoFiscal(c.tipo); });
  var totalIVA  = compsA.reduce(function(s,c){ return s+c.totalIVA*cfSigno(c); }, 0);
  var totalNeto = compsA.reduce(function(s,c){ return s+c.neto*cfSigno(c); }, 0);
  var iva21     = compsA.reduce(function(s,c){ return s+c.iva21*cfSigno(c); }, 0);
  var iva105    = compsA.reduce(function(s,c){ return s+c.iva105*cfSigno(c); }, 0);

  document.getElementById('cf-metrics-box').innerHTML =
    cfMetricCard('Crédito fiscal real', cfPesos(totalIVA), 'solo Facturas A · IVA computable', 'green') +
    cfMetricCard('IVA 21% (Fact. A)', cfPesos(iva21), 'alícuota general', 'blue') +
    cfMetricCard('IVA 10,5% (Fact. A)', cfPesos(iva105), 'alícuota reducida', 'amber') +
    cfMetricCard('Neto gravado (Fact. A)', cfPesos(totalNeto), 'base imponible computable', '');
}

function cfRenderAlicuotas(comps) {
  var compsA = comps.filter(function(c){ return cfEsCreditoFiscal(c.tipo); });
  var ali = [
    { lbl:'IVA 21%',   val: compsA.reduce(function(s,c){return s+c.iva21*cfSigno(c);},0),  color:'#3b82f6' },
    { lbl:'IVA 10,5%', val: compsA.reduce(function(s,c){return s+c.iva105*cfSigno(c);},0), color:'#f59e0b' },
    { lbl:'IVA 27%',   val: compsA.reduce(function(s,c){return s+c.iva27*cfSigno(c);},0),  color:'#a855f7' },
    { lbl:'IVA 5%',    val: compsA.reduce(function(s,c){return s+c.iva5*cfSigno(c);},0),   color:'#22c55e' },
    { lbl:'IVA 2,5%',  val: compsA.reduce(function(s,c){return s+c.iva25*cfSigno(c);},0),  color:'#64748b' },
  ].filter(function(a){ return a.val > 0; });
  var totalIVA = ali.reduce(function(s,a){ return s+a.val; }, 0);

  document.getElementById('cf-alicuotas-box').innerHTML = ali.length ? ali.map(function(a) {
    var pct = totalIVA > 0 ? Math.round(a.val/totalIVA*100) : 0;
    return '<div style="display:flex;align-items:center;gap:10px">' +
      '<div style="min-width:80px;font-size:12px;font-weight:600;color:'+a.color+'">'+a.lbl+'</div>' +
      '<div style="flex:1;background:'+a.color+'15;border-radius:3px;height:7px"><div style="width:'+pct+'%;height:7px;background:'+a.color+';border-radius:3px"></div></div>' +
      '<div style="font-family:monospace;font-size:13px;min-width:120px;text-align:right">'+cfPesos(a.val)+'</div>' +
      '<div style="font-size:11px;color:var(--text3);min-width:36px;text-align:right">'+pct+'%</div>' +
    '</div>';
  }).join('') : '<div style="color:var(--text3);font-size:12px">Sin IVA computable en este período</div>';
}

function cfRenderTipos(comps) {
  var tipos = {};
  comps.forEach(function(c){
    var t = CF_TIPOS_COMP[c.tipo] || 'Tipo '+c.tipo;
    tipos[t] = (tipos[t]||0) + 1;
  });
  document.getElementById('cf-tipos-box').innerHTML = Object.entries(tipos)
    .sort(function(a,b){ return b[1]-a[1]; })
    .map(function(e){ return '<span class="badge b-gray" style="font-size:11px">'+e[0]+' ×'+e[1]+'</span>'; })
    .join('');
}
function cfFiltrarHistorial(val) { cfRenderHistorial(cfGetCompFiltrados(), val); }

function cfRenderHistorial(comps, filtro) {
  var provs = {};
  comps.forEach(function(c) {
    var k = c.cuitEmisor;
    if (!provs[k]) provs[k] = { cuit:k, nombre:c.nombre, comps:[], totalIVA:0, total:0 };
    provs[k].comps.push(c);
    var esNC1 = ['3','8','12'].includes(String(c.tipo));
    if (cfEsCreditoFiscal(c.tipo)) provs[k].totalIVA += esNC1 ? -c.totalIVA : c.totalIVA;
    provs[k].total += esNC1 ? -c.total : c.total;
  });
  var lista = Object.values(provs).sort(function(a,b){ return b.totalIVA - a.totalIVA; });

  if (filtro) {
    var f = filtro.toLowerCase();
    lista = lista.filter(function(p){
      return p.nombre.toLowerCase().includes(f) || p.cuit.includes(f) ||
        p.comps.some(function(c){ return c.nroDoc.includes(f); });
    });
  }

  document.getElementById('cf-prov-qty').textContent = lista.length + ' proveedores';
  document.getElementById('cf-historial-box').innerHTML = lista.length
    ? lista.map(function(p, idx){ return cfRenderProvRow(p, idx); }).join('')
    : '<div style="color:var(--text3);font-size:13px;text-align:center;padding:20px">Sin resultados</div>';
}

function cfRenderProvRow(p, idx) {
  var id = 'cf-prov-'+idx;
  var compA = p.comps.filter(function(c){ return cfEsCreditoFiscal(c.tipo); });
  return '<div id="'+id+'" onclick="cfToggleProv(\''+id+'\')" style="background:var(--bg3);border-radius:var(--radius);padding:12px 14px;margin-bottom:6px;cursor:pointer;border-left:3px solid transparent">' +
    '<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">' +
      '<div>' +
        '<div style="font-weight:600;font-size:13px">'+escapeHTML(p.nombre)+'</div>' +
        '<div style="font-size:11px;color:var(--text3);margin-top:2px">CUIT '+p.cuit+' · '+p.comps.length+' comprobante'+(p.comps.length!==1?'s':'') +
          (compA.length ? ' · '+compA.length+' con crédito fiscal' : ' · sin crédito fiscal computable') + '</div>' +
      '</div>' +
      '<div style="text-align:right">' +
        '<div style="font-size:14px;font-weight:700;color:'+(p.totalIVA>0?'var(--green)':'var(--text3)')+'">'+cfPesos(p.totalIVA)+' IVA</div>' +
        '<div style="font-size:11px;color:var(--text3)">Total: '+cfPesos(p.total)+'</div>' +
      '</div>' +
    '</div>' +
    '<div id="'+id+'-det" style="display:none;margin-top:12px">' +
      '<div class="table-wrap"><table>' +
        '<thead><tr><th>Fecha</th><th>Tipo</th><th>N° Comp.</th><th class="tr">Neto</th><th class="tr">IVA</th><th class="tr">Total</th></tr></thead>' +
        '<tbody>' + p.comps.map(function(c) {
          var tipoNom = CF_TIPOS_COMP[c.tipo] || 'Tipo '+c.tipo;
          var computa = cfEsCreditoFiscal(c.tipo);
          var esNC = ['3','8','12'].includes(String(c.tipo));
          var numFmt = String(c.ptoVta).padStart(4,'0') + '-' + String(c.nroDoc).padStart(8,'0');
          return '<tr style="'+(computa?'':'opacity:.55')+'">' +
            '<td style="font-family:monospace;font-size:12px">'+c.fecha+'</td>' +
            '<td><span class="badge '+(computa?'b-green':'b-gray')+'" style="font-size:10px">'+tipoNom+'</span>' +
              (c.monedaOriginal ? ' <span class="badge b-blue" style="font-size:9px" title="TC: $'+c.tipoCambio+'">'+c.monedaOriginal+'</span>' : '') +
            '</td>' +
            '<td style="font-family:monospace;font-size:12px">'+numFmt+'</td>' +
            '<td class="tr" style="font-family:monospace">'+cfPesos(c.neto)+'</td>' +
            '<td class="tr" style="font-family:monospace;color:'+(esNC?'var(--red)':(computa?'var(--green)':'var(--text3)'))+';font-weight:'+(computa?'600':'400')+'">'+(computa?(esNC?'-':'')+cfPesos(c.totalIVA):(c.totalIVA>0?'(no computa)':'—'))+'</td>' +
            '<td class="tr" style="font-family:monospace">'+cfPesos(c.total)+'</td>' +
          '</tr>';
        }).join('') + '</tbody>' +
        '<tfoot><tr style="border-top:1px solid var(--border);font-weight:700">' +
          '<td colspan="3" style="font-size:11px;color:var(--text3)">CRÉDITO FISCAL COMPUTABLE</td>' +
          '<td class="tr" style="font-family:monospace">'+cfPesos(compA.reduce(function(s,c){return s+c.neto;},0))+'</td>' +
          '<td class="tr" style="font-family:monospace;color:var(--green)">'+cfPesos(p.totalIVA)+'</td>' +
          '<td class="tr" style="font-family:monospace">'+cfPesos(p.total)+'</td>' +
        '</tr></tfoot>' +
      '</table></div>' +
    '</div>' +
  '</div>';
}

function cfToggleProv(id) {
  var det = document.getElementById(id+'-det');
  var row = document.getElementById(id);
  if (!det) return;
  var abierto = det.style.display !== 'none';
  det.style.display = abierto ? 'none' : '';
  if (row) row.style.borderLeftColor = abierto ? 'transparent' : 'var(--green)';
}
// FACTURAS REALIZADAS — Débito Fiscal (comprobantes emitidos AFIP)
// Ruta Firebase: sisventas/comprobantesVenta/{id}
// Factura A / M / Tique Fact. A / Factura de Crédito Electrónica A
// discriminan IVA explícito (débito fiscal computable).
// Factura B es a consumidor final: el IVA va incluido en el precio.
var FV_DATA = [];          // todos los comprobantes emitidos (acumulado histórico)
var FV_PERIODO_ACTIVO = null;
var FV_TIPOS_CON_IVA_DISCRIMINADO = ['1','2','3','51','81','201'];
function fvConIvaDiscriminado(tipo) { return FV_TIPOS_CON_IVA_DISCRIMINADO.includes(String(tipo)); }
function fvEsNotaCredito(tipo) {
  var t = String(tipo||'').trim().toLowerCase();
  return ['3','8','12'].includes(t) || t.includes('nota') && t.includes('cr');
}
function fvSigno(c) { return fvEsNotaCredito(c && c.tipo) ? -1 : 1; }
function fvMontoFirmado(c, campo) { return (parseFloat(c && c[campo]) || 0) * fvSigno(c); }
function fvPesosFirmado(c, campo) { return cfPesos(fvMontoFirmado(c, campo)); }

function fvCargar() {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/comprobantesVenta'), function(snap) {
    var data = snap.val() || {};
    FV_DATA = Object.entries(data).map(function(e){ return Object.assign({fbKey:e[0]}, e[1]); });
    var periodos = [...new Set(FV_DATA.map(function(c){ return (c.fecha||'').slice(0,7); }))].filter(Boolean).sort();
    if (!FV_PERIODO_ACTIVO && periodos.length) FV_PERIODO_ACTIVO = periodos[periodos.length-1];
    fvActualizarPeriodosUI();
    if (FV_DATA.length) fvRenderTodo();
    if (typeof fvRenderCompensacion === 'function') fvRenderCompensacion();
    if (typeof actualizarKpiIvaDashboard === 'function') actualizarKpiIvaDashboard();
  });
}
// Drop zone para Facturas Realizadas
(function() {
  document.addEventListener('DOMContentLoaded', function() {
    var dz = document.getElementById('cf-drop-zone');
    if (dz) {
      dz.addEventListener('dragover', function(e){ e.preventDefault(); dz.style.borderColor='var(--blue)'; });
      dz.addEventListener('dragleave', function(){ dz.style.borderColor='var(--border2)'; });
      dz.addEventListener('drop', function(e){
        e.preventDefault(); dz.style.borderColor='var(--border2)';
        var f = e.dataTransfer.files[0]; if (f) cfProcesarArchivo(f);
      });
    }
    var dz2 = document.getElementById('fv-drop-zone');
    if (dz2) {
      dz2.addEventListener('dragover', function(e){ e.preventDefault(); dz2.style.borderColor='var(--blue)'; });
      dz2.addEventListener('dragleave', function(){ dz2.style.borderColor='var(--border2)'; });
      dz2.addEventListener('drop', function(e){
        e.preventDefault(); dz2.style.borderColor='var(--border2)';
        var f = e.dataTransfer.files[0]; if (f) fvProcesarArchivo(f);
      });
    }
  });
})();

function fvProcesarArchivo(file) {
  var reader = new FileReader();
  reader.onload = function(e) {
    try {
      var rows = fvParsearCSV(e.target.result);
      if (!rows.length) { notify('El archivo no tiene datos válidos'); return; }
      fvSubirAFirebase(rows);
    } catch(err) {
      notify('Error al procesar el CSV: ' + err.message);
    }
  };
  reader.readAsText(file, 'UTF-8');
}

function fvParsearCSV(text) {
  var lines = text.split('\n').filter(function(l){ return l.trim(); });
  var sep = lines[0].includes(';') ? ';' : ',';
  var headers = lines[0].split(sep).map(function(h){ return h.replace(/^"|"$/g,'').trim(); });
  return lines.slice(1).filter(function(l){ return l.trim(); }).map(function(line) {
    var vals = [], cur = '', inQ = false;
    for (var i=0; i<line.length; i++) {
      var ch = line[i];
      if (ch==='"') { inQ=!inQ; continue; }
      if (ch===sep && !inQ) { vals.push(cur.trim()); cur=''; continue; }
      cur+=ch;
    }
    vals.push(cur.trim());
    var obj = {};
    headers.forEach(function(h,i){ obj[h]=vals[i]||''; });
    return {
      fecha:        obj['Fecha de Emisión']||'',
      tipo:         obj['Tipo de Comprobante']||'',
      ptoVta:       obj['Punto de Venta']||'',
      nroDoc:       obj['Número Desde']||'',
      cuitReceptor: obj['Nro. Doc. Receptor']||'',
      nombre:       obj['Denominación Receptor']||'',
      neto:         cfNum(obj['Imp. Neto Gravado Total']),
      iva105:       cfNum(obj['IVA 10,5%']),
      neto105:      cfNum(obj['Imp. Neto Gravado IVA 10,5%']),
      iva21:        cfNum(obj['IVA 21%']),
      neto21:       cfNum(obj['Imp. Neto Gravado IVA 21%']),
      iva25:        cfNum(obj['IVA 2,5%']),
      iva5:         cfNum(obj['IVA 5%']),
      iva27:        cfNum(obj['IVA 27%']),
      totalIVA:     cfNum(obj['Total IVA']),
      total:        cfNum(obj['Imp. Total'])
    };
  }).filter(function(r){ return r.cuitReceptor && r.total !== 0; });
}

function fvSubirAFirebase(rows) {
  if (!window.fbDB) { notify('Sin conexión'); return; }
  var nuevos = 0, existentes = 0;
  var promesas = rows.map(function(r) {
    var key = r.cuitReceptor + '_' + r.tipo + '_' + r.ptoVta + '_' + r.nroDoc;
    var yaExiste = FV_DATA.some(function(c){ return c.fbKey === key; });
    if (yaExiste) { existentes++; return Promise.resolve(); }
    nuevos++;
    return window.fbSet(window.fbRef(window.fbDB, 'sisventas/comprobantesVenta/'+key),
      Object.assign({}, r, { cargadoPor: currentUser||'', ts: Date.now() }));
  });
  Promise.all(promesas).then(function() {
    document.getElementById('fv-drop-txt').textContent = '✓ ' + nuevos + ' comprobantes nuevos cargados' + (existentes ? ' · '+existentes+' ya existían' : '');
    notify('✓ ' + nuevos + ' comprobantes nuevos importados' + (existentes ? ' ('+existentes+' ya estaban cargados)' : ''));
  }).catch(function(e){ notify('Error: '+e.message); });
}
function fvActualizarPeriodosUI() {
  var periodos = [...new Set(FV_DATA.map(function(c){ return (c.fecha||'').slice(0,7); }))].filter(Boolean).sort();
  var box = document.getElementById('fv-periodos-chips');
  var cont = document.getElementById('fv-periodos-box');
  if (!box || !cont) return;
  if (!periodos.length) { cont.style.display='none'; return; }
  cont.style.display='block';
  var esAdmin = currentRole === 'admin';
  var aniosFV = [...new Set(periodos.map(function(p){ return p.slice(0,4); }))].sort();
  var htmlFV = '';
  if (aniosFV.length > 1) {
    aniosFV.forEach(function(anio) {
      var meses = periodos.filter(function(p){ return p.startsWith(anio); });
      htmlFV += '<div style="margin-bottom:8px"><div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px;margin-bottom:4px;padding-left:2px">'+anio+'</div><div style="display:flex;flex-wrap:wrap;gap:4px">';
      meses.forEach(function(p) {
        var d = new Date(p+'-01T12:00:00');
        var lbl = d.toLocaleDateString('es-AR',{month:'long'});
        var activo = p === FV_PERIODO_ACTIVO;
        var equis = esAdmin ? '<i class="ti ti-x" onclick="event.stopPropagation();fvEliminarPeriodo(\''+p+'\')" style="margin-left:6px;font-size:10px;vertical-align:middle"></i>' : '';
        htmlFV += '<span onclick="fvSelPeriodo(\''+p+'\')" style="padding:3px 10px;border-radius:20px;font-size:11px;cursor:pointer;background:'+(activo?'var(--blue)':'var(--blue-bg)')+';color:'+(activo?'#fff':'var(--blue)')+'">'+lbl+equis+'</span>';
      });
      htmlFV += '</div></div>';
    });
  } else {
    htmlFV = periodos.map(function(p) {
      var d = new Date(p+'-01T12:00:00');
      var lbl = d.toLocaleDateString('es-AR',{month:'long',year:'numeric'});
      var activo = p === FV_PERIODO_ACTIVO;
      var equis = esAdmin ? '<i class="ti ti-x" onclick="event.stopPropagation();fvEliminarPeriodo(\''+p+'\')" style="margin-left:6px;font-size:11px;vertical-align:middle" title="Eliminar período"></i>' : '';
      return '<span onclick="fvSelPeriodo(\''+p+'\')" style="padding:4px 10px;border-radius:20px;font-size:11px;cursor:pointer;background:'+(activo?'var(--blue)':'var(--blue-bg)')+';color:'+(activo?'#fff':'var(--blue)')+'">'+lbl+equis+'</span>';
    }).join('');
  }
  htmlFV += '<span onclick="fvSelPeriodo(null)" style="padding:4px 10px;border-radius:20px;font-size:11px;cursor:pointer;background:'+(!FV_PERIODO_ACTIVO?'var(--blue)':'var(--bg3)')+';color:'+(!FV_PERIODO_ACTIVO?'#fff':'var(--text3)')+'">Todos</span>';
  box.innerHTML = htmlFV;
}

function fvEliminarPeriodo(periodo) {
  if (currentRole !== 'admin') { notify('Solo un administrador puede eliminar un período'); return; }
  if (!window.fbDB) { notify('Sin conexión'); return; }
  var d = new Date(periodo+'-01T12:00:00');
  var lbl = d.toLocaleDateString('es-AR',{month:'long',year:'numeric'});
  var comps = FV_DATA.filter(function(c){ return (c.fecha||'').slice(0,7) === periodo; });
  if (!confirm('⚠ï¸ ATENCIÓN: Esto borra los '+comps.length+' comprobantes de '+lbl+' de FIREBASE (base de datos).\n\nNo es solo ocultar la vista — los datos se eliminan permanentemente.\nPodés volver a cargar el CSV después si los necesitás.\n\n¿Confirmar eliminación?')) return;
  var promesas = comps.map(function(c){ return window.fbRemove(window.fbRef(window.fbDB, 'sisventas/comprobantesVenta/'+c.fbKey)); });
  Promise.all(promesas).then(function(){
    if (FV_PERIODO_ACTIVO === periodo) FV_PERIODO_ACTIVO = null;
    notify('✓ Período '+lbl+' eliminado de Firebase ('+comps.length+' comprobantes)');
    fvRenderCompensacion();
    if (typeof actualizarKpiIvaDashboard === 'function') actualizarKpiIvaDashboard();
  }).catch(function(e){ notify('Error: '+e.message); });
}

function fvSelPeriodo(p) {
  FV_PERIODO_ACTIVO = p;
  var busq = document.querySelector('#fv-historial-box ~ * input, [oninput*="fvFiltrarHistorial"]');
  if (!busq) {
    document.querySelectorAll('input').forEach(function(el){
      if (el.placeholder && el.placeholder.includes('CUIT')) { el.value = ''; }
    });
  } else {
    busq.value = '';
  }
  fvActualizarPeriodosUI();
  fvRenderTodo();
  fvRenderCompensacion();
}

function fvGetCompFiltrados() {
  return FV_DATA.filter(function(c){ return !FV_PERIODO_ACTIVO || (c.fecha||'').startsWith(FV_PERIODO_ACTIVO); });
}
function fvRenderTodo() {
  var comps = fvGetCompFiltrados();
  document.getElementById('fv-card-totales').style.display = comps.length ? '' : 'none';
  document.getElementById('fv-card-historial').style.display = comps.length ? '' : 'none';
  if (!comps.length) return;

  var lbl = FV_PERIODO_ACTIVO
    ? new Date(FV_PERIODO_ACTIVO+'-01T12:00:00').toLocaleDateString('es-AR',{month:'long',year:'numeric'})
    : 'todos los períodos';
  document.getElementById('fv-totales-titulo').textContent = 'Totales — ' + lbl;
  document.getElementById('fv-totales-qty').textContent = comps.length + ' comprobantes';

  fvRenderMetricas(comps);
  fvRenderAlicuotas(comps);
  fvRenderTipos(comps);
  fvRenderHistorial(comps, '');
}

function fvRenderMetricas(comps) {
  var totalIVA   = comps.reduce(function(s,c){ return s+fvMontoFirmado(c,'totalIVA'); }, 0);
  var totalNeto  = comps.reduce(function(s,c){ return s+fvMontoFirmado(c,'neto'); }, 0);
  var totalFact  = comps.reduce(function(s,c){ return s+fvMontoFirmado(c,'total'); }, 0);
  var iva21      = comps.reduce(function(s,c){ return s+fvMontoFirmado(c,'iva21'); }, 0);
  var iva105     = comps.reduce(function(s,c){ return s+fvMontoFirmado(c,'iva105'); }, 0);

  document.getElementById('fv-metrics-box').innerHTML =
    cfMetricCard('Débito fiscal (IVA a ingresar)', cfPesos(totalIVA), 'facturas menos notas de crédito', 'red') +
    cfMetricCard('Total facturado', cfPesos(totalFact), 'facturas menos notas de crédito', '') +
    cfMetricCard('IVA 21%', cfPesos(iva21), 'alícuota general neta', 'blue') +
    cfMetricCard('IVA 10,5%', cfPesos(iva105), 'alícuota reducida neta', 'amber');
}

function fvRenderAlicuotas(comps) {
  var ali = [
    { lbl:'IVA 21%',   val: comps.reduce(function(s,c){return s+fvMontoFirmado(c,'iva21');},0),  color:'#3b82f6' },
    { lbl:'IVA 10,5%', val: comps.reduce(function(s,c){return s+fvMontoFirmado(c,'iva105');},0), color:'#f59e0b' },
    { lbl:'IVA 27%',   val: comps.reduce(function(s,c){return s+fvMontoFirmado(c,'iva27');},0),  color:'#a855f7' },
    { lbl:'IVA 5%',    val: comps.reduce(function(s,c){return s+fvMontoFirmado(c,'iva5');},0),   color:'#22c55e' },
    { lbl:'IVA 2,5%',  val: comps.reduce(function(s,c){return s+fvMontoFirmado(c,'iva25');},0),  color:'#64748b' },
  ].filter(function(a){ return Math.abs(a.val) > 0.005; });
  var totalIVA = ali.reduce(function(s,a){ return s+Math.abs(a.val); }, 0);

  document.getElementById('fv-alicuotas-box').innerHTML = ali.length ? ali.map(function(a) {
    var pct = totalIVA > 0 ? Math.round(Math.abs(a.val)/totalIVA*100) : 0;
    return '<div style="display:flex;align-items:center;gap:10px">' +
      '<div style="min-width:80px;font-size:12px;font-weight:600;color:'+a.color+'">'+a.lbl+'</div>' +
      '<div style="flex:1;background:'+a.color+'15;border-radius:3px;height:7px"><div style="width:'+pct+'%;height:7px;background:'+a.color+';border-radius:3px"></div></div>' +
      '<div style="font-family:monospace;font-size:13px;min-width:120px;text-align:right">'+cfPesos(a.val)+'</div>' +
      '<div style="font-size:11px;color:var(--text3);min-width:36px;text-align:right">'+pct+'%</div>' +
    '</div>';
  }).join('') : '<div style="color:var(--text3);font-size:12px">Sin IVA discriminado en este período</div>';
}

function fvRenderTipos(comps) {
  var tipos = {};
  comps.forEach(function(c){
    var t = CF_TIPOS_COMP[c.tipo] || 'Tipo '+c.tipo;
    tipos[t] = (tipos[t]||0) + 1;
  });
  document.getElementById('fv-tipos-box').innerHTML = Object.entries(tipos)
    .sort(function(a,b){ return b[1]-a[1]; })
    .map(function(e){ return '<span class="badge b-gray" style="font-size:11px">'+e[0]+' ×'+e[1]+'</span>'; })
    .join('');
}
function fvFiltrarHistorial(val) { fvRenderHistorial(fvGetCompFiltrados(), val); }

function fvRenderHistorial(comps, filtro) {
  var clientes = {};
  comps.forEach(function(c) {
    var k = c.cuitReceptor || ('CF_' + (c.nombre || 'Consumidor Final'));
    var nombre = c.nombre || (c.cuitReceptor ? c.cuitReceptor : 'Consumidor Final');
    if (!clientes[k]) clientes[k] = { cuit: c.cuitReceptor||'—', nombre: nombre, comps:[], totalIVA:0, total:0 };
    clientes[k].comps.push(c);
    clientes[k].totalIVA += fvMontoFirmado(c,'totalIVA');
    clientes[k].total += fvMontoFirmado(c,'total');
  });
  var lista = Object.values(clientes).sort(function(a,b){ return b.total - a.total; });

  if (filtro) {
    var f = filtro.toLowerCase();
    lista = lista.filter(function(p){
      return p.nombre.toLowerCase().includes(f) || p.cuit.includes(f) ||
        p.comps.some(function(c){ return c.nroDoc.includes(f); });
    });
  }

  document.getElementById('fv-prov-qty').textContent = lista.length + ' clientes';
  document.getElementById('fv-historial-box').innerHTML = lista.length
    ? lista.map(function(p, idx){ return fvRenderClienteRow(p, idx); }).join('')
    : '<div style="color:var(--text3);font-size:13px;text-align:center;padding:20px">Sin resultados</div>';
}

function fvRenderClienteRow(p, idx) {
  var id = 'fv-cli-'+idx;
  var compConIva = p.comps.filter(function(c){ return fvConIvaDiscriminado(c.tipo); });
  return '<div id="'+id+'" onclick="fvToggleCliente(\''+id+'\')" style="background:var(--bg3);border-radius:var(--radius);padding:12px 14px;margin-bottom:6px;cursor:pointer;border-left:3px solid transparent">' +
    '<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">' +
      '<div>' +
        '<div style="font-weight:600;font-size:13px">'+escapeHTML(p.nombre)+'</div>' +
        '<div style="font-size:11px;color:var(--text3);margin-top:2px">CUIT '+p.cuit+' · '+p.comps.length+' comprobante'+(p.comps.length!==1?'s':'') +
          (compConIva.length ? ' · '+compConIva.length+' con IVA discriminado' : ' · sin IVA discriminado') + '</div>' +
      '</div>' +
      '<div style="text-align:right">' +
        '<div style="font-size:14px;font-weight:700;color:'+(p.totalIVA>0?'var(--red)':'var(--text3)')+'">'+cfPesos(p.totalIVA)+' IVA</div>' +
        '<div style="font-size:11px;color:var(--text3)">Total: '+cfPesos(p.total)+'</div>' +
      '</div>' +
    '</div>' +
    '<div id="'+id+'-det" style="display:none;margin-top:12px">' +
      '<div class="table-wrap"><table>' +
        '<thead><tr><th>Fecha</th><th>Tipo</th><th>N° Comp.</th><th class="tr">Neto</th><th class="tr">IVA</th><th class="tr">Total</th></tr></thead>' +
        '<tbody>' + p.comps.map(function(c) {
          var tipoNom = CF_TIPOS_COMP[c.tipo] || 'Tipo '+c.tipo;
          var conIva = fvConIvaDiscriminado(c.tipo);
          var esNC = fvEsNotaCredito(c.tipo);
          var numFmt = String(c.ptoVta).padStart(4,'0') + '-' + String(c.nroDoc).padStart(8,'0');
          return '<tr>' +
            '<td style="font-family:monospace;font-size:12px">'+c.fecha+'</td>' +
            '<td><span class="badge '+(esNC?'b-red':(conIva?'b-blue':'b-gray'))+'" style="font-size:10px">'+tipoNom+'</span></td>' +
            '<td style="font-family:monospace;font-size:12px">'+numFmt+'</td>' +
            '<td class="tr" style="font-family:monospace;color:'+(esNC?'var(--red)':'inherit')+'">'+fvPesosFirmado(c,'neto')+'</td>' +
            '<td class="tr" style="font-family:monospace;color:'+(conIva?'var(--red)':'var(--text3)')+';font-weight:'+(conIva?'600':'400')+'">'+(conIva?fvPesosFirmado(c,'totalIVA'):(c.totalIVA>0?fvPesosFirmado(c,'totalIVA'):'—'))+'</td>' +
            '<td class="tr" style="font-family:monospace;color:'+(esNC?'var(--red)':'inherit')+'">'+fvPesosFirmado(c,'total')+'</td>' +
          '</tr>';
        }).join('') + '</tbody>' +
        '<tfoot><tr style="border-top:1px solid var(--border);font-weight:700">' +
          '<td colspan="3" style="font-size:11px;color:var(--text3)">TOTAL NETO</td>' +
          '<td class="tr" style="font-family:monospace">'+cfPesos(p.comps.reduce(function(s,c){return s+fvMontoFirmado(c,'neto');},0))+'</td>' +
          '<td class="tr" style="font-family:monospace;color:var(--red)">'+cfPesos(p.totalIVA)+'</td>' +
          '<td class="tr" style="font-family:monospace">'+cfPesos(p.total)+'</td>' +
        '</tr></tfoot>' +
      '</table></div>' +
    '</div>' +
  '</div>';
}

function fvToggleCliente(id) {
  var det = document.getElementById(id+'-det');
  var row = document.getElementById(id);
  if (!det) return;
  var abierto = det.style.display !== 'none';
  det.style.display = abierto ? 'none' : '';
  if (row) row.style.borderLeftColor = abierto ? 'transparent' : 'var(--blue)';
}
// periodo: 'YYYY-MM' o null/undefined para todos los períodos cargados.
function calcularCompensacionIVA(periodo) {
  var compCF = (CF_DATA||[]).filter(function(c){ return !periodo || (c.fecha||'').startsWith(periodo); });
  var compFV = (FV_DATA||[]).filter(function(c){ return !periodo || (c.fecha||'').startsWith(periodo); });
  var credito = compCF.filter(function(c){ return typeof cfEsCreditoFiscal === 'function' && cfEsCreditoFiscal(c.tipo); })
    .reduce(function(s,c){ return s + ((parseFloat(c.totalIVA)||0) * (typeof cfSigno === 'function' ? cfSigno(c) : 1)); }, 0);
  var debito = compFV.reduce(function(s,c){ return s + (typeof fvMontoFirmado === 'function' ? fvMontoFirmado(c,'totalIVA') : (parseFloat(c.totalIVA)||0)); }, 0);
  return { credito: credito, debito: debito, saldo: debito - credito };
}

function fvRenderCompensacion() {
  var card = document.getElementById('fact-compensacion-card');
  var box = document.getElementById('fact-compensacion-box');
  if (!box || !card) return;
  var hayDatos = (CF_DATA && CF_DATA.length) || (FV_DATA && FV_DATA.length);
  card.style.display = hayDatos ? '' : 'none';
  if (!hayDatos) return;
  // Sigue el período de la pestaña que el usuario está mirando en este momento.
  var periodo = FACT_TAB_ACTIVA === 'fv'
    ? (FV_PERIODO_ACTIVO || CF_PERIODO_ACTIVO || null)
    : (CF_PERIODO_ACTIVO || FV_PERIODO_ACTIVO || null);
  var c = calcularCompensacionIVA(periodo);
  var lblPeriodo = periodo ? new Date(periodo+'-01T12:00:00').toLocaleDateString('es-AR',{month:'long',year:'numeric'}) : 'todos los períodos';
  var aFavor = c.saldo <= 0;
  box.innerHTML =
    '<div class="metrics" style="grid-template-columns:repeat(3,minmax(0,1fr))">' +
      cfMetricCard('Débito fiscal', cfPesos(c.debito), 'facturas realizadas · '+lblPeriodo, 'red') +
      cfMetricCard('Crédito fiscal', cfPesos(c.credito), 'crédito fiscal · '+lblPeriodo, 'green') +
      cfMetricCard(aFavor ? 'Saldo a favor' : 'A compensar (pagar)', cfPesos(Math.abs(c.saldo)), aFavor ? 'crédito disponible para el próximo período' : 'IVA neto a ingresar a AFIP', aFavor ? 'blue' : 'amber') +
    '</div>';
}

function spCargar() {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/reclamos'), function(snap) {
    var data = snap.val() || {};
    SP_DATA = {};
    Object.entries(data).forEach(function(e) { SP_DATA[e[0]] = Object.assign({ fbKey: e[0] }, e[1]); });
    spRenderLista();
    spActualizarMetricas();
  });
}

function spActualizarMetricas() {
  var hoyMes = new Date().getMonth();
  var hoyAnio = new Date().getFullYear();
  var cnts = { nuevo:0, diagnostico:0, visita:0, ot_activa:0, cerrado:0 };
  Object.values(SP_DATA).forEach(function(r) {
    if (r.estado === 'cerrado') {
      var f = new Date(r.ts||0);
      if (f.getMonth() === hoyMes && f.getFullYear() === hoyAnio) cnts.cerrado++;
    } else {
      cnts[r.estado] = (cnts[r.estado]||0) + 1;
    }
  });
  Object.keys(cnts).forEach(function(k) {
    var el = document.getElementById('sp-cnt-' + k);
    if (el) el.textContent = cnts[k];
  });
}

function spFiltrar(estado) {
  var sel = document.getElementById('sp-filtro-estado');
  if (sel) sel.value = estado;
  spRenderLista();
}

function spRenderLista() {
  var cont = document.getElementById('sp-lista');
  if (!cont) return;
  var filtro = (document.getElementById('sp-filtro-estado')||{}).value || '';

  var lista = Object.values(SP_DATA).filter(function(r) {
    if (!filtro) return r.estado !== 'cerrado'; // por defecto oculta cerrados
    return r.estado === filtro;
  });
  lista.sort(function(a,b) { return (b.ts||0)-(a.ts||0); });

  if (!lista.length) {
    cont.innerHTML = '<div style="padding:28px;text-align:center;color:var(--text3);font-size:13px">Sin reclamos' + (filtro?' con ese estado':' abiertos') + '</div>';
    return;
  }

  cont.innerHTML = lista.map(function(r) {
    var est = SP_ESTADOS[r.estado] || SP_ESTADOS.nuevo;
    var ultimaNota = (r.historial||[]).slice(-1)[0];
    var notaTxt = ultimaNota ? escapeHTML(ultimaNota.texto||'') : '';
    var otLink = r.otKey ? '<span style="font-size:11px;color:var(--purple)">OT vinculada</span>' : '';
    return '<div onclick="spAbrirModal(\'' + r.fbKey + '\')" style="display:flex;align-items:center;gap:14px;padding:12px 0;border-bottom:0.5px solid var(--border);cursor:pointer" class="cr">' +
      '<div style="width:8px;height:8px;border-radius:50%;background:' + est.color + ';flex-shrink:0"></div>' +
      '<div style="flex:1;min-width:0">' +
        '<div style="font-weight:500;font-size:13px">' + escapeHTML(r.cliente||'Sin cliente') + '</div>' +
        '<div style="font-size:12px;color:var(--text3);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escapeHTML(r.descripcion||'') + '</div>' +
        (notaTxt ? '<div style="font-size:11px;color:var(--text2);margin-top:2px">↳ ' + notaTxt + '</div>' : '') +
      '</div>' +
      '<div style="flex-shrink:0;text-align:right">' +
        '<span class="badge ' + est.badge + '" style="font-size:10px">' + est.label + '</span>' + otLink +
        '<div style="font-size:11px;color:var(--text3);margin-top:4px">' + spFormatFecha(r.ts) + '</div>' +
      '</div>' +
    '</div>';
  }).join('');
}

function spFormatFecha(ts) {
  if (!ts) return '';
  var d = new Date(ts);
  return d.toLocaleDateString('es-AR',{day:'2-digit',month:'2-digit'}) + ' ' + d.toLocaleTimeString('es-AR',{hour:'2-digit',minute:'2-digit'});
}
function spAbrirNuevo() {
  document.getElementById('sp-nuevo-cli').value = '';
  document.getElementById('sp-nuevo-cli-id').value = '';
  document.getElementById('sp-nuevo-desc').value = '';
  document.getElementById('sp-modal-nuevo').style.display = 'flex';
}

function spBuscarCliente(val) {
  var drop = document.getElementById('sp-nuevo-cli-drop');
  if (!val || val.length < 2) { drop.style.display = 'none'; return; }
  var matches = (clientesData||[]).filter(function(c) {
    return (c.nombre||'').toLowerCase().includes(val.toLowerCase());
  }).slice(0,6);
  if (!matches.length) { drop.style.display = 'none'; return; }
  drop.innerHTML = matches.map(function(c) {
    return '<div class="di" style="padding:8px 12px;cursor:pointer;font-size:13px" onclick="spSelCliente(\'' +
      escapeHTML(c.nombre||'') + '\',\'' + escapeHTML(c.fbKey||c.id||'') + '\')">' + escapeHTML(c.nombre||'') + '</div>';
  }).join('');
  drop.style.display = 'block';
}

function spSelCliente(nombre, id) {
  document.getElementById('sp-nuevo-cli').value = nombre;
  document.getElementById('sp-nuevo-cli-id').value = id;
  document.getElementById('sp-nuevo-cli-drop').style.display = 'none';
}

function spGuardarNuevo() {
  var cli = document.getElementById('sp-nuevo-cli').value.trim();
  var cliSel = document.getElementById('sp-nuevo-cli-id').value;
  var desc = document.getElementById('sp-nuevo-desc').value.trim();
  if (!cli) { notify('Ingresá el cliente'); return; }
  if (!desc) { notify('Ingresá la descripción del problema'); return; }
  var clienteRef = (typeof window._svResolverClienteRegistro === 'function')
    ? window._svResolverClienteRegistro({ cliente:cli, clienteId:cliSel, idCliente:cliSel, clienteFbKey:cliSel }, true)
    : null;
  var clienteIdReclamo = (clienteRef && (clienteRef.id || clienteRef.numero || '')) || cliSel || '';
  var clienteFbKeyReclamo = (clienteRef && clienteRef.fbKey) || cliSel || '';

  var reclamo = {
    cliente:     cli,
    clienteId:   clienteIdReclamo,
    idCliente:   clienteIdReclamo,
    clienteFbKey: clienteFbKeyReclamo,
    clienteKey:   clienteFbKeyReclamo,
    descripcion: desc,
    estado:      'nuevo',
    ts:          Date.now(),
    usuario:     currentUser||'',
    historial:   [{ texto:'Reclamo registrado', autor: currentUser||'sistema', ts: Date.now() }]
  };

  if (!window.fbDB) { notify('Sin conexión'); return; }
  window.fbPush(window.fbRef(window.fbDB, 'sisventas/reclamos'), reclamo)
    .then(function() {
      notify('✓ Reclamo registrado');
      document.getElementById('sp-modal-nuevo').style.display = 'none';
    })
    .catch(function(e){ notify('Error: '+e.message); });
}
function spAbrirModal(fbKey) {
  var r = SP_DATA[fbKey];
  if (!r) return;
  SP_MODAL_KEY = fbKey;

  var est = SP_ESTADOS[r.estado] || SP_ESTADOS.nuevo;
  document.getElementById('sp-modal-titulo').textContent = 'Reclamo — ' + (r.cliente||'');
  document.getElementById('sp-modal-cliente').textContent = r.cliente||'—';
  document.getElementById('sp-modal-desc').textContent = r.descripcion||'—';
  document.getElementById('sp-modal-fecha').textContent = spFormatFecha(r.ts);
  document.getElementById('sp-modal-estado-badge').innerHTML = '<span class="badge '+est.badge+'">'+est.label+'</span>';

  // Link a OT y venta si existen
  var otLinkEl = document.getElementById('sp-modal-ot-link');
  if (r.otKey || r.ventaKey) {
    otLinkEl.style.display = '';
    var links = '';
    if (r.otKey) links += '<button class="btn btn-sm" onclick="spVerOT(\''+r.otKey+'\')"><i class="ti ti-file-text" style="font-size:13px"></i> Ver OT</button> ';
    if (r.ventaKey) links += '<button class="btn btn-sm" onclick="spVerVenta(\''+r.ventaId+'\')"><i class="ti ti-receipt" style="font-size:13px"></i> Ver venta '+(r.ventaId||'')+'</button>';
    otLinkEl.innerHTML = links;
  } else {
    otLinkEl.style.display = 'none';
  }

  // Historial
  var hist = r.historial || [];
  var histEl = document.getElementById('sp-modal-historial');
  histEl.innerHTML = hist.map(function(h) {
    return '<div style="background:var(--bg3);border-radius:var(--radius);padding:8px 12px">' +
      '<div style="font-size:12px">' + escapeHTML(h.texto||'') + '</div>' +
      '<div style="font-size:10px;color:var(--text3);margin-top:2px">' + escapeHTML(h.autor||'') + ' · ' + spFormatFecha(h.ts) + '</div>' +
    '</div>';
  }).join('') || '<div style="text-align:center;color:var(--text3);font-size:12px;padding:12px">Sin notas todavía</div>';
  histEl.scrollTop = histEl.scrollHeight;

  // Acciones según estado
  spRenderAcciones(r.estado);
  document.getElementById('sp-modal').style.display = 'flex';
}

function spCerrarModal() {
  document.getElementById('sp-modal').style.display = 'none';
  SP_MODAL_KEY = null;
}

function spRenderAcciones(estado) {
  var cont = document.getElementById('sp-modal-acciones');
  var btns = [];

  if (estado === 'nuevo') {
    btns.push('<button class="btn btn-sm btn-primary" onclick="spCambiarEstado(\'diagnostico\')"><i class="ti ti-search"></i> Tomar diagnóstico remoto</button>');
    btns.push('<button class="btn btn-sm" onclick="spCambiarEstado(\'cerrado\')" style="color:var(--green)"><i class="ti ti-check"></i> Resolver sin visita (cerrar)</button>');
  }
  if (estado === 'diagnostico') {
    btns.push('<button class="btn btn-sm" onclick="spCambiarEstado(\'cerrado\')" style="color:var(--green)"><i class="ti ti-check"></i> Resuelto de forma remota (cerrar)</button>');
    btns.push('<button class="btn btn-sm" onclick="spSolicitarVisita()" style="color:var(--red)"><i class="ti ti-truck"></i> Requiere visita técnica</button>');
  }
  if (estado === 'visita') {
    btns.push('<button class="btn btn-sm btn-primary" onclick="spGenerarOT()"><i class="ti ti-file-plus"></i> Generar OT y asignar técnico</button>');
  }
  if (estado === 'ot_activa') {
    btns.push('<button class="btn btn-sm" onclick="spCambiarEstado(\'cerrado\')" style="color:var(--green)"><i class="ti ti-check"></i> Marcar como resuelto (cerrar)</button>');
  }
  if (estado !== 'cerrado') {
    btns.push('<button class="btn btn-sm" onclick="spCambiarEstado(\'cerrado\')" style="color:var(--text3);margin-top:4px"><i class="ti ti-x"></i> Cerrar sin resolver</button>');
  }

  cont.innerHTML = btns.join('');
}

function spAgregarNota() {
  var inp = document.getElementById('sp-modal-nota');
  var texto = inp.value.trim();
  if (!texto || !SP_MODAL_KEY) return;
  var r = SP_DATA[SP_MODAL_KEY];
  var hist = r.historial ? r.historial.slice() : [];
  hist.push({ texto, autor: currentUser||'sistema', ts: Date.now() });
  window.fbUpdate(window.fbRef(window.fbDB, 'sisventas/reclamos/' + SP_MODAL_KEY), { historial: hist })
    .then(function(){ inp.value = ''; notify('✓ Nota agregada'); })
    .catch(function(e){ notify('Error: '+e.message); });
}

function spCambiarEstado(nuevoEstado, extraDatos) {
  if (!SP_MODAL_KEY) return;
  var r = SP_DATA[SP_MODAL_KEY];
  var hist = r.historial ? r.historial.slice() : [];
  var est = SP_ESTADOS[nuevoEstado];
  hist.push({ texto: 'Estado cambiado a: ' + (est?est.label:nuevoEstado), autor: currentUser||'sistema', ts: Date.now() });
  var update = Object.assign({ estado: nuevoEstado, historial: hist }, extraDatos||{});
  window.fbUpdate(window.fbRef(window.fbDB, 'sisventas/reclamos/' + SP_MODAL_KEY), update)
    .then(function(){
      notify('✓ ' + (est?est.label:'Estado actualizado'));
      if (nuevoEstado === 'cerrado') spCerrarModal();
    })
    .catch(function(e){ notify('Error: '+e.message); });
}

function spSolicitarVisita() {
  spCambiarEstado('visita');
}

function spGenerarOT() {
  if (!SP_MODAL_KEY) return;
  var r = SP_DATA[SP_MODAL_KEY];

  var prods = prodData ? Object.values(prodData) : [];
  var prodVisita = prods.find(function(p) {
    var nombre = (p.nombre||p.descripcion||'').toLowerCase();
    return p.esManoDeObra || nombre.includes('visita') || nombre.includes('técnica') || nombre.includes('mano de obra');
  });

  if (!prodVisita) {
    notify('No se encontró un producto de visita técnica en el catálogo. Cargá uno con la opción "Es mano de obra" activada.');
    return;
  }

  var tecnicos = Object.values(empData||{}).filter(function(e){
    return e.activo !== false;
  });
  var opciones = tecnicos.length
    ? tecnicos.map(function(t,i){ return i+') '+t.nombre; }).join('\n')
    : '(sin empleados cargados)';
  var selIdx = prompt('Elegí el técnico asignado:\n' + opciones);
  if (selIdx === null) return; // canceló
  var tecnico = (tecnicos[parseInt(selIdx)]) ? tecnicos[parseInt(selIdx)].nombre : 'Sin asignar';

  var punit = parseFloat(prodVisita.venta) || 0;
  var sub = punit;
  var iva = Math.round(sub * ((parseFloat(prodVisita.iva)||21)/100));
  var total = sub + iva;
  var ventaId = '#SP-' + String(Date.now()).slice(-5);
  var fechaHoy = new Date().toISOString().split('T')[0];
  var clienteRefReclamo = (typeof window._svResolverClienteRegistro === 'function')
    ? window._svResolverClienteRegistro(r, true)
    : null;
  var reclamoClienteId = r.clienteId || r.idCliente || (clienteRefReclamo && (clienteRefReclamo.id || clienteRefReclamo.numero || '')) || '';
  var reclamoClienteFbKey = r.clienteFbKey || r.clienteKey || (clienteRefReclamo && clienteRefReclamo.fbKey) || '';

  var nuevaVenta = {
    id:         ventaId,
    cliente:    r.cliente||'',
    clienteId:  reclamoClienteId,
    idCliente:  reclamoClienteId,
    clienteFbKey: reclamoClienteFbKey,
    clienteKey:   reclamoClienteFbKey,
    empleado:   tecnico,
    fecha:      fechaHoy,
    fechaOrden: fechaVentaOrdenISO(fechaHoy, Date.now()),
    ts:         Date.now(),
    estadoPago: 'pendiente_pago',
    estadoInst: 'pendiente_inst',
    origen:     'reclamo',
    reclamoKey: SP_MODAL_KEY,
    reclamoId:  r.id || r.numero || SP_MODAL_KEY,
    items: [{
      cod:   prodVisita.codigo||'',
      desc:  prodVisita.nombre||prodVisita.descripcion||'Visita técnica',
      qty:   1,
      punit: punit,
      sub:   sub
    }],
    subtotal: sub,
    iva:      iva,
    total:    total,
    pagos:    [],
    obs:      'Generada desde reclamo: ' + (r.descripcion||''),
    audit: [{ fecha: fechaHoy, usuario: currentUser||'Sistema', accion: 'Venta creada automáticamente desde reclamo de soporte' }]
  };

  window.fbPush(window.fbRef(window.fbDB, FB_PATHS.ventas), nuevaVenta)
    .then(function(ventaRef) {
      var ventaFbKey = ventaRef.key;
      nuevaVenta.fbKey = ventaFbKey;

      var ot = {
        id:          '',
        ventaId:     ventaId,
        ventaFbKey:  ventaFbKey,
        ventaKey:    ventaFbKey,
        cliente:     r.cliente||'',
        clienteId:   reclamoClienteId,
        idCliente:   reclamoClienteId,
        clienteFbKey: reclamoClienteFbKey,
        clienteKey:   reclamoClienteFbKey,
        estado:      'pendiente',
        tecnico:     tecnico,
        fecha:       fechaHoy,
        hora:        '09:00',
        duracion:    '4 horas',
        dir:         'Sin definir',
        obs:         'Reclamo: ' + (r.descripcion||''),
        tipoVisita:  'Reclamo post-venta',
        origen:      'reclamo',
        reclamoKey:  SP_MODAL_KEY,
        reclamoId:   r.id || r.numero || SP_MODAL_KEY,
        progreso:    0,
        checks: {
          preparacion: CHECKLISTS.preparacion.map(function(){ return false; }),
          instalacion: CHECKLISTS.instalacion.map(function(){ return false; }),
          verificacion: CHECKLISTS.verificacion.map(function(){ return false; })
        },
        materiales: [],
        audit: [{ fecha: fechaHoy, usuario: currentUser||'Sistema', accion: 'OT creada desde reclamo de soporte. Venta: ' + ventaId }]
      };

      var crearOTReclamo = typeof window.crearRegistroOTSeguro === 'function'
        ? window.crearRegistroOTSeguro(ot, { evitarDoble:true })
        : window.fbPush(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo), ot);
      return crearOTReclamo
        .then(function(otRef) {
          var otFbKey = otRef.key;
          var otIdGenerada = ot.id || '';
          spCambiarEstado('ot_activa', {
            otKey:      otFbKey,
            otId:       otIdGenerada,
            ventaKey:   ventaFbKey,
            ventaFbKey: ventaFbKey,
            ventaId:    ventaId,
            tecnico:    tecnico
          });
          notify('✓ Venta y OT generadas. Técnico: ' + tecnico + ' · Total: $' + total.toLocaleString('es-AR'));
        });
    })
    .catch(function(e){ notify('Error: '+e.message); });
}

function spVerOT(otKey) {
  spCerrarModal();
  showPage('ordentrabajo', null);
  setTimeout(function(){ verOT(otKey); }, 500);
}

function spVerVenta(ventaId) {
  spCerrarModal();
  showPage('detalle', document.querySelector('[onclick*="detalle"]'));
  setTimeout(function(){
    var v = _svResolverVentaRegistro(ventaId);
    if (v && v.fbKey) verVenta(v.fbKey);
  }, 600);
}

