// AGENDA — Calendario visual Día/Semana/Mes
// Tres tipos de evento:
//   🟢 instalacion — viene de OT con fecha asignada
//   🔵 reclamo     — viene de reclamo con OT fechada
//   🟡 interno     — creado manualmente en Agenda
var AG_DATA = [];         // eventos internos de sisventas/agenda
var AG_VISTA = 'mes';     // 'mes' | 'semana' | 'dia'
var AG_CURSOR = new Date(); // fecha actual del calendario
var AG_UNSUBSCRIBE = null;

var AG_COLORES = {
  instalacion: { bg:'#22c55e22', border:'#22c55e', text:'#22c55e' },
  reclamo:     { bg:'#3b82f622', border:'#3b82f6', text:'#3b82f6' },
  interno:     { bg:'#f59e0b22', border:'#f59e0b', text:'#f59e0b' }
};

function fbCargarAgenda() {
  if (!window.fbDB) return;
  if (typeof AG_UNSUBSCRIBE === 'function') AG_UNSUBSCRIBE();
  var cont=document.getElementById('ag-calendario');
  if(cont) cont.innerHTML='<div style="padding:34px;text-align:center;color:var(--text3)"><i class="ti ti-loader-2" style="display:inline-block;animation:spin 1s linear infinite;margin-right:6px"></i>Cargando agenda...</div>';
  AG_DATA=[];
  var queryApi=window.SisVentas&&window.SisVentas.DataQuery;
  if(queryApi){
    var bounds=queryApi.range(AG_CURSOR,AG_VISTA==='dia'?'semana':AG_VISTA);
    AG_UNSUBSCRIBE=queryApi.subscribeDateRange('sisventas/agenda',bounds,function(rows){
      AG_DATA=rows;
      agRenderCalendario();
      agActualizarMetricas();
    },function(error){
      console.error('[Agenda]',error);
      if(cont) cont.innerHTML='<div style="padding:28px;text-align:center;color:var(--red)">No se pudo cargar la agenda</div>';
    });
    return;
  }
  AG_UNSUBSCRIBE=window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/agenda'), function(snap) {
    var data=snap.val()||{};
    AG_DATA=Object.entries(data).map(function(e){ return Object.assign({fbKey:e[0]},e[1]); });
    agRenderCalendario();
    agActualizarMetricas();
  });
}

// Construir todos los eventos del calendario (internos + OTs con fecha)
function agGetTodosEventos() {
  var eventos = [];

  // 1. Eventos internos de Firebase
  AG_DATA.forEach(function(ev) {
    if (!ev.fecha) return;
    eventos.push({
      tipo: 'interno', fecha: ev.fecha, hora: ev.hora||'',
      titulo: ev.descripcion||'Evento', subtitulo: ev.empleado||'',
      notas: ev.notas||'', fbKey: ev.fbKey, ref: null
    });
  });

  // 2. OTs con fecha asignada
  (otData||[]).forEach(function(ot) {
    if (!ot.fecha || ot.estado === 'completada') return;
    var esReclamo = ot.tipoVisita === 'Reclamo post-venta' || ot.reclamoKey;
    eventos.push({
      tipo: esReclamo ? 'reclamo' : 'instalacion',
      fecha: ot.fecha, hora: ot.hora||'',
      titulo: ot.cliente||'Sin cliente',
      subtitulo: (ot.tipoVisita||'Instalación') + (ot.tecnico ? ' · ' + ot.tecnico : ''),
      notas: ot.obs||'',
      fbKey: ot.fbKey||ot.id, ref: ot, otId: ot.id
    });
  });

  return eventos.sort(function(a,b){
    return (a.fecha+a.hora) < (b.fecha+b.hora) ? -1 : 1;
  });
}

function agActualizarMetricas() {
  var hoy = new Date().toISOString().split('T')[0];
  var semFin = new Date(); semFin.setDate(semFin.getDate()+7);
  var semStr = semFin.toISOString().split('T')[0];
  var evs = agGetTodosEventos();
  var _e = function(id,v){ var el=document.getElementById(id); if(el) el.textContent=v; };
  _e('ag-hoy',    evs.filter(function(e){ return e.fecha===hoy; }).length);
  _e('ag-semana', evs.filter(function(e){ return e.fecha>=hoy && e.fecha<=semStr; }).length);
  _e('ag-inst',   evs.filter(function(e){ return e.tipo==='instalacion'; }).length);
  _e('ag-recl',   evs.filter(function(e){ return e.tipo==='reclamo'; }).length);
}
function agNav(dir) {
  if (AG_VISTA === 'mes') {
    AG_CURSOR.setMonth(AG_CURSOR.getMonth() + dir);
  } else if (AG_VISTA === 'semana') {
    AG_CURSOR.setDate(AG_CURSOR.getDate() + dir * 7);
  } else {
    AG_CURSOR.setDate(AG_CURSOR.getDate() + dir);
  }
  fbCargarAgenda();
}

function agIrHoy() { AG_CURSOR = new Date(); fbCargarAgenda(); }

function agCambiarVista(vista, btn) {
  AG_VISTA = vista;
  document.querySelectorAll('.ag-vista-btn').forEach(function(b){
    b.style.background = 'transparent'; b.style.color = 'var(--text3)';
  });
  if (btn) { btn.style.background = 'var(--bg3)'; btn.style.color = 'var(--text)'; }
  fbCargarAgenda();
}

function agEsPantallaMovil() {
  var cont = document.getElementById('agenda-calendar-card') || document.getElementById('page-agenda');
  var ancho = cont && cont.getBoundingClientRect ? cont.getBoundingClientRect().width : 0;
  return (window.matchMedia && window.matchMedia('(max-width: 900px)').matches) || (ancho > 0 && ancho <= 900);
}

function agRenderCalendario() {
  var cont = document.getElementById('ag-calendario');
  if (!cont) return;
  var pageAgenda = document.getElementById('page-agenda');
  var compacto = agEsPantallaMovil();
  if (pageAgenda) pageAgenda.classList.toggle('agenda-compact', compacto);
  cont.dataset.view = AG_VISTA;
  var scrollHint=document.getElementById('agenda-scroll-hint');
  if(scrollHint) scrollHint.style.display=compacto || AG_VISTA==='dia'?'none':'';
  var tit = document.getElementById('ag-titulo');
  if (AG_VISTA === 'mes') {
    if (tit) tit.textContent = AG_CURSOR.toLocaleDateString('es-AR',{month:'long',year:'numeric'});
    cont.innerHTML = agRenderMes();
  } else if (AG_VISTA === 'semana') {
    var ini = agInicioSemana(AG_CURSOR);
    var fin = new Date(ini); fin.setDate(fin.getDate()+6);
    if (tit) tit.textContent = 'Semana del ' + ini.getDate() + ' al ' + fin.getDate() + ' de ' + fin.toLocaleDateString('es-AR',{month:'long',year:'numeric'});
    cont.innerHTML = agRenderSemana(ini);
  } else {
    if (tit) tit.textContent = AG_CURSOR.toLocaleDateString('es-AR',{weekday:'long',day:'numeric',month:'long',year:'numeric'});
    cont.innerHTML = agRenderDia(AG_CURSOR);
  }
}
function agRenderMes() {
  if (agEsPantallaMovil()) return agRenderMesMovil();
  var evs = agGetTodosEventos();
  var anio = AG_CURSOR.getFullYear();
  var mes  = AG_CURSOR.getMonth();
  var hoy  = new Date().toISOString().split('T')[0];
  var primerDia = new Date(anio, mes, 1);
  var totalDias = new Date(anio, mes+1, 0).getDate();
  // Lun=0 ... Dom=6
  var diaInicio = (primerDia.getDay()+6)%7;

  var filasMes = Math.ceil((diaInicio + totalDias) / 7);
  var html = '<div class="ag-mes-desktop" style="display:grid;grid-template-columns:repeat(7,1fr);grid-template-rows:28px repeat('+filasMes+',minmax(88px,1fr));gap:1px;background:var(--border)">';
  var dias = ['Lun','Mar','Mié','Jue','Vie','Sáb','Dom'];
  dias.forEach(function(d){
    html += '<div class="ag-mes-head" style="background:var(--bg2);text-align:center;font-size:11px;font-weight:600;color:var(--text3);padding:6px 0;text-transform:uppercase">'+d+'</div>';
  });

  // Celdas vacías antes del primer día
  for (var i=0; i<diaInicio; i++) {
    html += '<div class="ag-mes-cell ag-mes-empty" style="background:var(--bg2);padding:4px"></div>';
  }

  for (var d=1; d<=totalDias; d++) {
    var fechaStr = anio+'-'+String(mes+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
    var esHoy = fechaStr === hoy;
    var esFinde = ((diaInicio+d-1)%7) >= 5; // sab/dom
    var evsDelDia = evs.filter(function(e){ return e.fecha===fechaStr; });
    var esLaboral = !esFinde;

    html += '<div class="ag-mes-cell" onclick="agClickDia(\''+fechaStr+'\')" style="background:'+(esHoy?'var(--blue-bg)':esFinde?'var(--bg)':'var(--bg2)')+';padding:4px;cursor:pointer;transition:background .1s" onmouseover="this.style.background=\'var(--bg3)\'" onmouseout="this.style.background=\''+(esHoy?'var(--blue-bg)':esFinde?'var(--bg)':'var(--bg2)')+'\'">';
    html += '<div style="font-size:12px;font-weight:'+(esHoy?'700':'400')+';color:'+(esHoy?'var(--blue)':esFinde?'var(--text3)':'var(--text)')+';margin-bottom:3px">'+d+'</div>';

    evsDelDia.slice(0,3).forEach(function(ev) {
      var col = AG_COLORES[ev.tipo] || AG_COLORES.interno;
      html += '<div onclick="event.stopPropagation();agVerEvento(\''+escapeHTML(ev.fbKey||'')+'\',\''+ev.tipo+'\')" style="font-size:10px;background:'+col.bg+';border-left:2px solid '+col.border+';padding:1px 4px;border-radius:2px;margin-bottom:2px;cursor:pointer;overflow:hidden;white-space:nowrap;text-overflow:ellipsis;color:'+col.text+'">'+
        (ev.hora?ev.hora.slice(0,5)+' ':'') + escapeHTML(ev.titulo) +
      '</div>';
    });
    if (evsDelDia.length > 3) {
      html += '<div style="font-size:10px;color:var(--text3)">+'+(evsDelDia.length-3)+' más</div>';
    }
    html += '</div>';
  }

  // Celdas vacías al final
  var totalCeldas = diaInicio + totalDias;
  var resto = totalCeldas % 7;
  if (resto > 0) {
    for (var j=0; j<(7-resto); j++) {
      html += '<div class="ag-mes-cell ag-mes-empty" style="background:var(--bg);padding:4px"></div>';
    }
  }
  html += '</div>';
  return html;
}

function agRenderMesMovil() {
  var evs = agGetTodosEventos();
  var anio = AG_CURSOR.getFullYear();
  var mes = AG_CURSOR.getMonth();
  var hoy = new Date().toISOString().split('T')[0];
  var primerDia = new Date(anio, mes, 1);
  var totalDias = new Date(anio, mes + 1, 0).getDate();
  var diaInicio = (primerDia.getDay() + 6) % 7;
  var dias = ['L','M','M','J','V','S','D'];
  var html = '<div class="ag-mes-movil">';

  dias.forEach(function(nombre) {
    html += '<div class="ag-mes-dia-nombre">' + nombre + '</div>';
  });
  for (var vacia = 0; vacia < diaInicio; vacia++) {
    html += '<div class="ag-mes-celda ag-mes-vacia"></div>';
  }
  for (var dia = 1; dia <= totalDias; dia++) {
    var fechaStr = anio + '-' + String(mes + 1).padStart(2, '0') + '-' + String(dia).padStart(2, '0');
    var eventos = evs.filter(function(ev) { return ev.fecha === fechaStr; });
    var clases = 'ag-mes-celda' + (fechaStr === hoy ? ' es-hoy' : '') + (((diaInicio + dia - 1) % 7) >= 5 ? ' es-finde' : '');
    html += '<button type="button" class="' + clases + '" onclick="agClickDia(\'' + fechaStr + '\')">';
    html += '<span class="ag-mes-numero">' + dia + '</span>';
    if (eventos.length) {
      html += '<span class="ag-mes-puntos">';
      eventos.slice(0, 3).forEach(function(ev) {
        var color = AG_COLORES[ev.tipo] || AG_COLORES.interno;
        html += '<i style="background:' + color.border + '"></i>';
      });
      html += '</span><span class="ag-mes-cantidad">' + eventos.length + '</span>';
    }
    html += '</button>';
  }
  var usadas = diaInicio + totalDias;
  for (var final = usadas % 7; final > 0 && final < 7; final++) {
    html += '<div class="ag-mes-celda ag-mes-vacia"></div>';
  }
  html += '</div>';

  var eventosMes = evs.filter(function(ev) {
    return ev.fecha && ev.fecha.slice(0, 7) === (anio + '-' + String(mes + 1).padStart(2, '0'));
  });
  html += '<div class="ag-mes-lista-movil">';
  html += '<div class="ag-mes-lista-head"><span>Agenda del mes</span><small>' + eventosMes.length + ' evento' + (eventosMes.length === 1 ? '' : 's') + '</small></div>';
  if (!eventosMes.length) {
    html += '<div class="ag-mes-lista-vacia">Sin eventos programados este mes.</div>';
  } else {
    eventosMes.forEach(function(ev) {
      var color = AG_COLORES[ev.tipo] || AG_COLORES.interno;
      var fecha = new Date((ev.fecha || '') + 'T12:00:00');
      var fechaTxt = isNaN(fecha.getTime()) ? (ev.fecha || '—') : fecha.toLocaleDateString('es-AR', { weekday:'short', day:'numeric', month:'short' });
      html += '<button type="button" class="ag-mes-lista-item" onclick="agVerEvento(\'' + escapeHTML(ev.fbKey || '') + '\',\'' + ev.tipo + '\')" style="border-left-color:' + color.border + '">';
      html += '<span class="ag-mes-lista-fecha" style="color:' + color.text + '">' + escapeHTML(fechaTxt) + '<small>' + escapeHTML(ev.hora ? ev.hora.slice(0, 5) : 'Sin hora') + '</small></span>';
      html += '<span class="ag-mes-lista-info"><strong>' + escapeHTML(ev.titulo || 'Evento') + '</strong><small>' + escapeHTML(ev.subtitulo || ev.notas || '') + '</small></span>';
      html += '</button>';
    });
  }
  html += '</div>';
  return html;
}
function agInicioSemana(fecha) {
  var d = new Date(fecha);
  var dia = (d.getDay()+6)%7; // Lun=0
  d.setDate(d.getDate()-dia);
  return d;
}

function agRenderSemana(lunes) {
  if (agEsPantallaMovil()) return agRenderSemanaMovil(lunes);
  var evs = agGetTodosEventos();
  var hoy = new Date().toISOString().split('T')[0];
  var HORAS = [];
  for (var h=8; h<=15; h++) HORAS.push(h);

  var fechas = [];
  for (var i=0; i<7; i++) {
    var d = new Date(lunes); d.setDate(d.getDate()+i);
    fechas.push(d);
  }

  var dias = ['Lun','Mar','Mié','Jue','Vie','Sáb','Dom'];
  var html = '<div style="display:grid;grid-template-columns:48px repeat(7,1fr);gap:0;border:0.5px solid var(--border);border-radius:var(--radius);overflow:hidden">';

  // Header
  html += '<div style="background:var(--bg3);border-bottom:0.5px solid var(--border)"></div>';
  fechas.forEach(function(d, i) {
    var fStr = d.toISOString().split('T')[0];
    var esHoy = fStr === hoy;
    var esFinde = i >= 5;
    html += '<div style="background:'+(esHoy?'var(--blue-bg)':esFinde?'var(--bg)':'var(--bg3)')+';text-align:center;padding:6px 2px;border-bottom:0.5px solid var(--border);border-left:0.5px solid var(--border)">' +
      '<div style="font-size:10px;color:var(--text3)">'+dias[i]+'</div>' +
      '<div style="font-size:15px;font-weight:'+(esHoy?'700':'400')+';color:'+(esHoy?'var(--blue)':'var(--text)')+'">'+d.getDate()+'</div>' +
    '</div>';
  });

  // Franjas horarias
  HORAS.forEach(function(hora) {
    var horaStr = String(hora).padStart(2,'0')+':00';
    html += '<div style="background:var(--bg3);font-size:10px;color:var(--text3);text-align:right;padding:4px 6px 0 0;border-bottom:0.5px solid var(--border)">'+horaStr+'</div>';
    fechas.forEach(function(d, i) {
      var fStr = d.toISOString().split('T')[0];
      var esFinde = i >= 5;
      var evsHora = evs.filter(function(e){
        return e.fecha === fStr && e.hora && parseInt(e.hora) === hora;
      });
      html += '<div style="background:'+(esFinde?'var(--bg)':'var(--bg2)')+';border-bottom:0.5px solid var(--border);border-left:0.5px solid var(--border);min-height:44px;padding:2px;position:relative">';
      evsHora.forEach(function(ev) {
        var col = AG_COLORES[ev.tipo] || AG_COLORES.interno;
        html += '<div onclick="agVerEvento(\''+escapeHTML(ev.fbKey||'')+'\',\''+ev.tipo+'\')" style="font-size:10px;background:'+col.bg+';border-left:2px solid '+col.border+';padding:2px 4px;border-radius:2px;margin-bottom:2px;cursor:pointer;color:'+col.text+'">'+escapeHTML(ev.titulo)+'</div>';
      });
      html += '</div>';
    });
  });
  html += '</div>';
  return html;
}

function agRenderSemanaMovil(lunes) {
  var evs = agGetTodosEventos();
  var hoy = new Date().toISOString().split('T')[0];
  var html = '<div class="ag-semana-movil">';

  for (var indice = 0; indice < 7; indice++) {
    var fecha = new Date(lunes);
    fecha.setDate(fecha.getDate() + indice);
    var fechaStr = fecha.getFullYear() + '-' + String(fecha.getMonth() + 1).padStart(2, '0') + '-' + String(fecha.getDate()).padStart(2, '0');
    var eventos = evs.filter(function(ev) { return ev.fecha === fechaStr; }).sort(function(a, b) {
      return String(a.hora || '99:99').localeCompare(String(b.hora || '99:99'));
    });
    html += '<section class="ag-semana-dia' + (fechaStr === hoy ? ' es-hoy' : '') + '">';
    html += '<button type="button" class="ag-semana-fecha" onclick="agClickDia(\'' + fechaStr + '\')">';
    html += '<strong>' + fecha.toLocaleDateString('es-AR', { weekday:'short', day:'numeric' }) + '</strong>';
    html += '<span>' + (eventos.length ? eventos.length + ' evento' + (eventos.length === 1 ? '' : 's') : 'Sin eventos') + '</span></button>';
    if (eventos.length) {
      html += '<div class="ag-semana-eventos">';
      eventos.forEach(function(ev) {
        var color = AG_COLORES[ev.tipo] || AG_COLORES.interno;
        html += '<button type="button" class="ag-semana-evento" onclick="agVerEvento(\'' + escapeHTML(ev.fbKey || '') + '\',\'' + ev.tipo + '\')" style="border-left-color:' + color.border + ';background:' + color.bg + '">';
        html += '<span style="color:' + color.text + '">' + escapeHTML(ev.hora ? ev.hora.slice(0, 5) : 'Sin hora') + '</span>';
        html += '<strong>' + escapeHTML(ev.titulo) + '</strong></button>';
      });
      html += '</div>';
    }
    html += '</section>';
  }
  return html + '</div>';
}
function agRenderDia(fecha) {
  var fStr = fecha.toISOString().split('T')[0];
  var evs = agGetTodosEventos().filter(function(e){ return e.fecha === fStr; });
  var HORAS = [];
  for (var h=8; h<=15; h++) HORAS.push(h);

  var html = '<div style="display:grid;grid-template-columns:60px 1fr;gap:0;border:0.5px solid var(--border);border-radius:var(--radius);overflow:hidden">';
  HORAS.forEach(function(hora) {
    var horaStr = String(hora).padStart(2,'0')+':00';
    var evsHora = evs.filter(function(e){ return e.hora && parseInt(e.hora) === hora; });
    var esLaboral = hora >= 8 && hora <= 15;

    html += '<div style="background:var(--bg3);font-size:11px;color:var(--text3);text-align:right;padding:8px 10px 0 0;border-bottom:0.5px solid var(--border)">'+horaStr+'</div>';
    html += '<div style="background:'+(esLaboral?'var(--bg2)':'var(--bg)')+';border-bottom:0.5px solid var(--border);border-left:0.5px solid var(--border);min-height:56px;padding:4px 8px">';
    evsHora.forEach(function(ev) {
      var col = AG_COLORES[ev.tipo] || AG_COLORES.interno;
      html += '<div onclick="agVerEvento(\''+escapeHTML(ev.fbKey||'')+'\',\''+ev.tipo+'\')" style="background:'+col.bg+';border-left:3px solid '+col.border+';padding:4px 8px;border-radius:4px;cursor:pointer;margin-bottom:4px">' +
        '<div style="font-size:13px;font-weight:500;color:'+col.text+'">'+escapeHTML(ev.titulo)+'</div>' +
        '<div style="font-size:11px;color:var(--text3)">'+escapeHTML(ev.subtitulo)+'</div>' +
      '</div>';
    });
    html += '</div>';
  });

  // Eventos sin hora
  var sinHora = evs.filter(function(e){ return !e.hora; });
  if (sinHora.length) {
    html += '<div style="background:var(--bg3);font-size:10px;color:var(--text3);text-align:right;padding:8px 10px 0 0;border-bottom:0.5px solid var(--border)">Sin hora</div>';
    html += '<div style="background:var(--bg2);border-bottom:0.5px solid var(--border);border-left:0.5px solid var(--border);padding:4px 8px">';
    sinHora.forEach(function(ev) {
      var col = AG_COLORES[ev.tipo] || AG_COLORES.interno;
      html += '<div onclick="agVerEvento(\''+escapeHTML(ev.fbKey||'')+'\',\''+ev.tipo+'\')" style="background:'+col.bg+';border-left:3px solid '+col.border+';padding:4px 8px;border-radius:4px;cursor:pointer;margin-bottom:4px">' +
        '<div style="font-size:13px;font-weight:500;color:'+col.text+'">'+escapeHTML(ev.titulo)+'</div>' +
        '<div style="font-size:11px;color:var(--text3)">'+escapeHTML(ev.subtitulo)+'</div>' +
      '</div>';
    });
    html += '</div>';
  }

  html += '</div>';
  if (!evs.length) html = '<div style="padding:32px;text-align:center;color:var(--text3);font-size:13px">Sin eventos para este día — <button class="btn btn-sm btn-primary" onclick="agAbrirNuevoEvento()">+ Crear evento interno</button></div>';
  return html;
}
function agClickDia(fechaStr) {
  AG_CURSOR = new Date(fechaStr + 'T12:00:00');
  agCambiarVista('dia', document.querySelector('[data-vista="dia"]'));
}
function agVerEvento(fbKey, tipo) {
  var panel = document.getElementById('ag-panel-evento');
  var cont  = document.getElementById('ag-panel-contenido');
  var tit   = document.getElementById('ag-panel-titulo');
  if (!panel || !cont) return;

  if (tipo === 'interno') {
    var ev = AG_DATA.find(function(e){ return e.fbKey === fbKey; });
    if (!ev) return;
    if (tit) tit.textContent = 'Evento interno';
    cont.innerHTML =
      agPanelFila('Descripción', ev.descripcion||'—') +
      agPanelFila('Fecha', ev.fecha||'—') +
      agPanelFila('Hora', ev.hora||'—') +
      agPanelFila('Responsable', ev.empleado||'—') +
      agPanelFila('Notas', ev.notas||'—') +
      '<button class="btn btn-sm" onclick="agEliminarEvento(\''+fbKey+'\')" style="color:var(--red);margin-top:8px"><i class="ti ti-trash"></i> Eliminar evento</button>';
  } else {
    // OT (instalación o reclamo)
    var ot = (otData||[]).find(function(o){ return (o.fbKey||o.id) === fbKey; });
    if (!ot) return;
    var col = AG_COLORES[tipo] || AG_COLORES.instalacion;
    if (tit) tit.innerHTML = '<span style="color:'+col.text+'">' + (tipo==='reclamo'?'Reclamo/Servicio':'Instalación') + '</span>';
    cont.innerHTML =
      agPanelFila('Cliente', ot.cliente||'—') +
      agPanelFila('Fecha', ot.fecha||'—') +
      agPanelFila('Hora', ot.hora||'Sin hora asignada') +
      agPanelFila('Técnico', ot.tecnico||'Sin asignar') +
      agPanelFila('Tipo', ot.tipoVisita||'—') +
      agPanelFila('Dirección', ot.dir||'—') +
      agPanelFila('Notas', ot.obs||'—') +
      agPanelFila('Progreso', (ot.progreso||0)+'%') +
      '<button class="btn btn-sm btn-primary" onclick="agIrAOT(\''+escapeHTML(ot.id||fbKey)+'\')" style="margin-top:8px;width:100%"><i class="ti ti-external-link"></i> Abrir OT completa</button>';
  }

  panel.style.display = 'block';
}

function agPanelFila(label, valor) {
  return '<div style="border-bottom:0.5px solid var(--border);padding:8px 0">' +
    '<div style="font-size:10px;color:var(--text3);text-transform:uppercase;letter-spacing:.4px;margin-bottom:2px">'+label+'</div>' +
    '<div style="font-size:13px">'+escapeHTML(String(valor))+'</div>' +
  '</div>';
}

function agIrAOT(otId) {
  _hide('ag-panel-evento');
  showPage('ordentrabajo', document.querySelector('[onclick*="ordentrabajo"]'));
  setTimeout(function(){ verOT(otId); }, 300);
}
function agAbrirNuevoEvento() {
  var hoy = new Date().toISOString().split('T')[0];
  document.getElementById('ag-ev-fecha').value = AG_CURSOR.toISOString().split('T')[0] || hoy;
  document.getElementById('ag-ev-hora').value  = '09:00';
  document.getElementById('ag-ev-desc').value  = '';
  document.getElementById('ag-ev-notas').value = '';
  // Poblar select de empleados
  var sel = document.getElementById('ag-ev-empleado');
  if (sel && sel.options.length <= 1) {
    Object.values(empData||{}).filter(function(e){ return e.activo !== false; }).forEach(function(e) {
      var opt = document.createElement('option'); opt.value=e.nombre; opt.textContent=e.nombre; sel.appendChild(opt);
    });
  }
  document.getElementById('ag-modal-nuevo').style.display = 'flex';
}

function agGuardarEvento() {
  var desc  = document.getElementById('ag-ev-desc').value.trim();
  var fecha = document.getElementById('ag-ev-fecha').value;
  if (!desc) { notify('Ingresá la descripción del evento'); return; }
  if (!fecha) { notify('Ingresá la fecha'); return; }
  var ev = {
    descripcion: desc,
    fecha, hora: document.getElementById('ag-ev-hora').value,
    empleado: document.getElementById('ag-ev-empleado').value,
    notas: document.getElementById('ag-ev-notas').value,
    tipo: 'interno', ts: Date.now(), usuario: currentUser||''
  };
  if (!window.fbDB) { notify('Sin conexión'); return; }
  window.fbPush(window.fbRef(window.fbDB, 'sisventas/agenda'), ev)
    .then(function(){ notify('✓ Evento guardado'); document.getElementById('ag-modal-nuevo').style.display='none'; })
    .catch(function(e){ notify('Error: '+e.message); });
}

function agEliminarEvento(fbKey) {
  if (!confirm('¿Eliminar este evento?')) return;
  window.fbRemove(window.fbRef(window.fbDB, 'sisventas/agenda/'+fbKey))
    .then(function(){ notify('Evento eliminado'); _hide('ag-panel-evento'); })
    .catch(function(e){ notify('Error: '+e.message); });
}

function imprimirRemito(fbKey) {
  if (!window.fbDB) return;
  window.fbOnValue(window.fbRef(window.fbDB, 'sisventas/remitos/'+fbKey), function(snap) {
    var r = snap.val();
    if (!r) { notify('Remito no encontrado'); return; }
    var empresa = { nombre: (document.getElementById('cfg-empresa-nombre')||{}).value||'Nixa', dir: (document.getElementById('cfg-empresa-dir')||{}).value||'Patagones 390' };
    var logo = window.logoEmpresaUrl ? '<img src="'+window.logoEmpresaUrl+'" style="height:45px;object-fit:contain">' : '<div style="font-size:20px;font-weight:700">'+empresa.nombre+'</div>';
    var w = window.open('','_blank','width=700,height=500');
    w.document.write('<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Remito '+r.numero+'</title>'+
      '<style>body{font-family:Arial,sans-serif;font-size:13px;color:#222;margin:40px}.header{display:flex;justify-content:space-between;border-bottom:2px solid #222;padding-bottom:14px;margin-bottom:24px}.firma{display:grid;grid-template-columns:1fr 1fr;gap:60px;margin-top:60px}.firma-line{border-top:1px solid #222;padding-top:6px;font-size:11px;color:#666;text-align:center}@media print{body{margin:20px}}</style></head><body>'+
      '<div class="header"><div>'+logo+'<div style="font-size:11px;color:#666">'+empresa.dir+'</div></div><div style="text-align:right"><div style="font-size:18px;font-weight:700">REMITO</div><div>'+escapeHTML(r.numero||'—')+'</div><div style="font-size:12px;color:#666">'+escapeHTML(r.fecha||'')+'</div></div></div>'+
      '<p><strong>Cliente:</strong> '+escapeHTML(r.cliente||'—')+'</p>'+
      '<p><strong>Venta vinculada:</strong> '+escapeHTML(r.venta||'—')+'</p>'+
      '<p><strong>Descripción:</strong> '+escapeHTML(r.descripcion||'—')+'</p>'+
      '<div class="firma"><div><div class="firma-line">Firma receptor</div></div><div><div class="firma-line">Firma Nixa</div></div></div>'+
      '</body></html>');
    w.document.close();
    setTimeout(function(){ w.print(); }, 500);
  }, { onlyOnce: true });
}
function toggleActivoRegistro(coleccion, fbKey, estadoActual) {
  if (!window.fbDB) return;
  var nuevoEstado = !estadoActual;
  window.fbUpdate(window.fbRef(window.fbDB, 'sisventas/' + coleccion + '/' + fbKey), { activo: nuevoEstado })
    .then(function(){ notify(nuevoEstado ? 'Marcado como activo' : 'Marcado como inactivo'); });
}

function buscarGarantia(val) {
  var tbody = document.getElementById('gar-tbody');
  if (!tbody) return;
  var v = (val||'').toLowerCase();
  tbody.querySelectorAll('tr').forEach(function(tr){
    tr.style.display = !v || tr.textContent.toLowerCase().includes(v) ? '' : 'none';
  });
}
