function abrirNuevoPresupuesto() {
  _hide('ppto-list-view');
  _hide('ppto-detalle-view');
  _block('ppto-form-view');
  const d = new Date();
  const fi = document.getElementById('pp-fecha');
  // no un valor fijo hardcodeado en el HTML.
  var diasEl = document.getElementById('pp-dias');
  if (diasEl) {
    var diasConfig = window._diasVencimientoConfig || 15;
    diasEl.value = diasConfig;
  }

  document.getElementById('pp-numero').value = '';
  document.getElementById('pp-cli').value = '';
  document.getElementById('pp-descuento').value = 0;
  var obsEl = document.querySelector('#ppto-form-view .fg input[placeholder="Condiciones, notas..."]');
  if (obsEl) obsEl.value = '';
  var tbody = document.getElementById('pp-body');
  if (tbody) tbody.innerHTML = '';
  addPpRow();

  if (fi) { fi.value = d.toISOString().split('T')[0]; calcVencimiento(); }
  _pptoConIva = true;
  var btnIva = document.getElementById('btn-toggle-iva-ppto');
  if (btnIva) { btnIva.innerHTML = '<i class="ti ti-receipt-tax"></i> Con IVA'; btnIva.style.color = ''; btnIva.style.borderColor = ''; }
  window._mostrarMargenPpto = false;
  var margenPptoBox = document.getElementById('ppto-margen-ganancia-box');
  var margenPptoIco = document.getElementById('ppto-margen-eye-icon');
  var margenPptoLbl = document.getElementById('ppto-margen-eye-lbl');
  if (margenPptoBox) margenPptoBox.style.display = 'none';
  if (margenPptoIco) margenPptoIco.className = 'ti ti-eye';
  if (margenPptoLbl) margenPptoLbl.textContent = 'Ver margen de ganancia';
  if (typeof iniciarMonedaPpto === 'function') iniciarMonedaPpto();
  calcPpTotales();
}
