// Badge de estado OT
function otBadge(estado) {
  const map = {
    pendiente:        ['badge b-amber','Pendiente'],
    programada:       ['badge b-blue','Programada'],
    en_curso:         ['badge b-blue','En curso'],
    en_progreso:      ['badge b-blue','En progreso'],
    completada:       ['badge b-green','Completada'],
    con_observaciones:['badge b-amber','Con observaciones'],
  };
  const [cls, label] = map[estado] || ['badge','—'];
  return `<span class="${cls}">${label}</span>`;
}

// Renderizar OTs — diferenciado por rol
function renderOTTabla(filtro) {
  var hoy = new Date().toISOString().split('T')[0];
  var mes = hoy.slice(0,7);
  var _e = function(id){ return document.getElementById(id); };
  // Si no se pasa filtro, leer el selector. Por defecto se muestran todos.
  if (filtro === undefined) {
    var sel = _e('ot-filtro-estado');
    filtro = sel ? sel.value : '';
  }

  // Métricas (iguales para todos)
  var esCompletadaOT = function(o){ return String(o && (o.estado || '')).toLowerCase() === 'completada'; };
  if (_e('ot-met-abiertas')) _e('ot-met-abiertas').textContent = otData.filter(function(o){ return !esCompletadaOT(o); }).length;
  if (_e('ot-met-hoy'))      _e('ot-met-hoy').textContent      = otData.filter(function(o){ return String(o.fecha||'').slice(0,10) === hoy; }).length;
  if (_e('ot-met-comp'))     _e('ot-met-comp').textContent     = otData.filter(esCompletadaOT).length;

  var esTecnico = currentRole === 'tecnico';
  if (_e('ot-vista-tecnico')) _e('ot-vista-tecnico').style.display = esTecnico ? '' : 'none';
  if (_e('ot-vista-admin'))   _e('ot-vista-admin').style.display   = esTecnico ? 'none' : '';

  if (esTecnico) {
    _renderOTVistaTenico(hoy);
  } else {
    _renderOTVistaAdmin(filtro||'', hoy);
  }
}
function _otTarjeta(o, hoy) {
  var esPrioridad = o.prioridad === true || o.prioridad === 'true';
  var esAtrasada  = o.fecha && o.fecha < hoy && o.estado !== 'completada';
  var borderColor = esPrioridad || esAtrasada ? 'var(--red)' : o.fecha === hoy ? 'var(--amber)' : 'var(--border)';
  var tipo = o.tipoVisita || o.tipo || 'Instalación nueva';
  var tipoIco = tipo.toLowerCase().includes('reclamo') ? 'ti-headset' : tipo.toLowerCase().includes('mant') ? 'ti-tool' : 'ti-bolt';
  var tipoColor = tipo.toLowerCase().includes('reclamo') ? 'var(--red)' : tipo.toLowerCase().includes('mant') ? 'var(--amber)' : 'var(--blue)';
  var visitasPrev = _contarVisitasPrevias(o.cliente, o.dir, o.id);
  return '<div style="background:var(--bg3);border-radius:var(--radius);padding:14px;border-left:3px solid '+borderColor+';cursor:pointer" onclick="verOT(\''+escapeHTML(o.fbKey||o.id||'')+'\')">' +
    '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px">' +
      '<div style="flex:1">' +
        '<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">' +
          (esPrioridad ? '<span class="badge b-red" style="font-size:10px"><i class="ti ti-flame" style="font-size:10px"></i> PRIORIDAD</span>' : '') +
          (esAtrasada  ? '<span class="badge b-red" style="font-size:10px">ATRASADA</span>' : '') +
          '<span style="font-size:12px;font-weight:600;font-family:monospace">'+escapeHTML(o.id||'')+'</span>' +
          (visitasPrev > 0 ? '<span style="font-size:11px;color:var(--amber)"><i class="ti ti-repeat"></i> Visita N°'+(visitasPrev+1)+'</span>' : '') +
        '</div>' +
        '<div style="font-size:14px;font-weight:500;margin-bottom:2px">'+escapeHTML(o.cliente||'Sin cliente')+'</div>' +
        '<div style="font-size:12px;color:var(--text3)"><i class="ti ti-map-pin" style="font-size:11px"></i> '+escapeHTML(o.dir||'Sin dirección')+'</div>' +
        (o.obs ? '<div style="font-size:12px;color:var(--text2);margin-top:4px;font-style:italic">'+escapeHTML(o.obs)+'</div>' : '') +
      '</div>' +
      '<div style="text-align:right;flex-shrink:0">' +
        '<div style="font-size:12px;color:'+tipoColor+'"><i class="ti '+tipoIco+'" style="font-size:12px"></i> '+escapeHTML(tipo)+'</div>' +
        (o.hora ? '<div style="font-size:13px;font-weight:600;margin-top:4px">'+escapeHTML(o.hora)+'</div>' : '') +
        '<div style="margin-top:6px">' +
          '<div class="progress-bar" style="margin:0;width:80px"><div class="progress-fill" style="width:'+(o.progreso||0)+'%"></div></div>' +
          '<div style="font-size:10px;color:var(--text3);margin-top:2px">'+(o.progreso||0)+'%</div>' +
        '</div>' +
      '</div>' +
    '</div>' +
  '</div>';
}

function _renderOTVistaTenico(hoy) {
  var _e = function(id){ return document.getElementById(id); };
  if (_e('ot-tec-fecha-lbl')) _e('ot-tec-fecha-lbl').textContent =
    new Date().toLocaleDateString('es-AR',{weekday:'long',day:'numeric',month:'long'});

  var miNombre = currentUser || '';
  var mias = otData.filter(function(o){
    return o.estado !== 'completada' &&
      (o.tecnico === miNombre || !miNombre);
  });

  // Ordenar: prioridad primero, luego fecha
  mias.sort(function(a,b){
    var ap = a.prioridad ? 0 : 1;
    var bp = b.prioridad ? 0 : 1;
    if (ap !== bp) return ap - bp;
    return (a.fecha||'9999') < (b.fecha||'9999') ? -1 : 1;
  });

  var atrasadas  = mias.filter(function(o){ return o.fecha && o.fecha < hoy; });
  var deHoy      = mias.filter(function(o){ return o.fecha === hoy; });
  var sinFecha   = mias.filter(function(o){ return !o.fecha || o.fecha > hoy; });

  var renderGrupo = function(containerId, boxId, lista) {
    var box  = _e(boxId);
    var cont = _e(containerId);
    if (!box || !cont) return;
    if (!lista.length) { box.style.display='none'; return; }
    box.style.display = '';
    cont.innerHTML = lista.map(function(o){ return _otTarjeta(o, hoy); }).join('');
  };

  renderGrupo('ot-tec-atrasadas',  'ot-tec-atrasadas-box',  atrasadas);
  renderGrupo('ot-tec-hoy',        'ot-tec-hoy-box',        deHoy);
  renderGrupo('ot-tec-pendientes', 'ot-tec-pendientes-box', sinFecha);

  var vacia = _e('ot-tec-vacia');
  if (vacia) vacia.style.display = mias.length ? 'none' : '';
}

function _renderOTVistaAdmin(filtro, hoy) {
  var tbody = document.getElementById('ot-tbody');
  if (!tbody) return;
  var busq = (document.getElementById('ot-busq')||{}).value||'';
  var filtroTec = (document.getElementById('ot-filtro-tecnico')||{}).value||'';

  var selTec = document.getElementById('ot-filtro-tecnico');
  if (selTec && selTec.options.length <= 1) {
    // Combinar técnicos de OTs existentes + empleados activos
    var tecDeOTs = new Set(otData.map(function(o){ return o.tecnico; }).filter(Boolean));
    var tecDeEmps = Object.values(empData||{}).filter(function(e){ return e.activo !== false; }).map(function(e){ return e.nombre; });
    var todosTecs = [...new Set([...tecDeOTs, ...tecDeEmps, 'Inicial'])].sort();
    todosTecs.forEach(function(t){
      var opt = document.createElement('option'); opt.value=t; opt.textContent=t;
      selTec.appendChild(opt);
    });
  }

  var rows = otData.filter(function(o){
    var matchFiltro = !filtro    || o.estado   === filtro;
    var matchTec    = !filtroTec || o.tecnico  === filtroTec;
    var matchBusq   = !busq      || (o.id||'').toLowerCase().includes(busq.toLowerCase()) || (o.cliente||'').toLowerCase().includes(busq.toLowerCase());
    return matchFiltro && matchTec && matchBusq;
  });

  // Ordenar: prioridad > atrasadas > hoy > futuras > sin fecha
  rows.sort(function(a,b){
    var score = function(o){
      if (o.prioridad) return 0;
      if (o.fecha && o.fecha < hoy) return 1;
      if (o.fecha === hoy) return 2;
      if (o.fecha > hoy) return 3;
      return 4;
    };
    return score(a) - score(b);
  });

  tbody.innerHTML = rows.map(function(o) {
    var esPrioridad = o.prioridad === true || o.prioridad === 'true';
    var esAtrasada  = o.fecha && o.fecha < hoy && o.estado !== 'completada';
    var rowColor    = esPrioridad || esAtrasada ? 'background:rgba(239,68,68,.06)' : o.fecha === hoy ? 'background:rgba(245,158,11,.04)' : '';
    var visitasPrev = _contarVisitasPrevias(o.cliente, o.dir, o.id);
    var iconoRep    = visitasPrev > 0 ? '<i class="ti ti-repeat" style="font-size:12px;color:var(--amber);margin-right:4px" title="Visita N°'+(visitasPrev+1)+'"></i>' : '';
    return '<tr style="'+rowColor+'">' +
      '<td style="text-align:center">' +
        (esPrioridad ? '<i class="ti ti-flame" style="color:var(--red);font-size:14px" title="Prioridad"></i>' : '') +
        (esAtrasada && !esPrioridad ? '<i class="ti ti-clock" style="color:var(--amber);font-size:14px" title="Atrasada"></i>' : '') +
      '</td>' +
      '<td style="font-weight:500;font-family:monospace;font-size:12px">'+iconoRep+escapeHTML(o.id||'')+'</td>' +
      '<td>'+escapeHTML(o.cliente||'—')+'</td>' +
      '<td style="font-size:12px;color:var(--text3)">'+escapeHTML(o.tecnico||'Sin asignar')+'</td>' +
      '<td style="font-size:12px;color:'+(esAtrasada?'var(--red)':o.fecha===hoy?'var(--amber)':'var(--text3)')+'">'+escapeHTML(o.fecha||'Sin fecha')+(o.hora?' '+o.hora:'')+'</td>' +
      '<td style="font-size:12px;color:var(--text3)">'+escapeHTML(o.tipoVisita||o.tipo||'—')+'</td>' +
      '<td style="min-width:80px"><div class="progress-bar" style="margin:0"><div class="progress-fill" style="width:'+(o.progreso||0)+'%"></div></div><div style="font-size:10px;color:var(--text3);margin-top:2px">'+(o.progreso||0)+'%</div></td>' +
      '<td>'+otBadge(o.estado)+'</td>' +
      '<td style="white-space:nowrap">' +
        '<button class="btn btn-sm btn-icon" onclick="verOT(\''+escapeHTML(o.fbKey||o.id||'')+'\')"><i class="ti ti-eye" style="font-size:14px"></i></button>' +
        '<button class="btn btn-sm btn-icon" onclick="eliminarOT(\''+escapeHTML(o.fbKey||o.id||'')+'\')"><i class="ti ti-trash" style="font-size:14px;color:var(--text3)"></i></button>' +
      '</td>' +
    '</tr>';
  }).join('');
  if (!rows.length) tbody.innerHTML = '<tr><td colspan="9" style="text-align:center;color:var(--text3);padding:20px">Sin órdenes</td></tr>';
}

function filtrarOT(v) { renderOTTabla(v); }
function filtrarOTTecnico(v) { renderOTTabla(); }
function buscarOT(v)  { renderOTTabla(); }

// Ver detalle de una OT
function abrirOTDesdeId(otId) {
  showPage('ordentrabajo', document.querySelector('[onclick*="ordentrabajo"]'));
  setTimeout(function() {
    if (typeof verOT === 'function') verOT(otId);
  }, 200);
}

function _otResolverDireccionCliente(ot) {
  var camposDireccion = ['direccion','domicilio','dir','direccionInstalacion','direccion_instalacion','direccionObra','direccion_obra','ubicacion','localidadDireccion','address'];
  function leerDir(obj) {
    if (!obj) return '';
    for (var i=0;i<camposDireccion.length;i++) {
      var v = obj[camposDireccion[i]];
      if (v !== undefined && v !== null && String(v).trim()) return String(v).trim();
    }
    return '';
  }
  var dir = leerDir(ot);
  if (dir) return dir;

  // 1) Buscar dirección desde la venta origen, si la OT nació desde una venta.
  if (ot && ot.ventaId && Array.isArray(ventasList)) {
    var ventaOrigen = _svResolverVentaRegistro(ot);
    dir = leerDir(ventaOrigen);
    if (dir) return dir;
    if (ventaOrigen && ventaOrigen.clienteObj) {
      dir = leerDir(ventaOrigen.clienteObj);
      if (dir) return dir;
    }
  }

  // 2) Buscar por id de cliente si existe.
  var clientesArr = Array.isArray(clientesData) ? clientesData : Object.values(clientesData||{});
  var cliId = ot ? (ot.clienteId || ot.idCliente || ot.id_cli || ot.clienteKey) : '';
  if (cliId) {
    var cliPorId = clientesArr.find(function(c){ return c.id === cliId || c.fbKey === cliId || c.key === cliId || c.codigo === cliId; });
    dir = leerDir(cliPorId);
    if (dir) return dir;
  }

  // 3) Buscar por nombre de cliente, tolerando mayúsculas, espacios y apellido.
  var nombreOT = String((ot && ot.cliente) || '').toLowerCase().trim();
  if (nombreOT) {
    var cliOT = clientesArr.find(function(c){
      var n1 = String(c.nombre || '').toLowerCase().trim();
      var n2 = String(((c.nombre || '') + ' ' + (c.apellidos || c.apellido || '')).trim()).toLowerCase();
      var n3 = String(c.razonSocial || c.razon_social || '').toLowerCase().trim();
      return n1 === nombreOT || n2 === nombreOT || n3 === nombreOT;
    });
    dir = leerDir(cliOT);
    if (dir) return dir;
  }
  return '';
}

function abrirDireccionEnMaps() {
  var dir = window._otDireccionActual || (document.getElementById('ot-det-dir')||{}).value || '';
  if (!dir) { notify('No hay dirección cargada para esta OT'); return; }
  var url = 'https://www.google.com/maps/dir/?api=1&destination=' + encodeURIComponent(dir + ', Mar del Plata, Argentina');
  window.open(url, '_blank');
}

function otResolverOrigen(ot) {
  if (!ot) return 'manual';
  var origen = String(ot.origen || '').toLowerCase().trim();
  if (origen === 'reclamo' || ot.reclamoKey || String(ot.tipoVisita||'').toLowerCase().includes('reclamo')) return 'reclamo';
  if (origen === 'venta' || origen === 'pago_seña' || origen === 'pago_sena' || ot.ventaId || ot.ventaFbKey || ot.origenVenta) return 'venta';
  return 'manual';
}

function otBuscarVentaOrigen(ot) {
  if (!ot) return null;
  var referencias = [ot.ventaFbKey, ot.ventaKey, ot.ventaId, ot.idVenta, ot.venta].filter(Boolean).map(String);
  var numeros = referencias.map(function(valor){ return valor.replace(/\D/g, ''); }).filter(Boolean);
  return (ventasList||[]).find(function(venta) {
    var ids = [venta.fbKey, venta.id, venta.numero, venta.ventaId, venta.nro, venta.codigo].filter(Boolean).map(String);
    return ids.some(function(valor){ return referencias.includes(valor); }) || ids.some(function(valor){
      var numero = valor.replace(/\D/g, '');
      return numero && numeros.includes(numero);
    });
  }) || null;
}

function otNormalizarMateriales(items, progreso) {
  return (items||[]).map(function(item) {
    var codigo = item.cod || item.codigo || item.sku || '';
    var avance = (progreso||[]).find(function(actual) {
      if (codigo && (actual.cod||actual.codigo) === codigo) return true;
      return !codigo && String(actual.desc||actual.nombre||actual.descripcion||'') === String(item.desc||item.nombre||item.descripcion||'');
    });
    return {
      cod: codigo,
      desc: item.desc || item.nombre || item.descripcion || item.producto || '',
      vendida: parseFloat(item.vendida || item.qty || item.cantidad || item.cant || 1),
      instalada: parseFloat((avance && (avance.instalada||avance.cantidadInstalada)) || item.instalada || item.cantidadInstalada || 0)
    };
  }).filter(function(item){ return item.desc; });
}

function verOT(id) {
  var ot = otData.find(function(o){ return o.fbKey === id; })
        || otData.find(function(o){ return o.id === id; });
  if (!ot) { notify('OT no encontrada'); return; }
  otActualId = ot.fbKey || ot.id || id;
  _hide('ot-list-view');
  _block('ot-detalle-view');
  var avisoEl = document.getElementById('ot-aviso-cambio-externo');
  if (avisoEl) avisoEl.style.display = 'none';
  window._otDetalleHuella = JSON.stringify(ot);

  var origenOT = otResolverOrigen(ot);
  if (ot.origen !== origenOT) {
    ot.origen = origenOT;
    if (ot.fbKey && window.fbDB) {
      window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo + '/' + ot.fbKey), { origen:origenOT }).catch(function(error){
        console.warn('No se pudo normalizar el origen de la OT:', error);
      });
    }
  }

  _set('ot-det-num', ot.id||'OT');
  document.getElementById('ot-det-estado-badge').innerHTML = otBadge(ot.estado);

  // Prioridad
  var esPrioridad = ot.prioridad === true || ot.prioridad === 'true';
  var prioChk = document.getElementById('ot-det-prioridad');
  var prioBadge = document.getElementById('ot-det-prioridad-badge');
  if (prioChk) prioChk.checked = esPrioridad;
  if (prioBadge) prioBadge.style.display = esPrioridad ? '' : 'none';

  var ventaInp = document.getElementById('ot-det-venta');
  var clienteInp = document.getElementById('ot-det-cliente');
  var esOTManual = origenOT === 'manual';
  var puedeEditarOrigen = esOTManual && currentRole !== 'tecnico';
  var origenLabel = document.getElementById('ot-det-origen-label');
  var origenBadge = document.getElementById('ot-det-origen-badge');
  if (origenLabel) origenLabel.textContent = origenOT === 'reclamo' ? 'Venta asociada' : (origenOT === 'venta' ? 'Venta origen' : 'Referencia / venta');
  if (origenBadge) {
    origenBadge.style.display = '';
    origenBadge.className = 'badge ' + (origenOT === 'reclamo' ? 'b-amber' : (origenOT === 'venta' ? 'b-green' : 'b-blue'));
    origenBadge.textContent = origenOT === 'reclamo' ? 'Origen: reclamo' : (origenOT === 'venta' ? 'Origen: venta' : 'Origen: manual');
  }
  if (ventaInp) {
    ventaInp.value = ot.ventaId||'';
    ventaInp.readOnly = !puedeEditarOrigen;
    ventaInp.style.background = puedeEditarOrigen ? '' : 'var(--bg3)';
    ventaInp.style.cursor = puedeEditarOrigen ? '' : 'not-allowed';
    ventaInp.placeholder = puedeEditarOrigen ? 'Opcional' : '';
  }
  if (clienteInp) {
    clienteInp.value = ot.cliente||'';
    clienteInp.readOnly = !puedeEditarOrigen;
    clienteInp.style.background = puedeEditarOrigen ? '' : 'var(--bg3)';
    clienteInp.style.cursor = puedeEditarOrigen ? '' : 'not-allowed';
    clienteInp.placeholder = puedeEditarOrigen ? 'Ingresá el cliente' : '';
  }
  document.getElementById('ot-det-fecha').value = ot.fecha||'';
  document.getElementById('ot-det-hora').value = ot.hora||'';
  var dirOT = _otResolverDireccionCliente(ot);
  document.getElementById('ot-det-dir').value = dirOT || '';
  if (dirOT && !ot.dir && !ot.direccion && !ot.domicilio) {
    ot.dir = dirOT;
    if (typeof fbGuardarOT === 'function') {
      window._otGuardandoLocalHasta = Date.now() + 2500;
      fbGuardarOT(ot).catch(function(e){ console.warn('No se pudo guardar dirección resuelta en OT:', e); });
    }
  }
  // Mostrar/ocultar botón de Maps según si hay dirección
  var mapsBtn = document.getElementById('ot-det-dir-maps-btn');
  if (mapsBtn) mapsBtn.style.display = dirOT ? '' : 'none';
  window._otDireccionActual = dirOT;
  document.getElementById('ot-det-obs').value = ot.obs||'';
  document.getElementById('ot-det-obs-tecnico').value = ot.obsTecnico||'';
  var obsAdminInp = document.getElementById('ot-det-obs');
  if (obsAdminInp) {
    obsAdminInp.readOnly = (currentRole === 'tecnico');
    obsAdminInp.style.background = (currentRole === 'tecnico') ? 'var(--bg3)' : '';
    obsAdminInp.style.cursor = (currentRole === 'tecnico') ? 'not-allowed' : '';
  }

  var tipoSel = document.getElementById('ot-det-tipovisita');
  if (tipoSel) tipoSel.value = ot.tipoVisita || 'Instalación nueva';

  // Técnico (select — poblar con empleados activos)
  var tecSel = document.getElementById('ot-det-tecnico');
  if (tecSel) {
    // Poblar opciones si aún no están
    if (tecSel.options.length <= 1) {
      var emps = Object.values(empData||{}).filter(function(e){
        if (e.activo === false) return false;
        var cat = (e.categoriaBase || e.cargo || '').toUpperCase();
        return cat.includes('TECNICO') || cat.includes('TÉCNICO');
      }).sort(function(a,b){ return (a.nombre||'').localeCompare(b.nombre||''); });
      emps.forEach(function(e){
        if ([...tecSel.options].some(function(o){ return o.value === e.nombre; })) return;
        var opt = document.createElement('option'); opt.value = e.nombre; opt.textContent = e.nombre;
        tecSel.appendChild(opt);
      });
    }
    if (ot.tecnico) tecSel.value = ot.tecnico;
    tecSel.dataset.previousValue=tecSel.value||'';
  }

  // Visita repetida
  var visitasPrev = _contarVisitasPrevias(ot.cliente, ot.dir, ot.id);
  var repetidaBox = document.getElementById('ot-det-repetida-box');
  var repetidaLbl = document.getElementById('ot-det-repetida-lbl');
  if (visitasPrev > 0 && repetidaBox && repetidaLbl) {
    repetidaBox.style.display = '';
    repetidaLbl.innerHTML = '<i class="ti ti-alert-triangle"></i> Visita N° '+(visitasPrev+1)+' — ya hay '+visitasPrev+' visita'+(visitasPrev!==1?'s':'')+ ' previa'+(visitasPrev!==1?'s':'')+' registrada'+(visitasPrev!==1?'s':'')+'.';
  } else if (repetidaBox) {
    repetidaBox.style.display = 'none';
  }
  otCargarCredenciales(ot);
  // Inicializar canvas de firma
  setTimeout(function() {
    firmaLimpiar();
    firmaInicializar();
    firmaCargar(ot);
  }, 100);
  var reclamoBox = document.getElementById('ot-reclamo-box');
  if (reclamoBox) {
    if (origenOT === 'reclamo' && ot.reclamoKey && SP_DATA[ot.reclamoKey]) {
      var reclamo = SP_DATA[ot.reclamoKey];
      reclamoBox.style.display = '';
      var descEl = document.getElementById('ot-reclamo-desc');
      if (descEl) descEl.textContent = reclamo.descripcion||'';
      var histEl = document.getElementById('ot-reclamo-hist');
      if (histEl) {
        var hist = reclamo.historial || [];
        histEl.innerHTML = hist.map(function(h) {
          return '<div style="background:var(--bg3);border-radius:var(--radius);padding:8px 12px">' +
            '<div style="font-size:12px">'+escapeHTML(h.texto||'')+'</div>' +
            '<div style="font-size:10px;color:var(--text3);margin-top:2px">'+escapeHTML(h.autor||'')+' · '+spFormatFecha(h.ts)+'</div>' +
          '</div>';
        }).join('') || '<div style="color:var(--text3);font-size:12px">Sin notas en el reclamo</div>';
      }
    } else {
      reclamoBox.style.display = 'none';
    }
  }
  otRenderNotas(ot);
  if (ot.checks) {
    renderChecklist('checklist-preparacion', ot.checks.preparacion||[], CHECKLISTS.preparacion, ot.id, 'preparacion');
    renderChecklist('checklist-instalacion', ot.checks.instalacion||[], CHECKLISTS.instalacion, ot.id, 'instalacion');
    renderChecklist('checklist-verificacion', ot.checks.verificacion||[], CHECKLISTS.verificacion, ot.id, 'verificacion');
    actualizarProgreso(ot);
  }
  var mat = document.getElementById('ot-materiales');
  if (mat) {
    var materiales = [];
    var materialesDerivados = false;

    // 1. Si la OT tiene materiales propios, usarlos
    if (ot.materiales && ot.materiales.length) {
      materiales = otNormalizarMateriales(ot.materiales, ot.items);
    }
    // 2. Si no, buscar en la venta origen
    else if (origenOT === 'venta' || ot.ventaId || ot.ventaFbKey) {
      var ventaOrigen = otBuscarVentaOrigen(ot);
      if (ventaOrigen && ventaOrigen.items && ventaOrigen.items.length) {
        materiales = otNormalizarMateriales(ventaOrigen.items, ot.items);
        materialesDerivados = materiales.length > 0;
      }
    }
    // 3. Respaldo para OTs antiguas que guardaban los productos como items.
    if (!materiales.length && ot.items && ot.items.length) {
      materiales = otNormalizarMateriales(ot.items, ot.items);
      materialesDerivados = materiales.length > 0;
    }
    if (materialesDerivados) {
      ot.materiales = materiales;
      if (ot.fbKey && window.fbDB) {
        window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo + '/' + ot.fbKey), { materiales:materiales }).catch(function(error){
          console.warn('No se pudieron guardar los materiales recuperados:', error);
        });
      }
    }

    var materialesFiltrados = materiales.map(function(m, indice){ return Object.assign({_indice:indice}, m); }).filter(function(m){
      var prod = Object.values(prodData||{}).find(function(p){ return p.codigo === m.cod; });
      if (!prod) return true; // si no se encuentra el producto, mostrar igual
      if (prod.esManoDeObra) return false;
      var cat = (prod.categoria||'').toUpperCase();
      if (cat.includes('MANO DE OBRA') || cat.includes('INSTALACION') || cat.includes('CONFIGURACION')) return false;
      return true;
    });
    mat.innerHTML = materialesFiltrados.length ? materialesFiltrados.map(function(m) {
      var instalado = m.instalada >= m.vendida;
      return '<tr>' +
        '<td style="font-size:12px;color:var(--text3)">'+escapeHTML(m.cod||'')+'</td>' +
        '<td>'+escapeHTML(m.desc||'')+'</td>' +
        '<td class="tr">'+m.vendida+'</td>' +
        '<td class="tr"><input type="checkbox" '+(instalado?'checked':'')+' style="width:18px;height:18px;accent-color:var(--green);cursor:pointer" onchange="otToggleInstalado(this,'+m._indice+','+m.vendida+')"></td>' +
      '</tr>';
    }).join('')
    : '<tr><td colspan="4" style="text-align:center;color:var(--text3);padding:12px">Sin materiales' +
      (ot.ventaId ? ' — la venta origen no tiene ítems registrados' : ' — OT sin venta vinculada') +
      '</td></tr>';
  }

  aplicarVistaTecnicoOT();
  var auditEl = document.getElementById('ot-audit');
  if (auditEl) auditEl.innerHTML = [...(ot.audit||[])].reverse().map(function(e) {
    return '<div style="display:flex;gap:10px;padding:8px 0;border-bottom:0.5px solid var(--border)">' +
      '<div style="width:28px;height:28px;border-radius:50%;background:var(--bg3);display:flex;align-items:center;justify-content:center;flex-shrink:0"><i class="ti ti-history" style="font-size:12px;color:var(--text3)"></i></div>' +
      '<div><div style="font-size:13px">'+escapeHTML(e.accion||'')+'</div><div style="font-size:11px;color:var(--text3);margin-top:2px">'+escapeHTML(e.usuario||'')+' · '+escapeHTML(e.fecha||'')+'</div></div>' +
    '</div>';
  }).join('');
  document.dispatchEvent(new CustomEvent('sisventas:ot-opened',{detail:{id:id,ot:ot}}));
}

function otActualizarMaterial(inp, cod) {
  var ot = otData.find(function(o){ return o.fbKey === otActualId || o.id === otActualId; });
  if (!ot || !ot.fbKey || !window.fbDB) return;

  // Reconstruir el array de ítems con el nuevo valor
  var filas = document.querySelectorAll('#ot-materiales tr');
  var items = [];
  filas.forEach(function(tr) {
    var tds = tr.querySelectorAll('td');
    var inpEl = tr.querySelector('input[type=number]');
    if (tds.length >= 2 && inpEl) {
      items.push({
        cod:       tds[0].textContent.trim(),
        desc:      tds[1].textContent.trim(),
        vendida:   parseFloat(tds[2].textContent) || 0,
        instalada: parseFloat(inpEl.value) || 0
      });
    }
  });

  var tr = inp.closest('tr');
  if (tr) {
    var vendida   = parseFloat(inp.max) || 0;
    var instalada = parseFloat(inp.value) || 0;
    var badgeEl   = tr.querySelector('.badge');
    if (badgeEl) {
      if (instalada >= vendida && vendida > 0) {
        badgeEl.className = 'badge b-green'; badgeEl.textContent = 'Completo';
      } else if (instalada > 0) {
        badgeEl.className = 'badge b-amber'; badgeEl.textContent = 'Parcial';
      } else {
        badgeEl.className = 'badge b-red'; badgeEl.textContent = 'Pendiente';
      }
    }
  }

  window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo + '/' + ot.fbKey), {
    items: items
  }).catch(function(e){ notify('Error guardando: ' + e.message); });
}
function otToggleInstalado(chk, indice, vendida) {
  var ot = otData.find(function(o){ return o.id === otActualId || o.fbKey === otActualId; });
  if (!ot || !window.fbDB) return;
  var nuevoVal = chk.checked ? vendida : 0;
  var materiales = (ot.materiales || []).slice();
  if (!materiales[indice]) return;
  materiales[indice] = Object.assign({}, materiales[indice], { instalada:nuevoVal });
  var key = ot.fbKey || otActualId;
  window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo+'/'+key), { materiales:materiales })
    .then(function(){ ot.materiales = materiales; });
}
var _otCarritoAdicional = [];

function otAbrirSelectorProductos() {
  _otCarritoAdicional = [];
  var modal = document.getElementById('ot-selector-prod-modal');
  if (modal) modal.style.display = 'flex';
  otFiltrarSelectorProductos('');
  otRenderCarritoAdicional();
  setTimeout(function(){ var inp = document.getElementById('ot-sel-prod-buscar'); if(inp) inp.focus(); }, 100);
}

function otCerrarSelectorProductos() {
  var modal = document.getElementById('ot-selector-prod-modal');
  if (modal) modal.style.display = 'none';
}

function otFiltrarSelectorProductos(texto) {
  var cont = document.getElementById('ot-sel-prod-lista');
  if (!cont) return;
  var lista = Object.values(prodData||{}).filter(function(p){ return !p.esManoDeObra; });
  if (texto) {
    var f = texto.toLowerCase();
    lista = lista.filter(function(p){
      return (p.nombre||'').toLowerCase().includes(f) || (p.codigo||'').toLowerCase().includes(f);
    });
  }
  lista = lista.slice(0, 30);
  if (!lista.length) { cont.innerHTML = '<div style="text-align:center;color:var(--text3);padding:16px">Sin resultados</div>'; return; }
  cont.innerHTML = lista.map(function(p) {
    return '<div style="display:flex;align-items:center;justify-content:space-between;padding:8px;border-bottom:0.5px solid var(--border);cursor:pointer" onclick="otAgregarAlCarrito(\''+p.fbKey+'\')">' +
      '<div><div style="font-size:13px">'+escapeHTML(p.nombre||'')+'</div><div style="font-size:11px;color:var(--text3)">'+escapeHTML(p.codigo||'')+' · $'+Math.round(p.venta||0).toLocaleString('es-AR')+'</div></div>' +
      '<i class="ti ti-plus" style="color:var(--blue)"></i>' +
    '</div>';
  }).join('');
}

function otAgregarAlCarrito(pid) {
  var p = Object.values(prodData||{}).find(function(x){ return x.fbKey === pid; });
  if (!p) return;
  var existente = _otCarritoAdicional.find(function(c){ return c.pid === pid; });
  if (existente) { existente.cantidad++; }
  else { _otCarritoAdicional.push({ pid: p.fbKey, codigo: p.codigo, nombre: p.nombre, precio: parseFloat(p.venta)||0, cantidad: 1 }); }
  otRenderCarritoAdicional();
  notify('+ ' + p.nombre);
}

function otRenderCarritoAdicional() {
  var cont = document.getElementById('ot-sel-prod-carrito');
  if (!cont) return;
  if (!_otCarritoAdicional.length) { cont.innerHTML = '<div style="font-size:12px;color:var(--text3);text-align:center">Sin productos seleccionados</div>'; return; }
  var total = _otCarritoAdicional.reduce(function(s,c){ return s + c.precio*c.cantidad; }, 0);
  cont.innerHTML = '<div style="font-size:11px;color:var(--text3);margin-bottom:6px">PRODUCTOS A AGREGAR</div>' +
    _otCarritoAdicional.map(function(c, idx) {
      return '<div style="display:flex;align-items:center;gap:8px;padding:6px 0">' +
        '<div style="flex:1;font-size:13px">'+escapeHTML(c.nombre)+'</div>' +
        '<input type="number" min="1" value="'+c.cantidad+'" style="width:50px" onchange="otCarritoCant('+idx+',this.value)">' +
        '<div style="width:80px;text-align:right;font-size:13px">$'+Math.round(c.precio*c.cantidad).toLocaleString('es-AR')+'</div>' +
        '<button class="btn btn-sm btn-icon" onclick="otQuitarCarrito('+idx+')" style="color:var(--red)"><i class="ti ti-x" style="font-size:13px"></i></button>' +
      '</div>';
    }).join('') +
    '<div style="display:flex;justify-content:space-between;margin-top:8px;padding-top:8px;border-top:0.5px solid var(--border);font-weight:600">' +
      '<span>Total</span><span>$'+Math.round(total).toLocaleString('es-AR')+'</span>' +
    '</div>';
}

function otCarritoCant(idx, val) {
  _otCarritoAdicional[idx].cantidad = Math.max(1, parseInt(val)||1);
  otRenderCarritoAdicional();
}

function otQuitarCarrito(idx) {
  _otCarritoAdicional.splice(idx, 1);
  otRenderCarritoAdicional();
}

function otConfirmarVentaAdicional() {
  if (!_otCarritoAdicional.length) { notify('Agregá al menos un producto'); return; }
  var ot = otData.find(function(o){ return o.id === otActualId || o.fbKey === otActualId; });
  if (!ot || !window.fbDB) return;

  var items = _otCarritoAdicional.map(function(c) {
    return { cod: c.codigo, desc: c.nombre, qty: c.cantidad, punit: c.precio, sub: c.precio*c.cantidad };
  });
  var total = items.reduce(function(s,i){ return s+i.sub; }, 0);

  var fechaVentaAdicional = new Date().toISOString().slice(0,10);
  var venta = {
    cliente:      ot.cliente || '',
    items:        items,
    total:        Math.round(total*100)/100,
    estadoPago:   'pendiente_pago',
    empleado:     currentUser || '',
    otId:         ot.fbKey || ot.id,
    origenOT:     true,
    nota:         'Venta adicional generada desde OT ' + (ot.id||''),
    fecha:        fechaVentaAdicional,
    fechaOrden:   fechaVentaAdicional,
    ts:           Date.now()
  };

  window.fbPush(window.fbRef(window.fbDB, FB_PATHS.ventas), venta).then(function(snap) {
    // Notificar al admin
    window.fbPush(window.fbRef(window.fbDB, 'sisventas/notificaciones_admin'), {
      tipo:    'venta_adicional_ot',
      otId:    ot.fbKey || ot.id,
      cliente: ot.cliente || '',
      tecnico: currentUser || '',
      monto:   venta.total,
      cantidadItems: items.length,
      ts:      Date.now(),
      leida:   false
    });
    notify('✓ Venta adicional generada por $' + Math.round(total).toLocaleString('es-AR') + ' — admin notificado');
    otCerrarSelectorProductos();
  }).catch(function(e){ notify('Error: ' + e.message); });
}
// FIRMA DIGITAL EN OT
var _firmaCtx    = null;
var _firmaDibujo = false;
var _firmaTiene  = false;

function firmaInicializar() {
  var canvas = document.getElementById('firma-canvas');
  if (!canvas) return;

  // Ajustar tamanio real del canvas al tamanio CSS
  var rect = canvas.getBoundingClientRect();
  canvas.width  = rect.width  * window.devicePixelRatio;
  canvas.height = rect.height * window.devicePixelRatio;
  _firmaCtx = canvas.getContext('2d');
  _firmaCtx.scale(window.devicePixelRatio, window.devicePixelRatio);
  _firmaCtx.strokeStyle = '#1a1a1a';
  _firmaCtx.lineWidth   = 2;
  _firmaCtx.lineCap     = 'round';
  _firmaCtx.lineJoin    = 'round';

  function getPos(e) {
    var r = canvas.getBoundingClientRect();
    var src = e.touches ? e.touches[0] : e;
    return { x: src.clientX - r.left, y: src.clientY - r.top };
  }

  function start(e) {
    e.preventDefault();
    _firmaDibujo = true;
    var p = getPos(e);
    _firmaCtx.beginPath();
    _firmaCtx.moveTo(p.x, p.y);
    document.getElementById('firma-placeholder').style.display = 'none';
  }
  function move(e) {
    if (!_firmaDibujo) return;
    e.preventDefault();
    var p = getPos(e);
    _firmaCtx.lineTo(p.x, p.y);
    _firmaCtx.stroke();
    _firmaTiene = true;
  }
  function end(e) {
    if (!_firmaDibujo) return;
    e.preventDefault();
    _firmaDibujo = false;
    if (_firmaTiene) firmaAutoguardar();
  }

  canvas.addEventListener('mousedown',  start, { passive: false });
  canvas.addEventListener('mousemove',  move,  { passive: false });
  canvas.addEventListener('mouseup',    end,   { passive: false });
  canvas.addEventListener('touchstart', start, { passive: false });
  canvas.addEventListener('touchmove',  move,  { passive: false });
  canvas.addEventListener('touchend',   end,   { passive: false });
}

function firmaLimpiar() {
  var canvas = document.getElementById('firma-canvas');
  if (!canvas || !_firmaCtx) return;
  _firmaCtx.clearRect(0, 0, canvas.width / window.devicePixelRatio, canvas.height / window.devicePixelRatio);
  _firmaTiene = false;
  document.getElementById('firma-placeholder').style.display = '';
  document.getElementById('firma-guardada-badge').style.display = 'none';
  document.getElementById('firma-preview').style.display = 'none';
}

function firmaAutoguardar() {
  var canvas = document.getElementById('firma-canvas');
  if (!canvas || !_firmaTiene) return;
  var dataUrl = canvas.toDataURL('image/png');

  // Subir a Firebase Storage
  if (!window.fbStorage || !window.fbDB) {
    // Sin storage — guardar como dataURL en Firebase (solo si es pequeña)
    firmaGuardarEnOT(dataUrl);
    return;
  }

  var ot = (otData||[]).find(function(o){ return o.fbKey === otActualId || o.id === otActualId; });
  if (!ot || !ot.fbKey) return;

  // Convertir dataURL a blob
  var arr = dataUrl.split(','), mime = arr[0].match(/:(.*?);/)[1];
  var bstr = atob(arr[1]), n = bstr.length, u8arr = new Uint8Array(n);
  while(n--) u8arr[n] = bstr.charCodeAt(n);
  var blob = new Blob([u8arr], {type: mime});

  var path = 'firmas/ot_' + ot.fbKey + '_' + Date.now() + '.png';
  var ref  = window.storageRef(window.fbStorage, path);

  window.uploadBytes(ref, blob).then(function(snap) {
    return window.getDownloadURL(snap.ref);
  }).then(function(url) {
    firmaGuardarEnOT(url);
  }).catch(function() {
    // Fallback: guardar dataURL directamente
    firmaGuardarEnOT(dataUrl);
  });
}

function firmaGuardarEnOT(firmaUrl) {
  var ot = (otData||[]).find(function(o){ return o.fbKey === otActualId || o.id === otActualId; });
  if (!ot || !ot.fbKey || !window.fbDB) return;
  window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo + '/' + ot.fbKey), {
    firmaClienteUrl: firmaUrl,
    firmada: true,
    fechaFirma: new Date().toISOString().slice(0,10)
  });
  var badge = document.getElementById('firma-guardada-badge');
  if (badge) badge.style.display = '';
  // Mostrar preview
  var preview = document.getElementById('firma-preview');
  var img     = document.getElementById('firma-img');
  if (preview && img) { img.src = firmaUrl; preview.style.display = ''; }
}

function firmaCargar(ot) {
  if (!ot || !ot.firmaClienteUrl) return;
  var badge = document.getElementById('firma-guardada-badge');
  var preview = document.getElementById('firma-preview');
  var img     = document.getElementById('firma-img');
  if (badge)   badge.style.display = '';
  if (preview) preview.style.display = '';
  if (img)     img.src = ot.firmaClienteUrl;
  _firmaTiene = true;
  document.getElementById('firma-placeholder').style.display = 'none';
}

function otCargarCredenciales(ot) {
  var box  = document.getElementById('ot-cred-box');
  var lista = document.getElementById('ot-cred-lista');
  if (!box || !lista) return;

  var cli = _svResolverClienteRegistro(ot, true);
  if (!cli || !window.fbDB) { box.style.display='none'; return; }

  window.fbGet(window.fbRef(window.fbDB, 'sisventas/credencialesPorCliente/'+(cli.fbKey||''))).then(function(snap) {
    var data = snap.val();
    if (!data && cli.id) {
      return window.fbGet(window.fbRef(window.fbDB, 'sisventas/credenciales/'+cli.id)).then(function(legacySnap){ return legacySnap.val(); });
    }
    return data;
  }).then(function(data) {
    if (!data) { box.style.display='none'; return; }
    box.style.display = '';
    var items = Object.values(data);
    lista.innerHTML = items.map(function(c) {
      var ico = (CRED_TIPO_ICONOS||{})[c.tipo] || 'ti-key';
      return '<div style="background:var(--bg3);border-radius:var(--radius);padding:12px;display:flex;gap:12px;align-items:flex-start">' +
        '<div style="width:32px;height:32px;border-radius:6px;background:var(--blue-bg);color:var(--blue);display:flex;align-items:center;justify-content:center;flex-shrink:0"><i class="ti '+ico+'" style="font-size:16px"></i></div>' +
        '<div style="flex:1">' +
          '<div style="font-weight:500;font-size:13px">'+escapeHTML(c.desc||c.tipo||'')+'</div>' +
          '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:6px;margin-top:6px">' +
            (c.user ? '<div><span style="font-size:10px;color:var(--text3);display:block">Usuario</span><span style="font-family:monospace;font-size:13px">'+escapeHTML(c.user)+'</span></div>' : '') +
            (c.pass ? '<div><span style="font-size:10px;color:var(--text3);display:block">Contraseña</span>' +
              '<div style="display:flex;align-items:center;gap:6px">' +
                '<span class="ot-cred-pass" style="font-family:monospace;font-size:13px">••••••••</span>' +
                '<button onclick="this.previousElementSibling.textContent=this.previousElementSibling.textContent===\'••••••••\'?\''+escapeHTML(c.pass||'')+'\':\'••••••••\'" style="background:none;border:none;cursor:pointer;color:var(--text3)"><i class="ti ti-eye" style="font-size:13px"></i></button>' +
              '</div></div>' : '') +
            (c.ip ? '<div><span style="font-size:10px;color:var(--text3);display:block">IP / Sistema</span><span style="font-family:monospace;font-size:12px">'+escapeHTML(c.ip)+(c.puerto?':'+escapeHTML(c.puerto):'')+'</span></div>' : '') +
          '</div>' +
          (c.notas ? '<div style="margin-top:6px;font-size:11px;color:var(--text3);font-style:italic">'+escapeHTML(c.notas)+'</div>' : '') +
        '</div>' +
      '</div>';
    }).join('');
  }).catch(function(){ box.style.display='none'; });
}
function otRenderNotas(ot) {
  var lista = document.getElementById('ot-notas-lista');
  var fotosCont = document.getElementById('ot-fotos-preview');
  if (!lista) return;
  var notas = ot.notasTecnico || [];
  lista.innerHTML = notas.length ? notas.map(function(n, idx) {
    var esPropia = (n.autor || '') === (currentUser || '') || currentRole === 'admin';
    var esAdmin  = ['admin','administrativo'].includes((n.rol||n.autor||'').toLowerCase()) || (n.autor||'') !== (currentUser||'');
    return '<div style="background:var(--bg3);border-radius:var(--radius);padding:10px 12px;border-left:3px solid '+(esPropia?'var(--blue)':'var(--border2)')+'">' +
      '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">' +
        '<div style="font-size:13px;flex:1">'+escapeHTML(n.texto||'')+'</div>' +
        (esPropia && currentRole !== 'admin' && esAdmin ? '' :
         esPropia ? '' : '<span title="Nota del administrador — solo lectura" style="font-size:11px;color:var(--text3)">🔒</span>') +
      '</div>' +
      '<div style="font-size:10px;color:var(--text3);margin-top:4px">'+
        '<span style="font-weight:500;color:'+(esPropia?'var(--blue)':'var(--text3)')+'">'+escapeHTML(n.autor||'')+'</span>' +
        ' · '+spFormatFecha(n.ts)+
      '</div>' +
      (n.fotoUrl ? '<img src="'+escapeHTML(n.fotoUrl)+'" style="max-width:100%;border-radius:6px;margin-top:8px;max-height:200px;object-fit:cover">' : '') +
    '</div>';
  }).join('') : '<div style="font-size:12px;color:var(--text3);text-align:center;padding:12px">Sin notas técnicas todavía</div>';
  if (fotosCont) fotosCont.innerHTML = '';
}

function otAgregarNota() {
  var inp = document.getElementById('ot-nota-nueva');
  var texto = inp ? inp.value.trim() : '';
  if (!texto) { notify('Ingresá el texto de la nota'); return; }
  var ot = otData.find(function(o){ return o.id === otActualId || o.fbKey === otActualId; });
  if (!ot || !window.fbDB) return;
  var notas = ot.notasTecnico ? ot.notasTecnico.slice() : [];
  notas.push({ texto, autor: currentUser||'Técnico', ts: Date.now() });
  var key = ot.fbKey || otActualId;
  window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo+'/'+key), { notasTecnico: notas })
    .then(function(){ inp.value=''; notify('✓ Nota agregada'); })
    .catch(function(e){ notify('Error: '+e.message); });
}

function otAgregarFoto(input) {
  var file = input.files[0];
  if (!file) return;
  if (file.size > 3*1024*1024) { notify('La foto no puede superar 3MB'); return; }
  if (!window.fbStorage) { notify('Storage no disponible'); return; }
  var inp  = document.getElementById('ot-nota-nueva');
  var texto = inp ? inp.value.trim() : 'Foto adjunta';
  var ot = otData.find(function(o){ return o.id === otActualId || o.fbKey === otActualId; });
  if (!ot) return;
  var path = 'sisventas/ots/'+(ot.fbKey||otActualId)+'/fotos/'+Date.now()+'_'+file.name;
  var sRef = window.fbStorageRef(window.fbStorage, path);
  notify('Subiendo foto...');
  window.fbUploadBytes(sRef, file).then(function(){
    return window.fbGetDownloadURL(sRef);
  }).then(function(url) {
    var notas = ot.notasTecnico ? ot.notasTecnico.slice() : [];
    notas.push({ texto: texto||'Foto', autor: currentUser||'Técnico', ts: Date.now(), fotoUrl: url });
    var key = ot.fbKey || otActualId;
    return window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo+'/'+key), { notasTecnico: notas });
  }).then(function(){ if(inp) inp.value=''; notify('✓ Foto adjuntada'); })
  .catch(function(e){ notify('Error: '+e.message); });
}

function otVerReclamo() {
  var ot = otData.find(function(o){ return o.id === otActualId || o.fbKey === otActualId; });
  if (!ot || !ot.reclamoKey) return;
  volverListaOT();
  showPage('soporte', document.querySelector('[onclick*="soporte"]'));
  setTimeout(function(){ spAbrirModal(ot.reclamoKey); }, 400);
}

function actualizarOTFecha() {
  var tecSel=document.getElementById('ot-det-tecnico');
  var fecha=(document.getElementById('ot-det-fecha')||{}).value || new Date().toISOString().slice(0,10);
  var periodo=tecSel&&tecSel.value ? periodoVacacionesPara(tecSel.value,fecha) : null;
  if(periodo) {
    notify('⚠ '+tecSel.value+' está de vacaciones en esa fecha. Elegí otro técnico antes de guardar.');
    return false;
  }
  actualizarOT();
  return true;
}

// Renderizar checklist de una fase
function renderChecklist(containerId, checks, labels, otId, fase) {
  const el = document.getElementById(containerId);
  if (!el) return;
  el.innerHTML = labels.map((lbl, i) => `
    <div class="checklist-item ${checks[i] ? 'checked' : ''}" onclick="toggleCheckOT('${otId}','${fase}',${i})">
      <input type="checkbox" ${checks[i] ? 'checked' : ''} onclick="event.stopPropagation();toggleCheckOT('${otId}','${fase}',${i})">
      <label>${escapeHTML(lbl)}</label>
      ${checks[i] ? '<i class="ti ti-check" style="color:var(--green);font-size:14px;flex-shrink:0"></i>' : ''}
    </div>`).join('');
}

// Toggle un ítem del checklist
function toggleCheckOT(otId, fase, idx) {
  const ot = otData.find(o => o.id === otId || o.fbKey === otId);
  if (!ot || ot.estado === 'completada') return;
  ot.checks[fase][idx] = !ot.checks[fase][idx];
  const ahora = new Date().toLocaleDateString('es-AR') + ' ' + new Date().toLocaleTimeString('es-AR',{hour:'2-digit',minute:'2-digit'});
  if (!ot.audit) ot.audit = [];
  ot.audit.push({ fecha: ahora, usuario: currentUser || (currentRole === 'admin' ? 'Admin' : ot.tecnico), accion: (ot.checks[fase][idx] ? '✓ ' : '✗ ') + CHECKLISTS[fase][idx] });
  actualizarProgreso(ot);
  renderChecklist(`checklist-${fase}`, ot.checks[fase], CHECKLISTS[fase], otId, fase);
  if (typeof fbGuardarOT === 'function') {
    fbGuardarOT(ot).catch(function(e){ console.error('Error guardando check:', e); });
  }
}

function actualizarProgreso(ot) {
  const total = Object.values(ot.checks).flat().length;
  const done  = Object.values(ot.checks).flat().filter(Boolean).length;
  const pct   = total > 0 ? Math.round(done/total*100) : 0;
  ot.progreso = pct;
  const fill  = document.getElementById('ot-progress-fill');
  const pctEl = document.getElementById('ot-progreso-pct');
  if (fill) fill.style.width = pct + '%';
  if (pctEl) { pctEl.textContent = pct + '%'; pctEl.style.color = pct === 100 ? 'var(--green)' : 'var(--blue)'; }
  if (pct === 100 && ot.estado === 'en_progreso') {
    ot.estado = 'completada';
    var hoyCierre = new Date().toISOString().slice(0,10);
    ot.fechaCierre = ot.fechaCierre || hoyCierre;
    ot.fechaCompletada = ot.fechaCompletada || hoyCierre;
    const badge = document.getElementById('ot-det-estado-badge');
    if (badge) badge.innerHTML = otBadge('completada');
    notify('¡Checklist completo! Podés finalizar la OT.');
  }
}

// Completar OT
function completarOT() {
  const ot = otData.find(o => o.id === otActualId || o.fbKey === otActualId);
  if (!ot) return;
  var _oc=document.getElementById('ot-acta-conf'); const conf = _oc?_oc.value:'';
  if (!conf) { notify('Seleccioná la conformidad del cliente'); return; }
  const ahora = new Date().toLocaleDateString('es-AR') + ' ' + new Date().toLocaleTimeString('es-AR',{hour:'2-digit',minute:'2-digit'});
  ot.estado = 'completada';
  ot.progreso = 100;
  var hoyCierre = new Date().toISOString().slice(0,10);
  ot.fechaCierre = ot.fechaCierre || hoyCierre;
  ot.fechaCompletada = ot.fechaCompletada || hoyCierre;
  if (!ot.audit) ot.audit = [];
  ot.audit.push({ fecha: ahora, usuario: currentUser || (currentRole === 'admin' ? 'Admin' : ot.tecnico), accion: 'OT marcada como completada. Conformidad: ' + conf });
  ot.audit.push({ fecha: ahora, usuario: 'Sistema', accion: 'Garantía activada automáticamente' });
  document.getElementById('ot-det-estado-badge').innerHTML = otBadge('completada');

  if (ot.ventaId && window.fbDB) {
    var ventaVinculada = _svResolverVentaRegistro(ot);
    if (ventaVinculada && ventaVinculada.fbKey && ventaVinculada.estadoInst !== 'instalado') {
      window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ventas + '/' + ventaVinculada.fbKey), { estadoInst: 'instalado' })
        .catch(function(e){ console.error('Error al actualizar estado de instalación de la venta:', e); });
    }
  }

  if (typeof fbGuardarOT === 'function') {
    fbGuardarOT(ot)
      .then(function() {
        notify('✓ OT completada y guardada en Firebase');
        volverListaOT();
      })
      .catch(function(e) { notify('OT completada pero error al guardar: ' + e.message); });
  } else {
    notify('Orden de trabajo completada. Garantía activada.');
    volverListaOT();
  }
}

function actualizarOT() {
  var ot = otData.find(function(o){ return o.id === otActualId || o.fbKey === otActualId; });
  if (!ot) return;

  var tecSel = document.getElementById('ot-det-tecnico');
  var durSel = document.getElementById('ot-det-duracion');
  var tipoSel = document.getElementById('ot-det-tipovisita');
  var prioChk = document.getElementById('ot-det-prioridad');
  var prioBadge = document.getElementById('ot-det-prioridad-badge');

  var ventaInp = document.getElementById('ot-det-venta');
  var clienteInp = document.getElementById('ot-det-cliente');
  var dirInp = document.getElementById('ot-det-dir');
  if (ventaInp && !ventaInp.readOnly) {
    ot.ventaId = ventaInp.value.trim();
    ot.origen = 'manual';
  }
  if (clienteInp && !clienteInp.readOnly) ot.cliente = clienteInp.value.trim();
  if (dirInp) {
    ot.dir = dirInp.value.trim();
    window._otDireccionActual = ot.dir;
    var mapsBtn = document.getElementById('ot-det-dir-maps-btn');
    if (mapsBtn) mapsBtn.style.display = ot.dir ? '' : 'none';
  }
  if (tecSel)  ot.tecnico    = tecSel.value;
  ot.fecha      = document.getElementById('ot-det-fecha').value;
  ot.hora       = document.getElementById('ot-det-hora').value;
  if (durSel)  ot.duracion   = durSel.value;
  if (tipoSel) ot.tipoVisita = tipoSel.value;
  ot.obs        = document.getElementById('ot-det-obs').value;
  ot.obsTecnico = document.getElementById('ot-det-obs-tecnico').value;
  if (prioChk) {
    ot.prioridad = prioChk.checked;
    if (prioBadge) prioBadge.style.display = prioChk.checked ? '' : 'none';
  }

  var ahora = new Date().toLocaleDateString('es-AR') + ' ' + new Date().toLocaleTimeString('es-AR',{hour:'2-digit',minute:'2-digit'});
  if (!ot.audit) ot.audit = [];
  ot.audit.push({ fecha: ahora, usuario: currentUser || 'Sistema', accion: 'Datos de la OT actualizados' + (ot.prioridad ? ' · Marcada como PRIORIDAD' : '') });

  if (typeof fbGuardarOT === 'function') fbGuardarOT(ot);
  notify('OT actualizada');
}

function aplicarVistaTecnicoOT() {
  var esTec = currentRole === 'tecnico';
  var idsOcultar = ['ot-contexto-box','ot-reclamo-box','ot-cred-box','ot-audit'];
  idsOcultar.forEach(function(id){ var el=document.getElementById(id); if(el) el.closest('.card') ? el.closest('.card').style.display = (esTec ? 'none' : '') : el.style.display = (esTec ? 'none' : ''); });
  var dur = document.getElementById('ot-det-duracion'); if (dur && dur.closest('.fg')) dur.closest('.fg').style.display = esTec ? 'none' : '';
  var tipo = document.getElementById('ot-det-tipovisita'); if (tipo && tipo.closest('.fg')) tipo.closest('.fg').style.display = esTec ? 'none' : '';
  var prio = document.getElementById('ot-det-prioridad'); if (prio && prio.closest('label')) prio.closest('label').style.display = esTec ? 'none' : '';
  var btnImp = document.querySelector('#ot-detalle-view button[onclick="imprimirOT()"]'); if (btnImp) btnImp.style.display = esTec ? 'none' : '';
  var btnMaps = document.getElementById('ot-det-dir-maps-btn');
  if (esTec && btnMaps) { btnMaps.classList.add('btn-primary'); btnMaps.innerHTML = '<i class="ti ti-map-pin"></i> Maps'; }
}

function imprimirOT() { abrirModalImprimir('ot', 'Orden de trabajo ' + otActualId); }

function volverListaOT() {
  _block('ot-list-view');
  _hide('ot-detalle-view');
  otActualId = null;
  window._otDetalleHuella = null;
  renderOTTabla();
  document.dispatchEvent(new CustomEvent('sisventas:ot-closed'));
}

// Normaliza cliente+dirección para detectar si es la misma instalación,
// tolerando diferencias menores de mayúsculas/espacios/tildes simples.
function _claveInstalacion(cliente, dir) {
  function limpiar(s) {
    return (s||'').toLowerCase().trim()
      .replace(/\s+/g,' ')
      .normalize('NFD').replace(/[\u0300-\u036f]/g,''); // quita tildes
  }
  return limpiar(cliente) + '|' + limpiar(dir);
}
// sin contar la OT actual. Sirve para marcar automáticamente cuándo una visita es una repetición.
function _contarVisitasPrevias(cliente, dir, otIdExcluir) {
  var clave = _claveInstalacion(cliente, dir);
  return (otData||[]).filter(function(o) {
    return o.id !== otIdExcluir && _claveInstalacion(o.cliente, o.dir) === clave;
  }).length;
}

function generarOTdesdeVenta(ventaId, cliente, dir) {
  var venta=(ventasList||[]).find(function(item){
    return String(item.id||item.numero||item.fbKey||'')===String(ventaId||'') ||
      (String(ventaId||'').replace(/\D/g,'') && String(item.id||item.numero||item.fbKey||'').replace(/\D/g,'')===String(ventaId||'').replace(/\D/g,''));
  })||null;
  var ventaRef = venta || { id: ventaId, numero: ventaId, ventaId: ventaId };
  var existente=(otData||[]).find(function(ot){return _svRegistroPerteneceVenta(ot, ventaRef);});
  if(existente) return existente.id||existente.fbKey||'';
  if(!dir||!String(dir).trim()||String(dir).trim()==='Sin definir'){
    if(typeof window._otResolverDireccionCliente==='function'){
      dir=window._otResolverDireccionCliente({ventaId:ventaId,cliente:cliente,clienteId:venta&&(venta.clienteId||venta.idCliente||venta.id_cli),ventaObj:venta})||'';
    }
  }
  var visitasPrevias = _contarVisitasPrevias(cliente, dir, null);
  function idOTLocalSeguro() {
    var max = 0;
    (otData||[]).forEach(function(o){
      var m = String(o && o.id || '').match(/OT-(\d+)/i);
      if (m) max = Math.max(max, parseInt(m[1], 10) || 0);
    });
    return 'OT-' + String(max + 1).padStart(3, '0');
  }
  const nuevo = {
    id: idOTLocalSeguro(),
    ventaId, ventaFbKey:venta&&(venta.fbKey||''), ventaKey:venta&&(venta.fbKey||''), cliente, clienteId:venta&&(venta.clienteId||venta.idCliente||''), clienteFbKey:venta&&(venta.clienteFbKey||venta.clienteKey||''), tecnico: 'Sin asignar',
    origen:'venta',
    fecha: '', hora: '09:00', duracion: '4 horas',
    dir: dir || 'Sin definir', obs: 'Generada automáticamente desde ' + ventaId,
    estado: 'pendiente', progreso: 0,
    tipoVisita: visitasPrevias > 0 ? 'Mantenimiento' : 'Instalación nueva',
    esRepetida: visitasPrevias > 0,
    visitaNro: visitasPrevias + 1,
    checks: {
      preparacion: CHECKLISTS.preparacion.map(() => false),
      instalacion: CHECKLISTS.instalacion.map(() => false),
      verificacion: CHECKLISTS.verificacion.map(() => false),
    },
    materiales: venta ? otNormalizarMateriales(venta.items||[], []) : [],
    audit: [{ fecha: new Date().toLocaleDateString('es-AR'), usuario: 'Sistema', accion: 'OT generada automáticamente desde venta ' + ventaId + (visitasPrevias > 0 ? ' (visita Nº ' + (visitasPrevias+1) + ' a esta instalación)' : '') }]
  };
  if (typeof window.crearRegistroOTSeguro === 'function' && window.fbDB) {
    window.crearRegistroOTSeguro(nuevo, { evitarDoble:true }).then(function(ref) {
      if (ref && ref.key) nuevo.fbKey = ref.key;
    }).catch(function(e){ notify('No se pudo crear la OT: ' + e.message); });
  } else if (typeof fbGuardarOT === 'function') {
    otData.unshift(nuevo);
    fbGuardarOT(nuevo).then(function(fbKey) { if (fbKey) nuevo.fbKey = fbKey; });
  }
  return nuevo.id;
}

// Inicializar al entrar al módulo
// KPIs DASHBOARD
// ══════════════════════════════════════════════
// TABLERO EJECUTIVO — datos reales
function renderTablero() {
  var anioSel = parseInt((document.getElementById('tab-anio-sel')||{}).value) || new Date().getFullYear();
  var mesActual = new Date().toISOString().slice(0,7);
  var _e = function(id,v){ var el=document.getElementById(id); if(el) el.textContent=v; };

  var ventas = (ventasList||[]).filter(function(v){ return (v.fecha||'').startsWith(String(anioSel)); });
  var ventasMes = ventas.filter(function(v){ return (v.fecha||'').slice(0,7)===mesActual; });
  var totalAnio = ventas.reduce(function(s,v){ return s+(parseFloat(v.total)||0); }, 0);
  var ticketProm = ventas.length ? totalAnio/ventas.length : 0;

  // Margen promedio anual
  var ventasConMargen = ventas.filter(function(v){ return v.margenPct > 0; });
  var margenProm = ventasConMargen.length
    ? ventasConMargen.reduce(function(s,v){ return s+(parseFloat(v.margenPct)||0); },0)/ventasConMargen.length
    : null;

  // Clientes únicos que compraron en el anio
  var clientesActivos = new Set(ventas.map(function(v){ return v.cliente||v.clienteId; })).size;

  _e('tab-anio-label', anioSel);
  _e('tab-ventas-acum', '$'+Math.round(totalAnio).toLocaleString('es-AR'));
  _e('tab-ventas-sub', ventas.length + ' ventas en el anio');
  _e('tab-margen', margenProm !== null ? Math.round(margenProm)+'%' : '—');
  _e('tab-margen-sub', 'promedio de ventas con margen');
  _e('tab-clientes', clientesActivos);
  _e('tab-clientes-sub', 'compraron en ' + anioSel);
  _e('tab-ticket', '$'+Math.round(ticketProm).toLocaleString('es-AR'));
  _e('tab-ticket-sub', 'ticket promedio anual');

  // Gráfico de barras mensual
  var MESES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
  var datosPorMes = MESES.map(function(m, i) {
    var mes = String(anioSel) + '-' + String(i+1).padStart(2,'0');
    var vMes = ventas.filter(function(v){ return (v.fecha||'').slice(0,7)===mes; });
    var gMes = (gastosList||[]).filter(function(g){ return (g.fecha||'').slice(0,7)===mes; });
    return {
      mes: m, esMesActual: mes===mesActual,
      ventas: vMes.reduce(function(s,v){ return s+(parseFloat(v.total)||0); },0),
      gastos: gMes.reduce(function(s,g){ return s+(parseFloat(g.monto)||0); },0)
    };
  });
  var maxVal = Math.max(1, ...datosPorMes.map(function(d){ return Math.max(d.ventas, d.gastos); }));
  var chart = document.getElementById('tab-chart');
  if (chart) {
    chart.innerHTML = datosPorMes.map(function(d) {
      var hv = Math.round((d.ventas/maxVal)*100);
      var hg = Math.round((d.gastos/maxVal)*100);
      var esMes = d.esMesActual;
      return '<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:4px" title="'+d.mes+' — Ventas: $'+Math.round(d.ventas).toLocaleString('es-AR')+' / Gastos: $'+Math.round(d.gastos).toLocaleString('es-AR')+'">' +
        '<div style="width:100%;display:flex;gap:2px;align-items:flex-end;height:100px">' +
          '<div style="flex:1;background:'+(esMes?'var(--green)':'var(--green-bg)')+';border:1px solid var(--green);border-radius:3px 3px 0 0;height:'+hv+'%;min-height:'+(d.ventas>0?'2px':'0')+'"></div>' +
          '<div style="flex:1;background:'+(esMes?'var(--red)':'var(--red-bg)')+';border:1px solid var(--red);border-radius:3px 3px 0 0;height:'+hg+'%;min-height:'+(d.gastos>0?'2px':'0')+'"></div>' +
        '</div>' +
        '<span style="font-size:10px;color:'+(esMes?'var(--text)':'var(--text3)')+';font-weight:'+(esMes?'600':'400')+'">'+d.mes+'</span>' +
      '</div>';
    }).join('');
  }

  // Top 5 productos
  var conteoProd = {};
  ventas.forEach(function(v) {
    (v.items||[]).forEach(function(it) {
      var k = it.desc||it.cod||'Sin nombre';
      if (!conteoProd[k]) conteoProd[k] = { cant:0, monto:0 };
      conteoProd[k].cant += parseInt(it.qty)||1;
      conteoProd[k].monto += parseFloat(it.sub)||0;
    });
  });
  var top5prod = Object.entries(conteoProd).sort(function(a,b){ return b[1].monto-a[1].monto; }).slice(0,5);
  var tabTopProd = document.getElementById('tab-top-productos');
  if (tabTopProd) {
    tabTopProd.innerHTML = top5prod.length ? top5prod.map(function(e,i) {
      return '<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:0.5px solid var(--border)">' +
        '<div><span style="font-size:11px;color:var(--text3);margin-right:8px">'+(i+1)+'.</span>'+escapeHTML(e[0])+'</div>' +
        '<div style="text-align:right;font-size:12px"><div style="font-weight:600">$'+Math.round(e[1].monto).toLocaleString('es-AR')+'</div>' +
        '<div style="color:var(--text3)">'+e[1].cant+' und.</div></div>' +
      '</div>';
    }).join('') : '<div style="padding:24px;text-align:center;color:var(--text3);font-size:13px">Sin ventas en '+anioSel+'</div>';
  }

  // Top 5 clientes
  var conteoClientes = {};
  ventas.forEach(function(v) {
    var k = v.cliente||'Sin nombre';
    if (!conteoClientes[k]) conteoClientes[k] = 0;
    conteoClientes[k] += parseFloat(v.total)||0;
  });
  var top5cli = Object.entries(conteoClientes).sort(function(a,b){ return b[1]-a[1]; }).slice(0,5);
  var tabTopCli = document.getElementById('tab-top-clientes');
  if (tabTopCli) {
    tabTopCli.innerHTML = top5cli.length ? top5cli.map(function(e,i) {
      return '<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:0.5px solid var(--border)">' +
        '<div><span style="font-size:11px;color:var(--text3);margin-right:8px">'+(i+1)+'.</span>'+escapeHTML(e[0])+'</div>' +
        '<div style="font-weight:600;font-size:13px">$'+Math.round(e[1]).toLocaleString('es-AR')+'</div>' +
      '</div>';
    }).join('') : '<div style="padding:24px;text-align:center;color:var(--text3);font-size:13px">Sin ventas en '+anioSel+'</div>';
  }

  // Indicadores de cobrabilidad
  var totalMesFact = ventasMes.reduce(function(s,v){ return s+(parseFloat(v.total)||0); },0);
  var totalMesCobrado = ventasMes.reduce(function(s,v){ return s+(parseFloat(v.totalPagado)||0); },0);
  var pctCobrado = totalMesFact > 0 ? Math.round((totalMesCobrado/totalMesFact)*100) : null;
  var ventasPendientes = (ventasList||[]).filter(function(v){
    return v.estadoPago !== 'pago_total' && v.estadoPago !== 'cobrado' &&
           ((parseFloat(v.total)||0) - (parseFloat(v.totalPagado)||0)) > 0;
  });
  var pendienteCobro = ventasPendientes.reduce(function(s,v){
    return s + (parseFloat(v.total)||0) - (parseFloat(v.totalPagado)||0);
  }, 0);
  var gastosMes = (gastosList||[]).filter(function(g){ return (g.fecha||'').slice(0,7)===mesActual; })
    .reduce(function(s,g){ return s+(parseFloat(g.monto)||0); },0);
  var otsPend = (otData||[]).filter(function(ot){ return ot.estado !== 'completada'; }).length;

  _e('tab-cobrado-mes', pctCobrado !== null ? pctCobrado+'%' : '—');
  _e('tab-pendiente', '$'+Math.round(pendienteCobro).toLocaleString('es-AR'));
  _e('tab-pendiente-sub', ventasPendientes.length + ' venta' + (ventasPendientes.length!==1?'s':'') + ' sin cobrar');
  _e('tab-gastos-mes', '$'+Math.round(gastosMes).toLocaleString('es-AR'));
  _e('tab-gastos-sub', (gastosList||[]).filter(function(g){ return (g.fecha||'').slice(0,7)===mesActual; }).length + ' gastos este mes');
  _e('tab-ots-pend', otsPend);
}
// Misma fuente que la tarjeta "Compensación de IVA" en Facturaciones — debe coincidir siempre.
function actualizarKpiIvaDashboard() {
  var hoyDate = new Date();
  var mesActual = hoyDate.getFullYear() + '-' + String(hoyDate.getMonth()+1).padStart(2,'0');
  var c = (typeof calcularCompensacionIVA === 'function') ? calcularCompensacionIVA(mesActual) : { saldo: 0 };
  var aFavor = c.saldo <= 0;
  var ivaEl = document.getElementById('kpi-iva');
  if (ivaEl) {
    ivaEl.textContent = '$' + Math.round(Math.abs(c.saldo)).toLocaleString('es-AR');
    ivaEl.style.color = aFavor ? 'var(--blue)' : 'var(--amber)';
  }
  var ivaMesEl = document.getElementById('kpi-iva-mes');
  if (ivaMesEl) {
    var meses = ['ene','feb','mar','abr','may','jun','jul','ago','sep','oct','nov','dic'];
    ivaMesEl.textContent = (aFavor ? 'a favor · ' : 'a pagar · ') + meses[hoyDate.getMonth()] + ' ' + hoyDate.getFullYear();
  }
}

function renderDashMiCuenta() {
  var card = document.getElementById('dash-micuenta-card');
  if (!card) return;
  if (currentRole === 'admin') { card.style.display = 'none'; return; }

  var usuActual = (window.usuariosData||[]).find(function(u){
    return (u.mail||'').toLowerCase() === (currentUserEmail||'').toLowerCase();
  });
  var empFbKey = usuActual && usuActual.empleadoFbKey;
  if (!empFbKey) {
    var empFallback = Object.values(empData||{}).find(function(e){
      return (e.nombre||'').toLowerCase().trim() === (currentUser||'').toLowerCase().trim();
    });
    if (empFallback) empFbKey = empFallback.fbKey || empFallback.id;
  }
  if (!empFbKey || !window.fbDB) { card.style.display = 'none'; return; }

  card.style.display = '';
  window.fbGet(window.fbRef(window.fbDB, 'sisventas/ctaemp/' + empFbKey)).then(function(snap) {
    var data = snap.val() || {};
    var ctaMovsOriginal = Object.keys(data).map(function(k){
      return Object.assign({ fbKey:k, _fuente:'ctaemp' }, data[k] || {});
    });
    var ctaMovs = ctaMovsOriginal.filter(function(m){
      return !_ctaEmpMovimientoLegacyDuplicadoPorGasto(m, empFbKey);
    });
    var fbKeysEnCtaemp = new Set(ctaMovs.map(function(m){ return m.gastoFbKey || m.gastoKey || ''; }).filter(Boolean));
    var gastosEmp = (gastosData||[]).filter(function(g){
      var gEmp = g.empleadoId || g.empleadoFbKey || '';
      if (gEmp !== empFbKey || fbKeysEnCtaemp.has(g.fbKey)) return false;
      var yaExiste = ctaMovs.some(function(m){
        if ((m.gastoFbKey || m.gastoKey || '') === g.fbKey) return true;
        var mismoMonto = Math.abs((parseFloat(m.monto)||0) - (parseFloat(g.monto)||0)) <= 1;
        var mismoMes = String(m.mes || m.fecha || '').slice(0,7) === String(g.mes || g.fecha || '').slice(0,7);
        var md = String(m.descripcion || m.desc || m.detalle || '').trim().toLowerCase();
        var gd = String(g.descripcion || g.desc || g.detalle || '').trim().toLowerCase();
        var mismoTexto = md && gd && (md === gd || md.includes(gd.slice(0,60)) || gd.includes(md.slice(0,60)));
        return mismoMonto && mismoMes && mismoTexto;
      });
      return !yaExiste;
    }).map(function(g){
      return {
        fbKey:       g.fbKey,
        tipo:        _ctaEmpTipoDesdeGasto(g),
        monto:       parseFloat(g.monto)||0,
        descripcion: g.descripcion || g.desc || g.detalle || '',
        desc:        g.descripcion || g.desc || g.detalle || '',
        fecha:       g.fecha || '',
        mes:         g.mes || String(g.fecha || '').slice(0,7),
        estado:      normalizarEstadoGasto(g),
        montoPagado: totalPagadoGasto(g),
        pagos:       g.pagos || {},
        gastoFbKey:  g.fbKey,
        ts:          g.ts || 0,
        _fuente:     'gastos'
      };
    });

    var prevCta = ctaEmpActual;
    ctaEmpActual = empFbKey;
    var movs = ctaMovs.concat(gastosEmp).sort(function(a,b){ return (b.ts||0)-(a.ts||0); });
    var mesActual = _mesSistema(0);
    var movsMes = movs.filter(function(m){ return _movEmpEnPeriodo(m, mesActual); });
    var comisionesPend  = movsMes.filter(function(m){ return m.tipo === 'comision' && _movEmpEstadoCalculado(m) === 'pendiente'; });
    var comisionesAprob = movsMes.filter(function(m){ return m.tipo === 'comision' && _movEmpEstadoCalculado(m) === 'aprobado'; });
    var adelantos       = movsMes.filter(function(m){ return m.tipo === 'adelanto' && String(m.estado||'').toLowerCase() !== 'rechazado'; });
    var tiposHaber = ['sueldo','aguinaldo','hextra','comision','transporte','materiales','gasto_empresa','otro'];
    var haberesCobrables = movsMes.filter(function(m){ return tiposHaber.includes(m.tipo) && _movEmpEsCobrable(m); });

    var totalHaberesPend = haberesCobrables.reduce(function(s,m){ return s + _movEmpSaldoPendiente(m); }, 0);
    var totalComPend     = comisionesPend.reduce(function(s,m){ return s + _movEmpSaldoPendiente(m); }, 0);
    var totalComAprob    = comisionesAprob.reduce(function(s,m){ return s + _movEmpSaldoPendiente(m); }, 0);
    var totalAdelanto    = adelantos.reduce(function(s,m){ return s+(parseFloat(m.monto)||0); }, 0);
    var totalAdelantoPend= adelantos.filter(function(m){ return _movEmpEsCobrable(m); }).reduce(function(s,m){ return s + _movEmpSaldoPendiente(m); }, 0);
    var totalCobrar      = Math.max(0, totalHaberesPend - totalAdelantoPend);

    var fmt = function(n){ return '$' + Math.round(n).toLocaleString('es-AR'); };
    var el = function(id){ return document.getElementById(id); };
    if(el('dash-mc-total'))      el('dash-mc-total').textContent      = fmt(totalCobrar);
    if(el('dash-mc-comisiones')) el('dash-mc-comisiones').textContent = fmt(totalComPend + totalComAprob);
    if(el('dash-mc-comisiones-sub')) el('dash-mc-comisiones-sub').textContent =
      comisionesPend.length + ' pendiente' + (comisionesPend.length !== 1 ? 's' : '') + ' · ' + comisionesAprob.length + ' aprobada' + (comisionesAprob.length !== 1 ? 's' : '') + ' sin pagar';
    if(el('dash-mc-adelantos'))  el('dash-mc-adelantos').textContent  = fmt(totalAdelanto);

    var hsexBox = el('dash-mc-hsextra-box');
    var hsexEst = el('dash-mc-hsex-estado');
    if (hsexBox) {
      hsexBox.style.display = 'flex';
      window.fbGet(window.fbRef(window.fbDB, 'sisventas/hsextra_solicitudes')).then(function(snap2) {
        var sols = snap2.val() ? Object.values(snap2.val()).filter(function(s){ return s.empFbKey === empFbKey; }) : [];
        var pendHs  = sols.filter(function(s){ return s.estado === 'pendiente'; });
        var aprobHs = sols.filter(function(s){ return s.estado === 'aprobado'; });
        var totalHsPend = pendHs.reduce(function(s,x){ return s+(parseFloat(x.horas)||0); }, 0);
        var totalHsAprob = aprobHs.filter(function(s){
          return (s.fecha||'').slice(0,7) >= new Date(new Date().setMonth(new Date().getMonth()-1)).toISOString().slice(0,7);
        }).reduce(function(s,x){ return s+(parseFloat(x.horas)||0); }, 0);
        if (hsexEst) {
          if (pendHs.length > 0) {
            hsexEst.textContent = pendHs.length + ' solicitud' + (pendHs.length > 1 ? 'es' : '') + ' pendiente' + (pendHs.length > 1 ? 's' : '') + ' (' + totalHsPend + ' hs)';
            hsexEst.style.color = 'var(--amber)';
          } else if (totalHsAprob > 0) {
            hsexEst.textContent = totalHsAprob + ' hs aprobadas este mes';
            hsexEst.style.color = 'var(--green)';
          } else {
            hsexEst.textContent = 'Sin solicitudes';
            hsexEst.style.color = 'var(--text3)';
          }
        }
      }).catch(function(){});
    }

    var histCard = document.getElementById('dash-historial-mes-card');
    var histBody = document.getElementById('dash-historial-mes-body');
    if (histCard && histBody) {
      histCard.style.display = '';
      var movsHist = movsMes.slice().sort(function(a,b){ return (b.ts||0)-(a.ts||0); }).slice(0,6);
      if (!movsHist.length) {
        histBody.innerHTML = '<div style="text-align:center;color:var(--text3);padding:16px">Sin movimientos este mes</div>';
      } else {
        var colorTipo = { sueldo:'var(--blue)', hextra:'var(--amber)', comision:'var(--green)', adelanto:'var(--red)', gasto_empresa:'var(--text3)', transporte:'var(--text3)', aguinaldo:'var(--blue)' };
        var labelTipo = { sueldo:'Sueldo', hextra:'Hs. extra', comision:'Comisión', adelanto:'Adelanto', gasto_empresa:'Gasto', transporte:'Transporte', aguinaldo:'Aguinaldo' };
        histBody.innerHTML = '<table style="width:100%;border-collapse:collapse">' +
          movsHist.map(function(m) {
            var estadoCalc = _movEmpEstadoCalculado(m);
            var color  = colorTipo[m.tipo] || 'var(--text)';
            var label  = labelTipo[m.tipo] || m.tipo || '—';
            var esEgreso = m.tipo === 'adelanto';
            var montoMostrar = _movEmpSaldoPendiente(m) || (parseFloat(m.monto)||0);
            var monto  = (esEgreso ? '-' : '') + '$' + Math.round(montoMostrar).toLocaleString('es-AR');
            var estadoColor = estadoCalc === 'pendiente' ? 'var(--amber)' : (estadoCalc === 'pagado' || estadoCalc === 'aprobado') ? 'var(--green)' : 'var(--text3)';
            var estadoLabel = {pendiente:'Pendiente',aprobado:'Aprobado',pagado:'Pagado',pagado_parcial:'Pago parcial',rechazado:'Rechazado',anulado:'Anulado'}[estadoCalc] || estadoCalc || '—';
            var fechaRaw = _movEmpFechaVisual(m);
            return '<tr style="border-bottom:0.5px solid var(--border)">' +
              '<td style="padding:8px 0;width:80px;font-size:11px;color:var(--text3)">' + (fechaRaw||'').slice(0,10) + '</td>' +
              '<td style="padding:8px 4px"><span style="font-size:11px;font-weight:600;color:' + color + ';background:' + color + '22;padding:2px 7px;border-radius:4px">' + label + '</span></td>' +
              '<td style="padding:8px 4px;font-size:12px;color:var(--text2);max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escapeHTML(m.descripcion||m.desc||'') + '</td>' +
              '<td style="padding:8px 0;text-align:right;font-weight:600;color:' + (esEgreso ? 'var(--red)' : 'var(--text)') + '">' + monto + '</td>' +
              '<td style="padding:8px 0 8px 8px;text-align:right;font-size:11px;color:' + estadoColor + '">' + estadoLabel + '</td>' +
            '</tr>';
          }).join('') + '</table>';
      }
    }
    ctaEmpActual = prevCta;
  }).catch(function(){ card.style.display = 'none'; });
}
function renderDashAdministrativo() {
  var mesActual = new Date().getFullYear() + '-' + String(new Date().getMonth()+1).padStart(2,'0');
  var usuario   = currentUser || '';

  // Mis presupuestos del mes
  var misPptos = (pptoData||[]).filter(function(p){
    return p.empleado === usuario && (p.fecha||'').slice(0,7) === mesActual;
  });
  var misConvertidos = misPptos.filter(function(p){ return p.estado === 'convertido'; });
  var tasaConv = misPptos.length > 0 ? Math.round(misConvertidos.length / misPptos.length * 100) : 0;

  // Mis ventas del mes
  var misVentas = (ventasList||[]).filter(function(v){
    return (v.vendedor||v.empleado||v.usuario||'') === usuario && (v.fecha||'').slice(0,7) === mesActual;
  });

  var el = function(id){ return document.getElementById(id); };
  if(el('dash-adm-pptos'))     el('dash-adm-pptos').textContent     = misPptos.length;
  if(el('dash-adm-pptos-sub')) el('dash-adm-pptos-sub').textContent = misConvertidos.length + ' convertidos';
  if(el('dash-adm-ventas'))    el('dash-adm-ventas').textContent    = misVentas.length;
  if(el('dash-adm-ventas-sub'))el('dash-adm-ventas-sub').textContent= misVentas.length + ' este mes';
  if(el('dash-adm-conv'))      el('dash-adm-conv').textContent      = tasaConv + '%';

  // Últimas ventas del administrativo
  var cont = el('dash-adm-ultventas');
  if (!cont) return;
  var ults = misVentas.slice().sort(function(a,b){ return (b.fecha||'').localeCompare(a.fecha||''); }).slice(0,5);
  if (!ults.length) {
    cont.innerHTML = '<div style="text-align:center;color:var(--text3);padding:12px;font-size:13px">Sin ventas este mes</div>';
    return;
  }
  cont.innerHTML = '<div style="font-size:11px;color:var(--text3);margin-bottom:6px;text-transform:uppercase;letter-spacing:.5px">Mis últimas ventas</div>' +
    ults.map(function(v) {
      return '<div style="display:flex;align-items:center;gap:10px;padding:8px 10px;background:var(--bg3);border-radius:var(--radius)">' +
        '<div style="flex:1"><div style="font-size:13px;font-weight:500">'+escapeHTML(v.cliente||'')+'</div>' +
        '<div style="font-size:11px;color:var(--text3)">'+escapeHTML(v.fecha||'')+'</div></div>' +
        '<div style="font-size:13px;font-weight:500;color:var(--green)">$'+Math.round(parseFloat(v.total)||0).toLocaleString('es-AR')+'</div>' +
      '</div>';
    }).join('');
}

function renderDashMisOTs() {
  var cont = document.getElementById('dash-mis-ots');
  if (!cont) return;
  var mis = (otData||[]).filter(function(o){
    return (o.tecnico||'') === (currentUser||'') && o.estado !== 'completada';
  }).sort(function(a,b){ return (a.fecha||'').localeCompare(b.fecha||''); });
  if (!mis.length) {
    cont.innerHTML = '<div style="text-align:center;color:var(--text3);padding:16px;font-size:13px">No tenés OTs pendientes asignadas</div>';
    return;
  }
  cont.innerHTML = mis.map(function(o) {
    var dir = o.dir || o.direccion || '';
    if (!dir && o.cliente) {
      var c = _svResolverClienteRegistro(o, true);
      if (c) dir = c.direccion || c.domicilio || '';
    }
    var estadoColor = o.estado==='en_curso'?'var(--blue)':o.estado==='pendiente'?'var(--amber)':'var(--text3)';
    return '<div style="display:flex;align-items:center;gap:10px;padding:10px 12px;background:var(--bg3);border-radius:var(--radius);cursor:pointer" onclick="showPage(\'ordentrabajo\',null);setTimeout(function(){verOT(\''+o.fbKey+'\')},300)">' +
      '<div style="flex:1">' +
        '<div style="font-weight:500;font-size:13px">'+escapeHTML(o.cliente||'—')+'</div>' +
        (dir?'<div style="font-size:11px;color:var(--text3)"><i class="ti ti-map-pin" style="font-size:10px"></i> '+escapeHTML(dir)+'</div>':'') +
        '<div style="font-size:11px;color:var(--text3)">'+escapeHTML(o.descripcion||o.desc||'')+'</div>' +
      '</div>' +
      '<div style="text-align:right">' +
        '<span style="font-size:11px;font-weight:500;color:'+estadoColor+'">'+escapeHTML(o.estado||'')+'</span>' +
        '<div style="font-size:11px;color:var(--text3)">'+escapeHTML(o.fecha||'')+'</div>' +
      '</div>' +
    '</div>';
  }).join('');
}

function renderKPIsDashboard() {
  var hoyDate = new Date();
  var hoy  = hoyDate.toLocaleDateString('es-AR'); // DD/MM/YYYY — formato real que usa el sistema
  var ayerDate = new Date(Date.now()-86400000);
  var ayer = ayerDate.toLocaleDateString('es-AR');
  var esAdmin = (currentRole === 'admin' || currentRole === 'administrativo');

  // Filtrar ventas por usuario si no es admin
  var todasVentas = ventasList || [];
  var ventas = esAdmin ? todasVentas : todasVentas.filter(function(v) {
    return (v.empleado||v.vendedor||v.usuario||'').toLowerCase() === (currentUser||'').toLowerCase();
  });
  var ventasHoy = ventas.filter(function(v){ return v.fecha === hoy; });
  var ventasAyer = ventas.filter(function(v){ return v.fecha === ayer; });
  var totalHoy  = ventasHoy.reduce(function(s,v){ return s + (parseFloat(v.total)||0); }, 0);
  var totalAyer = ventasAyer.reduce(function(s,v){ return s + (parseFloat(v.total)||0); }, 0);
  var diffPct   = totalAyer > 0 ? Math.round((totalHoy - totalAyer) / totalAyer * 100) : 0;

  _set('kpi-ventas-hoy', '$' + Math.round(totalHoy).toLocaleString('es-AR'));
  var diffEl = document.getElementById('kpi-ventas-diff');
  if (diffEl) {
    diffEl.textContent = (diffPct >= 0 ? '↑ +' : '↓ ') + diffPct + '% vs ayer';
    diffEl.style.color = diffPct >= 0 ? 'var(--green)' : 'var(--red)';
  }
  // Mismo criterio que usa Cobranzas: si está en pago_total el saldo es 0,
  // sino se resta lo ya cobrado (campo real: totalPagado)
  var ventasDeuda = esAdmin ? todasVentas : ventas;
  function _saldoPendienteVenta(v) {
    var total = parseFloat(v.total) || 0;
    if (v.estadoPago === 'pago_total') return 0;
    var pagado = parseFloat(v.totalPagado) || 0;
    return total - pagado;
  }
  var ventasConDeuda = ventasDeuda.filter(function(v) { return _saldoPendienteVenta(v) > 0; });
  var deudaTotal = ventasConDeuda.reduce(function(s,v){ return s + _saldoPendienteVenta(v); }, 0);
  var clientesUnicos = new Set(ventasConDeuda.map(function(v){ return v.cliente; })).size;
  _set('kpi-deuda', '$' + Math.round(deudaTotal).toLocaleString('es-AR'));
  var deudaSubEl = document.getElementById('kpi-deuda-sub');
  if (deudaSubEl) deudaSubEl.textContent = esAdmin ? (clientesUnicos + ' cliente' + (clientesUnicos !== 1 ? 's' : '') + ' con saldo') : 'mis ventas pendientes';
  var pptos = pptoData || [];
  var pptosActivos = pptos.filter(function(p){
    return ['borrador','revision','aprobado_int','enviado','visto','aceptado'].includes(p.estado);
  });
  var pptosConvertidos = pptos.filter(function(p){ return p.estado === 'convertido'; });
  var totalPptos = pptos.filter(function(p){ return p.estado !== 'anulado'; }).length;
  var tasaConv = totalPptos > 0 ? Math.round(pptosConvertidos.length / totalPptos * 100) : 0;
  _set('kpi-pptos', String(pptosActivos.length));
  var pptoSubEl = document.getElementById('kpi-pptos-sub');
  if (pptoSubEl) pptoSubEl.textContent = pptosActivos.length + ' activos';
  var pptoConvEl = document.getElementById('kpi-pptos-conv');
  if (pptoConvEl) pptoConvEl.textContent = pptosConvertidos.length + ' convertidos · ' + tasaConv + '% conversión';
  actualizarDolarDashboard();
  actualizarKpiIvaDashboard();
  var dias7 = [];
  for (var i = 6; i >= 0; i--) {
    // Usar fecha local (no UTC) para evitar desfase de zona horaria
    var d = new Date();
    d.setDate(d.getDate() - i);
    var yyyy = d.getFullYear();
    var mm   = String(d.getMonth()+1).padStart(2,'0');
    var dd   = String(d.getDate()).padStart(2,'0');
    dias7.push({ iso: yyyy+'-'+mm+'-'+dd, dmy: dd+'/'+mm+'/'+yyyy, dow: d.getDay() });
  }
  var maxVal = 0;
  var totales = dias7.map(function(dia) {
    var t = ventas.filter(function(v){
      var f = (v.fecha||'').trim();
      // Aceptar DD/MM/YYYY, DD/MM/YY, YYYY-MM-DD
      return f === dia.dmy || f.slice(0,10) === dia.iso ||
             f === dia.dmy.slice(0,8) + dia.dmy.slice(8);
    }).reduce(function(s,v){ return s + (parseFloat(v.total)||0); }, 0);
    if (t > maxVal) maxVal = t;
    return t;
  });
  var diaNombres = ['Do','Lu','Ma','Mi','Ju','Vi','Sa'];
  var maxPx = 72;
  for (var j = 0; j < 7; j++) {
    var barEl  = document.getElementById('bar-' + j);
    var lblEl  = document.getElementById('blbl-' + j);
    var alto   = maxVal > 0 ? Math.max(4, Math.round(totales[j]/maxVal*maxPx)) : 4;
    var esHoy  = j === 6;
    if (barEl) {
      barEl.style.height = alto + 'px';
      barEl.title = dias7[j].dmy + ': $' + Math.round(totales[j]).toLocaleString('es-AR');
      barEl.style.background = esHoy ? 'var(--blue)' : (totales[j] > 0 ? 'var(--green)' : 'var(--bg4)');
      barEl.style.cursor = 'pointer';
      barEl.dataset.fechaIso = dias7[j].iso;
      barEl.onclick = function(){ dashFiltrarVentasPorDia(this.dataset.fechaIso); };
    }
    if (lblEl) {
      lblEl.textContent = esHoy ? 'Hoy' : diaNombres[dias7[j].dow];
      lblEl.className = 'bar-lbl' + (esHoy ? ' today' : '');
    }
  }
  if (typeof dashRenderEvolucionMensual === 'function') dashRenderEvolucionMensual(ventas);
  var ultVentasEl = document.getElementById('dash-ultimas-ventas');
  if (ultVentasEl) {
    var ultimas = ventas.slice(0, 5);
    if (ultimas.length) {
      ultVentasEl.innerHTML = ultimas.map(function(v) {
        var estadoLbl = v.estadoPago === 'pago_total' ? '<span class="badge b-green">Pagado</span>'
                       : v.estadoPago === 'seniado' ? '<span class="badge b-blue">Señado</span>'
                       : '<span class="badge b-amber">Pendiente</span>';
        var subtotal = parseFloat(v.subtotal) || 0;
        var iva = parseFloat(v.iva) || 0;
        var total = parseFloat(v.total) || 0;
        var vid = escapeHTML(v.id||'');
        return '<tr style="cursor:pointer;touch-action:pan-x pan-y" onclick="verDetalleVentaDesdeId(\'' + vid + '\')" onmouseenter="this.style.background=\'var(--bg3)\'" onmouseleave="this.style.background=\'\'">' +
          '<td style="font-family:monospace;font-size:12px">' + vid + '</td>' +
          '<td>' + escapeHTML(v.cliente||'') + '</td>' +
          '<td class="hide-mobile" style="color:var(--text3);white-space:nowrap;min-width:90px">' + _mostrarFecha(v.fecha) + '</td>' +
          '<td style="text-align:right">$' + subtotal.toLocaleString('es-AR') + '</td>' +
          '<td style="text-align:right;color:var(--text3)">$' + iva.toLocaleString('es-AR') + '</td>' +
          '<td style="text-align:right;font-weight:600">$' + total.toLocaleString('es-AR') + '</td>' +
          '<td style="text-align:right;touch-action:pan-x pan-y">' + estadoLbl + '</td>' +
          '<td style="touch-action:pan-x pan-y"><button class="btn btn-sm btn-icon" style="touch-action:pan-x pan-y" onclick="event.stopPropagation();verDetalleVentaDesdeId(\'' + vid + '\')" title="Ver detalle completo"><i class="ti ti-arrow-right" style="font-size:14px"></i></button></td>' +
        '</tr>';
      }).join('');
    } else {
      ultVentasEl.innerHTML = '<tr><td colspan="8" style="text-align:center;padding:16px;color:var(--text3)">Sin ventas recientes</td></tr>';
    }
  }
  var ultVentasMobileEl = document.getElementById('dash-ventas-mobile-lista');
  if (ultVentasMobileEl) {
    var ultimasM = ventas.slice(0, 5);
    if (ultimasM.length) {
      ultVentasMobileEl.innerHTML = ultimasM.map(function(v) {
        var estadoLbl = v.estadoPago === 'pago_total' ? '<span class="badge b-green">Pagado</span>'
                       : v.estadoPago === 'seniado' ? '<span class="badge b-blue">Señado</span>'
                       : '<span class="badge b-amber">Pendiente</span>';
        var total = parseFloat(v.total) || 0;
        var vid = escapeHTML(v.id||'');
        return '<div onclick="verDetalleVentaDesdeId(\'' + vid + '\')" style="display:flex;align-items:center;padding:10px 0;border-bottom:0.5px solid var(--border);cursor:pointer">' +
          '<span style="flex:1;min-width:0">' +
            '<div style="font-size:13px;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escapeHTML(v.cliente||'') + '</div>' +
            '<div style="font-size:11px;color:var(--text3)">' + vid + ' · ' + _mostrarFecha(v.fecha) + '</div>' +
          '</span>' +
          '<span style="flex-shrink:0;margin-left:12px;font-weight:600;font-size:13px">$' + total.toLocaleString('es-AR') + '</span>' +
          '<span style="flex-shrink:0;margin-left:8px;min-width:68px;text-align:right">' + estadoLbl + '</span>' +
        '</div>';
      }).join('');
    } else {
      ultVentasMobileEl.innerHTML = '<div style="padding:16px;text-align:center;color:var(--text3);font-size:13px">Sin ventas recientes</div>';
    }
  }
  var otTabla = document.getElementById('dash-ot-pendientes');
  if (otTabla) {
    var otsPend = (otData||[]).filter(function(o){ return o.estado !== 'completada'; });
    if (!esAdmin) {
      otsPend = otsPend.filter(function(o){ return (o.tecnico||'').toLowerCase() === (currentUser||'').toLowerCase(); });
    }
    otsPend.sort(function(a,b){
      var ak = String(a.fecha || '9999-99-99') + ' ' + String(a.hora || '99:99');
      var bk = String(b.fecha || '9999-99-99') + ' ' + String(b.hora || '99:99');
      return ak.localeCompare(bk);
    });
    if (!otsPend.length) {
      otTabla.innerHTML = '<tr><td colspan="3" style="text-align:center;color:var(--text3);padding:12px">Sin OTs pendientes</td></tr>';
    } else {
      otTabla.innerHTML = otsPend.slice(0,6).map(function(o) {
        var badge = otBadge(o.estado);
        var fechaOT = o.fecha ? _mostrarFecha(o.fecha) : 'Sin fecha';
        var horaOT = o.hora ? String(o.hora).slice(0,5) : 'Sin hora';
        var fechaHoraOT = fechaOT + ' · ' + horaOT;
        return '<tr style="cursor:pointer;touch-action:pan-x pan-y" onclick="abrirOTDesdeId(\'' + escapeHTML(o.fbKey||o.id||'') + '\')" onmouseenter="this.style.background=\'var(--bg3)\'" onmouseleave="this.style.background=\'\'">' +
          '<td><div style="font-weight:500">' + escapeHTML(o.cliente||'') + '</div><div style="font-size:11px;color:var(--blue);margin-top:2px;font-family:monospace">' + escapeHTML(o.id||'OT') + '</div>' +
            '<div style="font-size:11px;color:var(--amber);margin-top:2px"><i class="ti ti-calendar-time" style="font-size:10px"></i> ' + escapeHTML(fechaHoraOT) + '</div>' +
            (function(){
              var dir = o.dir || o.direccion || '';
              if (!dir && o.cliente) {
                var c = _svResolverClienteRegistro(o, true);
                if (c) dir = c.direccion || c.domicilio || c.dir || '';
              }
              return dir ? '<div style="font-size:11px;color:var(--text3);margin-top:2px"><i class="ti ti-map-pin" style="font-size:10px"></i> ' + escapeHTML(dir) + '</div>' : '';
            })() +
          '</td>' +
          '<td style="color:var(--text3)">' + escapeHTML(o.tecnico||'Sin asignar') + '</td>' +
          '<td style="text-align:right;touch-action:pan-x pan-y">' + badge + '</td>' +
        '</tr>';
      }).join('');
    }
  }

  if (typeof dashRenderActividadReciente === 'function') dashRenderActividadReciente();
  if (currentRole === 'admin') renderRentabilidadDashboard(todasVentas);
  else { var rc = document.getElementById('dash-rentabilidad-card'); if (rc) rc.style.display = 'none'; }
}
function renderRentabilidadDashboard(todasVentas) {
  var card = document.getElementById('dash-rentabilidad-card');
  if (!card) return;
  if (currentRole !== 'admin') { card.style.display = 'none'; return; }
  card.style.display = '';

  var hoy = new Date();
  var mesActual = hoy.getMonth();
  var anioActual = hoy.getFullYear();

  var ventasDelMes = (todasVentas||[]).filter(function(v) {
    var f = v.fecha || '';
    var partes;
    if (f.indexOf('-') !== -1) { // YYYY-MM-DD
      partes = f.split('-');
      return parseInt(partes[1])-1 === mesActual && parseInt(partes[0]) === anioActual;
    } else if (f.indexOf('/') !== -1) { // DD/MM/YYYY
      partes = f.split('/');
      return parseInt(partes[1])-1 === mesActual && parseInt(partes[2]) === anioActual;
    }
    return false;
  });
  var ingresosMes = ventasDelMes.reduce(function(s,v){ return s + (parseFloat(v.total)||0); }, 0);

  var gastosDelMes = (gastosData||[]).filter(function(g) {
    var f = g.fecha || '';
    if (f.indexOf('-') === -1) return false;
    var partes = f.split('-');
    return parseInt(partes[1])-1 === mesActual && parseInt(partes[0]) === anioActual;
  });
  var gastosMes = gastosDelMes.reduce(function(s,g){ return s + (parseFloat(g.monto)||0); }, 0);

  var utilidad = ingresosMes - gastosMes;
  var margenPct = ingresosMes > 0 ? (utilidad / ingresosMes * 100) : 0;

  _set('dash-rent-ingresos', '$' + Math.round(ingresosMes).toLocaleString('es-AR'));
  _set('dash-rent-gastos', '$' + Math.round(gastosMes).toLocaleString('es-AR'));
  var utilEl = document.getElementById('dash-rent-utilidad');
  if (utilEl) {
    utilEl.textContent = '$' + Math.round(utilidad).toLocaleString('es-AR');
    utilEl.style.color = utilidad >= 0 ? 'var(--green)' : 'var(--red)';
  }

  var margenEl = document.getElementById('dash-rent-margen');
  var margenSubEl = document.getElementById('dash-rent-margen-sub');
  if (margenEl) margenEl.textContent = margenPct.toFixed(1) + '%';
  card.classList.remove('is-positive','is-warning','is-negative');
  if (margenPct < 15) {
    if (margenEl) margenEl.style.color = 'var(--red)';
    if (margenSubEl) margenSubEl.textContent = utilidad < 0 ? 'pérdida del mes' : 'margen bajo';
    card.classList.add('is-negative');
  } else if (margenPct <= 20) {
    if (margenEl) margenEl.style.color = 'var(--amber)';
    if (margenSubEl) margenSubEl.textContent = 'margen regular';
    card.classList.add('is-warning');
  } else {
    if (margenEl) margenEl.style.color = 'var(--green)';
    if (margenSubEl) margenSubEl.textContent = 'saludable';
    card.classList.add('is-positive');
  }

  // Barras comparativas, escaladas contra el mayor de los dos valores
  var maxVal = Math.max(ingresosMes, gastosMes, 1);
  var pctIng = Math.round(ingresosMes / maxVal * 100);
  var pctGas = Math.round(gastosMes / maxVal * 100);
  var barIng = document.getElementById('dash-rent-bar-ing');
  var barGas = document.getElementById('dash-rent-bar-gas');
  var lblIng = document.getElementById('dash-rent-bar-ing-lbl');
  var lblGas = document.getElementById('dash-rent-bar-gas-lbl');
  if (barIng) barIng.style.width = pctIng + '%';
  if (barGas) barGas.style.width = pctGas + '%';
  if (lblIng) lblIng.textContent = '$' + Math.round(ingresosMes).toLocaleString('es-AR');
  if (lblGas) lblGas.textContent = '$' + Math.round(gastosMes).toLocaleString('es-AR');
}

function kpiNavegar(tipo) {
  if (tipo === 'ventasHoy') {
    showPage('detalle', document.querySelector('[onclick*="detalle"]'));
    setTimeout(function() { if (typeof tabVentas === 'function') tabVentas('hoy', document.getElementById('vtab-hoy')); }, 150);
  } else if (tipo === 'deuda') {
    showPage('detalle', document.querySelector('[onclick*="detalle"]'));
    setTimeout(function() { if (typeof tabVentas === 'function') tabVentas('cobrar', document.getElementById('vtab-cobrar')); }, 150);
  } else if (tipo === 'presupuestos') {
    showPage('presupuesto', document.querySelector('[onclick*="presupuesto"]'));
  } else if (tipo === 'iva') {
    showPage('creditofiscal', document.querySelector('[onclick*="creditofiscal"]'));
  }
}

function verDetalleVentaDesdeId(ventaId) {
  showPage('detalle', document.querySelector('[onclick*="detalle"]'));
  setTimeout(function() {
    if (typeof verDetalleVenta === 'function') verDetalleVenta(ventaId);
  }, 150);
}
// HERRAMIENTA: MIGRAR COBROS HISTÓRICOS (desde Configuración)
// ══════════════════════════════════════════════════════════════════════════════

function moverVentaAPresupuesto(ventaId) {
  var permitidoMover = typeof window.tienePermiso === 'function'
    ? window.tienePermiso('ventas.moverPresupuesto', { args:[ventaId] })
    : (typeof esAdminOAdministrativo === 'function' ? esAdminOAdministrativo() : ['admin','administrativo'].indexOf(String(currentRole||'').toLowerCase()) >= 0);
  if (!permitidoMover) { notify('No tenés permiso para mover ventas a presupuestos'); return; }
  var v = _svResolverVentaRegistro(ventaId);
  if (!v) { notify('Venta no encontrada'); return; }
  var diasVencInput = document.getElementById('cfg-dias-venc');
  var diasVenc = diasVencInput ? (parseInt(diasVencInput.value)||10) : 10;
  if (!confirm('¿Mover la venta ' + ventaId + ' a Presupuestos?\n\nSe creará un presupuesto que vence en ' + diasVenc + ' día' + (diasVenc !== 1 ? 's' : '') + ', y la venta original se ELIMINARÁ del listado de ventas.\n\nEsta acción no se puede deshacer.')) return;
  if (!window.fbDB) { notify('Sin conexión'); return; }
  var ahora   = new Date().toISOString().split('T')[0];
  var vence   = new Date(Date.now() + diasVenc*86400000).toISOString().split('T')[0];
  var numPpto = 'PP-' + String(Date.now()).slice(-5);
  var ppto = {
    id: numPpto, cliente: v.cliente||'', empleado: v.empleado||v.usuario||currentUser||'',
    clienteId: v.clienteId||v.idCliente||'', idCliente: v.clienteId||v.idCliente||'', clienteFbKey: v.clienteFbKey||v.clienteKey||'',
    usuario: currentUser||'', fecha: ahora, vence: vence,
    items: v.items||[], subtotal: parseFloat(v.subtotal||v.total)||0,
    descuento: parseFloat(v.descuento)||0, iva: 0,
    total: parseFloat(v.total)||0, estado: 'enviado',
    ventaOrigenId: v.id || ventaId, ventaOrigenFbKey: v.fbKey || '', observaciones: 'Movido desde venta '+(v.id || ventaId),
    audit: [{ fecha:ahora, usuario:currentUser||'', accion:'Creado desde venta '+(v.id || ventaId) }],
    ts: Date.now()
  };
  window.fbPush(window.fbRef(window.fbDB, 'sisventas/presupuestos'), ppto)
    .then(function() {
      // Eliminar la venta original — ya está movida a presupuestos
      var promesas = [];
      (window._pagosListaActual||[]).filter(function(p){ return _svRegistroPerteneceVenta(p, v) && p.fbKey; }).forEach(function(p) {
        promesas.push(window.fbRemove(window.fbRef(window.fbDB, 'sisventas/pagos/' + p.fbKey)));
      });
      (otData||[]).filter(function(o){ return _svRegistroPerteneceVenta(o, v) && o.fbKey; }).forEach(function(o) {
        promesas.push(window.fbRemove(window.fbRef(window.fbDB, FB_PATHS.ordenesTrabajo + '/' + o.fbKey)));
      });
      if (v.fbKey) promesas.push(window.fbRemove(window.fbRef(window.fbDB, 'sisventas/ventas/' + v.fbKey)));
      return Promise.all(promesas);
    })
    .then(function() {
      notify('✓ Presupuesto ' + numPpto + ' creado · Venta original eliminada · Vence ' + vence);
      showPage('presupuesto', document.querySelector('[onclick*="presupuesto"]'));
    })
    .catch(function(e){ notify('Error: '+e.message); });
}

function renderVentaTimeline(containerId, estadoActual) {
  const el = document.getElementById(containerId);
  if (!el) return;
  const idx = VENTA_ESTADOS.findIndex(e => e.id === estadoActual);
  el.innerHTML = '<div class="venta-timeline">' + VENTA_ESTADOS.map((e, i) => {
    let cls = '';
    if (i < idx) cls = 'done';
    else if (i === idx) cls = e.cls;
    return `<div class="vt-step ${cls}">
      <div class="vt-dot"><i class="ti ${e.icon}" style="font-size:11px"></i></div>
      <div class="vt-label">${e.label}</div>
    </div>`;
  }).join('') + '</div>';
}

function ventaEstadoBadge(est) {
  const map = {
    pendiente_pago: ['badge b-amber','Pendiente pago'],
    seniado:        ['badge b-blue', 'Señado'],
    pago_total:     ['badge b-green','Pago total'],
    anulada:        ['badge','Anulada'],
  };
  const [cls, lbl] = map[est] || ['badge','—'];
  return `<span class="${cls}" style="${est==='anulada'?'background:rgba(239,68,68,.15);color:#f87171;border:0.5px solid rgba(239,68,68,.3)':''}">${lbl}</span>`;
}

function ventaEstadoInstBadge(est) {
  const map = {
    pendiente_inst: ['badge b-amber','No instalado'],
    en_instalacion: ['badge b-blue', 'En instalación'],
    instalado:      ['badge b-green','Instalado'],
    con_garantia:   ['badge b-green','Con garantía'],
  };
  const [cls, lbl] = map[est] || ['badge b-amber','No instalado'];
  return `<span class="${cls}">${lbl}</span>`;
}
// HISTORIAL POR CLIENTE

var clienteActualId = null;

function verHistorialCli(btn) {
  // Obtener datos del cliente desde la fila
  const tr = btn.closest('tr');
  const celdas = tr.querySelectorAll('td');
  const id = parseInt(celdas[0].textContent) || 1;
  const nombre = (celdas[1].textContent + ', ' + celdas[2].textContent).trim();
  verHistorialCliente(id, nombre);
}

function verHistorialCliente(id, nombre) {
  clienteActualId = id;
  var cli = (clientesData || []).find(function(c){ return String(c.fbKey) === String(id) || String(c.id) === String(id); });
  if (!cli) { notify('Cliente no encontrado (ID: '+id+')'); return; }
  showPage('historialcliente', null);
  var avisoHcEl = document.getElementById('hc-aviso-cambio-externo');
  if (avisoHcEl) avisoHcEl.style.display = 'none';

  if (typeof credSetCliente === 'function') credSetCliente(cli.fbKey || cli.id, cli);

  // Header
  var iniciales = (cli.nombre||'').split(' ').slice(0,2).map(function(p){ return p[0]||''; }).join('').toUpperCase() || '?';
  _set('hc-titulo','Historial — ' + cli.nombre);
  _set('hc-avatar', cli.iniciales || iniciales);
  _set('hc-nombre',cli.nombre);
  document.getElementById('hc-tel').innerHTML = '<i class="ti ti-phone" style="font-size:12px"></i> ' + (cli.tel||cli.telefono||'—');
  document.getElementById('hc-email').innerHTML = '<i class="ti ti-mail" style="font-size:12px"></i> ' + (cli.email||cli.mail||'—');
  document.getElementById('hc-dir').innerHTML = '<i class="ti ti-map-pin" style="font-size:12px"></i> ' + (cli.dir||'—');
  var cliActivo = cli.estado === 'activo' || cli.activo !== false;
  document.getElementById('hc-estado-badge').innerHTML =
    '<label class="toggle-sw" title="' + (cliActivo ? 'Activo — clic para dar de baja' : 'Inactivo — clic para reactivar') + '">' +
    '<input type="checkbox" ' + (cliActivo ? 'checked' : '') + ' onchange="toggleActivoCliente(\'' + cli.id + '\')">' +
    '<span class="toggle-knob"></span></label>' +
    '<span style="font-size:12px;color:var(--text3);margin-left:8px">' + (cliActivo ? 'Activo' : 'Inactivo') + '</span>';

  // Filtro estricto por ID — nunca por nombre para evitar mezclar sucursales
  function filtrarPorCliente(lista) {
    var idsCliente = [cli.fbKey, cli.id, cli.codigo, id].map(function(x){ return String(x||'').trim(); }).filter(Boolean);
    return (lista || []).filter(function(v) {
      return idsCliente.indexOf(String(v.clienteFbKey||'').trim()) >= 0 ||
             idsCliente.indexOf(String(v.clienteKey||'').trim()) >= 0 ||
             idsCliente.indexOf(String(v.idClienteOriginal||'').trim()) >= 0 ||
             idsCliente.indexOf(String(v.clienteId||'').trim()) >= 0 ||
             idsCliente.indexOf(String(v.idCliente||'').trim()) >= 0;
    });
  }

  // KPIs reales desde ventasList
  var vReales = filtrarPorCliente(ventasList);
  var totalReal = vReales.reduce(function(s,v){ return s+(parseFloat(v.total)||0); }, 0);
  var saldoReal = vReales.filter(function(v){ return v.estadoPago !== 'pago_total'; })
                         .reduce(function(s,v){ return s+(parseFloat(v.total)||0); }, 0);
  var totalDisplay = totalReal > 0 ? totalReal : (parseFloat(cli.total)||0);
  var saldoDisplay = totalReal > 0 ? saldoReal : (parseFloat(cli.saldo)||0);
  _set('hc-total','$' + Math.round(totalDisplay).toLocaleString('es-AR'));
  var saldoEl = document.getElementById('hc-saldo');
  if (saldoEl) {
    saldoEl.textContent = '$' + Math.round(saldoDisplay).toLocaleString('es-AR');
    saldoEl.style.color = saldoDisplay > 0 ? 'var(--amber)' : 'var(--green)';
  }
  _set('hc-saldo-sub', saldoDisplay > 0 ? 'pendiente de cobro' : 'al día');
  _set('hc-equipos', vReales.length || (cli.equipos||0));
  _set('hc-garantia-sub', 'ventas registradas');

  // Tab ventas
  var ventas = filtrarPorCliente(ventasList);
  var vBody = document.getElementById('hc-ventas-body');
  if (vBody) {
    vBody.innerHTML = ventas.length ? ventas.map(function(v) {
      var t = parseFloat(v.total)||0;
      return '<tr>' +
        '<td style="font-weight:500;font-family:monospace;font-size:12px">' + (v.id||'') + '</td>' +
        '<td style="color:var(--text3)">' + _mostrarFecha(v.fecha) + '</td>' +
        '<td class="tr" style="font-weight:500">$' + (parseFloat(t)||0).toLocaleString('es-AR') + '</td>' +
        '<td class="tr">' + ventaEstadoBadge(v.estadoPago) + '</td>' +
        '<td class="tr">' + ventaEstadoInstBadge(v.estadoInst) + '</td>' +
        '<td><button class="btn btn-sm btn-icon" onclick="verDetalleVenta(this.dataset.vid)" data-vid="' + v.id + '"><i class="ti ti-eye" style="font-size:13px"></i></button></td>' +
      '</tr>';
    }).join('') : '<tr><td colspan="6" style="color:var(--text3);text-align:center;padding:16px">Sin ventas registradas</td></tr>';
  }

  // Tab pagos
  const pBody = document.getElementById('hc-pagos-body');
  var idsClientePagos = [cli.fbKey, cli.id, cli.codigo, id].map(function(x){ return String(x||'').trim(); }).filter(Boolean);
  const pagosEmbHist = ventas.flatMap(v => (Array.isArray(v.pagos) ? v.pagos : []).map(p => ({...p, ventaId:v.id, ventaFbKey:v.fbKey||''})));
  const pagosGlobalHist = (window._pagosListaActual||[]).filter(function(p){
    return idsClientePagos.indexOf(String(p.clienteFbKey||'').trim()) >= 0 ||
      idsClientePagos.indexOf(String(p.clienteKey||'').trim()) >= 0 ||
      idsClientePagos.indexOf(String(p.clienteId||'').trim()) >= 0 ||
      idsClientePagos.indexOf(String(p.idCliente||'').trim()) >= 0;
  });
  const pagosVistosHist = {};
  const todosLosPagos = pagosGlobalHist.concat(pagosEmbHist).filter(function(p){
    var k = String(p.fbKey || p.id || p.key || '') || [p.fecha||'',p.monto||0,p.medio||p.medioPago||'',p.venta||p.ventaId||p.ventaFbKey||''].join('|');
    if (pagosVistosHist[k]) return false;
    pagosVistosHist[k] = true;
    return true;
  });
  pBody.innerHTML = todosLosPagos.length ? todosLosPagos.map(p => `<tr>
    <td>${escapeHTML(p.fecha)}</td>
    <td style="font-weight:500">${escapeHTML(p.ventaId)}</td>
    <td>${escapeHTML(p.medio)}</td>
    <td class="tr" style="color:var(--green);font-weight:500">$${(parseFloat(p.monto)||0).toLocaleString('es-AR')}</td>
    <td class="tr" style="color:${p.saldo>0?'var(--amber)':'var(--text3)'}">$${(parseFloat(p.saldo)||0).toLocaleString('es-AR')}</td>
  </tr>`).join('') : '<tr><td colspan="5" style="color:var(--text3);text-align:center;padding:16px">Sin pagos registrados</td></tr>';

  // Tab presupuestos — filtrar por ID real; nombre solo como compatibilidad legacy
  var pptos = typeof pptoData !== 'undefined' ? pptoData.filter(function(p) {
    return _svRegistroPerteneceCliente(p, cli, true);
  }) : [];
  const ppBody = document.getElementById('hc-ppto-body');
  ppBody.innerHTML = pptos.length ? pptos.map(p => `<tr>
    <td style="font-weight:500">${escapeHTML(p.id)}</td>
    <td>${escapeHTML(p.fecha)}</td>
    <td class="tr" style="font-weight:500">$${(parseFloat(p.total)||0).toLocaleString('es-AR')}</td>
    <td class="tr">${pptoStateBadge ? pptoStateBadge(p.estado) : p.estado}</td>
    <td><button class="btn btn-sm btn-icon" onclick="verPpto('${p.id}')"><i class="ti ti-eye" style="font-size:13px"></i></button></td>
  </tr>`).join('') : '<tr><td colspan="5" style="color:var(--text3);text-align:center;padding:16px">Sin presupuestos</td></tr>';

  // Tab tickets
  const tickets = ventas.flatMap(v => Array.isArray(v.tickets) ? v.tickets : []);
  const tBody = document.getElementById('hc-tickets-body');
  tBody.innerHTML = tickets.length ? tickets.map(t => `<tr>
    <td style="font-weight:500">${escapeHTML(t.n)}</td>
    <td>${escapeHTML(t.desc)}</td>
    <td class="tr"><span class="badge b-red">${escapeHTML(t.prio)}</span></td>
    <td class="tr"><span class="badge b-amber">${escapeHTML(t.est)}</span></td>
  </tr>`).join('') : '<tr><td colspan="4" style="color:var(--text3);text-align:center;padding:16px">Sin tickets</td></tr>';

  // Tab equipos
  const equipos = ventas.flatMap(v => (Array.isArray(v.equipos) ? v.equipos : []).map(e => ({...e, ventaId:v.id})));
  const eBody = document.getElementById('hc-eq-body');
  eBody.innerHTML = equipos.length ? equipos.map(e => `<tr>
    <td>${escapeHTML(e.eq)}</td>
    <td style="color:var(--text3)">${escapeHTML(e.serie)}</td>
    <td>${escapeHTML(e.inst)}</td>
    <td class="tr">${escapeHTML(e.vence)}</td>
    <td class="tr"><span class="badge b-green">Vigente</span></td>
  </tr>`).join('') : '<tr><td colspan="5" style="color:var(--text3);text-align:center;padding:16px">Sin equipos registrados</td></tr>';

  // Timeline consolidado (no reemplaza las solapas actuales)
  if (typeof renderClienteTimeline === 'function') renderClienteTimeline(cli, ventas, pptos, todosLosPagos);

  // Activar tab ventas por defecto para no cambiar el flujo actual
  switchHistTab('ventas', document.querySelector('.hist-tab-btn[onclick*="ventas"]'));

  // Huella para detectar cambios externos mientras se está mirando este historial
  window._histClienteHuella = JSON.stringify({cli: cli, ventas: ventas});
}

function renderClienteTimeline(cli, ventas, pptos, pagos) {
  var body = document.getElementById('hc-timeline-body');
  if (!body || !cli) return;
  function safe(v){ return (typeof escapeHTML === 'function') ? escapeHTML(v || '') : String(v || '').replace(/[&<>"']/g, function(c){ return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]; }); }
  function fecha(v){ return (v || '').slice(0,10) || '—'; }
  function ts(v){ var d = Date.parse(fecha(v)); return isNaN(d) ? 0 : d; }
  function money(v){ return '$' + Math.round(parseFloat(v)||0).toLocaleString('es-AR'); }
  var eventos = [];

  (pptos || []).forEach(function(p){
    eventos.push({
      fecha: p.fecha || p.createdAt || '',
      icon: 'ti-file-description',
      color: 'var(--blue)',
      titulo: 'Presupuesto ' + (p.id || p.numero || ''),
      detalle: (p.estado || '—') + ' · ' + money(p.total),
      accion: p.id ? 'verPpto(\'' + String(p.id).replace(/'/g,"\\'") + '\')' : ''
    });
    if (p.estado === 'convertido' || p.ventaId || p.ventaGeneradaId) {
      eventos.push({ fecha: p.fechaConversion || p.convertidoFecha || p.fecha || '', icon:'ti-arrow-right', color:'var(--green)', titulo:'Presupuesto convertido a venta', detalle: p.ventaId || p.ventaGeneradaId || p.id || '' });
    }
  });

  (ventas || []).forEach(function(v){
    eventos.push({
      fecha: v.fecha || v.createdAt || '',
      icon: 'ti-receipt',
      color: 'var(--green)',
      titulo: 'Venta ' + (v.id || v.numero || ''),
      detalle: (v.estadoPago || '—') + ' · ' + money(v.total),
      accion: v.id ? 'verDetalleVenta(\'' + String(v.id).replace(/'/g,"\\'") + '\')' : ''
    });
    var ot = (typeof otData !== 'undefined' ? (otData || []) : []).find(function(o){ return _svRegistroPerteneceVenta(o, v); });
    if (ot) {
      eventos.push({
        fecha: ot.fecha || ot.fechaProgramada || v.fecha || '',
        icon: 'ti-clipboard-list',
        color: ot.estado === 'completada' ? 'var(--green)' : 'var(--amber)',
        titulo: 'OT ' + (ot.id || ot.numero || ''),
        detalle: (ot.estado || 'pendiente') + (ot.tecnico ? ' · ' + ot.tecnico : ''),
        accion: (ot.fbKey || ot.id) ? 'verOT(\'' + String(ot.fbKey || ot.id).replace(/'/g,"\\'") + '\')' : ''
      });
    }
  });

  (pagos || []).forEach(function(p){
    eventos.push({
      fecha: p.fecha || p.createdAt || '',
      icon: 'ti-cash',
      color: 'var(--green)',
      titulo: 'Pago recibido' + (p.ventaId ? ' · ' + p.ventaId : ''),
      detalle: (p.medio || '—') + ' · ' + money(p.monto),
      accion: p.ventaId ? 'verDetalleVenta(\'' + String(p.ventaId).replace(/'/g,"\\'") + '\')' : ''
    });
  });

  var otsSueltas = (typeof otData !== 'undefined' ? (otData || []) : []).filter(function(o){
    if (o.ventaId || o.idVenta || o.ventaFbKey || o.ventaKey) return false;
    return _svRegistroPerteneceCliente(o, cli, true);
  });
  otsSueltas.forEach(function(o){
    eventos.push({
      fecha: o.fecha || o.fechaProgramada || '',
      icon: 'ti-clipboard-list',
      color: o.estado === 'completada' ? 'var(--green)' : 'var(--amber)',
      titulo: 'OT ' + (o.id || o.numero || ''),
      detalle: (o.estado || 'pendiente') + (o.tecnico ? ' · ' + o.tecnico : ''),
      accion: (o.fbKey || o.id) ? 'verOT(\'' + String(o.fbKey || o.id).replace(/'/g,"\\'") + '\')' : ''
    });
  });

  eventos = eventos.filter(function(e){ return e.fecha || e.titulo; }).sort(function(a,b){ return ts(b.fecha) - ts(a.fecha); }).slice(0,80);
  body.innerHTML = eventos.length ? eventos.map(function(e){
    var btn = e.accion ? '<button class="btn btn-sm" onclick="' + e.accion + '"><i class="ti ti-eye"></i> Ver</button>' : '';
    return '<div style="display:flex;align-items:center;gap:12px;padding:10px 12px;border:0.5px solid var(--border);border-radius:var(--radius);background:var(--bg2)">' +
      '<div style="width:32px;height:32px;border-radius:50%;background:var(--bg3);display:flex;align-items:center;justify-content:center;color:' + e.color + ';flex-shrink:0"><i class="ti ' + e.icon + '"></i></div>' +
      '<div style="flex:1;min-width:0">' +
        '<div style="font-size:13px;font-weight:600;color:var(--text)">' + safe(e.titulo) + '</div>' +
        '<div style="font-size:12px;color:var(--text3);margin-top:2px">' + safe(fecha(e.fecha)) + ' · ' + safe(e.detalle) + '</div>' +
      '</div>' + btn +
    '</div>';
  }).join('') : '<div style="text-align:center;color:var(--text3);padding:18px">Sin movimientos para mostrar</div>';
}

function switchHistTab(tab, btn) {
  document.querySelectorAll('.hist-sec').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.hist-tab-btn').forEach(b => b.classList.remove('active'));
  const sec = document.getElementById('hist-' + tab);
  if (sec) sec.classList.add('active');
  if (btn) btn.classList.add('active');
  if (tab === 'credenciales') credCargar();
}
// CREDENCIALES DEL CLIENTE
// Ruta nueva: sisventas/credencialesPorCliente/{clienteFbKey}/{credKey}
// Ruta legacy de respaldo: sisventas/credenciales/{clienteId}/{credKey}
var _credClienteId = null;
var _credClienteLegacyId = null;
var _credEditKey = null;

var CRED_TIPO_LABELS = {
  dvr:'DVR / NVR', alarma:'Panel de alarma', app:'App móvil',
  router:'Router / Red', camara:'Cámara IP', domotica:'Domótica', otro:'Otro'
};
var CRED_TIPO_ICONOS = {
  dvr:'ti-device-desktop-analytics', alarma:'ti-shield-check', app:'ti-device-mobile',
  router:'ti-router', camara:'ti-camera', domotica:'ti-smart-home', otro:'ti-key'
};

function credSetCliente(clienteId, clienteObj) {
  clienteObj = clienteObj || {};
  _credClienteId = String(clienteObj.fbKey || clienteId || '');
  _credClienteLegacyId = String(clienteObj.id || clienteObj.codigo || clienteId || '');
}
function credRutaNueva(itemKey) {
  return 'sisventas/credencialesPorCliente/' + _credClienteId + (itemKey ? '/' + itemKey : '');
}
function credRutaLegacy(itemKey) {
  return 'sisventas/credenciales/' + _credClienteLegacyId + (itemKey ? '/' + itemKey : '');
}
function credGetGrupo() {
  return window.fbGet(window.fbRef(window.fbDB, credRutaNueva())).then(function(snap) {
    var data = snap.val();
    if (data) return { data:data, fuente:'nueva' };
    if (!_credClienteLegacyId || _credClienteLegacyId === _credClienteId) return { data:null, fuente:'nueva' };
    return window.fbGet(window.fbRef(window.fbDB, credRutaLegacy())).then(function(legacySnap) {
      return { data: legacySnap.val(), fuente:'legacy' };
    });
  });
}
function credGetItem(fbKey) {
  return window.fbGet(window.fbRef(window.fbDB, credRutaNueva(fbKey))).then(function(snap) {
    var data = snap.val();
    if (data) return { data:data, fuente:'nueva' };
    if (!_credClienteLegacyId || _credClienteLegacyId === _credClienteId) return { data:null, fuente:'nueva' };
    return window.fbGet(window.fbRef(window.fbDB, credRutaLegacy(fbKey))).then(function(legacySnap) {
      return { data: legacySnap.val(), fuente:'legacy' };
    });
  });
}

function credCargar() {
  if (!_credClienteId || !window.fbDB) return;
  var lista = document.getElementById('hc-cred-lista');
  if (!lista) return;
  lista.innerHTML = '<div style="padding:20px;text-align:center;color:var(--text3);font-size:13px">Cargando...</div>';
  credCerrarEditor();
  credGetGrupo().then(function(res) {
    var data = res.data;
    if (!data) {
      lista.innerHTML = '<div style="padding:24px;text-align:center;color:var(--text3);font-size:13px">Sin credenciales cargadas para este cliente</div>';
      return;
    }
    var items = Object.entries(data).map(function(e){ return Object.assign({fbKey:e[0]}, e[1]); });
    lista.innerHTML = items.map(function(c) {
      var ico = CRED_TIPO_ICONOS[c.tipo] || 'ti-key';
      var lbl = CRED_TIPO_LABELS[c.tipo] || c.tipo;
      var puedeEditar = currentRole === 'admin' || currentRole === 'administrativo';
      return '<div style="background:var(--bg3);border-radius:var(--radius);padding:14px;display:flex;gap:14px;align-items:flex-start">' +
        '<div style="width:36px;height:36px;border-radius:8px;background:var(--blue-bg);color:var(--blue);display:flex;align-items:center;justify-content:center;flex-shrink:0">' +
          '<i class="ti '+ico+'" style="font-size:18px"></i></div>' +
        '<div style="flex:1;min-width:0">' +
          '<div style="font-weight:500;font-size:13px">'+escapeHTML(c.desc||lbl)+'</div>' +
          '<div style="font-size:11px;color:var(--text3);margin-bottom:8px">'+lbl+'</div>' +
          '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:6px">' +
            (c.user ? '<div><span style="font-size:10px;color:var(--text3);display:block">Usuario</span><span style="font-size:13px;font-family:monospace">'+escapeHTML(c.user)+'</span></div>' : '') +
            (c.pass ? '<div><span style="font-size:10px;color:var(--text3);display:block">Contraseña</span>' +
              '<div style="display:flex;align-items:center;gap:6px">' +
                '<span style="font-size:13px;font-family:monospace" id="cred-pass-view-'+c.fbKey+'">••••••••</span>' +
                '<button onclick="credMostrarPass(\''+c.fbKey+'\',\''+escapeHTML(c.pass||'').replace(/'/g,"\\'")+'\')" style="background:none;border:none;cursor:pointer;color:var(--text3);padding:0" title="Ver"><i class="ti ti-eye" style="font-size:14px"></i></button>' +
              '</div></div>' : '') +
            (c.ip ? '<div><span style="font-size:10px;color:var(--text3);display:block">IP / Dirección</span><span style="font-size:12px;font-family:monospace">'+escapeHTML(c.ip)+(c.puerto?':'+escapeHTML(c.puerto):'')+'</span></div>' : '') +
          '</div>' +
          (c.notas ? '<div style="margin-top:8px;font-size:12px;color:var(--text2);font-style:italic">'+escapeHTML(c.notas)+'</div>' : '') +
        '</div>' +
        (puedeEditar ? '<button class="btn btn-sm btn-icon" onclick="credAbrirEditor(\''+c.fbKey+'\')" title="Editar"><i class="ti ti-edit" style="font-size:14px"></i></button>' : '') +
      '</div>';
    }).join('');
  }).catch(function(e){ lista.innerHTML = '<div style="padding:14px;color:var(--red);font-size:12px">Error al cargar: '+e.message+'</div>'; });
}

function credMostrarPass(key, pass) {
  var el = document.getElementById('cred-pass-view-' + key);
  if (!el) return;
  if (el.textContent === '••••••••') {
    el.textContent = pass;
    setTimeout(function(){ if(el) el.textContent='••••••••'; }, 10000); // ocultar después de 10s
  } else {
    el.textContent = '••••••••';
  }
}

function credTogglePass() {
  var inp = document.getElementById('cred-pass');
  var ico = document.getElementById('cred-pass-ico');
  if (!inp) return;
  if (inp.type === 'password') { inp.type = 'text'; ico.className='ti ti-eye-off'; }
  else { inp.type = 'password'; ico.className='ti ti-eye'; }
}

function credAgregarNueva() {
  if (currentRole !== 'admin' && currentRole !== 'administrativo') { notify('Sin permisos para agregar credenciales'); return; }
  _credEditKey = null;
  document.getElementById('hc-cred-editor-titulo').textContent = 'Nueva credencial';
  document.getElementById('cred-tipo').value = 'dvr';
  document.getElementById('cred-desc').value = '';
  document.getElementById('cred-user').value = '';
  document.getElementById('cred-pass').value = '';
  document.getElementById('cred-pass').type = 'password';
  document.getElementById('cred-pass-ico').className = 'ti ti-eye';
  document.getElementById('cred-ip').value = '';
  document.getElementById('cred-puerto').value = '';
  document.getElementById('cred-notas').value = '';
  document.getElementById('cred-btn-eliminar').style.display = 'none';
  document.getElementById('hc-cred-editor').style.display = '';
  document.getElementById('hc-cred-editor').scrollIntoView({ behavior:'smooth', block:'start' });
}

function credAbrirEditor(fbKey) {
  if (currentRole !== 'admin' && currentRole !== 'administrativo') return;
  _credEditKey = fbKey;
  credGetItem(fbKey).then(function(res) {
    var c = res.data; if (!c) return;
    document.getElementById('hc-cred-editor-titulo').textContent = 'Editar credencial';
    document.getElementById('cred-tipo').value  = c.tipo  || 'dvr';
    document.getElementById('cred-desc').value  = c.desc  || '';
    document.getElementById('cred-user').value  = c.user  || '';
    document.getElementById('cred-pass').value  = c.pass  || '';
    document.getElementById('cred-pass').type   = 'password';
    document.getElementById('cred-pass-ico').className = 'ti ti-eye';
    document.getElementById('cred-ip').value    = c.ip    || '';
    document.getElementById('cred-puerto').value= c.puerto|| '';
    document.getElementById('cred-notas').value = c.notas || '';
    document.getElementById('cred-btn-eliminar').style.display = '';
    document.getElementById('hc-cred-editor').style.display = '';
    document.getElementById('hc-cred-editor').scrollIntoView({ behavior:'smooth', block:'start' });
  });
}

function credCerrarEditor() {
  var ed = document.getElementById('hc-cred-editor');
  if (ed) ed.style.display = 'none';
  _credEditKey = null;
}

function credGuardar() {
  if (!_credClienteId || !window.fbDB) { notify('Sin conexión'); return; }
  var tipo  = document.getElementById('cred-tipo').value;
  var desc  = document.getElementById('cred-desc').value.trim();
  var user  = document.getElementById('cred-user').value.trim();
  var pass  = document.getElementById('cred-pass').value.trim();
  if (!user && !pass) { notify('Ingresá al menos usuario o contraseña'); return; }
  var datos = {
    tipo, desc: desc || CRED_TIPO_LABELS[tipo],
    user, pass,
    ip:      document.getElementById('cred-ip').value.trim(),
    puerto:  document.getElementById('cred-puerto').value.trim(),
    notas:   document.getElementById('cred-notas').value.trim(),
    ts:      Date.now(),
    editadoPor: currentUser || ''
  };
  var path = credRutaNueva(_credEditKey || '');
  var op = _credEditKey
    ? window.fbUpdate(window.fbRef(window.fbDB, path), datos)
    : window.fbPush(window.fbRef(window.fbDB, credRutaNueva()), datos);
  op.then(function() {
    notify('✓ Credencial guardada');
    credCerrarEditor();
    credCargar();
  }).catch(function(e){ notify('Error: '+e.message); });
}

function credEliminar() {
  if (!_credEditKey || !_credClienteId) return;
  if (!confirm('¿Eliminar esta credencial? No se puede deshacer.')) return;
  window.fbRemove(window.fbRef(window.fbDB, credRutaNueva(_credEditKey)))
    .then(function(){ notify('Credencial eliminada'); credCerrarEditor(); credCargar(); })
    .catch(function(e){ notify('Error: '+e.message); });
}

function verDetalleVenta(ventaId) {
  var venta = _svResolverVentaRegistro(ventaId);
  if (!venta) { notify('Venta no encontrada'); return; }
  window._ventaDetActualId = ventaId;

  var lv  = document.getElementById('ventas-list-view');
  var dv  = document.getElementById('venta-detalle-view');
  if (lv)  lv.style.display  = 'none';
  var st1 = document.getElementById('ventas-list-stats-global');
  if (st1) st1.style.display = 'none';
  if (dv) {
    dv.style.display = 'block';
    renderDetalleVenta(venta);
  } else {
    crearVistaDetalleVenta(venta);
  }
}
function renderDetalleVenta(v) {
  window._ventaDetalleActual = v;
  var dv = document.getElementById('venta-detalle-view');
  if (!dv) return;

  var ESTADO_PAGO = {
    'pendiente_pago': { label:'Pendiente de pago', color:'var(--amber)', icon:'ti-clock' },
    'seniado':        { label:'Señado',             color:'var(--blue)',  icon:'ti-coin' },
    'pago_total':     { label:'Pago total',         color:'var(--green)', icon:'ti-check' },
  };
  var ESTADO_INST = {
    'pendiente_inst': { label:'No instalado',   color:'var(--amber)', icon:'ti-clock' },
    'en_instalacion': { label:'En instalación', color:'var(--blue)',  icon:'ti-tools' },
    'instalado':      { label:'Instalado',      color:'var(--green)', icon:'ti-check' },
    'con_garantia':   { label:'Con garantía',   color:'var(--purple)',icon:'ti-shield-check' },
  };

  function _estadoPagoPorImporteDetalle(totalVenta, pagadoVenta) {
    totalVenta = parseFloat(totalVenta) || 0;
    pagadoVenta = parseFloat(pagadoVenta) || 0;
    if (totalVenta > 0 && pagadoVenta >= (totalVenta - 1)) return 'pago_total';
    if (pagadoVenta > 0) return 'seniado';
    return 'pendiente_pago';
  }

  function _formatearFacturaDetalleVenta(venta) {
    if (!venta) return 'Sin factura';
    if (venta.facturaNumero) return String(venta.facturaNumero);
    if (venta.nroFactura) return String(venta.nroFactura);
    var f = venta.factura;
    if (!f) return venta.facturada ? 'Emitida' : 'Sin factura';
    if (typeof f === 'string') return f;
    if (typeof f === 'object') {
      var tipo = f.tipo || f.tipoComprobante || f.comprobanteTipo || f.comprobante_tipo || f.cbteTipo || 'Factura';
      var numero = f.numero || f.nro || f.numeroComprobante || f.comprobante || f.cbteNumero || f.numeroDesde || '';
      if (numero) return String(tipo) + ' ' + String(numero);
      if (f.cae) return 'Emitida · CAE ' + String(f.cae);
      return 'Emitida';
    }
    return String(f);
  }

  function _formatearOTAsociadaDetalleVenta(venta) {
    if (!venta) return '—';
    var raw = String(venta.otId || venta.ordenTrabajoId || venta.ot || '').trim();
    var idsVenta = [venta.id, venta.fbKey, venta.numero].map(function(x){ return String(x||'').trim(); }).filter(Boolean);
    var ot = (window.otData || []).find(function(o){
      if (!o) return false;
      var idsOT = [o.id, o.fbKey, o.otId, o.numero].map(function(x){ return String(x||'').trim(); }).filter(Boolean);
      if (raw && idsOT.indexOf(raw) >= 0) return true;
      var idsOTVenta = [o.ventaId, o.venta, o.ventaNumero, o.ventaFbKey].map(function(x){ return String(x||'').trim(); }).filter(Boolean);
      return idsVenta.some(function(idv){ return idsOTVenta.indexOf(idv) >= 0; });
    });
    if (ot) return String(ot.id || ot.numero || 'OT vinculada');
    if (raw && /^OT[-\s]?\d+/i.test(raw)) return raw;
    return raw ? 'OT vinculada' : '—';
  }

  var ep = ESTADO_PAGO[v.estadoPago] || { label: v.estadoPago||'—', color:'var(--text3)', icon:'ti-minus' };
  var ei = ESTADO_INST[v.estadoInst] || { label: v.estadoInst||'—', color:'var(--text3)', icon:'ti-minus' };
  var total    = parseFloat(v.total) || 0;
  var descuento = parseFloat(v.descuento) || 0; // monto en pesos
  var iva      = parseFloat(v.iva) || 0;
  // el detalle debe respetar conIva=false y no mostrar ni sumar impuesto.
  if (v.conIva === false) {
    iva = 0;
    var totalSinIva = parseFloat(v.subtotal) || 0;
    if (!totalSinIva && v.items && v.items.length) {
      totalSinIva = v.items.reduce(function(s, it) {
        return s + (parseFloat(it.sub) || Math.round((parseFloat(it.qty)||1) * (parseFloat(it.punit)||0) * (1 - (parseFloat(it.disc||it.descuento)||0)/100)));
      }, 0);
      var dg = parseFloat(v.descuentoGeneral)||0;
      if (dg > 0) totalSinIva = totalSinIva - Math.round(totalSinIva * dg / 100);
    }
    if (totalSinIva > 0) total = totalSinIva;
  }

  // Subtotal: si no está guardado, calcularlo desde los ítems
  var subtotal = parseFloat(v.subtotal) || 0;
  if (!subtotal && v.items && v.items.length) {
    subtotal = v.items.reduce(function(s, it) {
      var sub = parseFloat(it.sub) || Math.round((parseFloat(it.qty)||1) * (parseFloat(it.punit)||0) * (1 - (parseFloat(it.disc||it.descuento)||0)/100));
      return s + sub;
    }, 0);
  }
  if (!subtotal) subtotal = total + descuento; // fallback: total + descuento = subtotal original
  var items = v.items || [];
  var subtotalBrutoDetalle = items.length ? items.reduce(function(s,it){ return s + ((parseFloat(it.qty)||1) * (parseFloat(it.punit)||0)); },0) : (subtotal + descuento);
  var netoDetalle = Math.max(0, subtotalBrutoDetalle - descuento);
  var costoDetalle = parseFloat(v.costoTotal)||0;
  if (!costoDetalle && items.length) {
    costoDetalle = items.reduce(function(s,it){
      return s + obtenerCostoItemVenta(it);
    },0);
  }
  var gananciaDetalle = netoDetalle - costoDetalle;
  var margenDetalle = netoDetalle > 0 ? (gananciaDetalle / netoDetalle * 100) : 0;
  var idsVentaDetalle = [v.fbKey, v.id, v.numero, v.nro, v.codigo].map(function(x){ return String(x||'').trim(); }).filter(Boolean);
  var ventaIdNum = String(v.id||'').replace(/[^0-9]/g,'');
  var pagosGlobales = (window._historialPagosCompleto||[]).filter(function(p) {
    if (p && (p.anulado || String(p.estado||'').toLowerCase()==='anulado')) return false;
    var pVenta = String(p.ventaFbKey||p.ventaKey||p.venta||p.ventaId||p.idVenta||p.nroVenta||p.numeroVenta||'');
    var pNum   = pVenta.replace(/[^0-9]/g,'');
    if (idsVentaDetalle.indexOf(pVenta) >= 0) return true;
    return ventaIdNum && pNum === ventaIdNum;
  });
  var pagosEmbebidos = Array.isArray(v.pagos) ? v.pagos : [];
  // Unir fuentes de pago sin duplicar. El estado visual sale del importe real, no del flag legacy.
  var vistosPagos = {};
  var pagos = pagosGlobales.concat(pagosEmbebidos).filter(function(p){
    var k = String(p.fbKey || p.id || '') || [p.fecha || '', p.medio || '', p.monto || 0].join('|');
    if (vistosPagos[k]) return false;
    vistosPagos[k] = true;
    return true;
  });
  var pagadoPorPagos = pagos.reduce(function(s,p){ return s+(parseFloat(p.monto)||0); }, 0);
  var pagadoDirecto = parseFloat(v.totalPagado || v.pagado || v.montoPagado) || 0;
  var pagado = Math.max(pagadoPorPagos, pagadoDirecto);
  var estadoPagoReal = _estadoPagoPorImporteDetalle(total, pagado);
  ep = ESTADO_PAGO[estadoPagoReal] || ep;
  var saldo = Math.max(0, total - pagado);
  var porcPagado = total > 0 ? Math.min(100, (pagado / total) * 100) : 0;
  var comisionDetalle = 0;
  if (Array.isArray(v.comisiones)) {
    comisionDetalle = v.comisiones.reduce(function(s,c){ return s + (parseFloat(c.monto)||0); }, 0);
  } else {
    comisionDetalle = parseFloat(v.comisionMonto || v.comision || 0) || 0;
  }
  var otAsociada = _formatearOTAsociadaDetalleVenta(v);
  var facturaTxt = _formatearFacturaDetalleVenta(v);
  var puedeVerInternosVenta = (currentRole === 'admin');
  var puedeMoverVentaAPptoDetalle = typeof window.tienePermiso === 'function'
    ? window.tienePermiso('ventas.moverPresupuesto')
    : (typeof esAdminOAdministrativo === 'function' ? esAdminOAdministrativo() : ['admin','administrativo'].indexOf(String(currentRole||'').toLowerCase()) >= 0);
  var puedeEliminarVentaDetalle = typeof window.tienePermiso === 'function'
    ? window.tienePermiso('ventas.eliminar')
    : String(currentRole || '').toLowerCase() === 'admin';
  var metricVentaHtml = '<div class="metrics" id="venta-detalle-metricas" style="margin-bottom:12px;grid-template-columns:repeat(' + (puedeVerInternosVenta ? '4' : '3') + ',minmax(0,1fr))">' +
    '<div class="metric"><div class="m-label">Total venta</div><div class="m-value">$' + Math.round(total).toLocaleString('es-AR') + '</div><div class="m-sub">' + ep.label + '</div></div>' +
    '<div class="metric"><div class="m-label">Pagado</div><div class="m-value" style="color:var(--green)">$' + Math.round(pagado).toLocaleString('es-AR') + '</div><div class="m-sub">' + porcPagado.toFixed(0) + '% de la venta</div></div>' +
    '<div class="metric"><div class="m-label">Saldo</div><div class="m-value" style="color:' + (saldo > 0 ? 'var(--amber)' : 'var(--green)') + '">$' + Math.round(saldo).toLocaleString('es-AR') + '</div><div class="m-sub">' + (saldo > 0 ? 'pendiente de cobro' : 'cancelado') + '</div></div>' +
    (puedeVerInternosVenta ? '<div class="metric"><div class="m-label">Ganancia</div><div class="m-value" style="color:' + (gananciaDetalle >= 0 ? 'var(--green)' : 'var(--red)') + '">$' + Math.round(gananciaDetalle).toLocaleString('es-AR') + '</div><div class="m-sub">margen ' + margenDetalle.toFixed(1) + '%</div></div>' : '') +
  '</div>' +
  '<div class="metrics" id="venta-detalle-seguimiento" style="margin-bottom:12px;grid-template-columns:repeat(4,minmax(0,1fr))">' +
    '<div class="metric"><div class="m-label">Facturación</div><div class="m-value" style="font-size:18px">' + escapeHTML(String(facturaTxt)) + '</div><div class="m-sub">estado fiscal</div></div>' +
    '<div class="metric"><div class="m-label">Instalación</div><div class="m-value" style="font-size:18px;color:' + ei.color + '">' + ei.label + '</div><div class="m-sub">estado OT/inst.</div></div>' +
    '<div class="metric"><div class="m-label">OT asociada</div><div class="m-value" style="font-size:18px">' + escapeHTML(String(otAsociada || '—')) + '</div><div class="m-sub">seguimiento técnico</div></div>' +
    '<div class="metric"><div class="m-label">Última modif.</div><div class="m-value" style="font-size:18px">' + escapeHTML(String(v.editadoEn || v.actualizado || v.fecha || '—')) + '</div><div class="m-sub">auditoría de venta</div></div>' +
  '</div>';

  dv.innerHTML =
    // Header — fila 1: volver + título
    '<div style="display:flex;align-items:center;gap:12px;margin-bottom:12px;flex-wrap:wrap">' +
      '<button class="btn btn-sm" onclick="volverListaVentas()">' +
        '<i class="ti ti-arrow-left"></i> Volver' +
      '</button>' +
      '<div style="flex:1;min-width:140px">' +
        '<div style="font-size:18px;font-weight:700">Venta ' + v.id + '</div>' +
        '<div style="font-size:13px;color:var(--text3)">' + v.fecha + ' · ' + (v.usuario||'Sistema') + '</div>' +
      '</div>' +
    '</div>' +
    // Header — fila 2: acciones (envuelve en mobile)
    '<div style="display:flex;align-items:center;gap:8px;margin-bottom:20px;flex-wrap:wrap">' +
      (v.factura
        ? '<button class="btn btn-sm" style="color:var(--green);border-color:var(--green)" onclick="verFacturaEmitida(\''+v.factura.pdf_url+'\',\''+v.factura.cae+'\')" title="CAE: '+v.factura.cae+'"><i class="ti ti-file-check"></i> Facturada</button>'
        : '<button class="btn btn-sm" style="color:var(--blue);border-color:var(--blue)" onclick="abrirModalFactura(this.dataset.vid)" data-vid="'+v.id+'"><i class="ti ti-file-invoice"></i> Facturar</button>'
      ) +
      (puedeEditarVentaPermiso(v) ? '<button class="btn btn-sm" style="color:var(--blue);border-color:var(--blue)" onclick="abrirEditorVenta(\'' + escapeHTML(v.fbKey||'') + '\')" title="Editar"><i class="ti ti-edit"></i> Editar</button>' : '') +
      (puedeMoverVentaAPptoDetalle ? '<button class="btn btn-sm" style="color:var(--amber);border-color:var(--amber)" onclick="moverVentaAPresupuesto(\'' + escapeHTML(v.id||v.fbKey||'') + '\')" title="Mover a presupuestos"><i class="ti ti-arrow-back-up"></i> A presupuesto</button>' : '') +
      '<button class="btn btn-sm" id="venta-detalle-toggle" onclick="toggleVentaDetalle()" title="Cambia si el comprobante muestra precios o no" style="gap:6px">' +
        '<i class="ti ti-eye" id="venta-detalle-icon"></i> <span id="venta-detalle-label">Con detalle</span>' +
      '</button>' +
      (currentRole === 'admin' ? '<button class="btn btn-sm" onclick="toggleCostoCompraDetalleVenta()" title="Muestra u oculta la columna de precio de compra" style="gap:6px;color:var(--amber);border-color:var(--amber)"><i class="ti ' + (window._mostrarCostoCompraDetalleVenta ? 'ti-eye-off' : 'ti-eye') + '"></i> ' + (window._mostrarCostoCompraDetalleVenta ? 'Ocultar compra' : 'Ver compra') + '</button>' : '') +
      '<button class="btn btn-sm" onclick="imprimirVentaActual()" title="Abre el comprobante para imprimir o guardar como PDF"><i class="ti ti-printer"></i> Imprimir comprobante</button>' +
      '<button class="btn btn-sm" style="color:var(--green2,var(--green));border-color:var(--green2,var(--green))" onclick="pdfYWhatsappVenta(\'' + escapeHTML(v.id||v.fbKey||'') + '\')" title="Generar PDF y abrir WhatsApp del cliente"><i class="ti ti-brand-whatsapp"></i> PDF / WhatsApp</button>' +
      (puedeEliminarVentaDetalle ? '<button class="btn btn-sm" style="color:var(--red);border-color:var(--red)" onclick="eliminarVenta(\'' + escapeHTML(v.fbKey||'') + '\')" title="Eliminar venta (también elimina la OT y los pagos vinculados)"><i class="ti ti-trash"></i> Eliminar</button>' : '') +
    '</div>' +

    metricVentaHtml +

    // Cliente y estados
    '<div class="card" style="margin-bottom:12px">' +
      '<div style="display:flex;gap:16px;flex-wrap:wrap;align-items:flex-start">' +
        '<div style="flex:1;min-width:200px">' +
          '<div style="font-size:11px;color:var(--text3);text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px">Cliente</div>' +
          '<div style="font-size:16px;font-weight:600">' + (v.cliente||'—') + '</div>' +
          (v.descripcion ? '<div style="font-size:12px;color:var(--text3);margin-top:4px">' + v.descripcion + '</div>' : '') +
        '</div>' +
        '<div style="display:flex;gap:12px;flex-wrap:wrap">' +
          '<div style="text-align:center;padding:8px 16px;background:var(--bg3);border-radius:8px">' +
            '<i class="ti ' + ep.icon + '" style="color:' + ep.color + ';font-size:20px;display:block;margin-bottom:4px"></i>' +
            '<div style="font-size:11px;color:var(--text3)">Pago</div>' +
            '<div style="font-size:13px;font-weight:600;color:' + ep.color + '">' + ep.label + '</div>' +
          '</div>' +
          '<div style="text-align:center;padding:8px 16px;background:var(--bg3);border-radius:8px">' +
            '<i class="ti ' + ei.icon + '" style="color:' + ei.color + ';font-size:20px;display:block;margin-bottom:4px"></i>' +
            '<div style="font-size:11px;color:var(--text3)">Instalación</div>' +
            '<div style="font-size:13px;font-weight:600;color:' + ei.color + '">' + ei.label + '</div>' +
          '</div>' +
        '</div>' +
      '</div>' +
    '</div>' +

    // Productos
    '<div class="card" style="margin-bottom:12px">' +
      '<div style="font-weight:600;margin-bottom:12px">Productos / Servicios</div>' +
      (items.length
        ? '<table style="width:100%;border-collapse:collapse">' +
            '<thead><tr>' +
              '<th style="text-align:left;font-size:11px;color:var(--text3);font-weight:500;padding:6px 0;border-bottom:1px solid var(--border2)">Descripción</th>' +
              '<th style="text-align:right;font-size:11px;color:var(--text3);font-weight:500;padding:6px 4px;border-bottom:1px solid var(--border2)">Cant.</th>' +
              (currentRole === 'admin' && window._mostrarCostoCompraDetalleVenta ? '<th style="text-align:right;font-size:11px;color:var(--amber);font-weight:500;padding:6px 0;border-bottom:1px solid var(--border2)">P. compra</th>' : '') +
              '<th style="text-align:right;font-size:11px;color:var(--text3);font-weight:500;padding:6px 0;border-bottom:1px solid var(--border2)">P. Unit.</th>' +
              '<th style="text-align:right;font-size:11px;color:var(--text3);font-weight:500;padding:6px 0;border-bottom:1px solid var(--border2)">Subtotal</th>' +
              '<th style="text-align:right;font-size:11px;color:var(--text3);font-weight:500;padding:6px 0;border-bottom:1px solid var(--border2)">Acción</th>' +
            '</tr></thead><tbody>' +
            items.map(function(it) {
              var sub = it.sub || (it.qty * it.punit);
              var costoUnit = obtenerCostoUnitarioDetalleVenta(it);
              var prodRef = productoRefDesdeItem(it);
              var clickAttrs = prodRef ? ' onclick="navegarAProducto(\''+jsStringAttr(prodRef)+'\')" title="Ver producto" style="cursor:pointer"' : '';
              return '<tr'+clickAttrs+'>' +
                '<td style="padding:8px 0;border-bottom:.5px solid var(--border)">' +
                  '<div class="item-prod-mini-line">' +
                  imagenProductoItemHTML(it, '') +
                  '<span>' +
                  (it.cod ? '<span style="font-family:monospace;font-size:11px;color:var(--text3);margin-right:6px">' + it.cod + '</span>' : '') +
                  '<span style="font-size:13px">' + (it.desc||'') + '</span>' +
                  '</span></div>' +
                '</td>' +
                '<td style="text-align:right;padding:8px 4px;border-bottom:.5px solid var(--border);font-size:13px">' + (it.qty||1) + '</td>' +
                (currentRole === 'admin' && window._mostrarCostoCompraDetalleVenta ? '<td style="text-align:right;padding:8px 0;border-bottom:.5px solid var(--border);font-size:13px;color:var(--amber)">$' + Math.round(costoUnit || 0).toLocaleString('es-AR') + '</td>' : '') +
                '<td style="text-align:right;padding:8px 0;border-bottom:.5px solid var(--border);font-size:13px">$' + (it.punit||0).toLocaleString('es-AR') + '</td>' +
                '<td style="text-align:right;padding:8px 0;border-bottom:.5px solid var(--border);font-size:13px;font-weight:500">$' + (sub||0).toLocaleString('es-AR') + '</td>' +
                '<td style="text-align:right;padding:8px 0;border-bottom:.5px solid var(--border);font-size:13px">' + botonVerCompraProducto(it) + '</td>' +
              '</tr>';
            }).join('') +
          '</tbody></table>' +
          // Totales
          '<div style="margin-top:12px;display:flex;justify-content:flex-end">' +
            '<div style="min-width:220px">' +
              '<div style="display:flex;justify-content:space-between;font-size:13px;padding:4px 0;color:var(--text2)"><span>Subtotal bruto</span><span>$' + (parseFloat(subtotalBrutoDetalle)||0).toLocaleString('es-AR') + '</span></div>' +
              (descuento > 0
                ? '<div style="display:flex;justify-content:space-between;font-size:13px;padding:4px 0;color:var(--red)"><span>Descuento</span><span>-$' + (parseFloat(descuento)||0).toLocaleString('es-AR') + '</span></div>'
                : '') +
              '<div style="display:flex;justify-content:space-between;font-size:13px;padding:4px 0;color:var(--text2)"><span>Neto venta</span><span>$' + (parseFloat(netoDetalle)||0).toLocaleString('es-AR') + '</span></div>' +
              (iva > 0
                ? '<div style="display:flex;justify-content:space-between;font-size:13px;padding:4px 0;color:var(--amber)"><span>IVA 21%</span><span>$' + (parseFloat(iva)||0).toLocaleString('es-AR') + '</span></div>'
                : '') +
              '<div style="display:flex;justify-content:space-between;font-size:15px;font-weight:700;padding:8px 0;border-top:1.5px solid var(--border2);margin-top:4px"><span>Total</span><span>$' + (parseFloat(total)||0).toLocaleString('es-AR') + '</span></div>' +
            '</div>' +
          '</div>'
        : '<div style="text-align:center;padding:20px;color:var(--text3)">Sin ítems registrados</div>'
      ) +
    '</div>' +

    (puedeVerInternosVenta ?
      '<div class="card" style="margin-bottom:12px">' +
        '<div style="font-weight:600;margin-bottom:12px">Rentabilidad interna</div>' +
        '<div style="display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px">' +
          '<div class="metric"><div class="m-label">Neto venta</div><div class="m-value">$' + Math.round(netoDetalle).toLocaleString('es-AR') + '</div><div class="m-sub">subtotal − descuentos</div></div>' +
          '<div class="metric"><div class="m-label">Costo productos</div><div class="m-value" style="color:var(--amber)">$' + Math.round(costoDetalle).toLocaleString('es-AR') + '</div><div class="m-sub">compra × cantidad</div></div>' +
          '<div class="metric"><div class="m-label">Ganancia</div><div class="m-value" style="color:' + (gananciaDetalle >= 0 ? 'var(--green)' : 'var(--red)') + '">$' + Math.round(gananciaDetalle).toLocaleString('es-AR') + '</div><div class="m-sub">neto − costo</div></div>' +
          '<div class="metric"><div class="m-label">Margen</div><div class="m-value">' + margenDetalle.toFixed(1) + '%</div><div class="m-sub">sobre neto</div></div>' +
        '</div>' +
      '</div>' : '') +

    // Pagos
    '<div class="card" style="margin-bottom:12px">' +
      '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">' +
        '<span style="font-weight:600">Historial de pagos</span>' +
        (saldo > 0
          ? '<button class="btn btn-sm btn-primary" onclick="irACobranzasConVenta(this.dataset.vid)" data-vid="'+v.id+'"><i class="ti ti-plus"></i> Registrar pago</button>'
          : '<span style="font-size:12px;color:var(--green)"><i class="ti ti-check"></i> Saldo cancelado</span>'
        ) +
      '</div>' +
      (pagos.length
        ? pagos.map(function(p) {
            return '<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:.5px solid var(--border)">' +
              '<div>' +
                '<div style="font-size:13px;font-weight:500">$' + (parseFloat(p.monto)||0).toLocaleString('es-AR') + '</div>' +
                '<div style="font-size:11px;color:var(--text3)">' + (p.fecha||'') + ' · ' + (p.medio||'Efectivo') + (p.nota?' · '+p.nota:'') + '</div>' +
              '</div>' +
              '<span style="font-size:12px;padding:2px 8px;border-radius:6px;background:var(--green-bg);color:var(--green)">✓</span>' +
            '</div>';
          }).join('') +
          (saldo > 0
            ? '<div style="margin-top:10px;padding:10px;background:var(--amber-bg);border-radius:8px;font-size:13px;color:var(--amber);font-weight:500">Saldo pendiente: $' + (parseFloat(saldo)||0).toLocaleString('es-AR') + '</div>'
            : '')
        : '<div style="text-align:center;padding:16px;color:var(--text3);font-size:13px">Sin pagos registrados</div>'
      ) +
    '</div>' +

    '<div class="card" style="margin-bottom:12px">' +
      '<div style="font-weight:600;margin-bottom:12px"><i class="ti ti-route" style="margin-right:6px"></i>Resumen de seguimiento</div>' +
      '<div style="display:flex;flex-wrap:wrap;gap:8px;font-size:12px;color:var(--text2)">' +
        '<span class="badge b-blue">Venta confirmada</span>' +
        (pagos.length ? '<span class="badge b-green">' + pagos.length + ' pago' + (pagos.length!==1?'s':'') + '</span>' : '<span class="badge b-amber">Sin pagos</span>') +
        (otAsociada ? '<span class="badge b-purple">OT ' + escapeHTML(String(otAsociada)) + '</span>' : '<span class="badge">Sin OT</span>') +
        '<span class="badge" style="background:var(--bg3);color:var(--text2)">' + ei.label + '</span>' +
      '</div>' +
    '</div>' +

    // Auditoría
    (v.audit && v.audit.length
      ? '<div class="card">' +
          '<div style="font-weight:600;margin-bottom:10px;font-size:13px;color:var(--text2)">Auditoría</div>' +
          v.audit.map(function(a) {
            return '<div style="font-size:12px;color:var(--text3);padding:4px 0;border-bottom:.5px solid var(--border)">' +
              (a.fecha||'') + ' · ' + (a.usuario||'') + ' — ' + (a.accion||'') +
            '</div>';
          }).join('') +
        '</div>'
      : '');
}

function toggleCSF(vid, fk) {
  var permitidoCSF = typeof window.tienePermiso === 'function'
    ? window.tienePermiso('ventas.contadoSinFactura', { args:[vid, fk] })
    : String(currentRole || '').toLowerCase() === 'admin';
  if (!permitidoCSF) { notify('Solo un admin puede cambiar contado sin factura'); return; }
  var v = _svResolverVentaRegistro(vid);
  if (!v || !fk) return;
  var csf = v.contadoSinFactura === true;
  var t = parseFloat(v.total)||0;
  var nt = csf ? Math.round(t * 1.21) : Math.round(t / 1.21);
  if (!confirm((csf ? 'Restaurar IVA? Total: $'+t.toLocaleString('es-AR')+' -> $'+nt.toLocaleString('es-AR') : 'Contado sin factura? Se quita IVA. $'+t.toLocaleString('es-AR')+' -> $'+nt.toLocaleString('es-AR')))) return;
  if (!window.fbDB) return;
  window.fbUpdate(window.fbRef(window.fbDB, FB_PATHS.ventas+'/'+fk), {
    contadoSinFactura: !csf, total: nt, iva: csf ? Math.round(nt-t) : 0,
    audit: (v.audit||[]).concat([{fecha:new Date().toISOString().slice(0,10), usuario:currentUser||'Admin', accion: csf ? 'IVA restaurado' : 'Contado sin factura'}])
  }).then(function(){ notify(csf ? 'IVA restaurado' : 'Contado sin factura aplicado'); })
    .catch(function(e){ notify('Error: '+e.message); });
}

// Mantenida por compatibilidad — ahora todo registro de pago pasa por el
// módulo de Cobranzas (irACobranzasConVenta), para que quede centralizado.
function registrarPagoVenta(ventaId) {
  irACobranzasConVenta(ventaId);
}
// STOCK DISPONIBLE VS RESERVADO

function getStockDisponible(cod) {
  const s = stockData[cod];
  if (!s) return null;
  return { real:s.real, reservado:s.reservado, disponible: s.real - s.reservado };
}

function reservarStock(cod, cantidad) {
  if (!stockData[cod]) return false;
  const disp = stockData[cod].real - stockData[cod].reservado;
  if (cantidad > disp) { notify('Sin stock suficiente para ' + cod); return false; }
  stockData[cod].reservado += cantidad;
  notify('Stock reservado: ' + cod + ' × ' + cantidad);
  return true;
}
// NOTIFICACIONES INTELIGENTES AUTOMÁTICAS

// Configuración de alertas (qué activa cada tipo)

// Estado de notificaciones leídas

function generarNotificaciones() {
  try {
  todasNotifs = [];
  const ahora = new Date();
  const hoy   = ahora.toLocaleDateString('es-AR');
  Object.entries(stockData || {}).forEach(([cod, s]) => {
    const disp = s.real - s.reservado;
    if (disp <= 0 && NOTIF_CONFIG.stock_critico.activo) {
      todasNotifs.push({
        id: 'stock_crit_' + cod, tipo:'stock', urgente:true,
        icono:'ti-alert-circle', color:'red',
        titulo: 'Sin stock — ' + s.desc,
        sub: 'Stock disponible: 0. Stock mínimo configurado: 3 unidades.',
        tiempo: 'Ahora · Sistema',
        accion: { label:'Ordenar', fn:"showPage('ordenes',document.querySelector('[onclick*=ordenes]'))" },
      });
    } else if (disp > 0 && disp < (s.stockMin || 5) && NOTIF_CONFIG.stock_bajo.activo) {
      todasNotifs.push({
        id: 'stock_bajo_' + cod, tipo:'stock', urgente:false,
        icono:'ti-alert-triangle', color:'amber',
        titulo: 'Stock bajo — ' + s.desc,
        sub: disp + ' unidades disponibles (' + s.reservado + ' reservadas). Mínimo: ' + (s.stockMin || 5) + '.',
        tiempo: 'Hace 2 horas · Sistema',
        accion: { label:'Ordenar', fn:"showPage('ordenes',document.querySelector('[onclick*=ordenes]'))" },
      });
    }
  });
  if (typeof pptoData !== 'undefined') {
    pptoData.forEach(function(p) {
      if (['rechazado','vencido','convertido'].includes(p.estado)) return;
      if (!p.vence) return;
      var venc;
      if (p.vence.indexOf('/') !== -1) {
        var partes = p.vence.split('/');
        if (partes.length < 3) return;
        venc = new Date(partes[2] < 100 ? 2000 + parseInt(partes[2]) : partes[2], partes[1]-1, partes[0]);
      } else if (p.vence.indexOf('-') !== -1) {
        var partesISO = p.vence.split('-');
        if (partesISO.length < 3) return;
        venc = new Date(partesISO[0], partesISO[1]-1, partesISO[2]);
      } else {
        return;
      }
      if (isNaN(venc.getTime())) return;
      var dias = Math.round((venc - ahora) / 86400000);

      if (dias <= 2 && dias >= 0 && NOTIF_CONFIG.ppto_vence_2.activo) {
        todasNotifs.push({
          id: 'ppto_v2_' + p.id, tipo:'presupuesto', urgente:true,
          icono:'ti-file-description', color:'red',
          titulo: 'Presupuesto ' + p.id + ' vence en ' + dias + ' día(s)',
          sub: p.cliente + ' — $' + (parseFloat(p.total)||0).toLocaleString('es-AR') + '. Estado: ' + (pptoEstadoLabel(p.estado)) + '.',
          tiempo: 'Hoy · Sistema',
          accion: { label:'Ver presupuesto', fn:"abrirPresupuestoDesdeNotificacion('" + p.id + "')" },
        });
      } else if (dias <= 7 && dias > 2 && NOTIF_CONFIG.ppto_vence_7.activo) {
        todasNotifs.push({
          id: 'ppto_v7_' + p.id, tipo:'presupuesto', urgente:false,
          icono:'ti-file-description', color:'amber',
          titulo: 'Presupuesto ' + p.id + ' vence en ' + dias + ' días',
          sub: p.cliente + ' — $' + (parseFloat(p.total)||0).toLocaleString('es-AR') + '. Sin respuesta del cliente.',
          tiempo: 'Hoy · Sistema',
          accion: { label:'Ver presupuesto', fn:"abrirPresupuestoDesdeNotificacion('" + p.id + "')" },
        });
      }

      // Presupuesto enviado sin respuesta hace +5 días
      if (p.estado === 'enviado' && NOTIF_CONFIG.ppto_sin_resp.activo) {
        todasNotifs.push({
          id: 'ppto_sinresp_' + p.id, tipo:'presupuesto', urgente:false,
          icono:'ti-clock', color:'amber',
          titulo: 'Sin respuesta — Presupuesto ' + p.id,
          sub: p.cliente + ' — Enviado el ' + p.fecha + '. Sin confirmación del cliente.',
          tiempo: 'Hace 5 días · Sistema',
          accion: { label:'Ver presupuesto', fn:"abrirPresupuestoDesdeNotificacion('" + p.id + "')" },
        });
      }

      // Requiere aprobación admin
      if (p.requiereAprobacion && p.estado === 'revision') {
        todasNotifs.push({
          id: 'ppto_aprob_' + p.id, tipo:'presupuesto', urgente:true,
          icono:'ti-shield-check', color:'amber',
          titulo: 'Requiere aprobación — ' + p.id,
          sub: p.cliente + ' — ' + p.motivo,
          tiempo: 'Pendiente · Sistema',
          accion: { label:'Revisar', fn:"abrirPresupuestoDesdeNotificacion('" + p.id + "')" },
        });
      }
    });
  }
  const deudas30 = [];
  const deudas15 = [];

  if (NOTIF_CONFIG.deuda_30.activo) {
    deudas30.forEach(d => {
      todasNotifs.push({
        id: 'deuda30_' + d.cliente.replace(/\W/g,''), tipo:'deuda', urgente:true,
        icono:'ti-wallet', color:'red',
        titulo: 'Deuda vencida — ' + d.cliente,
        sub: '$' + (parseFloat(d.monto)||0).toLocaleString('es-AR') + ' pendientes hace ' + d.dias + ' días. Requiere gestión urgente.',
        tiempo: 'Hace ' + d.dias + ' días · Sistema',
        accion: { label:'Ver cuenta', fn:"showPage('cuentacorriente',document.querySelector('[onclick*=cuentacorriente]'))" },
      });
    });
  }

  if (NOTIF_CONFIG.deuda_15.activo) {
    deudas15.forEach(d => {
      todasNotifs.push({
        id: 'deuda15_' + d.cliente.replace(/\W/g,''), tipo:'deuda', urgente:false,
        icono:'ti-coin', color:'amber',
        titulo: 'Saldo pendiente — ' + d.cliente,
        sub: '$' + (parseFloat(d.monto)||0).toLocaleString('es-AR') + ' sin cobrar hace ' + d.dias + ' días.',
        tiempo: 'Hace ' + d.dias + ' días · Sistema',
        accion: { label:'Ver cuenta', fn:"showPage('cuentacorriente',document.querySelector('[onclick*=cuentacorriente]'))" },
      });
    });
  }
  if (typeof otData !== 'undefined') {
    otData.forEach(ot => {
      if (ot.estado === 'completada') return;

      // OT sin técnico
      if ((ot.tecnico === 'Sin asignar' || !ot.tecnico) && NOTIF_CONFIG.ot_sin_tecnico.activo) {
        todasNotifs.push({
          id: 'ot_tec_' + ot.id, tipo:'ot', urgente:true,
          icono:'ti-user-exclamation', color:'red',
          titulo: 'Sin técnico — ' + ot.id,
          sub: ot.cliente + ' — Orden de trabajo sin técnico asignado.',
          tiempo: 'Pendiente · Sistema',
          accion: { label:'Asignar técnico', fn:"abrirOTDesdeNotificacion('" + ot.id + "')" },
        });
      }

      // OT programada para hoy
      const fechaOT = ot.fecha ? new Date(ot.fecha) : null;
      const esHoy = fechaOT && fechaOT.toDateString() === ahora.toDateString();
      if (esHoy && ot.estado === 'pendiente' && NOTIF_CONFIG.ot_hoy.activo) {
        todasNotifs.push({
          id: 'ot_hoy_' + ot.id, tipo:'ot', urgente:false,
          icono:'ti-tool', color:'blue',
          titulo: 'Instalación hoy — ' + ot.id,
          sub: ot.cliente + ' · ' + ot.tecnico + ' · ' + ot.hora + 'hs · ' + ot.dir,
          tiempo: 'Hoy · Agenda',
          accion: { label:'Ver OT', fn:"abrirOTDesdeNotificacion('" + ot.id + "')" },
        });
      }

      // OT en progreso sin avance (progreso < 20% y tiene fecha pasada)
      if (ot.estado === 'en_progreso' && ot.progreso < 20 && fechaOT && fechaOT < ahora) {
        todasNotifs.push({
          id: 'ot_parada_' + ot.id, tipo:'ot', urgente:false,
          icono:'ti-clock-pause', color:'amber',
          titulo: 'OT sin avance — ' + ot.id,
          sub: ot.cliente + ' — En progreso pero con menos del 20% completado.',
          tiempo: 'Ayer · Sistema',
          accion: { label:'Ver OT', fn:"abrirOTDesdeNotificacion('" + ot.id + "')" },
        });
      }
    });
  }

  // Ordenar: urgentes primero, luego por tipo
  todasNotifs.sort((a,b) => (b.urgente?1:0) - (a.urgente?1:0));

  renderNotificaciones();
  actualizarBadgeNotif();
  } catch(errNotif) {
    console.error('[Notificaciones] Error generando:', errNotif);
    var notifLista = document.getElementById('notif-lista');
    if (notifLista) notifLista.innerHTML = '<div style="padding:24px;text-align:center;color:var(--red)"><i class="ti ti-alert-circle" style="font-size:24px"></i><div style="margin-top:8px;font-size:13px">Error al cargar notificaciones</div><div style="font-size:11px;color:var(--text3);margin-top:4px">'+errNotif.message+'</div></div>';
  }
}

function pptoEstadoLabel(est) {
  const m = { borrador:'Borrador', revision:'En revisión', aprobado_int:'Aprobado internamente', enviado:'Enviado al cliente', visto:'Visto', aceptado:'Aceptado', rechazado:'Rechazado', vencido:'Vencido', convertido:'Convertido' };
  return m[est] || est;
}

function renderConfigAlertas() {
  const el = document.getElementById('notif-config-lista');
  if (!el) return;
  el.innerHTML = Object.entries(NOTIF_CONFIG).map(([key, cfg], i, arr) => `
    <div style="display:flex;align-items:center;justify-content:space-between;padding:12px 0;${i < arr.length-1 ? 'border-bottom:0.5px solid var(--border)' : ''}">
      <div>
        <div style="font-size:13px;color:var(--text);font-weight:${cfg.urgente?'500':'400'}">${cfg.label}${cfg.urgente ? ' <span style="font-size:10px;background:var(--red-bg);color:var(--red);padding:1px 6px;border-radius:10px">URGENTE</span>' : ''}</div>
        <div style="font-size:12px;color:var(--text3);margin-top:2px">${cfg.sub}</div>
      </div>
      <div style="display:flex;align-items:center;gap:8px;flex-shrink:0;margin-left:12px">
        <div style="display:flex;gap:4px">${cfg.canales.map(c => `<span class="badge b-${c==='WhatsApp'?'green':c==='Email'?'blue':'purple'}">${c}</span>`).join('')}</div>
        <label style="display:flex;align-items:center;gap:6px;cursor:pointer;font-size:12px;color:var(--text2)">
          <input type="checkbox" ${cfg.activo ? 'checked' : ''} onchange="toggleNotifConfig('${key}',this.checked)" style="accent-color:var(--green)">
          Activo
        </label>
      </div>
    </div>`).join('');
}

function toggleNotifConfig(key, val) {
  NOTIF_CONFIG[key].activo = val;
  generarNotificaciones();
  notify(NOTIF_CONFIG[key].label + (val ? ' activada' : ' desactivada'));
}

// MÓDULO DETALLE DE VENTAS

// Datos completos de ventas

// Renderizar la tabla de ventas
function renderVentasTabla(lista) {
  const tbody = document.getElementById('ventas-tbody');
  const count = document.getElementById('ventas-count');
  if (!tbody) return;
  const rows = lista || ventasList;
  if (count) count.textContent = rows.length + ' venta' + (rows.length !== 1 ? 's' : '');
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:var(--text3);padding:24px">Sin ventas para mostrar</td></tr>';
    return;
  }
  tbody.innerHTML = rows.map(v => `<tr style="cursor:pointer;touch-action:pan-x pan-y" onclick="verVenta('${v.id}')">
    <td style="font-weight:500;color:var(--text);font-family:monospace;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escapeHTML(v.id)}</td>
    <td style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHTML(v.cliente)}</td>
    <td style="color:var(--text3);white-space:nowrap">${_mostrarFecha(v.fecha)}</td>
    <td class="tr" style="font-weight:500;white-space:nowrap">$${(parseFloat(v.total)||0).toLocaleString('es-AR')}</td>
    <td class="tr" style="white-space:nowrap">${ventaEstadoBadge(v.estadoPago)}</td>
    <td class="tr" style="white-space:nowrap">${ventaEstadoInstBadge(v.estadoInst)}</td>
    <td style="text-align:center;white-space:nowrap">
      ${v.notaCredito && v.notaCredito.cae
        ? `<span title="Factura anulada con NC — CAE NC: ${escapeHTML(v.notaCredito.cae)}" style="display:inline-flex;align-items:center;gap:3px">
            <i class="ti ti-file-check" style="font-size:13px;color:var(--text3);text-decoration:line-through;opacity:.5"></i>
            <i class="ti ti-file-minus" style="font-size:15px;color:var(--red)"></i>
           </span>`
        : v.factura && v.factura.cae
          ? `<span title="Factura emitida — CAE: ${escapeHTML(v.factura.cae)}" style="color:var(--green)"><i class="ti ti-file-check" style="font-size:15px"></i></span>`
          : ''}
    </td>
    <td onclick="event.stopPropagation()" style="text-align:center">
      <button class="btn btn-sm btn-icon" onclick="verVenta('${v.id}')" title="Ver detalle"><i class="ti ti-eye" style="font-size:14px"></i></button>
    </td>
  </tr>`).join('');
}

// Filtros
window._filtrosVentas = { texto:'', estado:'', mes:'', tab:'todas' };

function filtrarVentas(v) {
  window._filtrosVentas.texto = v || '';
  _aplicarFiltrosVentas();
}
function filtrarVentasEstado(est) {
  window._filtrosVentas.estado = est || '';
  _aplicarFiltrosVentas();
}
function filtrarVentasMes(mes) {
  window._filtrosVentas.mes = mes || '';
  _aplicarFiltrosVentas();
}
function tabVentas(tipo, btn) {
  window._filtrosVentas.tab = tipo;
  document.querySelectorAll('[id^=vtab-]').forEach(b => {
    b.style.background=''; b.style.color=''; b.style.borderColor='';
  });
  var btnActivo = btn || document.getElementById('vtab-'+tipo);
  if (btnActivo) { btnActivo.style.background='var(--text)'; btnActivo.style.color='var(--bg2)'; btnActivo.style.borderColor='var(--text)'; }
  _aplicarFiltrosVentas();
}

function _aplicarFiltrosVentas() {
  const f = window._filtrosVentas;
  let lista = (ventasList || []).slice().sort(function(a,b) {
    var diferencia = fechaVentaTimestamp(b.fecha, b.ts) - fechaVentaTimestamp(a.fecha, a.ts);
    return diferencia || ((b.ts||0) - (a.ts||0));
  });
  lista = lista.filter(v => !v.anulada || v.notaCredito);

  if (f.texto) {
    const t = f.texto.toLowerCase();
    lista = lista.filter(x => (x.id||'').toLowerCase().includes(t) || (x.cliente||'').toLowerCase().includes(t));
  }
  if (f.estado) {
    lista = lista.filter(v => v.estadoPago === f.estado || v.estadoInst === f.estado);
  }
  if (f.mes) {
    lista = lista.filter(v => typeof _fechaEsDelMes === 'function' ? _fechaEsDelMes(v.fecha, f.mes) : true);
  }
  const inicioHoy = new Date(); inicioHoy.setHours(0,0,0,0);
  const mapasTab = {
    todas:      lista,
    cobrar:     lista.filter(v => ['pendiente_pago','seniado'].includes(v.estadoPago)),
    instalar:   lista.filter(v => ['pendiente_inst','en_instalacion'].includes(v.estadoInst)),
    hoy:        lista.filter(v => fechaVentaTimestamp(v.fecha, v.ts) === Date.UTC(inicioHoy.getFullYear(), inicioHoy.getMonth(), inicioHoy.getDate())),
    facturadas: lista.filter(v => !!v.factura),
  };
  renderVentasTabla(mapasTab[f.tab] || lista);
  _actualizarBannerFiltroVentas();
}

function _actualizarBannerFiltroVentas() {
  var f = window._filtrosVentas || {};
  var banner = document.getElementById('ventas-filtro-activo-banner');
  var txtEl  = document.getElementById('ventas-filtro-activo-texto');
  if (!banner || !txtEl) return;

  var partes = [];
  if (f.tab && f.tab !== 'todas') {
    var tabLbl = {cobrar:'Por cobrar', instalar:'Por instalar', hoy:'Hoy', facturadas:'Facturadas'}[f.tab] || f.tab;
    partes.push(tabLbl);
  }
  if (f.estado) {
    var estLbl = {pendiente_pago:'Pendiente pago', seniado:'Señado', pago_total:'Pago total', en_instalacion:'En instalación', instalado:'Instalado', con_garantia:'Con garantía'}[f.estado] || f.estado;
    partes.push(estLbl);
  }
  if (f.mes) {
    var d = new Date(f.mes + '-01T12:00:00');
    partes.push(d.toLocaleDateString('es-AR',{month:'long',year:'numeric'}));
  }
  if (f.texto) partes.push('"' + f.texto + '"');

  if (partes.length) {
    txtEl.textContent = 'Mostrando solo: ' + partes.join(' · ') + ' — puede haber ventas nuevas ocultas por este filtro';
    banner.style.display = 'flex';
  } else {
    banner.style.display = 'none';
  }
}

function limpiarFiltrosVentas() {
  window._filtrosVentas = { texto:'', estado:'', mes:'', tab:'todas' };
  _restaurarControlesFiltrosVentas();
  _aplicarFiltrosVentas();
}
function _restaurarControlesFiltrosVentas() {
  const f = window._filtrosVentas;
  var elSearch = document.getElementById('ventas-search');
  var elEstado = document.getElementById('ventas-estado');
  var elMes    = document.getElementById('ventas-mes');
  if (elSearch) elSearch.value = f.texto || '';
  if (elEstado) elEstado.value = f.estado || '';
  if (elMes)    elMes.value    = f.mes || '';
  document.querySelectorAll('[id^=vtab-]').forEach(b => {
    b.style.background=''; b.style.color=''; b.style.borderColor='';
  });
  var btnTab = document.getElementById('vtab-'+(f.tab||'todas'));
  if (btnTab) { btnTab.style.background='var(--text)'; btnTab.style.color='var(--bg2)'; btnTab.style.borderColor='var(--text)'; }
}

// Ver detalle de una venta
function verVenta(id) {
  return verDetalleVenta(id);
}

// Inicializar al entrar

var CONFIG_COMISIONES = {
  'Cat. 39': { pct: 2.5, min: 0, max: 999999 },
  'Cat. 15': { pct: 1.5, min: 0, max: 999999 },
  'Cat. 08': { pct: 1.0, min: 0, max: 999999 }
};

function _normComisionKey(v) {
  return String(v || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function _aliasesComisionCargo(cargoId) {
  var c = (CARGOS_DATA || {})[cargoId] || {};
  var arr = [cargoId, c.id, c.nombre, c.cargo, c.categoria, c.categoriaBase];
  var base = _normComisionKey(c.categoriaBase || c.nombre || cargoId);
  var idn  = _normComisionKey(cargoId);
  // Compatibilidad con claves usadas en versiones anteriores.
  if (idn === 'tecnico_c' || base === 'tecnico_c') arr.push('Cat. 39', 'cat_39', 'TECNICO C', 'Técnico C');
  if (idn === 'tecnico_b' || base === 'tecnico_b') arr.push('Cat. 15', 'cat_15', 'TECNICO B', 'Técnico B');
  if (idn === 'tecnico_a' || base === 'tecnico_a') arr.push('Cat. 08', 'cat_08', 'TECNICO A', 'Técnico A');
  if (idn === 'administrativo' || base === 'adminis' || base === 'administrativo') arr.push('ADMINIS', 'Administrativo');
  if (idn === 'inicial' || base === 'inicial') arr.push('INICIAL', 'Inicial');
  if (idn === 'temporal' || base === 'a_temp' || base === 'temporal') arr.push('A-TEMP', 'Temporal');
  return Array.from(new Set(arr.filter(function(x){ return x !== undefined && x !== null && String(x).trim() !== ''; })));
}

function obtenerConfigComisionCargo(cargoId) {
  var cfgs = CONFIG_COMISIONES || {};
  if (cfgs[cargoId]) return cfgs[cargoId];
  var aliases = _aliasesComisionCargo(cargoId);
  for (var i = 0; i < aliases.length; i++) {
    if (cfgs[aliases[i]]) return cfgs[aliases[i]];
  }
  var aliasesNorm = aliases.map(_normComisionKey);
  var keys = Object.keys(cfgs);
  for (var k = 0; k < keys.length; k++) {
    if (aliasesNorm.indexOf(_normComisionKey(keys[k])) >= 0) return cfgs[keys[k]];
  }
  return { pct:0, min:0, max:0 };
}

function guardarConfigComisionCargo(cargoId, cfg) {
  if (!cargoId) return;
  CONFIG_COMISIONES[cargoId] = {
    pct: parseFloat(cfg && cfg.pct) || 0,
    min: parseFloat(cfg && cfg.min) || 0,
    max: parseFloat(cfg && cfg.max) || 0
  };
}

/* v20.362: Firebase RTDB no acepta . # $ / [ ] en claves. Los defaults históricos
   ('Cat. 39', etc.) hacían fallar TODO fbSet de comisiones, por eso nada persistía.
   Este helper renombra las claves inválidas con _normComisionKey ('Cat. 39' → 'cat_39'),
   que la lectura ya resuelve vía _aliasesComisionCargo. */
function _comisionesParaFirebase() {
  var out = {};
  Object.keys(CONFIG_COMISIONES || {}).forEach(function(k) {
    var key = /[.#$\/\[\]]/.test(k) ? _normComisionKey(k) : k;
    if (!key) return;
    out[key] = CONFIG_COMISIONES[k];
  });
  return out;
}

function renderComisionesConfig() {
  var tbody = document.getElementById('cfg-comisiones-tbody');
  if (!tbody) return;
  var ids = Object.keys(CARGOS_DATA || {});
  if (!ids.length) {
    tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:var(--text3);padding:16px">No hay cargos creados aún. Creá los cargos en la solapa <strong>Cargos</strong> primero.</td></tr>';
    return;
  }
  ids.sort(function(a,b){ return ((CARGOS_DATA[a]||{}).nombre||a).localeCompare(((CARGOS_DATA[b]||{}).nombre||b)); });
  var inp = function(val, w) {
    return '<input type="number" value="'+(parseFloat(val)||0)+'" style="width:'+w+'px;background:var(--bg3);border:0.5px solid var(--border);border-radius:4px;padding:4px 6px;text-align:right;font-size:13px;font-family:inherit">';
  };
  tbody.innerHTML =
    '<tr><th>Cargo</th><th style="text-align:right">% sobre venta</th><th style="text-align:right">Mínimo garantizado</th><th style="text-align:right">Tope máximo</th><th></th></tr>' +
    ids.map(function(id) {
      var c = CARGOS_DATA[id] || {};
      var com = obtenerConfigComisionCargo(id) || {};
      return '<tr data-cargo-id="'+escapeHTML(id)+'">' +
        '<td style="font-weight:500">'+escapeHTML(c.nombre||id)+'</td>' +
        '<td style="text-align:right">'+inp(com.pct||0, 60)+'%</td>' +
        '<td style="text-align:right">'+inp(com.min||0, 80)+'</td>' +
        '<td style="text-align:right">'+inp(com.max||0, 80)+'</td>' +
        '<td><button class="btn btn-sm btn-icon" onclick="guardarFilaConfig(this)" title="Guardar"><i class="ti ti-check" style="font-size:14px;color:var(--green)"></i></button></td>' +
      '</tr>';
    }).join('');
}

function guardarFilaConfig(btn) {
  var tr = btn && btn.closest ? btn.closest('tr') : null;
  if (!tr) return;
  var inputs = tr.querySelectorAll('input[type=number]');
  var cargoId = tr.dataset.cargoId;
  var vals = Array.from(inputs).map(function(i){ return parseFloat(i.value)||0; });
  if (!cargoId) { notify('Fila sin cargo ID — recargá la solapa de comisiones'); return; }
  guardarConfigComisionCargo(cargoId, { pct: vals[0]||0, min: vals[1]||0, max: vals[2]||0 });
  if (window.fbDB) {
    window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/comisiones'), _comisionesParaFirebase())
      .then(function(){ notify('✓ Comisión guardada para ' + ((CARGOS_DATA[cargoId]||{}).nombre || cargoId)); })
      .catch(function(e){ notify('Error: '+e.message); });
  } else {
    notify('Sin conexión a Firebase');
  }
  var icon = btn.querySelector('i');
  if (icon) { icon.className = 'ti ti-check-circle'; btn.style.color='var(--green)'; }
  setTimeout(function(){ if(icon){ icon.className='ti ti-check'; btn.style.color=''; } }, 2000);
}
// MEDIOS DE PAGO CONFIGURABLES

var MEDIOS_PAGO_CONFIG = [
  { nombre: 'Efectivo',       tipo: 'efectivo' },
  { nombre: 'Transferencia',  tipo: 'transferencia' },
  { nombre: 'Tarjeta',        tipo: 'tarjeta' },
  { nombre: 'QR',             tipo: 'qr' },
  { nombre: 'Cheque',         tipo: 'cheque' },
];

var TIPO_LABEL_MP = {
  efectivo: 'Efectivo', transferencia: 'Transferencia / Alias',
  tarjeta: 'Tarjeta', qr: 'QR / Billetera', cheque: 'Cheque', otro: 'Otro'
};
var TIPO_LABEL_MP_CORTO = {
  efectivo: 'EFECTIVO', transferencia: 'TRANSFERENCIA', tarjeta: 'TARJETA',
  qr: 'QR', cheque: 'CHEQUE', otro: 'OTRO'
};
function obtenerMedioPagoConfig(medio) {
  var n = String(medio || '').trim();
  if (!n) return null;
  var norm = function(v){ return String(v||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim(); };
  var base = (typeof MEDIOS_PAGO_CONFIG !== 'undefined' && Array.isArray(MEDIOS_PAGO_CONFIG)) ? MEDIOS_PAGO_CONFIG : [];
  var nNorm = norm(n);
  return base.find(function(m){
    var nombre = String(m.nombre || '').trim();
    var tipo = String(m.tipo || 'otro').trim();
    var tipoLbl = TIPO_LABEL_MP_CORTO[tipo] || tipo.toUpperCase();
    return norm(nombre) === nNorm || norm(tipoLbl + ' / ' + nombre) === nNorm;
  }) || null;
}
function formatoMedioPago(medio) {
  var n = String(medio || '').trim();
  if (!n) return '—';
  var cfg = obtenerMedioPagoConfig(n);
  if (!cfg) return n;
  var tipo = String(cfg.tipo || 'otro').trim();
  var tipoLbl = TIPO_LABEL_MP_CORTO[tipo] || tipo.toUpperCase();
  var nombre = String(cfg.nombre || n).trim();
  return tipoLbl + ' / ' + nombre;
}

function cargarMediosPago() {
  if (!window.fbDB) return;
  window.fbGet(window.fbRef(window.fbDB, 'sisventas/config/mediosPago')).then(function(snap) {
    var data = snap.val();
    if (data && Array.isArray(data) && data.length) {
      MEDIOS_PAGO_CONFIG = data;
    }
    renderMediosPagoConfig();
    poblarSelectoresMediosPago();
  }).catch(function() {
    poblarSelectoresMediosPago(); // usar defaults si falla
  });
}

function renderMediosPagoConfig() {
  var tbody = document.getElementById('cfg-mp-tbody');
  if (!tbody) return;
  if (!MEDIOS_PAGO_CONFIG.length) {
    tbody.innerHTML = '<tr><td colspan="3" style="text-align:center;color:var(--text3);padding:16px">No hay medios configurados</td></tr>';
    return;
  }
  tbody.innerHTML = MEDIOS_PAGO_CONFIG.map(function(m, i) {
    return '<tr style="border-bottom:0.5px solid var(--border)">' +
      '<td style="padding:10px 0;font-size:13px;font-weight:500">' + escapeHTML(m.nombre) + '</td>' +
      '<td style="padding:10px 0;font-size:12px;color:var(--text3)">' + (TIPO_LABEL_MP[m.tipo]||m.tipo) + '</td>' +
      '<td style="padding:10px 0;text-align:right">' +
        '<button class="btn btn-sm" style="color:var(--red);border-color:var(--red);padding:3px 8px" onclick="eliminarMedioPago(' + i + ')">' +
          '<i class="ti ti-trash"></i>' +
        '</button>' +
      '</td>' +
    '</tr>';
  }).join('');
}

function agregarMedioPago() {
  var nombre = (document.getElementById('cfg-mp-nombre').value || '').trim();
  var tipo   = document.getElementById('cfg-mp-tipo').value;
  if (!nombre) { notify('Ingresá un nombre'); return; }
  if (MEDIOS_PAGO_CONFIG.find(function(m){ return m.nombre.toLowerCase() === nombre.toLowerCase(); })) {
    notify('Ya existe un medio con ese nombre'); return;
  }
  MEDIOS_PAGO_CONFIG.push({ nombre: nombre, tipo: tipo });
  guardarMediosPago();
  document.getElementById('cfg-mp-nombre').value = '';
}

function eliminarMedioPago(idx) {
  var m = MEDIOS_PAGO_CONFIG[idx];
  if (!m) return;
  if (!confirm('¿Eliminar "' + m.nombre + '"? Los cobros ya registrados con este medio no se modifican.')) return;
  MEDIOS_PAGO_CONFIG.splice(idx, 1);
  guardarMediosPago();
}

function guardarMediosPago() {
  if (!window.fbDB) return;
  window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/mediosPago'), MEDIOS_PAGO_CONFIG)
    .then(function() {
      notify('✓ Medios de pago guardados');
      renderMediosPagoConfig();
      poblarSelectoresMediosPago();
    }).catch(function(e){ notify('Error: ' + e.message); });
}

// Puebla todos los selectores de medio de pago del sistema
function poblarSelectoresMediosPago() {
  var ids = ['cob-medio', 'cob-filtro-medio', 'g-medio', 'mpg-medio', 'cm-medio', 'ng-medio', 'gr-medio'];
  var html = MEDIOS_PAGO_CONFIG.map(function(m) {
    return '<option value="' + escapeHTML(m.nombre) + '">' + escapeHTML(formatoMedioPago(m.nombre)) + '</option>';
  }).join('');
  var htmlFiltro = '<option value="">Todos los medios</option>' + html;

  ids.forEach(function(id) {
    var el = document.getElementById(id);
    if (!el) return;
    var actual = el.value;
    el.innerHTML = id === 'cob-filtro-medio' ? htmlFiltro : '<option value="">— Seleccionar —</option>' + html;
    if (actual) el.value = actual;
  });
}

function cargarConfigComisiones() {
  if (!window.fbDB) return;
  window.fbGet(window.fbRef(window.fbDB, 'sisventas/config/comisiones')).then(function(snap) {
    var data = snap.val();
    if (data && typeof data === 'object') {
      CONFIG_COMISIONES = Object.assign({}, CONFIG_COMISIONES || {}, data);
      actualizarInputsComisiones();
      var panel = document.getElementById('cfg-comisiones');
      if (panel && panel.style.display !== 'none') renderComisionesConfig();
    }
  }).catch(function(){});
  window.fbGet(window.fbRef(window.fbDB, 'sisventas/config/maxComisionPct')).then(function(snap) {
    var val = snap.val();
    if (val != null) {
      APROBACION_CONFIG.maxComisionPct = parseFloat(val) || 10;
      var el = document.getElementById('cfg-max-comision-pct');
      if (el) el.value = APROBACION_CONFIG.maxComisionPct;
    }
  }).catch(function(){});
}

function guardarMaxComisionPct() {
  var el = document.getElementById('cfg-max-comision-pct');
  var val = parseFloat(el ? el.value : 10) || 10;
  APROBACION_CONFIG.maxComisionPct = val;
  window.fbSet(window.fbRef(window.fbDB, 'sisventas/config/maxComisionPct'), val)
    .then(function(){ notify('✓ Tope máximo de comisión guardado: ' + val + '%'); })
    .catch(function(e){ notify('Error: ' + e.message); });
}

function actualizarInputsComisiones() {
  var tabla = document.querySelector('#cfg-comisiones-tbody');
  if (!tabla) return;
  Array.from(tabla.querySelectorAll('tr[data-cargo-id]')).forEach(function(tr) {
    var cargoId = tr.dataset.cargoId;
    var cfg = obtenerConfigComisionCargo(cargoId) || {};
    var inputs = tr.querySelectorAll('input[type=number]');
    if (inputs[0]) inputs[0].value = parseFloat(cfg.pct || 0) || 0;
    if (inputs[1]) inputs[1].value = parseFloat(cfg.min || 0) || 0;
    if (inputs[2]) inputs[2].value = parseFloat(cfg.max || 0) || 0;
  });
}

function obtenerCategoriaEmpleado(emp) {
  var cargo = (emp.cargo||'').toUpperCase();
  if (cargo.includes('TECNICO C')||cargo.includes('TÉCNICO C')) return 'TECNICO C';
  if (cargo.includes('TECNICO B')||cargo.includes('TÉCNICO B')) return 'TECNICO B';
  if (cargo.includes('TECNICO A')||cargo.includes('TÉCNICO A')) return 'TECNICO A';
  if (cargo.includes('ADMIN'))   return 'ADMINIS';
  if (cargo.includes('INICIAL')) return 'INICIAL';
  if (cargo.includes('TEMP'))    return 'A-TEMP';
  if (emp.categoria==39) return 'TECNICO C';
  if (emp.categoria==15) return 'TECNICO B';
  return 'TECNICO A';
}

function calcularComisionEmpleado(emp, mesAMM) {
  var cat = obtenerCategoriaEmpleado ? obtenerCategoriaEmpleado(emp) : '';
  var cfgCat = cat.includes('C')||cat.includes('B') ? CONFIG_COMISIONES['Cat. 39']
             : cat.includes('A')                    ? CONFIG_COMISIONES['Cat. 15']
             : CONFIG_COMISIONES['Cat. 08'];

  var ventas = (ventasList||[]).filter(function(v){
    return (v.empleado===emp.nombre||v.empleadoId===emp.fbKey) &&
           (v.fecha||'').slice(0,7) === (mesAMM||new Date().toISOString().slice(0,7));
  });

  var totalVentas = ventas.reduce(function(s,v){ return s+(parseFloat(v.total)||0); }, 0);
  var comision    = totalVentas * (cfgCat.pct||0) / 100;
  var comisionFinal = Math.max(cfgCat.min||0, Math.min(cfgCat.max||999999, comision));

  return {
    totalVentas: totalVentas,
    cantVentas:  ventas.length,
    pct:         cfgCat.pct||0,
    comision:    comisionFinal,
    sinTope:     comision
  };
}

