// Editar cliente
function editarCliente(id) {
  var cli = clientesData ? clientesData.find(function(c){ return c.id === id; }) : null;
  window._editingClienteId = id;
  abrirModalNuevo('cliente');
  if (cli) {
    setTimeout(function() {
      var partes = (cli.nombre || '').trim().split(' ');
      var nm = partes[0] || '';
      var ap = partes.length > 1 ? partes.slice(1).join(' ') : '';
      var campos = {
        'nc-nm': nm, 'nc-ap': ap, 'nc-dni': cli.dni||'', 'nc-cuit': cli.cuit||'',
        'nc-tel': cli.telefono||cli.tel||'', 'nc-em': cli.mail||cli.email||'',
        'nc-empresa': cli.empresa||'', 'nc-dir': cli.dir||cli.direccion||''
      };
      Object.entries(campos).forEach(function(kv) {
        var el = document.getElementById(kv[0]); if (el) el.value = kv[1];
      });
      _set('modal-nuevo-title', 'Editar cliente — ' + cli.nombre);
    }, 50);
  }
}

function toggleFab() {
  fabOpen = !fabOpen;
  var container = document.getElementById('fab-container');
  var main      = document.getElementById('fab-main');
  if (main) main.classList.toggle('open', fabOpen);

  if (fabOpen) {
    // Crear acciones dinámicamente
    var existing = document.getElementById('fab-actions');
    if (existing) existing.remove();
    var accionesBase = [
      { label: 'Nuevo presupuesto', color: '#185fa5', icon: 'ti-file-description', accion: 'presupuesto' },
      { label: 'Nueva venta',       color: '#2a7a38', icon: 'ti-plus',             accion: 'venta' },
      { label: 'Registrar cobro',   color: '#7a5c00', icon: 'ti-cash',             accion: 'cobro' },
      { label: 'Nuevo gasto',       color: '#a32d2d', icon: 'ti-receipt',          accion: 'gasto' },
      { label: 'Agendar evento',    color: '#4a3ab0', icon: 'ti-calendar-plus',    accion: 'agenda' },
      { label: 'Asistente IA',      color: 'linear-gradient(135deg,#6366f1,#8b5cf6)', icon: 'ti-robot', accion: 'ia' }
    ];
    // Filtrar IA según config de widgets
    var iaPermitida = DASH_WIDGETS_CONFIG['btn_ia'] !== undefined
      ? !!DASH_WIDGETS_CONFIG['btn_ia'][currentRole]
      : true;
    var acciones = accionesBase.filter(function(a) {
      if (a.accion === 'ia') return iaPermitida;
      if (currentRole === 'tecnico') return a.accion === 'agenda' || a.accion === 'gasto';
      return true;
    });
    var div = document.createElement('div');
    div.className = 'fab-actions open'; div.id = 'fab-actions';
    acciones.forEach(function(a) {
      var btn = document.createElement('button');
      btn.className = 'fab-item';
      btn.innerHTML = '<span class="fab-label">'+a.label+'</span><div class="fab-btn" style="background:'+a.color+'"><i class="ti '+a.icon+'" style="font-size:17px;color:#fff"></i></div>';
      btn.onclick = function() { closeFab(); if(a.accion==='ia') iaAbrir(); else fabAccion(a.accion); };
      div.appendChild(btn);
    });
    if (container) container.insertBefore(div, container.firstChild);
  } else {
    var actions = document.getElementById('fab-actions');
    if (actions) actions.remove();
  }
}

function closeFab() {
  fabOpen = false;
  var actions = document.getElementById('fab-actions');
  var main    = document.getElementById('fab-main');
  if (actions) actions.remove();
  if (main)    main.classList.remove('open');
}
// Fix Android/iOS: anclar FAB al visual viewport para que no se mueva
// cuando la barra del browser aparece/desaparece al scrollear
(function() {
  var fab = document.getElementById('fab-container');
  if (!fab || !window.visualViewport) return;
  function reposFab() {
    var vv = window.visualViewport;
    var bottom = (window.innerHeight - vv.height - vv.offsetTop);
    var fabBase = window.innerWidth <= 1024 ? 16 : 82;
    fab.style.bottom = Math.max(fabBase, fabBase + bottom) + 'px';
  }
  window.visualViewport.addEventListener('resize', reposFab, { passive: true });
  window.visualViewport.addEventListener('scroll', reposFab, { passive: true });
})();
function fabAccion(tipo) {
  closeFab();
  switch(tipo) {
    case 'presupuesto':
      showPage('presupuesto', document.querySelector('[onclick*="presupuesto"]'));
      setTimeout(function(){ if(typeof abrirNuevoPresupuesto==='function') abrirNuevoPresupuesto(); }, 150);
      break;
    case 'venta':
      showPage('venta', document.querySelector('.nav-item[onclick*="venta"]'));
      break;
    case 'cobro':
      showPage('cobranzas', document.querySelector('[onclick*="cobranzas"]'));
      break;
    case 'gasto':
      if (esTecnico && esTecnico()) {
        if (typeof abrirGastoRapido === 'function') abrirGastoRapido();
        else notify('Acceso restringido para tu rol');
      } else {
        showPage('gastos', document.querySelector('[onclick*="gastos"]'));
        setTimeout(function(){ if(typeof abrirModalNuevo==='function') abrirModalNuevo('gasto'); }, 150);
      }
      break;
    case 'agenda':
      showPage('agenda', document.querySelector('[onclick*="agenda"]'));
      setTimeout(function(){ if(typeof abrirModalNuevo==='function') abrirModalNuevo('evento'); }, 150);
      break;
  }
}
